// Helper: Belirli bir tarih için aktif parametreyi bul
function getActivePayrollParams(data, dateStr) {
  const versions = data?.hrPayrollParams?.versions || [];
  if (!versions.length) return null;
  const targetDate = dateStr || new Date().toISOString().slice(0, 10);
  // Önce tarihe uyan ve aktif olanı bul
  const matching = versions.find(v =>
    !v.isDraft &&
    (!v.effectiveFrom || v.effectiveFrom <= targetDate) &&
    (!v.effectiveTo || v.effectiveTo >= targetDate)
  );
  if (matching) return matching;
  // En son aktif olanı
  const active = versions.find(v => v.active && !v.isDraft);
  if (active) return active;
  // Yoksa son versiyon
  return versions[versions.length - 1] || null;
}

// Helper: Gelir vergisi cetvelinden vergi hesapla (kümülatif matrahla)
function calculateIncomeTax(annualCumulativeBase, brackets) {
  if (!brackets || !brackets.length || annualCumulativeBase <= 0) return 0;
  let totalTax = 0;
  for (const b of brackets) {
    const upper = b.to == null ? Infinity : b.to;
    if (annualCumulativeBase <= b.from) break;
    const bracketAmount = Math.min(annualCumulativeBase, upper) - b.from;
    if (bracketAmount > 0) {
      totalTax += bracketAmount * (b.rate / 100);
    }
    if (annualCumulativeBase <= upper) break;
  }
  return totalTax;
}

/* =====================================================================
   ÇALIŞAN → ORG BİRİM ENTEGRASYON HELPER'LARI
   ---------------------------------------------------------------------
   Bordro motoru için bilgi toplama zinciri:
   Employee.jobTitleId → JobTitle.departmentId → Department.orgUnitId → OrgUnit
                                                                        ↓
                                          (teşvik, SGK kodu, banka, nakit akış)
===================================================================== */

// Çalışanın bağlı olduğu Pozisyon Tanımı
function getEmployeeJobTitle(employee, data) {
  if (!employee?.jobTitleId) return null;
  return (data?.hrJobTitles || []).find(j => j.id === employee.jobTitleId) || null;
}

// Çalışanın bağlı olduğu Departman
function getEmployeeDepartment(employee, data) {
  const jt = getEmployeeJobTitle(employee, data);
  if (!jt?.departmentId) return null;
  return (data?.hrDepartments || []).find(d => d.id === jt.departmentId) || null;
}

// Çalışanın bağlı olduğu Org Birimi
function getEmployeeOrgUnit(employee, data) {
  // 1. Manuel override varsa onu kullan (örn: Ar-Ge teşvikinden faydalanmıyor)
  if (employee?.payrollProfile?.orgUnitOverrideId) {
    const override = (data?.hrOrgUnits || []).find(o => o.id === employee.payrollProfile.orgUnitOverrideId);
    if (override) return override;
  }
  // 2. Departmandan türet
  const dept = getEmployeeDepartment(employee, data);
  if (dept?.orgUnitId) {
    return (data?.hrOrgUnits || []).find(o => o.id === dept.orgUnitId) || null;
  }
  return null;
}

// Çalışanın hesaplama yaşı (BES otomatik katılım için)
function getEmployeeAge(employee) {
  if (!employee?.birthDate) return null;
  const today = new Date();
  const birth = new Date(employee.birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) age--;
  return age;
}

// Çalışanın kıdem (yıl)
function getEmployeeTenure(employee) {
  if (!employee?.startDate) return 0;
  const today = new Date();
  const start = new Date(employee.startDate);
  const ms = today.getTime() - start.getTime();
  return ms / (365.25 * 24 * 3600 * 1000);
}

// Çalışanın yıllık izin hakkı (kıdeme + iş kanunu parametresine göre)
function getEmployeeAnnualLeave(employee, data) {
  const tenure = getEmployeeTenure(employee);
  const params = getActivePayrollParams(data);
  const labor = params?.laborLaw || { annualLeave1: 14, annualLeave5: 20, annualLeave15: 26 };
  if (tenure >= 15) return labor.annualLeave15;
  if (tenure >= 5) return labor.annualLeave5;
  if (tenure >= 1) return labor.annualLeave1;
  return 0;
}

// Bordro motoru için TOPLU bağlam çıkar
function getEmployeePayrollContext(employee, data, dateStr) {
  if (!employee) return null;
  const jobTitle = getEmployeeJobTitle(employee, data);
  const department = getEmployeeDepartment(employee, data);
  const orgUnit = getEmployeeOrgUnit(employee, data);
  const params = getActivePayrollParams(data, dateStr);
  const profile = employee.payrollProfile || {};

  // Teşvik uygulanabilir mi?
  const incentiveType = orgUnit?.incentive?.type || "none";
  const isRDIncentive = ["rd_5746", "design_5746", "tech_park_4691"].includes(incentiveType);
  const benefitsFromIncentive = isRDIncentive && !profile.optOutIncentive && (profile.includedInIncentive !== false);

  // GV stopaj oranını belirle (kişi bazında)
  let gvStopajRate = 0;
  if (benefitsFromIncentive) {
    if (profile.isTop25Percent) gvStopajRate = params?.rdIncentive?.gvStopajRateTop25 || 100;
    else if (profile.hasPhD) gvStopajRate = params?.rdIncentive?.gvStopajRatePhD || 95;
    else gvStopajRate = orgUnit?.incentive?.gvStopajRate || params?.rdIncentive?.gvStopajRateStandard || 80;
  }

  // SGK işveren desteği
  const sgkSupportRate = benefitsFromIncentive ? (orgUnit?.incentive?.sgkSupportRate || params?.rdIncentive?.sgkEmployerSupportRate || 50) : 0;

  // Tehlike sınıfı primi
  const hazardClass = orgUnit?.sgk?.hazardClass || "az";
  const hazardRate = params?.sgkRates?.hazardRates?.[hazardClass] || 1.5;

  // Çalışma rejimi
  const workRegime = orgUnit?.payroll?.workRegime || "full_time_45h";
  const workdaysPerMonth = orgUnit?.payroll?.workdaysPerMonth || 22;
  const weeklyHours = orgUnit?.payroll?.weeklyHours || 45;

  // Yan haklar
  const providesMeal = !!orgUnit?.payroll?.providesMeal;
  const providesTransport = !!orgUnit?.payroll?.providesTransport;
  const providesHealth = !!orgUnit?.payroll?.providesHealth;
  const providesBes = !!orgUnit?.payroll?.providesBes;

  // BES otomatik katılım
  const age = getEmployeeAge(employee);
  const besAutoEnrolled = age != null && age < (params?.bes?.autoEnrollAge || 45) && !profile.besOptOut;

  // Bordro banka hesabı
  const payrollBankId = orgUnit?.bank?.payrollBankId || orgUnit?.bank?.primaryBankId || null;
  const payrollAccountId = orgUnit?.bank?.payrollAccountId || orgUnit?.bank?.primaryAccountId || null;

  // SGK İşyeri Kodu (beyanname için)
  const sgkWorkplaceCode = orgUnit?.sgk?.workplaceCode || null;

  // Nakit akış kategorisi
  const payrollCfCategory = orgUnit?.finance?.payrollCategoryId || null;

  return {
    employee,
    jobTitle,
    department,
    orgUnit,
    params,
    profile,
    incentive: {
      type: incentiveType,
      isRDIncentive,
      benefitsFromIncentive,
      gvStopajRate,
      sgkSupportRate,
    },
    sgk: {
      workplaceCode: sgkWorkplaceCode,
      hazardClass,
      hazardRate,
    },
    bank: {
      payrollBankId,
      payrollAccountId,
    },
    finance: {
      payrollCfCategory,
    },
    work: {
      regime: workRegime,
      workdaysPerMonth,
      weeklyHours,
    },
    benefits: {
      providesMeal,
      providesTransport,
      providesHealth,
      providesBes,
      besAutoEnrolled,
    },
    personal: {
      age,
      tenure: getEmployeeTenure(employee),
      annualLeaveDays: getEmployeeAnnualLeave(employee, data),
      hasPhD: !!profile.hasPhD,
      isTop25Percent: !!profile.isTop25Percent,
      maritalStatus: employee.maritalStatus || "single",
      childCount: profile.childCount || 0,
      spouseWorking: !!profile.spouseWorking,
      disabilityDegree: profile.disabilityDegree || 0, // 1, 2, 3 (engellilik dereceli GV indirimi)
    },
  };
}

// Brüt → Net hızlı hesap (önizleme amaçlı, tam bordro motoru değil)
function quickCalculateNet(brutAylik, data, employee) {
  const params = getActivePayrollParams(data);
  if (!params || !brutAylik) return { net: 0, employerCost: 0, sgkEmp: 0, gv: 0, dv: 0 };
  const gross = Number(brutAylik) || 0;
  const sgkEmp = gross * ((params.sgkRates?.employeeRate || 14) / 100);
  const unempEmp = gross * ((params.sgkRates?.employeeUnempRate || 1) / 100);
  const gvBase = Math.max(0, gross - sgkEmp - unempEmp);
  const annualGvBase = gvBase * 12;
  const gvAnnual = calculateIncomeTax(annualGvBase, params.incomeTaxBrackets || []);
  let gvMonthly = gvAnnual / 12;
  let dv = gross * ((params.stampDutyRate || 0.759) / 100);

  // Asgari ücret istisnası: asgari ücret kadarki kısım için istisna
  const minWageGross = params.minimumWage?.gross || 0;
  if (params.exemptions?.minWageIncomeTaxExemption && minWageGross > 0) {
    // Asgari ücretin GV'si ne kadarsa, o kadar istisna
    const minSgkEmp = minWageGross * ((params.sgkRates?.employeeRate || 14) / 100);
    const minUnempEmp = minWageGross * ((params.sgkRates?.employeeUnempRate || 1) / 100);
    const minGvBase = Math.max(0, minWageGross - minSgkEmp - minUnempEmp);
    const minAnnualGvAtMyRate = calculateIncomeTax(minGvBase * 12, params.incomeTaxBrackets || []) / 12;
    gvMonthly = Math.max(0, gvMonthly - minAnnualGvAtMyRate);
  }
  if (params.exemptions?.minWageStampDutyExemption && minWageGross > 0) {
    const minDv = minWageGross * ((params.stampDutyRate || 0.759) / 100);
    dv = Math.max(0, dv - minDv);
  }

  // Ar-Ge teşviki uygulanırsa GV stopajı azaltılır (işverene ait, çalışana yansımaz ama gösterim için ekleyelim)
  let gvStopajIncentive = 0;
  if (employee) {
    const ctx = getEmployeePayrollContext(employee, data);
    if (ctx?.incentive?.benefitsFromIncentive) {
      gvStopajIncentive = gvMonthly * (ctx.incentive.gvStopajRate / 100);
    }
  }

  const net = gross - sgkEmp - unempEmp - gvMonthly - dv;
  const sgkEr = gross * ((params.sgkRates?.employerRate || 20.75) / 100);
  const unempEr = gross * ((params.sgkRates?.employerUnempRate || 2) / 100);
  const employerCost = gross + sgkEr + unempEr - gvStopajIncentive;

  return { net, employerCost, sgkEmp, unempEmp, gvMonthly, dv, sgkEr, unempEr, gvStopajIncentive };
}

/* =====================================================================
   NET → BRÜT (tam motor tersine çevirme)
   ---------------------------------------------------------------------
   Hedeflenen NET maaşı verince, calculatePayroll tam motorunu ikili arama
   (bisection) ile tersine çevirerek karşılık gelen BRÜT maaşı bulur.
   Net, brütle monoton arttığı için bisection güvenle yakınsar.

   Giriş ekranları için temsilî dönem (efektif tarihin ay/yılı) ve temiz
   kümülatif (prevCumulatives = {}) kullanılır → "ilk ay neti". Yıl içinde
   kümülatif vergi nedeniyle ilerleyen aylarda gerçek net bir miktar
   düşebilir; bu, brütü sabitleyen standart sektör davranışıdır.
===================================================================== */
function grossFromNet(netTarget, period, data, employee, prevCumulatives = {}) {
  const target = Number(netTarget) || 0;
  if (target <= 0) return 0;
  if (!data || !employee) return 0;

  const evalNet = (g) => {
    const res = calculatePayroll({ ...employee, brutSalary: g }, period, data, prevCumulatives);
    return res?.totals?.net || 0;
  };

  let lo = target;                 // brüt her zaman >= net
  let hi = target * 2 + 50000;     // bol bir üst sınır
  // hedef neti aşana kadar üst sınırı genişlet
  let guard = 0;
  while (evalNet(hi) < target && guard < 25) { hi *= 1.5; guard++; }

  for (let i = 0; i < 60; i++) {
    const mid = (lo + hi) / 2;
    const net = evalNet(mid);
    if (Math.abs(net - target) < 0.5) return Math.round(mid * 100) / 100;
    if (net < target) lo = mid; else hi = mid;
  }
  return Math.round(((lo + hi) / 2) * 100) / 100;
}

/* =====================================================================
   BORDRO HESAPLAMA MOTORU (Payroll Calculation Engine)
   ---------------------------------------------------------------------
   Türkiye İş Hukuku ve Vergi Mevzuatına uygun, parametrik, kümülatif
   matrahlarla çalışan tam bordro hesaplama motoru.

   GİRDİ:
   • employee: çalışan kaydı
   • period: { year, month, workDays?, overtimeHours?, advances?, ... }
   • data: tüm şirket verisi (parametreler, bileşenler, org birimi)
   • prevCumulatives: { gvBase, sgkBase } (önceki ayların kümülatif matrahı)

   ÇIKTI: {
     period, employee,
     incomes: [{ code, name, amount, taxable: {...} }],
     deductions: [{ code, name, amount }],
     bases: { gvBase, gvCumulative, sgkBase, dvBase },
     taxes: { sgkEmployee, sgkEmployer, unempEmployee, unempEmployer,
              incomeTax, incomeTaxExempt, stampDuty, stampDutyExempt },
     incentives: { rdGvStopaj, rdSgkSupport },
     totals: { gross, totalIncome, totalDeductions, net, employerCost,
               totalEmployerBurden },
     breakdown: [{ row, label, amount }] // Slip için satır satır
   }
===================================================================== */

function calculatePayroll(employee, period, data, prevCumulatives = {}) {
  if (!employee || !data) return null;
  const periodDate = period?.date || `${period?.year || new Date().getFullYear()}-${String(period?.month || 1).padStart(2, "0")}-15`;
  const ctx = getEmployeePayrollContext(employee, data, periodDate);
  if (!ctx?.params) return null;
  const params = ctx.params;

  // Çalışma günü/saat bilgileri (period'tan veya org birim varsayılanından)
  const workdaysPerMonth = period?.workDays != null ? period.workDays : (ctx.work?.workdaysPerMonth || 30);
  const sgkDays = period?.sgkDays != null ? period.sgkDays : 30; // SGK için her ay 30 gün
  const mealDays = period?.mealDays != null ? period.mealDays : workdaysPerMonth;
  const transportDays = period?.transportDays != null ? period.transportDays : workdaysPerMonth;
  const overtimeNormalHours = period?.overtimeNormalHours || 0;
  const overtimeWeekendHours = period?.overtimeWeekendHours || 0;
  const overtimeHolidayHours = period?.overtimeHolidayHours || 0;

  // Brüt maaş — tam ay çalışmışsa direkt, kısmi çalışma için orantılı
  const baseBrutAylik = Number(employee.brutSalary) || 0;
  const baseBrut = workdaysPerMonth >= 30 ? baseBrutAylik : (baseBrutAylik / 30) * workdaysPerMonth;

  // Saatlik ücret
  const dailyWage = baseBrutAylik / 30;
  const hourlyWage = baseBrutAylik / 225; // 30 gün × 7.5 saat = 225 saat (tam zamanlı)

  // ---- Tüm aktif bordro bileşenlerini al (şarta bağlı olanlar bu çalışan için değerlendirilir) ----
  const allComponents = (data.hrPayrollComponents || []).filter(c => c.active && evaluateComponentConditions(c, employee, data));
  const incomes = [];
  const deductions = [];

  // Yardımcı: bir bileşen değerini hesapla
  function computeComponentValue(c, helpers) {
    const method = c.calc?.method;
    // ÖNCELİK: 1) Period override, 2) Avans talebi taksit, 3) Benefit contract, 4) Component default
    // Period (toplu puantajdan) override
    const periodOverride = period?.componentOverrides?.[c.code];
    if (periodOverride != null && periodOverride !== "") return Number(periodOverride);

    // Avans talebi taksit kontrolü (sadece AVANS gibi avans bileşeni için)
    if (c.code === "AVANS" || c.category === "special_deduction") {
      const advanceRequests = (data?.hrRequests || []).filter(r =>
        r.kind === "advance" &&
        r.employeeId === employee.id &&
        r.status === "approved" &&
        r.payrollComponentCode === c.code
      );
      let advanceTotal = 0;
      const periodYM = `${period?.year}-${String(period?.month || 1).padStart(2, "0")}`;
      for (const adv of advanceRequests) {
        const startYM = adv.payrollMonth || ""; // "2026-05"
        if (!startYM || startYM > periodYM) continue;
        const totalAmount = Number(adv.amount) || 0;
        const installments = Number(adv.installments) || 1;
        const monthlyDeduction = totalAmount / installments;
        // Bu ay kaç ay geçmiş?
        const [sy, sm] = startYM.split("-").map(Number);
        const monthDiff = ((period.year - sy) * 12) + (period.month - sm) + 1;
        if (monthDiff >= 1 && monthDiff <= installments) {
          advanceTotal += monthlyDeduction;
        }
      }
      if (advanceTotal > 0) return advanceTotal;
    }

    // Yan hak sözleşmesinden tutar çek (varsa)
    const benefit = getBenefitAmountForComponent(employee.id, c.code, data, periodDate);
    const benefitDaily = getBenefitDailyAmountForComponent(employee.id, c.code, data, periodDate);

    if (method === "fixed_amount") {
      // Özel kaynak referansı
      if (c.calc.source === "employee_brutSalary") return baseBrut;
      // Sözleşmedeki sabit aylık tutar
      if (benefit?.total != null) return benefit.total;
      return Number(c.calc.value) || 0;
    }
    if (method === "percent_base") {
      const pct = Number(c.calc.value) || 0;
      const base = helpers.getFactor(c.calc.factorBase);
      return base * (pct / 100);
    }
    if (method === "per_day") {
      // Sözleşmedeki günlük tutar varsa kullan, yoksa component default
      const daily = (benefitDaily != null && benefitDaily > 0) ? benefitDaily : (Number(c.calc.value) || 0);
      const dayCount = helpers.getDayCount(c.calc.dayType);
      return daily * dayCount;
    }
    if (method === "per_hour") {
      const factor = Number(c.calc.value) || 1.5;
      let hours = 0;
      if (c.calc.hourType === "overtime_hours") hours = overtimeNormalHours;
      else if (c.calc.hourType === "weekend_hours") hours = overtimeWeekendHours;
      else if (c.calc.hourType === "holiday_hours") hours = overtimeHolidayHours;
      return hourlyWage * factor * hours;
    }
    return 0;
  }

  // SGK matrahı progresif hesaplandığı için iki geçişli yaklaşım: önce gelirleri topla
  // sonra matrahları, sonra kesintileri
  let totalGrossIncome = 0;       // Tüm brüt gelirler
  let sgkBase = 0;                 // SGK matrahı (tabi olanlar)
  let incomeTaxBase = 0;           // GV matrahı (SGK kesintileri sonrası)
  let stampDutyBase = 0;           // DV matrahı (tabi olanlar - istisnalı kısım hariç)

  // Geçici factor değerleri (yüzde bazlı bileşenler için)
  const helpers = {
    getFactor: (factorBase) => {
      switch (factorBase) {
        case "brut_salary":  return baseBrut;
        case "sgk_matrah":   return sgkBase; // sonradan kullanılır
        case "gv_matrah":    return incomeTaxBase;
        case "net_salary":   return 0; // henüz hesaplanmadı
        case "daily_wage":   return dailyWage;
        case "minimum_wage": return params.minimumWage?.gross || 0;
        default:             return baseBrut;
      }
    },
    getDayCount: (dayType) => {
      switch (dayType) {
        case "worked_days":    return workdaysPerMonth;
        case "sgk_days":       return sgkDays;
        case "meal_days":      return mealDays;
        case "transport_days": return transportDays;
        case "calendar_days":  return 30;
        default:               return workdaysPerMonth;
      }
    },
  };

  // ====== 1. AŞAMA: TÜM GELİRLERİ HESAPLA + MATRAHA EKLE ======
  for (const c of allComponents) {
    if (c.category !== "legal_income" && c.category !== "special_income") continue;
    const rawValue = computeComponentValue(c, helpers);
    if (rawValue === 0 && c.code !== "BRUT") continue;

    const tax = c.tax || {};
    const exemption = c.exemption || {};

    // İstisna tutarı hesabı (yemek, yol için)
    let taxableAmount = rawValue;
    let exemptAmount = 0;
    if (exemption.gvAmount > 0 && tax.incomeTax) {
      // Per_day ise gün × istisna, yoksa direkt
      const exemptTotal = c.calc?.method === "per_day"
        ? exemption.gvAmount * helpers.getDayCount(c.calc.dayType)
        : exemption.gvAmount;
      const exemptFinal = Math.min(rawValue, exemptTotal);
      taxableAmount = Math.max(0, rawValue - exemptFinal);
      exemptAmount = exemptFinal;
    }

    // Bileşeni gelirler listesine ekle
    incomes.push({
      code: c.code,
      name: c.name?.tr || c.code,
      category: c.category,
      amount: rawValue,
      exemptAmount,
      taxable: {
        sgk:        tax.sgk          ? taxableAmount : 0,
        incomeTax:  tax.incomeTax    ? taxableAmount : 0,
        stampDuty:  tax.stampDuty    ? rawValue      : 0, // DV genelde tüm tutara
        unemployment: tax.unemployment ? taxableAmount : 0,
      },
      _component: c,
    });

    totalGrossIncome += rawValue;
    if (tax.sgk) sgkBase += taxableAmount;
    if (tax.stampDuty) stampDutyBase += rawValue;
  }

  // ====== 2. AŞAMA: SGK TAVANI UYGULA ======
  const sgkCeiling = (params.minimumWage?.gross || 0) * (params.sgkRates?.sgkCeilingMultiplier || 7.5);
  const sgkBaseCapped = Math.min(sgkBase, sgkCeiling);
  const sgkCappedAtCeiling = sgkBase > sgkCeiling;

  // ====== 3. SGK İŞÇİ KESİNTİLERİ ======
  const sgkEmployeeRate = (params.sgkRates?.employeeRate || 14) / 100;
  const unempEmployeeRate = (params.sgkRates?.employeeUnempRate || 1) / 100;
  const sgkEmployee = sgkBaseCapped * sgkEmployeeRate;
  const unempEmployee = sgkBaseCapped * unempEmployeeRate;

  // ====== 4. GV MATRAHI = SGK'lı gelirler - işçi kesintileri ======
  let gvBaseFromIncomes = 0;
  for (const inc of incomes) {
    if (inc.taxable.incomeTax > 0) gvBaseFromIncomes += inc.taxable.incomeTax;
  }
  // SGK kesintileri SGK'ya tabi olan gelirden düşülür
  const sgkRatio = sgkBase > 0 ? sgkBaseCapped / sgkBase : 1;
  const gvBaseAfterSgk = Math.max(0, gvBaseFromIncomes - (sgkEmployee + unempEmployee));
  incomeTaxBase = gvBaseAfterSgk;

  // ====== 5. KÜMÜLATİF GV MATRAHI ile vergi hesabı ======
  const prevGvCumulative = Number(prevCumulatives.gvBase) || 0;
  const newGvCumulative = prevGvCumulative + incomeTaxBase;
  // Yıllık kümülatif matrahta toplam vergi - önceki ayların matrahında hesaplanan vergi = bu ay vergisi
  const taxTotalToDate = calculateIncomeTax(newGvCumulative, params.incomeTaxBrackets || []);
  const taxAlreadyPaid = calculateIncomeTax(prevGvCumulative, params.incomeTaxBrackets || []);
  let incomeTax = taxTotalToDate - taxAlreadyPaid;

  // ====== 6. ASGARİ ÜCRET GV İSTİSNASI ======
  let incomeTaxExempt = 0;
  if (params.exemptions?.minWageIncomeTaxExemption) {
    const minWageGross = params.minimumWage?.gross || 0;
    const minSgk = minWageGross * sgkEmployeeRate;
    const minUnemp = minWageGross * unempEmployeeRate;
    const minGvBase = Math.max(0, minWageGross - minSgk - minUnemp);
    // Asgari ücret matrahının yıllık kümülatif vergisi
    const monthIdx = (period?.month || 1) - 1; // 0-tabanlı ay
    const minCumulative = minGvBase * (monthIdx + 1);
    const minPrevCumulative = minGvBase * monthIdx;
    const minTax = calculateIncomeTax(minCumulative, params.incomeTaxBrackets || []) -
                   calculateIncomeTax(minPrevCumulative, params.incomeTaxBrackets || []);
    incomeTaxExempt = Math.min(minTax, incomeTax);
  }
  const incomeTaxFinal = Math.max(0, incomeTax - incomeTaxExempt);

  // ====== 7. AR-GE / TEKNOPARK TEŞVİK (işveren stopaj indirimi) ======
  // GV stopaj indirimi: tahakkuk eden GV'nin belli bir oranı işverene "destek" olur
  // Çalışan değil, işveren faydalanır; net maaşa yansıması yok
  let rdGvStopajIncentive = 0;
  if (ctx.incentive?.benefitsFromIncentive && ctx.incentive?.gvStopajRate > 0) {
    rdGvStopajIncentive = incomeTaxFinal * (ctx.incentive.gvStopajRate / 100);
  }

  // ====== 8. DAMGA VERGİSİ ======
  const stampDutyRate = (params.stampDutyRate || 0.759) / 100;
  let stampDuty = stampDutyBase * stampDutyRate;
  let stampDutyExempt = 0;
  if (params.exemptions?.minWageStampDutyExemption) {
    const minWageGross = params.minimumWage?.gross || 0;
    const minDv = minWageGross * stampDutyRate;
    stampDutyExempt = Math.min(minDv, stampDuty);
  }
  const stampDutyFinal = Math.max(0, stampDuty - stampDutyExempt);

  // ====== 9. YASAL KESİNTİLERİ EKLE ======
  // (SGK işçi, İşsizlik işçi, GV, DV otomatik olarak motor tarafından hesaplandı.
  // Eğer bordro bileşenler listesinde de varsa, motor değerini yaz)
  for (const c of allComponents) {
    if (c.category !== "legal_deduction") continue;
    let amount = 0;
    let label = c.name?.tr || c.code;
    switch (c.code) {
      case "SGK_ISCI":      amount = sgkEmployee; break;
      case "ISSIZLIK_ISCI": amount = unempEmployee; break;
      case "GV":            amount = incomeTaxFinal; break;
      case "DV":            amount = stampDutyFinal; break;
      default:
        // Bilinmeyen yasal kesinti — bileşenden hesapla
        amount = computeComponentValue(c, helpers);
    }
    if (amount > 0) {
      deductions.push({
        code: c.code,
        name: label,
        category: c.category,
        amount,
        _component: c,
      });
    }
  }

  // ====== 10. ÖZEL KESİNTİLER (avans, BES işçi, sendika, icra) ======
  for (const c of allComponents) {
    if (c.category !== "special_deduction") continue;
    const amount = computeComponentValue(c, helpers);
    if (amount === 0) continue;
    deductions.push({
      code: c.code,
      name: c.name?.tr || c.code,
      category: c.category,
      amount,
      _component: c,
    });
  }

  // ====== 11. NET HESAP ======
  const totalDeductions = deductions.reduce((s, d) => s + d.amount, 0);
  const net = totalGrossIncome - totalDeductions;

  // ====== 12. İŞVEREN TARAFI ======
  const sgkEmployerRate = (params.sgkRates?.employerRate || 20.75) / 100;
  const sgkEmployerDiscountedRate = (params.sgkRates?.employerRateDiscounted || 15.75) / 100;
  const unempEmployerRate = (params.sgkRates?.employerUnempRate || 2) / 100;
  // 5510 5p indirimi varsa indirimli oran
  const hasDiscount = !!ctx.orgUnit?.sgk?.has5510Discount;
  const sgkEmployer = sgkBaseCapped * (hasDiscount ? sgkEmployerDiscountedRate : sgkEmployerRate);
  const unempEmployer = sgkBaseCapped * unempEmployerRate;

  // Ar-Ge SGK İşveren Desteği
  let rdSgkSupport = 0;
  if (ctx.incentive?.benefitsFromIncentive && ctx.incentive?.sgkSupportRate > 0) {
    rdSgkSupport = sgkEmployer * (ctx.incentive.sgkSupportRate / 100);
  }

  // Toplam İşveren Maliyeti
  const employerCost = totalGrossIncome + sgkEmployer + unempEmployer;
  const employerCostWithIncentives = employerCost - rdGvStopajIncentive - rdSgkSupport;

  // ====== 13. SLİP İÇİN SATIR BAŞINA AÇIKLAMA ======
  const breakdown = [];
  // Gelirler
  breakdown.push({ row: "header", label: "GELİRLER" });
  incomes.forEach(inc => {
    breakdown.push({
      row: "income",
      code: inc.code,
      label: inc.name,
      amount: inc.amount,
      exemptAmount: inc.exemptAmount,
      taxable: inc.taxable,
    });
  });
  breakdown.push({ row: "subtotal", label: "Toplam Brüt", amount: totalGrossIncome });

  // Matrahlar
  breakdown.push({ row: "header", label: "MATRAHLAR" });
  breakdown.push({ row: "info", label: "SGK Matrahı", amount: sgkBase });
  if (sgkCappedAtCeiling) breakdown.push({ row: "info", label: `SGK Tavanı (×${params.sgkRates?.sgkCeilingMultiplier || 7.5} = ${fmtTL(sgkCeiling)})`, amount: sgkBaseCapped, warning: true });
  breakdown.push({ row: "info", label: "GV Matrahı (bu ay)", amount: incomeTaxBase });
  breakdown.push({ row: "info", label: "GV Kümülatif Matrah", amount: newGvCumulative });
  breakdown.push({ row: "info", label: "DV Matrahı", amount: stampDutyBase });

  // Kesintiler
  breakdown.push({ row: "header", label: "KESİNTİLER" });
  deductions.forEach(d => {
    breakdown.push({
      row: "deduction",
      code: d.code,
      label: d.name,
      amount: d.amount,
    });
  });
  breakdown.push({ row: "subtotal", label: "Toplam Kesinti", amount: totalDeductions });

  // İstisnalar
  if (incomeTaxExempt > 0 || stampDutyExempt > 0) {
    breakdown.push({ row: "header", label: "İSTİSNALAR (BİLGİ)" });
    if (incomeTaxExempt > 0) breakdown.push({ row: "info_positive", label: "✓ Asgari Ücret GV İstisnası", amount: incomeTaxExempt });
    if (stampDutyExempt > 0) breakdown.push({ row: "info_positive", label: "✓ Asgari Ücret DV İstisnası", amount: stampDutyExempt });
  }

  // Net
  breakdown.push({ row: "net", label: "NET ÜCRET", amount: net });

  // İşveren tarafı
  breakdown.push({ row: "header", label: "İŞVEREN TARAFI" });
  breakdown.push({ row: "employer", label: `SGK İşveren (%${(hasDiscount ? sgkEmployerDiscountedRate : sgkEmployerRate) * 100})`, amount: sgkEmployer });
  breakdown.push({ row: "employer", label: `İşsizlik İşveren (%${unempEmployerRate * 100})`, amount: unempEmployer });
  if (rdGvStopajIncentive > 0) breakdown.push({ row: "incentive", label: `✨ Ar-Ge GV Stopaj Teşviki (%${ctx.incentive.gvStopajRate})`, amount: -rdGvStopajIncentive });
  if (rdSgkSupport > 0) breakdown.push({ row: "incentive", label: `✨ Ar-Ge SGK İşveren Desteği (%${ctx.incentive.sgkSupportRate})`, amount: -rdSgkSupport });
  breakdown.push({ row: "total", label: "TOPLAM İŞVEREN MALİYETİ", amount: employerCostWithIncentives });

  return {
    period: { year: period?.year, month: period?.month, date: periodDate, workdaysPerMonth, sgkDays, mealDays, transportDays },
    employee: { id: employee.id, firstName: employee.firstName, lastName: employee.lastName },
    incomes,
    deductions,
    bases: {
      sgkBase, sgkBaseCapped, sgkCappedAtCeiling, sgkCeiling,
      gvBase: incomeTaxBase, gvCumulative: newGvCumulative,
      dvBase: stampDutyBase,
    },
    taxes: {
      sgkEmployee, unempEmployee,
      sgkEmployer, unempEmployer,
      incomeTax: incomeTaxFinal, incomeTaxBeforeExemption: incomeTax, incomeTaxExempt,
      stampDuty: stampDutyFinal, stampDutyBeforeExemption: stampDuty, stampDutyExempt,
    },
    incentives: { rdGvStopaj: rdGvStopajIncentive, rdSgkSupport },
    totals: {
      gross: totalGrossIncome,
      totalIncome: totalGrossIncome,
      totalDeductions,
      net,
      employerCost,
      employerCostWithIncentives,
      totalEmployerBurden: employerCostWithIncentives,
    },
    breakdown,
    context: { orgUnit: ctx.orgUnit?.name, incentiveType: ctx.incentive?.type, sgkWorkplaceCode: ctx.sgk?.workplaceCode },
  };
}

// Toplu bordro çalıştırma (bir döneme dair tüm aktif çalışanlar)
function runPayrollBatch(data, period, options = {}) {
  const employees = (data?.hrEmployees || []).filter(e => e.status === "active");
  // Önceki ayların kümülatif matrahları (yıl içinde her ay arttırmalı)
  const prevCumulatives = options.prevCumulatives || {};

  const results = employees.map(emp => {
    // Bu çalışan için önceki aylar
    let cumulative = prevCumulatives[emp.id] || { gvBase: 0 };
    // Önceki aylar varsa (ocak-mevcut), simüle et
    if (!options.skipCumulativeSimulation && period?.month > 1) {
      for (let m = 1; m < period.month; m++) {
        // Önceki ay için puantaj sheet'i varsa kullan, yoksa standart
        const prevSheet = (data?.hrAttendanceSheets || []).find(s =>
          s.employeeId === emp.id && s.year === period.year && s.month === m
        );
        const prevPeriod = prevSheet
          ? attendanceSheetToPayrollPeriod(prevSheet)
          : { year: period.year, month: m };
        const prevResult = calculatePayroll(emp, prevPeriod, data, cumulative);
        if (prevResult) {
          cumulative = { gvBase: prevResult.bases.gvCumulative };
        }
      }
    }
    // Bu ayın puantaj sheet'ini bul
    const currentSheet = (data?.hrAttendanceSheets || []).find(s =>
      s.employeeId === emp.id && s.year === period.year && s.month === period.month
    );
    const effectivePeriod = currentSheet
      ? { ...attendanceSheetToPayrollPeriod(currentSheet), date: period.date }
      : period;
    return calculatePayroll(emp, effectivePeriod, data, cumulative);
  }).filter(Boolean);

  // Toplamlar
  const totals = results.reduce((s, r) => ({
    grossTotal: s.grossTotal + r.totals.gross,
    netTotal: s.netTotal + r.totals.net,
    sgkEmployeeTotal: s.sgkEmployeeTotal + r.taxes.sgkEmployee,
    sgkEmployerTotal: s.sgkEmployerTotal + r.taxes.sgkEmployer,
    incomeTaxTotal: s.incomeTaxTotal + r.taxes.incomeTax,
    stampDutyTotal: s.stampDutyTotal + r.taxes.stampDuty,
    employerCostTotal: s.employerCostTotal + r.totals.employerCostWithIncentives,
    rdIncentiveTotal: s.rdIncentiveTotal + (r.incentives.rdGvStopaj + r.incentives.rdSgkSupport),
    count: s.count + 1,
  }), {
    grossTotal: 0, netTotal: 0, sgkEmployeeTotal: 0, sgkEmployerTotal: 0,
    incomeTaxTotal: 0, stampDutyTotal: 0, employerCostTotal: 0, rdIncentiveTotal: 0, count: 0,
  });

  return { period, results, totals };
}

