function getPublicHolidays(year) {
  if (year === 2026) return TR_PUBLIC_HOLIDAYS_2026;
  if (year === 2025) return TR_PUBLIC_HOLIDAYS_2025;
  return [];
}

function isPublicHoliday(dateStr) {
  const year = parseInt(dateStr.substring(0, 4));
  return getPublicHolidays(year).some(h => h.date === dateStr);
}

function isWeekend(dateStr) {
  const d = new Date(dateStr);
  const dow = d.getDay();
  return dow === 0 || dow === 6; // Sunday or Saturday
}

// İş günü sayısını dön (hafta sonu ve resmi tatil hariç)
function getWorkdaysInMonth(year, month) {
  const days = daysInMonth(year, month);
  let count = 0;
  for (let d = 1; d <= days; d++) {
    const dateStr = `${year}-${String(month).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
    if (!isWeekend(dateStr) && !isPublicHoliday(dateStr)) count++;
  }
  return count;
}

// Bir çalışan için belirli ay/yıl puantaj sheet'ini bul veya başlatıcı dön
function findOrInitAttendanceSheet(employeeId, year, month, data) {
  const existing = (data?.hrAttendanceSheets || []).find(s =>
    s.employeeId === employeeId && s.year === year && s.month === month
  );
  if (existing) return existing;
  // Varsayılan değerler
  const standardWorkdays = getWorkdaysInMonth(year, month);
  return {
    id: null, // henüz kaydedilmedi
    employeeId, year, month,
    workedDays: standardWorkdays,         // Çalışılan gün (standart başlangıç)
    sgkDays: 30,                            // SGK günü (her zaman 30)
    mealDays: standardWorkdays,           // Yemek günü (varsayılan = çalışılan)
    transportDays: standardWorkdays,      // Yol günü
    overtimeNormalHours: 0,
    overtimeWeekendHours: 0,
    overtimeHolidayHours: 0,
    leaveAnnualDays: 0,
    leaveSickDays: 0,
    leaveUnpaidDays: 0,
    leaveReportDays: 0,
    leaveOtherDays: 0,
    componentValues: {},                    // Bileşen-özel değerler (AVANS: 5000, vb.)
    notes: "",
    status: "draft",
    source: "bulk_entry",
  };
}

// Puantaj sheet'inden bordro periyodu için "period" objesi üret
function attendanceSheetToPayrollPeriod(sheet) {
  if (!sheet) return null;
  return {
    year: sheet.year,
    month: sheet.month,
    workDays: sheet.workedDays,
    sgkDays: sheet.sgkDays,
    mealDays: sheet.mealDays,
    transportDays: sheet.transportDays,
    overtimeNormalHours: sheet.overtimeNormalHours || 0,
    overtimeWeekendHours: sheet.overtimeWeekendHours || 0,
    overtimeHolidayHours: sheet.overtimeHolidayHours || 0,
    componentOverrides: sheet.componentValues || {},
    _attendanceSheetId: sheet.id,
  };
}

// Yıllık izin bakiyesini hesapla (çalışanın kıdemine ve kullandığına göre)
function calculateLeaveBalance(employee, data, year) {
  if (!employee) return { entitled: 0, used: 0, remaining: 0 };
  const tenure = getEmployeeTenure(employee);
  const params = getActivePayrollParams(data);
  const labor = params?.laborLaw || { annualLeave1: 14, annualLeave5: 20, annualLeave15: 26 };

  let entitled = 0;
  if (tenure >= 15) entitled = labor.annualLeave15 || 26;
  else if (tenure >= 5) entitled = labor.annualLeave5 || 20;
  else if (tenure >= 1) entitled = labor.annualLeave1 || 14;

  // O yıl içinde toplam yıllık izin kullanımı
  const sheets = (data?.hrAttendanceSheets || []).filter(s =>
    s.employeeId === employee.id && s.year === year
  );
  const used = sheets.reduce((sum, s) => sum + (s.leaveAnnualDays || 0), 0);

  // Manuel kayıtta override
  const balance = (data?.hrLeaveBalances || []).find(b =>
    b.employeeId === employee.id && b.year === year
  );
  if (balance) {
    return {
      entitled: balance.annualEntitled || entitled,
      used: Math.max(used, balance.annualUsed || 0),
      remaining: (balance.annualEntitled || entitled) - Math.max(used, balance.annualUsed || 0),
      carryOver: balance.carryOverDays || 0,
    };
  }
  return { entitled, used, remaining: entitled - used, carryOver: 0 };
}

/* =====================================================================
   TAKVİMLİ PUANTAJ — Yardımcı Fonksiyonlar
   ---------------------------------------------------------------------
   • Saat aralıklarından çalışılan saat hesabı
   • Günlük kayıtlardan aylık özet üretme
   • PDKS CSV import
===================================================================== */

// "HH:MM" → dakika
function timeToMinutes(timeStr) {
  if (!timeStr || !/^\d{1,2}:\d{2}$/.test(timeStr)) return null;
  const [h, m] = timeStr.split(":").map(Number);
  return h * 60 + m;
}

// Giriş-çıkış saatlerinden çalışılan saat hesabı (mola otomatik düşülmez)
function calculateWorkedHours(checkIn, checkOut, breakMinutes = 0) {
  const inMin = timeToMinutes(checkIn);
  const outMin = timeToMinutes(checkOut);
  if (inMin == null || outMin == null) return 0;
  let minutes = outMin - inMin;
  if (minutes < 0) minutes += 24 * 60; // Gece vardiyası — ertesi güne sarktı
  minutes -= breakMinutes;
  return Math.max(0, minutes / 60);
}

// Standart çalışma saati (varsayılan 7.5)
function getStandardWorkHours(employee, data) {
  const ctx = getEmployeePayrollContext(employee, data);
  const weeklyHours = ctx?.work?.weeklyHours || 45;
  const daysPerWeek = ctx?.orgUnit?.payroll?.workdaysPerWeek || 5;
  return weeklyHours / daysPerWeek;
}

// Çalışılan saatten fazla mesai hesabı
function splitWorkHours(workedHours, standardHours, dayType) {
  // dayType: "work" → fazlası normal mesai (×1.5)
  // dayType: "weekend" → tüm saat hafta tatili mesaisi (×2.0)
  // dayType: "holiday" → tüm saat resmi tatil mesaisi (×2.0)
  let normal = 0, overtime = 0, weekend = 0, holiday = 0;
  if (dayType === "work" || dayType === "half_day") {
    normal = Math.min(workedHours, standardHours);
    overtime = Math.max(0, workedHours - standardHours);
  } else if (dayType === "weekend") {
    weekend = workedHours;
  } else if (dayType === "holiday") {
    holiday = workedHours;
  }
  return { normal, overtime, weekend, holiday };
}

// Belirli bir çalışan-ay için günlük kayıtlardan toplu özet üret
function summarizeDaysToSheet(employeeId, year, month, days) {
  const employeeDays = days.filter(d =>
    d.employeeId === employeeId &&
    d.date.startsWith(`${year}-${String(month).padStart(2, "0")}`)
  );
  let workedDays = 0;
  let leaveAnnualDays = 0;
  let leaveSickDays = 0;
  let leaveUnpaidDays = 0;
  let leaveMaternityDays = 0;
  let leaveOtherDays = 0;
  let overtimeNormalHours = 0;
  let overtimeWeekendHours = 0;
  let overtimeHolidayHours = 0;
  let workedHoursTotal = 0;
  let halfDays = 0;
  let absentDays = 0;
  let businessTripDays = 0;

  for (const d of employeeDays) {
    switch (d.dayType) {
      case "work":
        workedDays++;
        workedHoursTotal += d.workedHours || 0;
        overtimeNormalHours += d.overtimeNormal || 0;
        break;
      case "half_day":
        workedDays += 0.5;
        halfDays++;
        workedHoursTotal += d.workedHours || 0;
        break;
      case "weekend":
        if (d.workedHours > 0) {
          overtimeWeekendHours += d.workedHours;
        }
        break;
      case "holiday":
        if (d.workedHours > 0) {
          overtimeHolidayHours += d.workedHours;
        }
        break;
      case "leave_annual":
        leaveAnnualDays++;
        break;
      case "leave_sick":
        leaveSickDays++;
        break;
      case "leave_unpaid":
        leaveUnpaidDays++;
        break;
      case "leave_maternity":
      case "leave_paternity":
      case "leave_marriage":
      case "leave_bereavement":
        leaveOtherDays++;
        break;
      case "absent":
        absentDays++;
        break;
      case "business_trip":
        workedDays++; // görevli seyahat çalışılmış sayılır
        businessTripDays++;
        break;
      default:
        break;
    }
  }

  // SGK günü: ay 30 (sabit) - sadece ücretsiz izin ve devamsızlık düşer
  const sgkDays = Math.max(0, 30 - leaveUnpaidDays - absentDays);
  const mealDays = workedDays + businessTripDays;          // Yemek günü = çalışılan + seyahat
  const transportDays = workedDays;                          // Yol günü = çalışılan

  return {
    workedDays,
    sgkDays,
    mealDays,
    transportDays,
    leaveAnnualDays,
    leaveSickDays,
    leaveUnpaidDays,
    leaveOtherDays,
    overtimeNormalHours,
    overtimeWeekendHours,
    overtimeHolidayHours,
    workedHoursTotal: parseFloat(workedHoursTotal.toFixed(2)),
    halfDays,
    absentDays,
    businessTripDays,
    daysCount: employeeDays.length,
  };
}

// Çalışan-ay için takvim günlerini bul ya da varsayılan üret
function buildCalendarDays(employeeId, year, month, existingDays) {
  const days = daysInMonth(year, month);
  const map = {};
  // Mevcut kayıtları map'le
  for (const d of existingDays) {
    if (d.employeeId === employeeId && d.date.startsWith(`${year}-${String(month).padStart(2, "0")}`)) {
      map[d.date] = d;
    }
  }
  const result = [];
  for (let day = 1; day <= days; day++) {
    const dateStr = `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    const existing = map[dateStr];
    const weekend = isWeekend(dateStr);
    const holiday = isPublicHoliday(dateStr);
    result.push(existing || {
      id: null,
      employeeId,
      date: dateStr,
      dayType: holiday ? "holiday" : weekend ? "weekend" : "work",
      checkIn: "",
      checkOut: "",
      breakMinutes: 0,
      workedHours: 0,
      overtimeNormal: 0,
      overtimeWeekend: 0,
      overtimeHoliday: 0,
      notes: "",
      source: "manual",
    });
  }
  return result;
}

// CSV parse: PDKS export tipik formatı
// Format 1: TC,Tarih,Giriş,Çıkış
// Format 2: SicilNo,Tarih,Giriş,Çıkış
// Format 3: Ad Soyad,Tarih,Giriş,Çıkış
function parsePdksCsv(csvText, employees) {
  const lines = csvText.split(/\r?\n/).filter(l => l.trim());
  if (lines.length === 0) return { records: [], errors: ["Empty CSV"] };

  const records = [];
  const errors = [];
  // Başlık satırı varsa atla
  const firstLine = lines[0].toLowerCase();
  const hasHeader = firstLine.includes("tarih") || firstLine.includes("date") || firstLine.includes("giriş") || firstLine.includes("check");
  const dataLines = hasHeader ? lines.slice(1) : lines;

  for (let i = 0; i < dataLines.length; i++) {
    const line = dataLines[i];
    // Hem virgül hem noktalı virgül ayırıcısını dene
    const parts = (line.includes(";") ? line.split(";") : line.split(",")).map(p => p.trim());
    if (parts.length < 3) continue;

    const [identifier, dateStr, checkIn, checkOut, breakMin] = parts;

    // Çalışanı bul
    const emp = employees.find(e =>
      e.tcNo === identifier ||
      e.sgkNo === identifier ||
      `${e.firstName} ${e.lastName}`.toLowerCase() === identifier.toLowerCase() ||
      e.email?.toLowerCase() === identifier.toLowerCase() ||
      e.id === identifier
    );
    if (!emp) {
      errors.push(`Satır ${i + (hasHeader ? 2 : 1)}: Çalışan bulunamadı "${identifier}"`);
      continue;
    }

    // Tarih parse — DD/MM/YYYY veya DD.MM.YYYY veya YYYY-MM-DD
    let normalizedDate = null;
    if (/^\d{4}-\d{2}-\d{2}$/.test(dateStr)) {
      normalizedDate = dateStr;
    } else if (/^\d{1,2}[\/.]\d{1,2}[\/.]\d{4}$/.test(dateStr)) {
      const [d, m, y] = dateStr.split(/[\/.]/);
      normalizedDate = `${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`;
    } else {
      errors.push(`Satır ${i + (hasHeader ? 2 : 1)}: Tarih formatı tanımlanamadı "${dateStr}"`);
      continue;
    }

    records.push({
      employeeId: emp.id,
      date: normalizedDate,
      checkIn: checkIn || "",
      checkOut: checkOut || "",
      breakMinutes: parseInt(breakMin) || 0,
    });
  }

  return { records, errors };
}

