// Bir çalışan için aktif benefit contract'larını bul
function getEmployeeBenefits(employeeId, data, dateStr) {
  const today = dateStr || new Date().toISOString().slice(0, 10);
  return (data?.hrBenefitContracts || []).filter(c =>
    c.active &&
    (c.coveredEmployeeIds || []).includes(employeeId) &&
    (!c.startDate || c.startDate <= today) &&
    (!c.endDate || c.endDate >= today)
  );
}

// Bir bordro bileşeni kodu için çalışana ait aktif sözleşmedeki tutarı dön
function getBenefitAmountForComponent(employeeId, componentCode, data, dateStr) {
  const benefits = getEmployeeBenefits(employeeId, data, dateStr);
  // İlk eşleşeni dön (component-level)
  const match = benefits.find(b => b.linkedComponentCode === componentCode);
  if (!match) return null;

  // Kişi başı veya sabit (toplam) tutar yorumu
  if (match.premiumType === "per_employee") {
    return {
      total: Number(match.premiumMonthly) || 0,
      employer: Number(match.employerShare) || 0,
      employee: Number(match.employeeShare) || 0,
      details: match.details,
      contractId: match.id,
      contractName: match.name,
    };
  }
  // Sabit toplam tutarsa atanmış kişi sayısına böl
  const covered = (match.coveredEmployeeIds || []).length || 1;
  const total = (Number(match.premiumMonthly) || 0) / covered;
  return {
    total,
    employer: (Number(match.employerShare) || 0) / covered,
    employee: (Number(match.employeeShare) || 0) / covered,
    details: match.details,
    contractId: match.id,
    contractName: match.name,
  };
}

// Bir bordro bileşeninin günlük tutarını sözleşmeden çek (yemek kartı, yol kartı için)
function getBenefitDailyAmountForComponent(employeeId, componentCode, data, dateStr) {
  const benefits = getEmployeeBenefits(employeeId, data, dateStr);
  const match = benefits.find(b => b.linkedComponentCode === componentCode);
  if (!match) return null;
  return Number(match.details?.dailyAmount) || 0;
}

