// Bir çalışanın taleplerini bul (kind filtreli)
function getEmployeeRequests(employeeId, kind, data) {
  let list = (data?.hrRequests || []).filter(r => r.employeeId === employeeId);
  if (kind) list = list.filter(r => r.kind === kind);
  return list.sort((a, b) => new Date(b.requestedAt || 0) - new Date(a.requestedAt || 0));
}

// Bir çalışanın aktif zimmetlerini bul
function getEmployeeAssets(employeeId, data) {
  return (data?.hrAssets || []).filter(a => 
    a.assignedEmployeeId === employeeId && a.status === "assigned"
  );
}

// Bir avans talebinin kalan taksitini hesapla
function getAdvanceRemaining(request, data) {
  if (!request || request.kind !== "advance" || !request.installments) return null;
  const totalAmount = Number(request.amount) || 0;
  const installments = Number(request.installments) || 1;
  const monthlyDeduction = totalAmount / installments;
  
  // Kaç ay kesildi? — bordro runs içinde bu request'in component değeri olan ayları say
  const startYear = parseInt(request.payrollMonth?.substring(0, 4)) || new Date().getFullYear();
  const startMonth = parseInt(request.payrollMonth?.substring(5, 7)) || 1;
  
  const deductedMonths = (data?.hrPayrollRuns || []).filter(run => {
    const ry = run.period?.year, rm = run.period?.month;
    if (!ry || !rm) return false;
    const isAfterStart = (ry > startYear) || (ry === startYear && rm >= startMonth);
    if (!isAfterStart) return false;
    // Bu run'da çalışanın slipinde AVANS deduction'u var mı?
    const slip = (run.results || []).find(r => r.employee?.id === request.employeeId);
    if (!slip) return false;
    return (slip.deductions || []).some(d => d.code === request.payrollComponentCode);
  }).length;
  
  const paidAmount = deductedMonths * monthlyDeduction;
  const remaining = Math.max(0, totalAmount - paidAmount);
  return { totalAmount, paidAmount, remaining, deductedMonths, installments, monthlyDeduction };
}

