// HTML e-posta şablonu üret — responsive, inline CSS (bütün mail client'larda çalışsın)
function generateEmailHtml({ title, body, accent, ctaText, ctaUrl, footer, lang = "tr", logoText = "M Suite", details = [] }) {
  const safeAccent = accent || "#0b3d2e";
  const dir = LANGUAGES?.[lang]?.rtl ? "rtl" : "ltr";
  const langCode = lang || "tr";

  // Detay tablosu HTML'i
  const detailsHtml = details.length > 0 ? `
    <table cellpadding="0" cellspacing="0" border="0" style="width:100%; margin:20px 0; border-collapse:collapse;">
      ${details.map(d => `
        <tr>
          <td style="padding:8px 12px; background:#f5f5f4; font-size:12px; color:#737373; border-bottom:1px solid #e5e5e5; width:40%;">${d.label}</td>
          <td style="padding:8px 12px; font-size:13px; color:#1c1c1c; font-weight:600; border-bottom:1px solid #e5e5e5;">${d.value}</td>
        </tr>
      `).join("")}
    </table>
  ` : "";

  const ctaHtml = ctaText && ctaUrl ? `
    <table cellpadding="0" cellspacing="0" border="0" style="margin:24px 0;">
      <tr>
        <td style="background:${safeAccent}; border-radius:6px;">
          <a href="${ctaUrl}" target="_blank"
             style="display:inline-block; padding:12px 24px; color:#ffffff; text-decoration:none; font-weight:600; font-size:14px; font-family:Helvetica,Arial,sans-serif;">
            ${ctaText}
          </a>
        </td>
      </tr>
    </table>
  ` : "";

  return `<!DOCTYPE html>
<html lang="${langCode}" dir="${dir}">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>${title}</title>
</head>
<body style="margin:0; padding:0; background:#f5f5f4; font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;">
  <table cellpadding="0" cellspacing="0" border="0" style="width:100%; background:#f5f5f4; padding:40px 20px;">
    <tr>
      <td align="center">
        <table cellpadding="0" cellspacing="0" border="0" style="max-width:560px; width:100%; background:#ffffff; border-radius:8px; overflow:hidden; box-shadow:0 2px 8px rgba(0,0,0,0.05);">
          <!-- Üst bar (accent renkli şerit) -->
          <tr>
            <td style="background:${safeAccent}; padding:20px 30px;">
              <div style="color:#ffffff; font-size:18px; font-weight:700; letter-spacing:-0.3px;">
                ${logoText}
              </div>
            </td>
          </tr>
          <!-- İçerik -->
          <tr>
            <td style="padding:30px;">
              <h1 style="margin:0 0 16px 0; font-size:20px; font-weight:700; color:#1c1c1c; line-height:1.3;">
                ${title}
              </h1>
              <div style="font-size:14px; color:#404040; line-height:1.6;">
                ${body}
              </div>
              ${detailsHtml}
              ${ctaHtml}
            </td>
          </tr>
          <!-- Footer -->
          <tr>
            <td style="padding:20px 30px; background:#fafafa; border-top:1px solid #e5e5e5;">
              <div style="font-size:11px; color:#737373; line-height:1.5;">
                ${footer || (lang === "en"
                  ? "This is an automated notification from M Suite. To change your email preferences, log in to the portal."
                  : "Bu, M Suite sisteminden otomatik gönderilen bir bildirimdir. E-posta tercihlerinizi değiştirmek için portala giriş yapın.")}
              </div>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;
}

// Mailto link üret — backend olmadan basit fallback
function generateMailtoLink({ to, subject, body }) {
  const params = new URLSearchParams();
  params.set("subject", subject);
  // mailto body düz metin
  const plainBody = body.replace(/<[^>]+>/g, "").replace(/\n\s+/g, "\n").trim();
  params.set("body", plainBody);
  return `mailto:${to}?${params.toString()}`;
}

// E-posta şablon dolduran fonksiyon — bildirim verilerinden HTML üretir
function buildEmailFromNotification({ notification, recipient, lang = "tr", baseUrl = "" }) {
  const tpl = EMAIL_TEMPLATES[notification.kind] || EMAIL_TEMPLATES.generic;

  // Subject placeholder replace
  let subject = (tpl.subject[lang] || tpl.subject.tr || tpl.subject.en);
  const placeholders = {
    "{{employeeName}}": notification.meta?.employeeName || "",
    "{{kindLabel}}": notification.meta?.kindLabel || "",
    "{{amount}}": notification.meta?.amount ? new Intl.NumberFormat("tr-TR").format(notification.meta.amount) : "",
    "{{period}}": notification.meta?.period || "",
  };
  Object.entries(placeholders).forEach(([k, v]) => {
    subject = subject.replace(new RegExp(k.replace(/[{}]/g, "\\$&"), "g"), v);
  });

  // CTA URL — link'e göre
  let ctaUrl = baseUrl || (typeof window !== "undefined" ? window.location.origin : "");
  if (notification.link?.type === "request") ctaUrl += "/?view=requests";
  else if (notification.link?.type === "leave") ctaUrl += "/?view=leaves";

  // Body
  const greeting = lang === "en" ? "Hello" : "Merhaba";
  const recipientName = recipient?.firstName || recipient?.username || "";

  const body = `
    <p style="margin:0 0 12px 0;">${greeting}${recipientName ? " <b>" + recipientName + "</b>" : ""},</p>
    <p style="margin:0 0 12px 0;">${notification.body || ""}</p>
  `;

  // Detaylar
  const details = [];
  if (notification.meta?.amount) {
    details.push({
      label: lang === "en" ? "Amount" : "Tutar",
      value: `${new Intl.NumberFormat("tr-TR", { minimumFractionDigits: 2 }).format(notification.meta.amount)} ${notification.meta.currency || "₺"}`,
    });
  }
  if (notification.meta?.startDate) {
    details.push({
      label: lang === "en" ? "Period" : "Dönem",
      value: `${notification.meta.startDate}${notification.meta.endDate ? ` → ${notification.meta.endDate}` : ""}`,
    });
  }
  if (notification.meta?.days) {
    details.push({
      label: lang === "en" ? "Days" : "Gün",
      value: notification.meta.days,
    });
  }
  if (notification.meta?.installments) {
    details.push({
      label: lang === "en" ? "Installments" : "Taksit",
      value: `${notification.meta.installments} ${lang === "en" ? "months" : "ay"}`,
    });
  }
  if (notification.meta?.approverNote) {
    details.push({
      label: lang === "en" ? "Note" : "Not",
      value: notification.meta.approverNote,
    });
  }
  if (notification.meta?.rejectionReason) {
    details.push({
      label: lang === "en" ? "Reason" : "Sebep",
      value: notification.meta.rejectionReason,
    });
  }

  const ctaText = lang === "en" ? "View in M Suite →" : "M Suite'te Görüntüle →";

  const html = generateEmailHtml({
    title: notification.title || subject,
    body,
    accent: tpl.accent,
    ctaText,
    ctaUrl,
    details,
    lang,
  });

  return { subject, html };
}

// Kullanıcı e-posta tercihleri — varsayılan
const DEFAULT_EMAIL_PREFERENCES = {
  enabled: true,                    // Genel açma/kapama (default açık)
  kinds: {
    request_pending: true,
    request_approved: true,
    request_rejected: true,
    request_paid: true,
    request_delivered: true,
    request_returned: true,
    leave_pending: true,
    leave_approved: true,
    leave_rejected: true,
    comment_added: false,           // Yorumlar e-posta için varsayılan KAPALI (spam riski)
    payslip_ready: true,
  },
  digest: {                         // Toplu özet e-posta seçeneği
    enabled: false,
    frequency: "daily",             // daily | weekly | never
    time: "09:00",
  },
};

function getUserEmailPreferences(username, data) {
  return (data?.hrEmailPreferences || {})[username] || DEFAULT_EMAIL_PREFERENCES;
}

function shouldEmailNotification(notification, prefs) {
  if (!prefs || !prefs.enabled) return false;
  const kind = notification.kind;
  if (kind && prefs.kinds && prefs.kinds[kind] === false) return false;
  return true;
}

