/* =====================================================================
   MUHASEBE HELPER FONKSİYONLARI
===================================================================== */

// Hesap kodundan seviye bul
// 1 → 1 (Sınıf), 10 → 2 (Grup), 100 → 3 (Ana hesap), 100.01 → 4, 100.01.001 → 5
function getAccountLevel(code) {
  if (!code) return 0;
  const s = String(code);
  const firstPart = s.split(".")[0];
  if (!s.includes(".")) {
    if (firstPart.length === 1) return 1;
    if (firstPart.length === 2) return 2;
    if (firstPart.length === 3) return 3;
    return 3;
  }
  return 3 + s.split(".").length - 1;
}

// Üst hesap kodunu bul
// 100.01.001 → 100.01, 100.01 → 100, 100 → 10, 10 → 1, 1 → null
function getParentCode(code) {
  if (!code) return null;
  const s = String(code);
  if (s.includes(".")) {
    const parts = s.split(".");
    parts.pop();
    return parts.join(".");
  }
  if (s.length === 1) return null;
  if (s.length === 2) return s.substring(0, 1);
  if (s.length === 3) return s.substring(0, 2);
  return null;
}

// TDHP standart seed'inden hesap planı oluştur
function buildChartOfAccountsFromTdhp() {
  return TDHP_SEED.map((row) => {
    const [code, name, nameEn, type, normalBalance] = row;
    const level = getAccountLevel(code);
    const parentCode = getParentCode(code);
    return {
      id: "coa_" + code.replace(/\./g, "_"),
      code,
      name,
      nameEn,
      parentCode,
      level,
      type,
      normalBalance,
      statement: ACCOUNT_TYPES[type]?.statement || "none",
      // Sadece yaprak (en alt) hesaplar işlem yapabilir
      // Default: Ana hesaplar (seviye 3) işlem yapılabilir, alt hesap açılırsa false olur
      allowTransaction: level >= 3,
      isStandard: true,
      active: true,
      description: "",
      createdAt: new Date().toISOString(),
      createdBy: "system",
    };
  });
}

// Hesap planını ağaç yapısına çevir
function buildAccountTree(accounts) {
  const sorted = [...accounts].sort((a, b) =>
    String(a.code).localeCompare(String(b.code), "tr", { numeric: true })
  );
  const map = new Map();
  const roots = [];
  sorted.forEach(acc => {
    map.set(acc.code, { ...acc, children: [] });
  });
  sorted.forEach(acc => {
    const node = map.get(acc.code);
    if (acc.parentCode && map.has(acc.parentCode)) {
      map.get(acc.parentCode).children.push(node);
    } else {
      roots.push(node);
    }
  });
  return roots;
}

// Hesabın yaprak (leaf) olup olmadığı
function isLeafAccount(code, accounts) {
  return !accounts.some(a => a.parentCode === code);
}

// Hesap kodu mevcut mu?
function isAccountCodeTaken(code, accounts, excludeId = null) {
  return accounts.some(a => a.code === code && a.id !== excludeId);
}

// Hesap kodu validate
function validateAccountCode(code, parentCode, accounts, excludeId = null) {
  if (!code || typeof code !== "string") {
    return { valid: false, error: "Hesap kodu zorunlu" };
  }
  const s = code.trim();
  if (s.length === 0) return { valid: false, error: "Hesap kodu boş olamaz" };
  if (!/^[0-9.]+$/.test(s)) {
    return { valid: false, error: "Sadece rakam ve nokta kullanılabilir" };
  }
  if (s.startsWith(".") || s.endsWith(".")) {
    return { valid: false, error: "Kod nokta ile başlayamaz/bitemez" };
  }
  if (s.includes("..")) {
    return { valid: false, error: "Ardışık nokta olamaz" };
  }
  if (isAccountCodeTaken(s, accounts, excludeId)) {
    return { valid: false, error: "Bu kod zaten kullanılıyor" };
  }
  // Üst hesap altında doğru prefix mi?
  if (parentCode) {
    const expectedPrefix = parentCode + ".";
    if (!s.startsWith(expectedPrefix) && s !== parentCode) {
      return {
        valid: false,
        error: `Üst hesap "${parentCode}" altında "${expectedPrefix}XX" formatında olmalı`
      };
    }
  }
  return { valid: true };
}

// Bir hesabın direkt bakiyesini hesapla (kendi hareketleri, alt hesaplar dahil değil)
function calculateAccountBalance(accountCode, entries, options = {}) {
  const { dateFrom, dateTo } = options;
  let totalDebit = 0;
  let totalCredit = 0;
  (entries || []).forEach(entry => {
    if (entry.status === "cancelled") return;
    if (dateFrom && entry.date < dateFrom) return;
    if (dateTo && entry.date > dateTo) return;
    (entry.lines || []).forEach(line => {
      if (line.accountCode === accountCode) {
        totalDebit += Number(line.debit) || 0;
        totalCredit += Number(line.credit) || 0;
      }
    });
  });
  return {
    debit: totalDebit,
    credit: totalCredit,
    balance: totalDebit - totalCredit, // Pozitif = borç bakiye
  };
}

// Hesap + tüm alt hesaplarının toplam bakiyesi (özet için)
function calculateAccountBalanceRecursive(accountCode, accounts, entries, options = {}) {
  const direct = calculateAccountBalance(accountCode, entries, options);
  const children = accounts.filter(a => a.parentCode === accountCode);
  let debit = direct.debit;
  let credit = direct.credit;
  children.forEach(child => {
    const childBalance = calculateAccountBalanceRecursive(child.code, accounts, entries, options);
    debit += childBalance.debit;
    credit += childBalance.credit;
  });
  return { debit, credit, balance: debit - credit };
}

