  receipt:  { label: { tr: "Tahsil Fişi",  en: "Receipt" },  prefix: "TAH", color: "#15803d" },
  payment:  { label: { tr: "Tediye Fişi",  en: "Payment" },  prefix: "TED", color: "#b91c1c" },
