// AI: Bir açıklamadan hesap önerisi (keyword matching)
function suggestAccountByDescription(description, accounts, maxResults = 5) {
  if (!description || !description.trim()) return [];
  const desc = description.toLowerCase().trim();
  const words = desc.split(/\s+/).filter(w => w.length >= 3);
  if (words.length === 0) return [];

  const scored = [];
  accounts.forEach(acc => {
    if (acc.active === false || acc.allowTransaction === false) return;

    let score = 0;

    // Keywords match (en yüksek puan)
    if (Array.isArray(acc.keywords)) {
      acc.keywords.forEach(kw => {
        const kwLower = String(kw).toLowerCase();
        if (desc.includes(kwLower)) score += 10;
        words.forEach(w => {
          if (kwLower.includes(w)) score += 3;
        });
      });
    }

    // Name match
    const nameLower = (acc.name || "").toLowerCase();
    words.forEach(w => {
      if (nameLower.includes(w)) score += 2;
    });

    // English name
    const nameEnLower = (acc.nameEn || "").toLowerCase();
    words.forEach(w => {
      if (nameEnLower.includes(w)) score += 1;
    });

    // Short name
    if (acc.shortName) {
      const shortLower = String(acc.shortName).toLowerCase();
      words.forEach(w => {
        if (shortLower.includes(w)) score += 2;
      });
    }

    if (score > 0) scored.push({ account: acc, score });
  });

  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, maxResults).map(s => s.account);
}

// AI: Bir hesap için sık karşı hesapları öner
function suggestOffsetAccounts(accountCode, accounts, entries, maxResults = 5) {
  const account = accounts.find(a => a.code === accountCode);
  if (!account) return [];

  // Önce hesap kartındaki manuel tanımlananları al
  const manualOffsets = (account.commonOffsetAccounts || [])
    .map(code => accounts.find(a => a.code === code))
    .filter(Boolean);

  // Geçmiş yevmiye fişlerinden bu hesapla birlikte kullanılan hesapları say
  const offsetCounts = {};
  (entries || []).forEach(entry => {
    if (entry.status === "cancelled") return;
    const lineWithThisAccount = entry.lines?.find(l => l.accountCode === accountCode);
    if (!lineWithThisAccount) return;
    // Bu fişteki diğer hesapları say
    entry.lines.forEach(line => {
      if (line.accountCode !== accountCode) {
        offsetCounts[line.accountCode] = (offsetCounts[line.accountCode] || 0) + 1;
      }
    });
  });

  const learnedOffsets = Object.entries(offsetCounts)
    .sort(([, a], [, b]) => b - a)
    .map(([code]) => accounts.find(a => a.code === code))
    .filter(Boolean);

  // Manuel + öğrenilen, duplicate olmadan
  const seen = new Set();
  const result = [];
  [...manualOffsets, ...learnedOffsets].forEach(acc => {
    if (!seen.has(acc.code)) {
      seen.add(acc.code);
      result.push(acc);
    }
  });

  return result.slice(0, maxResults);
}

// AI: Benzer geçmiş yevmiye fişlerini bul
function findSimilarEntries(description, entries, maxResults = 5) {
  if (!description || !description.trim()) return [];
  const desc = description.toLowerCase().trim();
  const words = desc.split(/\s+/).filter(w => w.length >= 3);
  if (words.length === 0) return [];

  const scored = [];
  (entries || []).forEach(entry => {
    if (entry.status === "cancelled") return;

    let score = 0;
    const entryDesc = (entry.description || "").toLowerCase();
    words.forEach(w => {
      if (entryDesc.includes(w)) score += 3;
    });

    // Satır açıklamalarında da ara
    (entry.lines || []).forEach(line => {
      const lineDesc = (line.description || "").toLowerCase();
      words.forEach(w => {
        if (lineDesc.includes(w)) score += 1;
      });
    });

    if (score > 0) scored.push({ entry, score });
  });

  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, maxResults).map(s => s.entry);
}

/* =====================================================================
   AI ÖĞRENME ENGINE — Geçmiş Yevmiyelerden Pattern Mining
   ---------------------------------------------------------------------
   Bu fonksiyonlar geçmiş yevmiye fişlerini analiz ederek:
   - Kelime → Hesap eşleştirmeleri öğrenir
   - Birlikte kullanılan hesapları tespit eder (co-occurrence)
   - Hesap planı için önerilen güncellemeler üretir
===================================================================== */

// Yevmiye satır açıklamalarından kelime çıkar (3+ karakter)
function extractKeywords(text) {
  if (!text) return [];
  const stopwords = new Set([
    "için", "için", "olan", "olarak", "şube", "tarihli", "tarihi", "tutar", "tutarı",
    "ödeme", "ödemesi", "tahsil", "tahsilat", "fatura", "fişi", "fiş", "no", "nolu",
    "the", "and", "for", "from", "with", "this", "that", "ile", "olan", "olarak",
    "bin", "lira", "tl", "kdv", "vergi", "vergisi"
  ]);
  return String(text).toLowerCase()
    .replace(/[^\wçğıöşüÇĞİÖŞÜa-zA-Z0-9\s]/g, " ")
    .split(/\s+/)
    .filter(w => w.length >= 3 && !stopwords.has(w) && !/^\d+$/.test(w));
}

// AI: Geçmiş yevmiyelerden bir hesap için anahtar kelime önerileri çıkar
function learnKeywordsForAccount(accountCode, entries, minOccurrence = 2) {
  const wordCounts = {};
  let totalUsage = 0;

  (entries || []).forEach(entry => {
    if (entry.status !== "posted") return;
    const usedHere = entry.lines?.some(l => l.accountCode === accountCode);
    if (!usedHere) return;
    totalUsage++;

    // Genel açıklamadan kelimeler
    extractKeywords(entry.description).forEach(w => {
      wordCounts[w] = (wordCounts[w] || 0) + 2;
    });
    // Bu hesabın satır açıklamasından kelimeler
    (entry.lines || [])
      .filter(l => l.accountCode === accountCode)
      .forEach(l => {
        extractKeywords(l.description).forEach(w => {
          wordCounts[w] = (wordCounts[w] || 0) + 1;
        });
      });
  });

  return Object.entries(wordCounts)
    .filter(([w, count]) => count >= minOccurrence)
    .map(([w, count]) => ({
      keyword: w,
      occurrences: count,
      confidence: totalUsage > 0 ? Math.min(100, Math.round((count / totalUsage) * 100)) : 0,
    }))
    .sort((a, b) => b.occurrences - a.occurrences);
}

// AI: Bir hesap için co-occurrence (birlikte kullanılan hesaplar) öğren
function learnOffsetAccountsForAccount(accountCode, entries, accounts, minOccurrence = 2) {
  const coCounts = {};
  let totalUsage = 0;

  (entries || []).forEach(entry => {
    if (entry.status !== "posted") return;
    const usedHere = entry.lines?.some(l => l.accountCode === accountCode);
    if (!usedHere) return;
    totalUsage++;

    // Bu fişteki diğer hesapları say
    const otherCodes = new Set();
    (entry.lines || []).forEach(l => {
      if (l.accountCode && l.accountCode !== accountCode) {
        otherCodes.add(l.accountCode);
      }
    });
    otherCodes.forEach(code => {
      coCounts[code] = (coCounts[code] || 0) + 1;
    });
  });

  return Object.entries(coCounts)
    .filter(([code, count]) => count >= minOccurrence)
    .map(([code, count]) => {
      const acc = accounts.find(a => a.code === code);
      return {
        code,
        name: acc?.name || "—",
        occurrences: count,
        confidence: totalUsage > 0 ? Math.min(100, Math.round((count / totalUsage) * 100)) : 0,
      };
    })
    .sort((a, b) => b.occurrences - a.occurrences);
}

// AI: Bir hesap için ortalama tutar ve son hareket bilgileri
function getAccountStats(accountCode, entries) {
  let count = 0, total = 0, lastDate = null, firstDate = null;
  const amounts = [];

  (entries || []).forEach(entry => {
    if (entry.status !== "posted") return;
    (entry.lines || []).forEach(l => {
      if (l.accountCode !== accountCode) return;
      const amt = Math.max(Number(l.debit) || 0, Number(l.credit) || 0);
      if (amt > 0) {
        count++;
        total += amt;
        amounts.push(amt);
        if (!lastDate || entry.date > lastDate) lastDate = entry.date;
        if (!firstDate || entry.date < firstDate) firstDate = entry.date;
      }
    });
  });

  if (count === 0) return null;

  amounts.sort((a, b) => a - b);
  const median = amounts[Math.floor(amounts.length / 2)];
  const avg = total / count;
  const min = amounts[0];
  const max = amounts[amounts.length - 1];

  return {
    count, total, avg, median, min, max,
    firstDate, lastDate,
  };
}

// AI: Bir hesap için "tamlık skoru" — hesap planının ne kadar AI-ready olduğu
function calculateAccountCompleteness(account) {
  let score = 0;
  let maxScore = 0;

  // Temel bilgiler (10 puan)
  maxScore += 10;
  if (account.name) score += 5;
  if (account.nameEn) score += 2;
  if (account.shortName) score += 3;

  // Para birimi & vergi (15 puan)
  maxScore += 15;
  if (account.defaultCurrency) score += 5;
  if (account.vatType && account.vatType !== "none") score += 5;
  if (account.partyType && account.partyType !== "none") score += 5;

  // AI alanları (40 puan) — En kritik
  maxScore += 40;
  if (Array.isArray(account.keywords) && account.keywords.length >= 3) score += 15;
  else if (Array.isArray(account.keywords) && account.keywords.length > 0) score += 8;
  if (account.defaultDescription) score += 5;
  if (Array.isArray(account.commonOffsetAccounts) && account.commonOffsetAccounts.length >= 2) score += 10;
  else if (Array.isArray(account.commonOffsetAccounts) && account.commonOffsetAccounts.length > 0) score += 5;
  if (Array.isArray(account.moduleSources) && account.moduleSources.length > 0) score += 10;

  return {
    score,
    maxScore,
    percentage: Math.round((score / maxScore) * 100),
    level: score >= maxScore * 0.8 ? "excellent" : score >= maxScore * 0.5 ? "good" : score >= maxScore * 0.2 ? "basic" : "incomplete",
  };
}

// AI: Tüm hesap planı için iyileştirme önerileri çıkar
function generateAccountSuggestions(accounts, entries, minOccurrence = 3) {
  const suggestions = [];

  // Her aktif yaprak hesap için
  const activeAccounts = accounts.filter(a =>
    a.active !== false && a.allowTransaction !== false
  );

  activeAccounts.forEach(account => {
    // Bu hesap geçmişte kullanılmış mı?
    const usageCount = (entries || [])
      .filter(e => e.status === "posted")
      .filter(e => (e.lines || []).some(l => l.accountCode === account.code))
      .length;

    if (usageCount < minOccurrence) return;

    // 1. Önerilen anahtar kelimeler (mevcutta olmayan)
    const learnedKeywords = learnKeywordsForAccount(account.code, entries, 2);
    const currentKeywords = new Set((account.keywords || []).map(k => String(k).toLowerCase()));
    const newKeywords = learnedKeywords
      .filter(k => !currentKeywords.has(k.keyword))
      .filter(k => k.confidence >= 30) // En az %30 güven
      .slice(0, 5);

    // 2. Önerilen karşı hesaplar (mevcutta olmayan)
    const learnedOffsets = learnOffsetAccountsForAccount(account.code, entries, accounts, 2);
    const currentOffsets = new Set(account.commonOffsetAccounts || []);
    const newOffsets = learnedOffsets
      .filter(o => !currentOffsets.has(o.code))
      .filter(o => o.confidence >= 30)
      .slice(0, 5);

    // 3. Önerilen modül kaynağı (kayıt source'larından)
    const sourceCounts = {};
    (entries || []).forEach(e => {
      if (e.status !== "posted" || !e.source || e.source === "manual") return;
      const used = (e.lines || []).some(l => l.accountCode === account.code);
      if (used) sourceCounts[e.source] = (sourceCounts[e.source] || 0) + 1;
    });
    const currentSources = new Set(account.moduleSources || []);
    const newSources = Object.entries(sourceCounts)
      .filter(([src, cnt]) => cnt >= 2 && !currentSources.has(src))
      .map(([src, cnt]) => ({ source: src, occurrences: cnt }));

    if (newKeywords.length > 0 || newOffsets.length > 0 || newSources.length > 0) {
      suggestions.push({
        account,
        usageCount,
        completeness: calculateAccountCompleteness(account),
        newKeywords,
        newOffsets,
        newSources,
        priority: newKeywords.length + newOffsets.length + newSources.length,
      });
    }
  });

  // En çok iyileştirme gerekenler üstte
  suggestions.sort((a, b) => b.priority - a.priority);
  return suggestions;
}

// AI: Anomali tespiti — olağandışı yevmiye fişleri
function detectAnomalies(entries, accounts) {
  const anomalies = [];

  (entries || []).forEach(entry => {
    if (entry.status !== "posted") return;

    // 1. Aşırı büyük tutar (medianın 10 katından fazla)
    (entry.lines || []).forEach(line => {
      const stats = getAccountStats(line.accountCode, entries);
      if (!stats || stats.count < 5) return;
      const amt = Math.max(Number(line.debit) || 0, Number(line.credit) || 0);
      if (amt > stats.median * 10 && amt > 50000) {
        anomalies.push({
          type: "large_amount",
          severity: "warning",
          entry,
          line,
          message: `${line.accountCode} için olağandışı tutar: ${fmtTL(amt)} ₺ (ortalama: ${fmtTL(stats.median)} ₺)`,
        });
      }
    });

    // 2. Hiç kullanılmamış (yeni) hesaplar
    (entry.lines || []).forEach(line => {
      const stats = getAccountStats(line.accountCode, entries.filter(e => e.id !== entry.id));
      if (!stats || stats.count === 0) {
        const acc = accounts.find(a => a.code === line.accountCode);
        if (acc) {
          anomalies.push({
            type: "first_use",
            severity: "info",
            entry,
            line,
            message: `İlk kez kullanılan hesap: ${line.accountCode} - ${acc.name}`,
          });
        }
      }
    });

    // 3. Pasif hesap kullanımı
    (entry.lines || []).forEach(line => {
      const acc = accounts.find(a => a.code === line.accountCode);
      if (acc && acc.active === false) {
        anomalies.push({
          type: "inactive_account",
          severity: "error",
          entry,
          line,
          message: `Pasif hesap kullanılmış: ${line.accountCode} - ${acc.name}`,
        });
      }
    });
  });

  return anomalies;
}

// AI: Geliştirilmiş hesap önerisi (V2) - geçmiş kullanım frekansı dahil
function suggestAccountByDescriptionV2(description, accounts, entries, maxResults = 5) {
  if (!description || !description.trim()) return [];

  // V1 sonuçları (keyword/name match)
  const v1Results = suggestAccountByDescription(description, accounts, maxResults * 2);

  // Her hesap için geçmiş kullanım bonusu ver
  const enriched = v1Results.map(acc => {
    const stats = getAccountStats(acc.code, entries);
    const usageBonus = stats ? Math.min(10, Math.log10(stats.count + 1) * 5) : 0;
    return {
      account: acc,
      stats,
      bonus: usageBonus,
    };
  });

  // Tekrar sırala
  enriched.sort((a, b) => b.bonus - a.bonus);
  return enriched.slice(0, maxResults).map(e => e.account);
}

/* =====================================================================
   AUTO-VOUCHER ENGINE — Modüllerden Otomatik Yevmiye Üreteci
   ---------------------------------------------------------------------
   Kasa, Banka, Fatura hareketlerini otomatik yevmiye fişine dönüştürür.
===================================================================== */

// Bir modül kaynağı için en uygun hesabı bul (moduleSources + keyword + party)
function findAccountByModule(moduleSource, accounts, options = {}) {
  const { description = "", partyType = null, currency = "TRY", preferActive = true } = options;

  // 1. moduleSources içeren hesaplar
  const candidates = accounts.filter(a => {
    if (preferActive && a.active === false) return false;
    if (a.allowTransaction === false) return false;
    return Array.isArray(a.moduleSources) && a.moduleSources.includes(moduleSource);
  });

  if (candidates.length === 0) return null;

  // 2. Eğer partyType uyuyorsa puan ekle
  // 3. Keyword match varsa puan ekle
  const scored = candidates.map(acc => {
    let score = 1;
    if (partyType && acc.partyType === partyType) score += 5;
    if (description && Array.isArray(acc.keywords)) {
      const desc = description.toLowerCase();
      acc.keywords.forEach(kw => {
        if (desc.includes(String(kw).toLowerCase())) score += 3;
      });
    }
    if (acc.defaultCurrency === currency) score += 1;
    return { acc, score };
  });

  scored.sort((a, b) => b.score - a.score);
  return scored[0].acc;
}

// Bir banka hesabı için karşılık gelen muhasebe hesabını bul
// Örn: bankAccount.name="Garanti BBVA" → 102.XX hesabı
function findAccountForBankAccount(bankAccountId, bankAccounts, accounts) {
  const bank = bankAccounts.find(b => b.id === bankAccountId);
  if (!bank) return null;
  const bankName = (bank.name || "").toLowerCase();

  // 1. moduleSource="bank" olan ve keywords'te banka adı geçen hesaplar
  const candidates = accounts.filter(a => {
    if (a.active === false || a.allowTransaction === false) return false;
    if (!Array.isArray(a.moduleSources) || !a.moduleSources.includes("bank")) return false;
    if (!String(a.code).startsWith("102")) return false;
    return true;
  });

  // İsim eşleşmesi
  const matched = candidates.find(a =>
    a.keywords && a.keywords.some(kw => bankName.includes(String(kw).toLowerCase()))
  );
  if (matched) return matched;

  // İsme göre name match
  const byName = candidates.find(a =>
    (a.name || "").toLowerCase().includes(bankName) ||
    bankName.includes((a.name || "").toLowerCase())
  );
  if (byName) return byName;

  // Yine bulamazsa: ilk uygun 102.XX
  return candidates[0] || null;
}

// Bir kasa hesabı için 100.XX bulur
function findAccountForKasa(kasaAccountId, kasaAccounts, accounts) {
  const kasa = kasaAccounts.find(k => k.id === kasaAccountId);
  if (!kasa) return null;
  const kasaName = (kasa.name || "").toLowerCase();
  const kasaCurrency = kasa.currency || "TRY";

  const candidates = accounts.filter(a => {
    if (a.active === false || a.allowTransaction === false) return false;
    if (!Array.isArray(a.moduleSources) || !a.moduleSources.includes("kasa")) return false;
    if (!String(a.code).startsWith("100")) return false;
    return true;
  });

  // Para birimi + isim eşleşmesi
  const matched = candidates.find(a =>
    a.defaultCurrency === kasaCurrency &&
    (a.keywords?.some(kw => kasaName.includes(String(kw).toLowerCase())) ||
     (a.name || "").toLowerCase().includes(kasaName))
  );
  if (matched) return matched;

  // Para birimi eşleşmesi
  const byCurrency = candidates.find(a => a.defaultCurrency === kasaCurrency);
  if (byCurrency) return byCurrency;

  return candidates[0] || null;
}

// Auto-voucher: Banka hareketi → Yevmiye fişi
function generateVoucherFromBankEntry(bankEntry, bankAccounts, accounts, entries) {
  const bank = bankAccounts.find(b => b.id === bankEntry.bankAccountId);
  if (!bank) return { success: false, error: "Banka hesabı bulunamadı" };

  // Banka muhasebe hesabı (102.XX)
  const bankAcc = findAccountForBankAccount(bankEntry.bankAccountId, bankAccounts, accounts);
  if (!bankAcc) {
    return {
      success: false,
      error: `${bank.name} için 102.XX banka hesabı tanımlanmamış. Hesap planında "moduleSources: bank" özelliği ile bir 102.XX hesabı oluşturun ve keyword'lere banka adını ekleyin.`,
    };
  }

  // Karşı hesap (description'a göre)
  let offsetAcc = null;
  if (bankEntry.description) {
    const suggestions = suggestAccountByDescription(bankEntry.description, accounts, 3);
    offsetAcc = suggestions.find(a => a.code !== bankAcc.code);
  }
  // Yine bulamazsak commonOffsetAccounts'tan
  if (!offsetAcc && Array.isArray(bankAcc.commonOffsetAccounts)) {
    for (const code of bankAcc.commonOffsetAccounts) {
      const candidate = accounts.find(a => a.code === code);
      if (candidate && candidate.allowTransaction !== false) {
        offsetAcc = candidate;
        break;
      }
    }
  }
  // Yine yoksa: openClose tahminleri
  if (!offsetAcc) {
    // Para girişi (in) → muhtemelen 120 (Alıcılar) veya 600 (Yurtiçi Satışlar)
    // Para çıkışı (out) → muhtemelen 320 (Satıcılar) veya 770 (Genel Yönetim Giderleri)
    if (bankEntry.type === "in") {
      offsetAcc = accounts.find(a => a.code === "120") || accounts.find(a => a.code === "320");
    } else {
      offsetAcc = accounts.find(a => a.code === "320") || accounts.find(a => a.code === "770");
    }
  }

  if (!offsetAcc) {
    return { success: false, error: "Karşı hesap önerisi bulunamadı. Hesap planını kontrol edin." };
  }

  const amt = Number(bankEntry.amount) || 0;
  // Banka'da giriş (in) → 102 borç, karşı hesap alacak
  // Banka'da çıkış (out) → 102 alacak, karşı hesap borç
  const lines = bankEntry.type === "in" ? [
    {
      id: `line_1_${Date.now()}`,
      accountCode: bankAcc.code,
      description: `${bank.name} - ${bankEntry.description || "Tahsilat"}`,
      debit: amt, credit: 0,
      currency: bank.currency || "TRY",
    },
    {
      id: `line_2_${Date.now() + 1}`,
      accountCode: offsetAcc.code,
      description: bankEntry.description || "",
      debit: 0, credit: amt,
      currency: bank.currency || "TRY",
    },
  ] : [
    {
      id: `line_1_${Date.now()}`,
      accountCode: offsetAcc.code,
      description: bankEntry.description || "",
      debit: amt, credit: 0,
      currency: bank.currency || "TRY",
    },
    {
      id: `line_2_${Date.now() + 1}`,
      accountCode: bankAcc.code,
      description: `${bank.name} - ${bankEntry.description || "Ödeme"}`,
      debit: 0, credit: amt,
      currency: bank.currency || "TRY",
    },
  ];

  const voucherType = bankEntry.type === "in" ? "receipt" : "payment";
  const year = new Date(bankEntry.date).getFullYear();
  const voucherNo = generateVoucherNo(voucherType, year, entries);

  return {
    success: true,
    voucher: {
      voucherNo,
      voucherType,
      date: bankEntry.date,
      description: `${bank.name} - ${bankEntry.description || (bankEntry.type === "in" ? "Tahsilat" : "Ödeme")}`,
      source: "bank",
      sourceId: bankEntry.id,
      lines,
      totalDebit: amt,
      totalCredit: amt,
      status: "draft",
    },
    suggestedAccounts: { bankAcc, offsetAcc },
  };
}

// Auto-voucher: Kasa hareketi → Yevmiye fişi
function generateVoucherFromKasaEntry(kasaEntry, kasaAccounts, accounts, entries) {
  const kasa = kasaAccounts.find(k => k.id === kasaEntry.kasaAccountId);
  if (!kasa) return { success: false, error: "Kasa bulunamadı" };

  const kasaAcc = findAccountForKasa(kasaEntry.kasaAccountId, kasaAccounts, accounts);
  if (!kasaAcc) {
    return {
      success: false,
      error: `${kasa.name} için 100.XX kasa hesabı tanımlanmamış. Hesap planında "moduleSources: kasa" özelliği ile bir 100.XX hesabı oluşturun.`,
    };
  }

  let offsetAcc = null;
  if (kasaEntry.description) {
    const suggestions = suggestAccountByDescription(kasaEntry.description, accounts, 3);
    offsetAcc = suggestions.find(a => a.code !== kasaAcc.code);
  }
  if (!offsetAcc && Array.isArray(kasaAcc.commonOffsetAccounts)) {
    for (const code of kasaAcc.commonOffsetAccounts) {
      const candidate = accounts.find(a => a.code === code);
      if (candidate && candidate.allowTransaction !== false) {
        offsetAcc = candidate;
        break;
      }
    }
  }
  if (!offsetAcc) {
    if (kasaEntry.type === "in") {
      offsetAcc = accounts.find(a => a.code === "120") || accounts.find(a => a.code === "600");
    } else {
      offsetAcc = accounts.find(a => a.code === "770") || accounts.find(a => a.code === "320");
    }
  }

  if (!offsetAcc) return { success: false, error: "Karşı hesap önerisi bulunamadı" };

  const amt = Number(kasaEntry.amount) || 0;
  const lines = kasaEntry.type === "in" ? [
    {
      id: `line_1_${Date.now()}`,
      accountCode: kasaAcc.code,
      description: `${kasa.name} - ${kasaEntry.description || "Tahsilat"}`,
      debit: amt, credit: 0,
      currency: kasa.currency || "TRY",
    },
    {
      id: `line_2_${Date.now() + 1}`,
      accountCode: offsetAcc.code,
      description: kasaEntry.description || "",
      debit: 0, credit: amt,
      currency: kasa.currency || "TRY",
    },
  ] : [
    {
      id: `line_1_${Date.now()}`,
      accountCode: offsetAcc.code,
      description: kasaEntry.description || "",
      debit: amt, credit: 0,
      currency: kasa.currency || "TRY",
    },
    {
      id: `line_2_${Date.now() + 1}`,
      accountCode: kasaAcc.code,
      description: `${kasa.name} - ${kasaEntry.description || "Ödeme"}`,
      debit: 0, credit: amt,
      currency: kasa.currency || "TRY",
    },
  ];

  const voucherType = kasaEntry.type === "in" ? "receipt" : "payment";
  const year = new Date(kasaEntry.date).getFullYear();
  const voucherNo = generateVoucherNo(voucherType, year, entries);

  return {
    success: true,
    voucher: {
      voucherNo,
      voucherType,
      date: kasaEntry.date,
      description: `${kasa.name} - ${kasaEntry.description || (kasaEntry.type === "in" ? "Tahsilat" : "Ödeme")}`,
      source: "kasa",
      sourceId: kasaEntry.id,
      lines,
      totalDebit: amt,
      totalCredit: amt,
      status: "draft",
    },
    suggestedAccounts: { kasaAcc, offsetAcc },
  };
}

/* =====================================================================
   AUTO-VOUCHER: Çek/Senet → Yevmiye Fişi
   ---------------------------------------------------------------------
   Çek/Senet tipine ve durumuna göre uygun yevmiye fişi üretir:
   
   ANA HAREKET (çek alındığı/verildiği anda):
     - Alınan Çek:   101 BORÇ  / 120 (cari) ALACAK
     - Verilen Çek:  320 (cari) BORÇ / 103 ALACAK
     - Alınan Senet: 121 BORÇ  / 120 (cari) ALACAK
     - Verilen Senet: 320 (cari) BORÇ / 321 ALACAK
   
   DURUM GEÇİŞLERİ:
     - in_bank (Bankaya tahsile): aynı 101 hesabı içinde alt grup hareketi
       → genelde yapılmaz (alt hesap kullanmıyorsak), atlanır
     - collected (Tahsil edildi): 102 (Banka) BORÇ / 101 (Alınan Çek) ALACAK
     - paid (Ödendi - verilen çek için): 103 ALACAK iken bu sefer 103 BORÇ/102 ALACAK
     - bounced (Karşılıksız): ters hareket → 120 BORÇ / 101 ALACAK
     - cancelled (İptal): ters hareket
===================================================================== */
function generateVoucherFromCheck(check, action, accounts, entries, party, bank) {
  // action: "main" | "in_bank" | "collected" | "paid" | "bounced" | "cancelled" | "endorsed"
  const amount = Number(check.amount) || 0;
  if (amount <= 0) return { success: false, error: "Tutar sıfır veya negatif" };

  const findAcc = (code) =>
    accounts.find(a => a.code === code && a.allowTransaction !== false) ||
    accounts.find(a => String(a.code).startsWith(code) && a.allowTransaction !== false);

  // Hesap eşleştirmeleri (TDHP)
  // 101 ALINAN ÇEKLER
  // 103 VERILEN ÇEKLER VE ÖDEME EMIRLERI (-)
  // 121 ALACAK SENETLERI
  // 321 BORÇ SENETLERI
  // 102 BANKALAR
  // 120 ALICILAR
  // 320 SATICILAR

  const isReceivedCheck = check.checkType === "received_check";
  const isGivenCheck    = check.checkType === "given_check";
  const isReceivedNote  = check.checkType === "received_note";
  const isGivenNote     = check.checkType === "given_note";
  const isReceived = isReceivedCheck || isReceivedNote;

  // Çek hesabı (kendine ait)
  let checkAcc;
  if (isReceivedCheck) checkAcc = findAcc("101");
  else if (isGivenCheck) checkAcc = findAcc("103");
  else if (isReceivedNote) checkAcc = findAcc("121");
  else if (isGivenNote) checkAcc = findAcc("321");

  if (!checkAcc) {
    const codeName = isReceivedCheck ? "101 ALINAN ÇEKLER" :
                     isGivenCheck ? "103 VERILEN ÇEKLER" :
                     isReceivedNote ? "121 ALACAK SENETLERI" : "321 BORÇ SENETLERI";
    return { success: false, error: `${codeName} hesabı hesap planında bulunamadı` };
  }

  // Cari hesabı (party'den)
  let partyAcc;
  if (party) {
    const candidateCodes = [
      party.accounting?.accountCode_alici,
      party.accounting?.accountCode_satici,
      party.accounting?.accountCode_personel,
      party.accounting?.accountCode_diger,
    ].filter(Boolean);
    for (const code of candidateCodes) {
      const acc = accounts.find(a => a.code === code);
      if (acc) { partyAcc = acc; break; }
    }
  }
  // Yoksa generic
  if (!partyAcc) {
    partyAcc = isReceived ? findAcc("120") : findAcc("320");
  }
  if (!partyAcc) {
    return { success: false, error: isReceived ? "120 Alıcılar hesabı bulunamadı" : "320 Satıcılar hesabı bulunamadı" };
  }

  // Banka hesabı (tahsil/ödeme için)
  let bankAcc;
  if (bank?.accountCode) {
    bankAcc = accounts.find(a => a.code === bank.accountCode);
  }
  if (!bankAcc) bankAcc = findAcc("102");

  // İşlem tarihi
  const today = new Date().toISOString().slice(0, 10);
  const eventDate = check.eventDate || today;

  // Açıklama
  const typeInfo = CHECK_TYPES[check.checkType] || {};
  const baseDesc = `${typeInfo.tr || check.checkType} - ${check.serialNo || check.id?.slice(-6)}`;
  const partyName = check.partyName || party?.name || "";

  // Voucher type ve lines build
  let voucherType = "compound";
  let description = "";
  let lines = [];

  const mkLine = (acc, debit, credit, lineDesc) => ({
    id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
    accountCode: acc.code,
    accountName: acc.name,
    description: lineDesc,
    debit: Number(debit) || 0, credit: Number(credit) || 0,
    currency: check.currency || "TRY",
  });

  if (action === "main") {
    // Ana hareket: çek alındı/verildi
    if (isReceived) {
      // 101/121 BORÇ - cari ALACAK
      voucherType = "compound";
      description = `${baseDesc} - ${partyName} (Tahsilat)`;
      lines.push(mkLine(checkAcc, amount, 0, `${baseDesc} portföye alındı`));
      lines.push(mkLine(partyAcc, 0, amount, `${partyName} - ${check.serialNo || ""}`));
    } else {
      // cari BORÇ - 103/321 ALACAK
      voucherType = "compound";
      description = `${baseDesc} - ${partyName} (Ödeme)`;
      lines.push(mkLine(partyAcc, amount, 0, `${partyName} - ${check.serialNo || ""}`));
      lines.push(mkLine(checkAcc, 0, amount, `${baseDesc} keşide edildi`));
    }
  } else if (action === "collected") {
    // Alınan çek tahsil edildi: 102 Banka BORÇ / 101 Alınan Çek ALACAK
    if (!isReceived) return { success: false, error: "Tahsilat sadece alınan çek/senet için olur" };
    voucherType = "receipt";
    description = `${baseDesc} - Tahsil edildi`;
    lines.push(mkLine(bankAcc, amount, 0, `${baseDesc} banka hesabına geçti`));
    lines.push(mkLine(checkAcc, 0, amount, `${baseDesc} tahsil`));
  } else if (action === "paid") {
    // Verilen çek ödendi: 103/321 Verilen Çek BORÇ / 102 Banka ALACAK
    if (isReceived) return { success: false, error: "Ödendi sadece verilen çek/senet için olur" };
    voucherType = "payment";
    description = `${baseDesc} - Ödendi`;
    lines.push(mkLine(checkAcc, amount, 0, `${baseDesc} kapatıldı`));
    lines.push(mkLine(bankAcc, 0, amount, `${baseDesc} bankadan ödendi`));
  } else if (action === "bounced") {
    // Karşılıksız → ters hareket
    voucherType = "compound";
    description = `${baseDesc} - KARŞILIKSIZ`;
    if (isReceived) {
      // 120 BORÇ / 101 ALACAK (cari tekrar borç)
      lines.push(mkLine(partyAcc, amount, 0, `${partyName} - Karşılıksız çek`));
      lines.push(mkLine(checkAcc, 0, amount, `${baseDesc} karşılıksız`));
    } else {
      // 103 BORÇ / 320 ALACAK (verilen çek geri döndü, cari tekrar alacaklı)
      lines.push(mkLine(checkAcc, amount, 0, `${baseDesc} karşılıksız (geri döndü)`));
      lines.push(mkLine(partyAcc, 0, amount, `${partyName} - geri açıldı`));
    }
  } else if (action === "cancelled") {
    // İptal → tam ters ana hareket
    voucherType = "compound";
    description = `${baseDesc} - İPTAL`;
    if (isReceived) {
      lines.push(mkLine(partyAcc, amount, 0, `${partyName} - İptal`));
      lines.push(mkLine(checkAcc, 0, amount, `${baseDesc} iptal`));
    } else {
      lines.push(mkLine(checkAcc, amount, 0, `${baseDesc} iptal`));
      lines.push(mkLine(partyAcc, 0, amount, `${partyName} - İptal`));
    }
  } else if (action === "in_bank") {
    // Bankaya tahsile verildi → eğer hesap planında alt hesap varsa kullan, yoksa atlat
    // Bu opsiyonel - şimdilik atla
    return { success: false, skipped: true, reason: "in_bank durumu için yevmiye fişi atlandı (alt hesap yok)" };
  } else if (action === "endorsed") {
    return { success: false, skipped: true, reason: "Ciro durumu için manuel fiş tavsiye edilir" };
  } else {
    return { success: false, error: `Bilinmeyen aksiyon: ${action}` };
  }

  const totals = calculateEntryTotals(lines);
  if (!totals.isBalanced) {
    return { success: false, error: "Borç ve alacak dengeli değil" };
  }

  const year = new Date(eventDate).getFullYear();
  const voucherNo = generateVoucherNo(voucherType, year, entries);

  return {
    success: true,
    voucher: {
      voucherNo,
      voucherType,
      date: eventDate,
      description,
      lines,
      source: "check",
      sourceId: check.id,
      sourceMeta: { checkSerial: check.serialNo, action, checkType: check.checkType },
      status: "draft",
      currency: check.currency || "TRY",
    },
  };
}

// Auto-voucher: Fatura → Yevmiye fişi
function generateVoucherFromInvoice(invoice, accounts, entries, overrides = {}) {
  // Fatura tipi belirle: satış mı alış mı?
  // Veri modeli: type="out" → Giden/Satış, type="in" → Gelen/Alış
  const isSales = invoice.type === "out" || invoice.kind === "sale" || invoice.type === "sale" || invoice.type === "sales";
  const amt = Number(invoice.total ?? invoice.totalAmount ?? invoice.amount ?? invoice.grossAmount) || 0;
  const vatAmt = Number(invoice.vatAmount ?? invoice.vat) || 0;
  const netAmt = amt - vatAmt;
  const currency = invoice.currency || "TRY";
  const partyName = invoice.counterparty || invoice.partyName || "";

  if (amt <= 0) return { success: false, reason: "zero_amount", error: "Fatura tutarı sıfır veya negatif" };

  // Manuel hesap kodu seçimleri (modal'dan gelir) — varsa öncelikli
  const ov = overrides || {};
  const byCode = (code) => code ? accounts.find(a => a.code === code) : null;

  let mainAcc, partyAcc, vatAcc;

  if (isSales) {
    // SATIŞ FATURASI: 120 (Alıcılar) Borç → 600 (Yurtiçi Satışlar) Alacak + 391 (Hesaplanan KDV) Alacak
    partyAcc = byCode(ov.party) ||
               findAccountByModule("invoice", accounts, { description: partyName, partyType: "customer", currency }) ||
               accounts.find(a => String(a.code).startsWith("120") && a.allowTransaction !== false);
    mainAcc = byCode(ov.main) ||
              findAccountByModule("invoice", accounts, { description: invoice.description, currency }) ||
              accounts.find(a => a.code === "600");
    if (vatAmt > 0) {
      vatAcc = byCode(ov.vat) ||
               accounts.find(a => a.code === "391" && a.allowTransaction !== false) ||
               accounts.find(a => String(a.code).startsWith("391") && a.allowTransaction !== false);
    }
  } else {
    // ALIŞ FATURASI: 153/770 (Stok/Gider) Borç + 191 (İndirilecek KDV) Borç → 320 (Satıcılar) Alacak
    partyAcc = byCode(ov.party) ||
               findAccountByModule("invoice", accounts, { description: partyName, partyType: "vendor", currency }) ||
               accounts.find(a => String(a.code).startsWith("320") && a.allowTransaction !== false);
    mainAcc = byCode(ov.main) ||
              findAccountByModule("invoice", accounts, { description: invoice.description, currency }) ||
              accounts.find(a => a.code === "153") ||
              accounts.find(a => a.code === "770");
    if (vatAmt > 0) {
      vatAcc = byCode(ov.vat) ||
               accounts.find(a => a.code === "191" && a.allowTransaction !== false) ||
               accounts.find(a => String(a.code).startsWith("191") && a.allowTransaction !== false);
    }
  }

  // Eksik hesapları topla → modal manuel seçim sunabilsin (KDV dahil; aksi halde fiş dengesiz kalır)
  const missing = {};
  if (!partyAcc) missing.party = true;
  if (!mainAcc) missing.main = true;
  if (vatAmt > 0 && !vatAcc) missing.vat = true;
  if (missing.party || missing.main || missing.vat) {
    const labels = [];
    if (missing.party) labels.push(isSales ? "120 Alıcılar" : "320 Satıcılar");
    if (missing.main) labels.push(isSales ? "600 Satış" : "153/770 Stok/Gider");
    if (missing.vat) labels.push(isSales ? "391 Hesaplanan KDV" : "191 İndirilecek KDV");
    return {
      success: false,
      reason: "missing_account",
      missing,
      expected: {
        party: isSales ? "120" : "320",
        main: isSales ? "600" : "153/770",
        vat: isSales ? "391" : "191",
      },
      error: `${labels.join(", ")} hesabı bulunamadı`,
    };
  }

  const lines = [];
  let idx = 0;
  const desc = `${invoice.invoiceNo || ""} - ${partyName}`.trim();

  if (isSales) {
    // 120 Alıcılar Borç (toplam)
    lines.push({
      id: `line_${++idx}_${Date.now()}`,
      accountCode: partyAcc.code,
      description: desc,
      debit: amt, credit: 0,
      currency,
    });
    // 600 Yurtiçi Satışlar Alacak (net)
    lines.push({
      id: `line_${++idx}_${Date.now() + 1}`,
      accountCode: mainAcc.code,
      description: invoice.description || partyName,
      debit: 0, credit: netAmt,
      currency,
    });
    // 391 Hesaplanan KDV Alacak (KDV)
    if (vatAmt > 0 && vatAcc) {
      lines.push({
        id: `line_${++idx}_${Date.now() + 2}`,
        accountCode: vatAcc.code,
        description: `KDV %${invoice.vatRate || ""} - ${invoice.invoiceNo || ""}`,
        debit: 0, credit: vatAmt,
        currency,
      });
    }
  } else {
    // 153/770 Borç (net)
    lines.push({
      id: `line_${++idx}_${Date.now()}`,
      accountCode: mainAcc.code,
      description: invoice.description || partyName,
      debit: netAmt, credit: 0,
      currency,
    });
    // 191 İndirilecek KDV Borç
    if (vatAmt > 0 && vatAcc) {
      lines.push({
        id: `line_${++idx}_${Date.now() + 1}`,
        accountCode: vatAcc.code,
        description: `KDV %${invoice.vatRate || ""} - ${invoice.invoiceNo || ""}`,
        debit: vatAmt, credit: 0,
        currency,
      });
    }
    // 320 Satıcılar Alacak (toplam)
    lines.push({
      id: `line_${++idx}_${Date.now() + 2}`,
      accountCode: partyAcc.code,
      description: desc,
      debit: 0, credit: amt,
      currency,
    });
  }

  const voucherType = "compound"; // Fatura için MAH fişi
  const year = new Date(invoice.date || invoice.invoiceDate || new Date()).getFullYear();
  const voucherNo = generateVoucherNo(voucherType, year, entries);

  return {
    success: true,
    voucher: {
      voucherNo,
      voucherType,
      date: invoice.date || invoice.invoiceDate,
      description: `${isSales ? "Satış" : "Alış"} Fat. ${invoice.invoiceNo || ""} - ${partyName}`,
      source: "invoice",
      sourceId: invoice.id,
      lines,
      totalDebit: amt,
      totalCredit: amt,
      status: "draft",
    },
    suggestedAccounts: { partyAcc, mainAcc, vatAcc },
  };
}

