/* ---------- ESKİ veri yapısını yeni yapıya migrate eder ---------- */
function migrateLegacyData(d) {
  if (!d) return null;
  // Eğer companies & companyData zaten varsa, eski formatta değil
  if (d.companies && d.companyData) {
    // Yine de backfill kontrolü yap
    const backfilled = backfillCompanyData(d);
    return { data: backfilled, migrated: backfilled !== d };
  }

  // Eski format: tüm per-company alanlar üst düzeyde
  const newCompanyId = "comp_legacy_" + Date.now();
  const companyData = {};
  PER_COMPANY_FIELDS.forEach(f => {
    if (d[f] !== undefined) {
      companyData[f] = d[f];
      delete d[f];
    }
  });

  // Default değerleri tamamla
  const defaults = createEmptyCompanyData({
    fiscalYear: companyData.fiscalYear,
    fiscalStartMonth: companyData.fiscalStartMonth,
  });
  PER_COMPANY_FIELDS.forEach(f => {
    if (companyData[f] === undefined) companyData[f] = defaults[f];
  });

  d.companies = [{
    id: newCompanyId,
    name: "Promet AŞ",
    taxNo: "",
    color: "#dc2626",
    createdAt: new Date().toISOString(),
  }];
  d.activeCompanyId = newCompanyId;
  d.companyData = { [newCompanyId]: companyData };
  return { data: d, migrated: true };
}

/**
 * Backfill — Yeni alanlar eklendiğinde mevcut şirketlere
 * varsayılan değerleri verir (data kaybı olmadan).
 */
function backfillCompanyData(d) {
  if (!d?.companyData) return d;
  let changed = false;
  const defaults = createEmptyCompanyData();

  Object.keys(d.companyData).forEach(companyId => {
    const cd = d.companyData[companyId];
    if (!cd) return;
    PER_COMPANY_FIELDS.forEach(f => {
      if (cd[f] === undefined) {
        cd[f] = defaults[f];
        changed = true;
      }
    });
  });

  return changed ? { ...d } : d;
}


