/* ---------- Departman Form Modal ---------- */
function DepartmentFormModal({ draft, setDraft, orgUnits, departments, employees, users, canManageAuth, lang, onClose, onSave }) {
  const possibleParents = departments.filter(d =>
    d.id !== draft.id && d.orgUnitId === draft.orgUnitId
  );

  const colorPalette = ["#1d4ed8", "#0f766e", "#dc2626", "#ea580c", "#7c3aed", "#db2777", "#475569", "#0891b2", "#15803d", "#ca8a04"];

  return (
    <Modal title={draft.id ? t("deptForm.edit", lang) : t("deptForm.new", lang)}
      icon={FolderTree} onClose={onClose} onSave={onSave} maxWidth="max-w-xl">
      <div className="space-y-3">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <div>
            <div className="label mb-1">{t("deptForm.name", lang)} *</div>
            <input className="input w-full" autoFocus
              value={draft.name || ""} placeholder={lang === "en" ? "Human Resources" : lang === "de" ? "Personalwesen" : lang === "ar" ? "الموارد البشرية" : "İnsan Kaynakları"}
              onChange={e => setDraft({ ...draft, name: e.target.value })}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Code" : lang === "de" ? "Code" : lang === "ar" ? "الرمز" : "Kod"}</div>
            <input className="input w-full mono" placeholder="HR"
              value={draft.code || ""}
              onChange={e => setDraft({ ...draft, code: e.target.value })}/>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          <div>
            <div className="label mb-1">{t("deptForm.orgUnit", lang)} *</div>
            <select className="input w-full" value={draft.orgUnitId || ""}
              onChange={e => setDraft({ ...draft, orgUnitId: e.target.value, parentDeptId: null })}>
              <option value="">— {t("form.select", lang)} —</option>
              {orgUnits.map(o => (
                <option key={o.id} value={o.id}>
                  {ORG_UNIT_TYPES[o.type]?.icon} {o.name}
                </option>
              ))}
            </select>
          </div>
          <div>
            <div className="label mb-1">{t("deptForm.parent", lang)} {t("form.optional", lang)}</div>
            <select className="input w-full" value={draft.parentDeptId || ""}
              onChange={e => setDraft({ ...draft, parentDeptId: e.target.value || null })}>
              <option value="">— {lang === "en" ? "Top level" : lang === "de" ? "Oberste Ebene" : lang === "ar" ? "أعلى مستوى" : "Üst seviye"} —</option>
              {possibleParents.map(p => (
                <option key={p.id} value={p.id}>{p.name}</option>
              ))}
            </select>
          </div>
        </div>

        <div>
          <div className="label mb-1">{t("deptForm.color", lang)}</div>
          <div className="flex items-center gap-1.5 flex-wrap">
            {colorPalette.map(c => (
              <button key={c} onClick={() => setDraft({ ...draft, color: c })}
                className="w-6 h-6 rounded-full"
                style={{
                  background: c,
                  border: draft.color === c ? "2px solid #000" : "2px solid transparent",
                }}/>
            ))}
            <input type="color" className="ml-2 w-8 h-8 cursor-pointer rounded"
              value={draft.color || "#737373"}
              onChange={e => setDraft({ ...draft, color: e.target.value })}/>
          </div>
        </div>

        <div>
          <div className="label mb-1">{t("deptForm.manager", lang)}</div>
          <select className="input w-full" value={draft.managerEmployeeId || ""}
            onChange={e => setDraft({ ...draft, managerEmployeeId: e.target.value || null })}>
            <option value="">— {t("form.none", lang)} —</option>
            {employees.map(e => (
              <option key={e.id} value={e.id}>{e.firstName} {e.lastName}</option>
            ))}
          </select>
        </div>

        {canManageAuth && (
          <AuthorizedUsersPicker
            users={users}
            selected={draft.authorizedUsers || []}
            onChange={(arr) => setDraft({ ...draft, authorizedUsers: arr })}
            lang={lang}
          />
        )}
      </div>
    </Modal>
  );
}

