/* ---------- Bordro Parametre Önizleme Modal ---------- */
function PayrollParamsPreviewModal({ version, lang, onClose }) {
  // Asgari ücretli için tüm hesap detayını gösteren önizleme
  const gross = version.minimumWage?.gross || 0;
  const sgkEmp = gross * ((version.sgkRates?.employeeRate || 14) / 100);
  const unempEmp = gross * ((version.sgkRates?.employeeUnempRate || 1) / 100);
  const gvBase = gross - sgkEmp - unempEmp;
  const annualGvBase = gvBase * 12;
  const gvAnnual = calculateIncomeTax(annualGvBase, version.incomeTaxBrackets || []);
  const gvMonthly = gvAnnual / 12;
  const dv = gross * ((version.stampDutyRate || 0.759) / 100);
  let netCalc = gross - sgkEmp - unempEmp - gvMonthly - dv;
  if (version.exemptions?.minWageIncomeTaxExemption) netCalc += gvMonthly;
  if (version.exemptions?.minWageStampDutyExemption) netCalc += dv;
  const sgkEr = gross * ((version.sgkRates?.employerRate || 20.75) / 100);
  const unempEr = gross * ((version.sgkRates?.employerUnempRate || 2) / 100);
  const employerCost = gross + sgkEr + unempEr;

  return (
    <Modal title={`👁 ${version.year} ${lang === "en" ? "Parameter Preview" : "Parametre Önizleme"}`}
      icon={Receipt} maxWidth="max-w-3xl" onClose={onClose}>
      <div className="space-y-3">
        <div className="card p-3" style={{ background: "var(--accent-soft)" }}>
          <div style={{ fontSize: 12, color: "var(--accent)" }}>
            <b>📊 {lang === "en" ? "Minimum Wage Payroll Simulation" : "Asgari Ücretli Bordro Simülasyonu"}</b>
            <div style={{ marginTop: 4, color: "var(--ink-soft)", fontWeight: 400, fontSize: 11 }}>
              {lang === "en" ? "Step-by-step calculation based on parameters" : "Parametrelere göre adım adım hesaplama"}
            </div>
          </div>
        </div>

        {/* Bordro tablosu */}
        <div className="card overflow-hidden">
          <table className="w-full" style={{ fontSize: 12 }}>
            <thead>
              <tr style={{ background: "var(--bg)", color: "var(--ink-mute)", fontWeight: 600 }}>
                <th className="text-left p-2">{lang === "en" ? "Description" : "Açıklama"}</th>
                <th className="text-right p-2">{lang === "en" ? "Calculation" : "Hesap"}</th>
                <th className="text-right p-2">{lang === "en" ? "Amount" : "Tutar"}</th>
              </tr>
            </thead>
            <tbody>
              <tr style={{ borderTop: "1px solid var(--line-soft)" }}>
                <td className="p-2">
                  <span className="chip" style={{ background: "#dcfce7", color: "#15803d", fontSize: 9.5, padding: "1px 5px", fontWeight: 700 }}>+</span>{" "}
                  {lang === "en" ? "Gross Salary" : "Brüt Ücret"}
                </td>
                <td className="text-right p-2 text-xs" style={{ color: "var(--ink-mute)" }}>
                  {lang === "en" ? "Minimum wage" : "Asgari ücret"}
                </td>
                <td className="text-right p-2 mono font-bold">{fmtTL(gross)} ₺</td>
              </tr>
              <tr style={{ borderTop: "1px solid var(--line-soft)" }}>
                <td className="p-2">
                  <span className="chip" style={{ background: "#fee2e2", color: "#b91c1c", fontSize: 9.5, padding: "1px 5px", fontWeight: 700 }}>-</span>{" "}
                  {lang === "en" ? "SGK Employee" : "SGK İşçi"}
                </td>
                <td className="text-right p-2 text-xs mono" style={{ color: "var(--ink-mute)" }}>
                  ×{version.sgkRates?.employeeRate}%
                </td>
                <td className="text-right p-2 mono" style={{ color: "var(--negative)" }}>-{fmtTL(sgkEmp)}</td>
              </tr>
              <tr style={{ borderTop: "1px solid var(--line-soft)" }}>
                <td className="p-2">
                  <span className="chip" style={{ background: "#fee2e2", color: "#b91c1c", fontSize: 9.5, padding: "1px 5px", fontWeight: 700 }}>-</span>{" "}
                  {lang === "en" ? "Unemployment Employee" : "İşsizlik İşçi"}
                </td>
                <td className="text-right p-2 text-xs mono" style={{ color: "var(--ink-mute)" }}>
                  ×{version.sgkRates?.employeeUnempRate}%
                </td>
                <td className="text-right p-2 mono" style={{ color: "var(--negative)" }}>-{fmtTL(unempEmp)}</td>
              </tr>
              <tr style={{ borderTop: "1px solid var(--line-soft)" }}>
                <td className="p-2">
                  <span className="chip" style={{ background: version.exemptions?.minWageIncomeTaxExemption ? "var(--bg-alt)" : "#fee2e2", color: version.exemptions?.minWageIncomeTaxExemption ? "var(--ink-mute)" : "#b91c1c", fontSize: 9.5, padding: "1px 5px", fontWeight: 700 }}>
                    {version.exemptions?.minWageIncomeTaxExemption ? "✓" : "-"}
                  </span>{" "}
                  {lang === "en" ? "Income Tax" : "Gelir Vergisi"}
                  {version.exemptions?.minWageIncomeTaxExemption && (
                    <span style={{ fontSize: 10, color: "var(--positive)", fontWeight: 600 }}> ({lang === "en" ? "EXEMPT" : "İSTİSNA"})</span>
                  )}
                </td>
                <td className="text-right p-2 text-xs mono" style={{ color: "var(--ink-mute)" }}>
                  {lang === "en" ? "annual cumulative" : "yıllık kümülatif"}
                </td>
                <td className="text-right p-2 mono" style={{ color: version.exemptions?.minWageIncomeTaxExemption ? "var(--ink-mute)" : "var(--negative)", textDecoration: version.exemptions?.minWageIncomeTaxExemption ? "line-through" : "none" }}>
                  -{fmtTL(gvMonthly)}
                </td>
              </tr>
              <tr style={{ borderTop: "1px solid var(--line-soft)" }}>
                <td className="p-2">
                  <span className="chip" style={{ background: version.exemptions?.minWageStampDutyExemption ? "var(--bg-alt)" : "#fee2e2", color: version.exemptions?.minWageStampDutyExemption ? "var(--ink-mute)" : "#b91c1c", fontSize: 9.5, padding: "1px 5px", fontWeight: 700 }}>
                    {version.exemptions?.minWageStampDutyExemption ? "✓" : "-"}
                  </span>{" "}
                  {lang === "en" ? "Stamp Duty" : "Damga Vergisi"}
                  {version.exemptions?.minWageStampDutyExemption && (
                    <span style={{ fontSize: 10, color: "var(--positive)", fontWeight: 600 }}> ({lang === "en" ? "EXEMPT" : "İSTİSNA"})</span>
                  )}
                </td>
                <td className="text-right p-2 text-xs mono" style={{ color: "var(--ink-mute)" }}>×‰{version.stampDutyRate * 10}</td>
                <td className="text-right p-2 mono" style={{ color: version.exemptions?.minWageStampDutyExemption ? "var(--ink-mute)" : "var(--negative)", textDecoration: version.exemptions?.minWageStampDutyExemption ? "line-through" : "none" }}>
                  -{fmtTL(dv)}
                </td>
              </tr>
              <tr style={{ borderTop: "2px solid var(--accent)", background: "var(--accent-soft)" }}>
                <td className="p-2 font-bold" style={{ color: "var(--accent)" }}>
                  💰 {lang === "en" ? "NET (Calculated)" : "NET (Hesaplanan)"}
                </td>
                <td className="text-right p-2 text-xs" style={{ color: "var(--ink-mute)" }}>
                  {lang === "en" ? "Saved net" : "Kayıtlı net"}: {fmtTL(version.minimumWage?.net || 0)}
                </td>
                <td className="text-right p-2 mono font-bold" style={{ color: "var(--accent)", fontSize: 14 }}>
                  {fmtTL(netCalc)} ₺
                </td>
              </tr>
            </tbody>
          </table>
        </div>

        {/* İşveren maliyeti */}
        <div className="card p-3" style={{ background: "#fef9c3" }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: "#854d0e", marginBottom: 6 }}>
            🏢 {lang === "en" ? "Employer Side" : "İşveren Tarafı"}
          </div>
          <div className="grid grid-cols-3 gap-3 text-xs">
            <div>
              <div style={{ color: "#854d0e" }}>{lang === "en" ? "SGK Employer" : "SGK İşveren"} ×{version.sgkRates?.employerRate}%</div>
              <div className="mono font-bold">{fmtTL(sgkEr)}</div>
            </div>
            <div>
              <div style={{ color: "#854d0e" }}>{lang === "en" ? "Unemployment" : "İşsizlik"} ×{version.sgkRates?.employerUnempRate}%</div>
              <div className="mono font-bold">{fmtTL(unempEr)}</div>
            </div>
            <div>
              <div style={{ color: "#854d0e", fontWeight: 700 }}>{lang === "en" ? "TOTAL COST" : "TOPLAM MALİYET"}</div>
              <div className="mono font-bold" style={{ color: "var(--accent)", fontSize: 14 }}>{fmtTL(employerCost)} ₺</div>
            </div>
          </div>
        </div>

        <div className="card p-2 text-xs" style={{ background: "var(--bg)", color: "var(--ink-mute)" }}>
          ℹ️ {lang === "en"
            ? "This simulation uses minimum wage as input. The actual Payroll Engine will perform the same calculation per employee, also applying meal/transport exemptions, R&D incentives, BES, etc."
            : "Bu simülasyon asgari ücreti girdi alır. Bordro Motoru her çalışan için aynı hesabı yaparak yemek/yol istisnaları, Ar-Ge teşvikleri, BES vb. de uygular."}
        </div>
      </div>
    </Modal>
  );
}

/* =====================================================================
   YAN HAK SÖZLEŞMELERİ YÖNETİMİ (BenefitContractsManager)
   ---------------------------------------------------------------------
   • 7 hak tipi (sağlık, BES, yemek kart, yol kart, telefon, spor, diğer)
   • Sözleşme listesi + tip bazlı filtre
   • Yeni/düzenle sözleşme (kapsamlı modal)
   • Çalışan atama (toplu seçim)
   • Bordro bileşenine link (otomatik feed)
===================================================================== */
function BenefitContractsManager({ data, session, onChange, logAudit, notify, canManage, lang }) {
  const [typeFilter, setTypeFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("active");
  const [searchTerm, setSearchTerm] = useState("");
  const [modal, setModal] = useState(null); // { kind: "new" | "edit", contract }

  const contracts = data?.hrBenefitContracts || [];
  const employees = data?.hrEmployees || [];
  const components = (data?.hrPayrollComponents || []).filter(c => c.active);

  const filtered = useMemo(() => {
    let list = contracts.slice();
    if (typeFilter !== "all") list = list.filter(c => c.type === typeFilter);
    if (statusFilter === "active") list = list.filter(c => c.active);
    else if (statusFilter === "inactive") list = list.filter(c => !c.active);
    if (searchTerm) {
      const q = searchTerm.toLowerCase();
      list = list.filter(c => `${c.name} ${c.providerName} ${c.contractNo}`.toLowerCase().includes(q));
    }
    return list.sort((a, b) => (a.type || "").localeCompare(b.type || "") || (a.name || "").localeCompare(b.name || ""));
  }, [contracts, typeFilter, statusFilter, searchTerm]);

  // KPI hesabı
  const stats = useMemo(() => {
    const activeContracts = contracts.filter(c => c.active);
    const totalMonthly = activeContracts.reduce((s, c) => s + (Number(c.premiumMonthly) || 0), 0);
    const totalEmployer = activeContracts.reduce((s, c) => s + (Number(c.employerShare) || 0), 0);
    const totalEmployee = activeContracts.reduce((s, c) => s + (Number(c.employeeShare) || 0), 0);
    const totalCoverage = new Set(activeContracts.flatMap(c => c.coveredEmployeeIds || [])).size;
    const byType = {};
    activeContracts.forEach(c => {
      byType[c.type] = (byType[c.type] || 0) + 1;
    });
    return { totalMonthly, totalEmployer, totalEmployee, totalCoverage, byType, totalContracts: activeContracts.length };
  }, [contracts]);

  // Sözleşme kaydet
  const saveContract = async (draft) => {
    if (!draft.name || !draft.type) {
      notify(lang === "en" ? "Name and type required" : "Ad ve tip zorunlu", "err");
      return;
    }
    const isNew = !draft.id;
    const item = isNew ? {
      ...draft,
      id: "bc_" + Date.now() + "_" + Math.random().toString(36).slice(2, 5),
      createdAt: new Date().toISOString(),
      createdBy: session.username,
    } : draft;
    const next = isNew ? [...contracts, item] : contracts.map(c => c.id === item.id ? item : c);
    await onChange({ ...data, hrBenefitContracts: next });
    await logAudit && logAudit("benefit_contract_" + (isNew ? "create" : "update"), { id: item.id, type: item.type, name: item.name });
    notify(lang === "en" ? "Contract saved" : "Sözleşme kaydedildi");
    setModal(null);
  };

  // Aktif/Pasif geçişi
  const toggleActive = async (contract) => {
    const next = contracts.map(c => c.id === contract.id ? { ...c, active: !c.active } : c);
    await onChange({ ...data, hrBenefitContracts: next });
    notify(lang === "en" ? (contract.active ? "Deactivated" : "Activated") : (contract.active ? "Pasifleştirildi" : "Aktifleştirildi"));
  };

  const deleteContract = async (contract) => {
    if (contract.coveredEmployeeIds?.length > 0) {
      if (!confirm(lang === "en"
        ? `This contract covers ${contract.coveredEmployeeIds.length} employees. Delete anyway?`
        : `Bu sözleşmede ${contract.coveredEmployeeIds.length} çalışan var. Yine de silinsin mi?`)) return;
    } else {
      if (!confirm(lang === "en" ? "Delete this contract?" : "Bu sözleşmeyi silmek istediğinize emin misiniz?")) return;
    }
    await onChange({ ...data, hrBenefitContracts: contracts.filter(c => c.id !== contract.id) });
    await logAudit && logAudit("benefit_contract_delete", { id: contract.id });
    notify(lang === "en" ? "Contract deleted" : "Sözleşme silindi");
  };

  return (
    <div className="space-y-3">
      {/* Bilgi şeridi */}
      <div className="card p-3" style={{ background: "var(--accent-soft)", border: "1px solid var(--accent)" }}>
        <div className="flex items-start gap-2">
          <span style={{ fontSize: 20 }}>🎁</span>
          <div style={{ fontSize: 11.5, color: "var(--accent)" }}>
            <b>{lang === "en" ? "Benefit Contracts" : "Yan Hak Sözleşmeleri"}</b>
            <div style={{ marginTop: 4, color: "var(--ink-soft)", fontWeight: 400 }}>
              {lang === "en"
                ? "Manage health insurance, BES, meal cards, transport cards and other benefits. Link contracts to payroll components — amounts will automatically feed into payroll calculations."
                : "Sağlık sigortası, BES, yemek/yol kartları ve diğer yan hakları yönetin. Sözleşmeleri bordro bileşenlerine bağlayın — tutarlar bordroya otomatik aktarılır."}
            </div>
          </div>
        </div>
      </div>

      {/* KPI Kartları */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <div className="card p-3">
          <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
            🎁 {lang === "en" ? "Active Contracts" : "Aktif Sözleşme"}
          </div>
          <div className="mono" style={{ fontSize: 22, fontWeight: 700, color: "var(--accent)" }}>{stats.totalContracts}</div>
        </div>
        <div className="card p-3">
          <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
            👥 {lang === "en" ? "Covered Employees" : "Kapsam Altı"}
          </div>
          <div className="mono" style={{ fontSize: 22, fontWeight: 700, color: "var(--positive)" }}>{stats.totalCoverage}</div>
        </div>
        <div className="card p-3">
          <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
            💰 {lang === "en" ? "Total Premium" : "Toplam Prim"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700 }}>{fmtTL(stats.totalMonthly)} ₺</div>
          <div style={{ fontSize: 9.5, color: "var(--ink-mute)", marginTop: 2 }}>/ay</div>
        </div>
        <div className="card p-3">
          <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
            🏢 {lang === "en" ? "Employer / Employee" : "İşveren / Çalışan"}
          </div>
          <div style={{ fontSize: 11.5 }}>
            <div className="mono" style={{ color: "#ca8a04", fontWeight: 700 }}>{fmtTL(stats.totalEmployer)} ₺ {lang === "en" ? "(empr.)" : "(işv.)"}</div>
            <div className="mono" style={{ color: "var(--negative)", fontWeight: 600 }}>{fmtTL(stats.totalEmployee)} ₺ {lang === "en" ? "(empl.)" : "(çal.)"}</div>
          </div>
        </div>
      </div>

      {/* Toolbar */}
      <div className="card p-3">
        <div className="flex items-center gap-3 flex-wrap">
          {/* Tip filtreleri */}
          <div className="flex items-center gap-1 flex-wrap">
            <button onClick={() => setTypeFilter("all")} className="text-xs px-2 py-1 rounded"
              style={{
                background: typeFilter === "all" ? "var(--accent)" : "var(--bg-alt)",
                color: typeFilter === "all" ? "#fff" : "var(--ink)",
                fontWeight: 600,
              }}>
              {lang === "en" ? "All" : "Tümü"} <span style={{ fontSize: 9, opacity: 0.7 }}>({contracts.filter(c => c.active).length})</span>
            </button>
            {Object.entries(BENEFIT_TYPES).map(([k, bt]) => {
              const count = stats.byType[k] || 0;
              if (count === 0 && typeFilter !== k) return null;
              return (
                <button key={k} onClick={() => setTypeFilter(k)}
                  className="text-xs px-2 py-1 rounded flex items-center gap-1"
                  style={{
                    background: typeFilter === k ? bt.color : (bt.color + "15"),
                    color: typeFilter === k ? "#fff" : bt.color,
                    fontWeight: 600,
                    border: `1px solid ${bt.color}40`,
                  }}>
                  <span>{bt.icon}</span>
                  {bt.labels[lang] || bt.labels.tr}
                  {count > 0 && (
                    <span style={{
                      background: typeFilter === k ? "#ffffff30" : bt.color + "30",
                      color: typeFilter === k ? "#fff" : bt.color,
                      padding: "1px 5px", borderRadius: 3,
                      fontSize: 9.5, fontWeight: 700,
                    }}>{count}</span>
                  )}
                </button>
              );
            })}
          </div>
        </div>
        <div className="flex items-center gap-2 mt-2">
          <select className="input text-xs" value={statusFilter} onChange={e => setStatusFilter(e.target.value)} style={{ width: 120 }}>
            <option value="active">✓ {lang === "en" ? "Active" : "Aktif"}</option>
            <option value="inactive">{lang === "en" ? "Inactive" : "Pasif"}</option>
            <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
          </select>
          <input className="input text-xs" style={{ width: 200 }}
            placeholder={lang === "en" ? "Search..." : "Ara..."}
            value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/>
          {canManage && (
            <button onClick={() => setModal({ kind: "new", contract: {
              type: "health",
              name: "",
              providerName: "",
              contractNo: "",
              startDate: new Date().toISOString().slice(0, 10),
              endDate: "",
              active: true,
              linkedComponentCode: BENEFIT_TYPES.health.defaultComponent,
              premiumType: "per_employee",
              premiumMonthly: 0,
              employerShare: 0,
              employeeShare: 0,
              coveredEmployeeIds: [],
              details: {},
              notes: "",
            }})} className="btn btn-primary text-xs ml-auto">
              <Plus size={11}/> {lang === "en" ? "New Contract" : "Yeni Sözleşme"}
            </button>
          )}
        </div>
      </div>

      {/* Sözleşme Kartları */}
      {filtered.length === 0 ? (
        <EmptyState icon={Award}
          title={lang === "en" ? "No contracts" : "Sözleşme yok"}
          message={lang === "en" ? "Create a new benefit contract" : "Yeni yan hak sözleşmesi oluşturun"}/>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
          {filtered.map(contract => (
            <BenefitContractCard key={contract.id} contract={contract}
              employees={employees}
              components={components}
              canManage={canManage}
              lang={lang}
              onEdit={() => setModal({ kind: "edit", contract })}
              onToggle={() => toggleActive(contract)}
              onDelete={() => deleteContract(contract)}/>
          ))}
        </div>
      )}

      {/* Modal */}
      {modal && (
        <BenefitContractFormModal
          draft={modal.contract}
          setDraft={(c) => setModal({ ...modal, contract: c })}
          employees={employees.filter(e => e.status === "active")}
          components={components}
          lang={lang}
          onClose={() => setModal(null)}
          onSave={() => saveContract(modal.contract)}/>
      )}
    </div>
  );
}

/* ---------- Yan Hak Sözleşme Kartı ---------- */
function BenefitContractCard({ contract, employees, components, canManage, lang, onEdit, onToggle, onDelete }) {
  const bt = BENEFIT_TYPES[contract.type] || BENEFIT_TYPES.other;
  const coveredCount = contract.coveredEmployeeIds?.length || 0;
  const linkedComp = components.find(c => c.code === contract.linkedComponentCode);
  const today = new Date().toISOString().slice(0, 10);
  const isExpired = contract.endDate && contract.endDate < today;
  const isFuture = contract.startDate && contract.startDate > today;

  return (
    <div className="card p-3" style={{
      borderLeft: `4px solid ${bt.color}`,
      opacity: contract.active ? 1 : 0.6,
      background: contract.active ? "var(--paper)" : "var(--bg)",
    }}>
      {/* Header */}
      <div className="flex items-start justify-between mb-2">
        <div className="flex items-center gap-2">
          <span style={{ fontSize: 22 }}>{bt.icon}</span>
          <div>
            <div style={{ fontSize: 12.5, fontWeight: 700 }}>{contract.name}</div>
            <div style={{ fontSize: 9.5, color: bt.color, fontWeight: 600 }}>
              {bt.labels[lang] || bt.labels.tr}
            </div>
          </div>
        </div>
        <div className="flex items-center gap-1">
          {!contract.active && (
            <span className="chip" style={{ background: "var(--bg-alt)", color: "var(--ink-mute)", fontSize: 9, padding: "1px 5px", fontWeight: 600 }}>
              {lang === "en" ? "INACTIVE" : "PASİF"}
            </span>
          )}
          {isExpired && (
            <span className="chip" style={{ background: "#fee2e2", color: "#b91c1c", fontSize: 9, padding: "1px 5px", fontWeight: 600 }}>
              {lang === "en" ? "EXPIRED" : "SÜRESİ DOLMUŞ"}
            </span>
          )}
          {isFuture && (
            <span className="chip" style={{ background: "#fef3c7", color: "#854d0e", fontSize: 9, padding: "1px 5px", fontWeight: 600 }}>
              {lang === "en" ? "FUTURE" : "GELECEKTE"}
            </span>
          )}
        </div>
      </div>

      {/* Sağlayıcı */}
      {contract.providerName && (
        <div style={{ fontSize: 11, color: "var(--ink-mute)", marginBottom: 6 }}>
          🏢 {contract.providerName}
          {contract.contractNo && <span className="mono" style={{ marginLeft: 6, fontSize: 10 }}>#{contract.contractNo}</span>}
        </div>
      )}

      {/* Tarihler */}
      <div style={{ fontSize: 10.5, color: "var(--ink-mute)", marginBottom: 8 }}>
        📅 {contract.startDate || "—"} → {contract.endDate || (lang === "en" ? "Open" : "Süresiz")}
      </div>

      {/* Prim bilgisi */}
      <div className="card p-2 mb-2" style={{ background: bt.color + "10" }}>
        <div className="grid grid-cols-3 gap-1 text-xs">
          <div>
            <div style={{ fontSize: 9, color: "var(--ink-mute)" }}>{lang === "en" ? "Total" : "Toplam"}</div>
            <div className="mono font-bold" style={{ color: bt.color }}>{fmtTL(contract.premiumMonthly || 0)} ₺</div>
          </div>
          <div>
            <div style={{ fontSize: 9, color: "var(--ink-mute)" }}>{lang === "en" ? "Employer" : "İşveren"}</div>
            <div className="mono font-bold" style={{ color: "#ca8a04" }}>{fmtTL(contract.employerShare || 0)} ₺</div>
          </div>
          <div>
            <div style={{ fontSize: 9, color: "var(--ink-mute)" }}>{lang === "en" ? "Employee" : "Çalışan"}</div>
            <div className="mono font-bold" style={{ color: "var(--negative)" }}>{fmtTL(contract.employeeShare || 0)} ₺</div>
          </div>
        </div>
        <div style={{ fontSize: 9, color: "var(--ink-mute)", marginTop: 4, textAlign: "center" }}>
          {BENEFIT_PREMIUM_TYPES[contract.premiumType]?.labels[lang] || contract.premiumType} • /ay
        </div>
      </div>

      {/* Kapsam ve bileşen */}
      <div className="flex items-center gap-1 flex-wrap mb-2">
        <span className="chip" style={{ background: "var(--accent-soft)", color: "var(--accent)", padding: "1px 6px", fontSize: 10, fontWeight: 700 }}>
          👥 {coveredCount} {lang === "en" ? "covered" : "kapsam"}
        </span>
        {linkedComp && (
          <span className="chip" style={{
            background: "#dbeafe", color: "#1d4ed8",
            padding: "1px 6px", fontSize: 9.5, fontWeight: 600,
          }} title={lang === "en" ? "Auto-feeds to this payroll component" : "Bu bordro bileşenine otomatik beslenir"}>
            🔗 {linkedComp.code}
          </span>
        )}
        {contract.details?.dailyAmount > 0 && (
          <span className="chip" style={{
            background: "#fef3c7", color: "#854d0e",
            padding: "1px 6px", fontSize: 9.5, fontWeight: 600,
          }}>
            {fmtTL(contract.details.dailyAmount)} ₺/g
          </span>
        )}
      </div>

      {contract.notes && (
        <div style={{ fontSize: 10, color: "var(--ink-mute)", marginBottom: 8, fontStyle: "italic" }}>
          💬 {contract.notes.slice(0, 80)}{contract.notes.length > 80 && "..."}
        </div>
      )}

      {/* Aksiyonlar */}
      <div className="flex items-center gap-1 flex-wrap" style={{ borderTop: "1px solid var(--line-soft)", paddingTop: 8 }}>
        {canManage && (
          <>
            <button onClick={onEdit} className="text-xs px-2 py-1 rounded"
              style={{ background: "var(--accent-soft)", color: "var(--accent)", fontWeight: 600 }}>
              <Edit3 size={10} style={{ display: "inline-block", marginRight: 2 }}/>
              {lang === "en" ? "Edit" : "Düzenle"}
            </button>
            <button onClick={onToggle} className="text-xs px-2 py-1 rounded"
              style={{
                background: contract.active ? "var(--bg-alt)" : "var(--positive-soft)",
                color: contract.active ? "var(--ink-mute)" : "var(--positive)",
                fontWeight: 600,
              }}>
              {contract.active ? `⏸ ${lang === "en" ? "Disable" : "Pasifleştir"}` : `▶ ${lang === "en" ? "Enable" : "Aktifleştir"}`}
            </button>
            <button onClick={onDelete} className="text-xs px-2 py-1 rounded ml-auto"
              style={{ background: "var(--negative-soft)", color: "var(--negative)" }}>
              <Trash2 size={10}/>
            </button>
          </>
        )}
      </div>
    </div>
  );
}

/* ---------- Yan Hak Sözleşme Form Modal ---------- */
function BenefitContractFormModal({ draft, setDraft, employees, components, lang, onClose, onSave }) {
  const [tab, setTab] = useState("basic"); // basic | financial | coverage | details

  const bt = BENEFIT_TYPES[draft.type] || BENEFIT_TYPES.other;

  // Tip değiştiğinde varsayılan bileşeni güncelle
  const changeType = (newType) => {
    const newBt = BENEFIT_TYPES[newType] || BENEFIT_TYPES.other;
    setDraft({
      ...draft,
      type: newType,
      linkedComponentCode: newBt.defaultComponent || draft.linkedComponentCode,
      details: {}, // reset details
    });
  };

  // Çalışan toggle
  const toggleEmployee = (empId) => {
    const list = draft.coveredEmployeeIds || [];
    if (list.includes(empId)) {
      setDraft({ ...draft, coveredEmployeeIds: list.filter(id => id !== empId) });
    } else {
      setDraft({ ...draft, coveredEmployeeIds: [...list, empId] });
    }
  };

  // Toplu seçim
  const selectAll = () => setDraft({ ...draft, coveredEmployeeIds: employees.map(e => e.id) });
  const selectNone = () => setDraft({ ...draft, coveredEmployeeIds: [] });

  // Per-employee toplamı otomatik hesapla
  const recalcTotal = () => {
    if (draft.premiumType === "per_employee" && draft.coveredEmployeeIds?.length > 0) {
      // Toplam = (işveren+çalışan) × kişi sayısı varsayımı
      const perPerson = (Number(draft.employerShare) || 0) + (Number(draft.employeeShare) || 0);
      setDraft({ ...draft, premiumMonthly: perPerson });
    }
  };

  const tabs = [
    { id: "basic",     icon: Info,     label: { tr: "Temel Bilgi",     en: "Basic Info" } },
    { id: "financial", icon: Wallet,   label: { tr: "Mali Bilgi",       en: "Financial" } },
    { id: "coverage",  icon: Users,    label: { tr: "Kapsam (Çalışan)", en: "Coverage" } },
    { id: "details",   icon: Settings, label: { tr: "Detaylar",          en: "Details" } },
  ];

  return (
    <Modal
      title={draft.id
        ? `✏️ ${lang === "en" ? "Edit Benefit Contract" : "Yan Hak Sözleşmesi Düzenle"}`
        : `🎁 ${lang === "en" ? "New Benefit Contract" : "Yeni Yan Hak Sözleşmesi"}`}
      icon={Award} maxWidth="max-w-4xl"
      onClose={onClose} onSave={onSave}>
      <div className="space-y-3">
        {/* Sekme barı */}
        <div className="flex items-center gap-1 overflow-x-auto pb-1" style={{ borderBottom: "1px solid var(--line)" }}>
          {tabs.map(t => {
            const active = tab === t.id;
            return (
              <button key={t.id} type="button" onClick={() => setTab(t.id)}
                className="flex items-center gap-1.5 transition-all flex-shrink-0"
                style={{
                  padding: "6px 10px", fontSize: 11.5,
                  fontWeight: active ? 600 : 500,
                  color: active ? "var(--accent)" : "var(--ink-mute)",
                  borderBottom: active ? "2px solid var(--accent)" : "2px solid transparent",
                  marginBottom: -1, whiteSpace: "nowrap",
                }}>
                <t.icon size={11} strokeWidth={active ? 2 : 1.5}/>
                {t.label[lang] || t.label.tr}
              </button>
            );
          })}
        </div>

        {/* TEMEL BİLGİ */}
        {tab === "basic" && (
          <div className="space-y-3">
            <div>
              <div className="label mb-1">{lang === "en" ? "Benefit Type" : "Yan Hak Tipi"} *</div>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-1">
                {Object.entries(BENEFIT_TYPES).map(([k, b]) => (
                  <button key={k} type="button" onClick={() => changeType(k)}
                    className="text-xs p-2 rounded text-left"
                    style={{
                      background: draft.type === k ? b.color : "var(--bg)",
                      color: draft.type === k ? "#fff" : b.color,
                      border: `1px solid ${b.color}40`,
                      fontWeight: 600,
                    }}>
                    {b.icon} {b.labels[lang] || b.labels.tr}
                  </button>
                ))}
              </div>
              <div className="text-xs mt-2" style={{ color: "var(--ink-mute)" }}>
                {bt.descriptions?.[lang] || bt.descriptions?.tr || ""}
              </div>
            </div>

            <div>
              <div className="label mb-1">{lang === "en" ? "Contract Name" : "Sözleşme Adı"} *</div>
              <input className="input w-full" autoFocus
                placeholder={draft.type === "health" ? "Örn: Anadolu Sigorta Mavi Plan" :
                  draft.type === "bes" ? "Örn: AvivaSA BES Sözleşmesi" :
                  draft.type === "meal_card" ? "Örn: Multinet Yemek Kartı" : ""}
                value={draft.name || ""}
                onChange={e => setDraft({ ...draft, name: e.target.value })}/>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <div className="label mb-1">{lang === "en" ? "Provider Company" : "Sağlayıcı Şirket"}</div>
                <input className="input w-full"
                  placeholder={lang === "en" ? "e.g. Anadolu Sigorta" : "Örn: Anadolu Sigorta"}
                  value={draft.providerName || ""}
                  onChange={e => setDraft({ ...draft, providerName: e.target.value })}/>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Contract Number" : "Sözleşme No"}</div>
                <input className="input w-full mono"
                  value={draft.contractNo || ""}
                  onChange={e => setDraft({ ...draft, contractNo: e.target.value })}/>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
              <div>
                <div className="label mb-1">{lang === "en" ? "Start Date" : "Başlangıç Tarihi"}</div>
                <input type="date" className="input w-full"
                  value={draft.startDate || ""}
                  onChange={e => setDraft({ ...draft, startDate: e.target.value })}/>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "End Date (optional)" : "Bitiş Tarihi (opsiyonel)"}</div>
                <input type="date" className="input w-full"
                  value={draft.endDate || ""}
                  onChange={e => setDraft({ ...draft, endDate: e.target.value })}/>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Status" : "Durum"}</div>
                <select className="input w-full" value={draft.active ? "active" : "inactive"}
                  onChange={e => setDraft({ ...draft, active: e.target.value === "active" })}>
                  <option value="active">✓ {lang === "en" ? "Active" : "Aktif"}</option>
                  <option value="inactive">{lang === "en" ? "Inactive" : "Pasif"}</option>
                </select>
              </div>
            </div>

            <div>
              <div className="label mb-1">{lang === "en" ? "Notes" : "Notlar"}</div>
              <textarea className="input w-full" rows="2" style={{ fontSize: 11.5 }}
                value={draft.notes || ""}
                onChange={e => setDraft({ ...draft, notes: e.target.value })}/>
            </div>
          </div>
        )}

        {/* MALİ BİLGİ */}
        {tab === "financial" && (
          <div className="space-y-3">
            <div className="card p-3" style={{ background: "var(--accent-soft)" }}>
              <div style={{ fontSize: 11, color: "var(--accent)" }}>
                <b>💰 {lang === "en" ? "Premium Type" : "Prim Tipi"}</b>
                <div style={{ marginTop: 4, color: "var(--ink-soft)", fontSize: 10.5, fontWeight: 400 }}>
                  {draft.premiumType === "per_employee"
                    ? (lang === "en" ? "Amount is per employee. Total = per-person × covered employee count." : "Tutar kişi başınadır. Toplam = kişi başı × kapsama dahil çalışan sayısı.")
                    : (lang === "en" ? "Total amount is shared across all covered employees." : "Toplam tutar tüm kapsama dahil çalışanlar arasında paylaşılır.")}
                </div>
              </div>
            </div>

            <div>
              <div className="label mb-1">{lang === "en" ? "Premium Type" : "Prim Tipi"}</div>
              <div className="grid grid-cols-2 md:grid-cols-3 gap-1">
                {Object.entries(BENEFIT_PREMIUM_TYPES).map(([k, pt]) => (
                  <button key={k} type="button"
                    onClick={() => setDraft({ ...draft, premiumType: k })}
                    className="text-xs p-2 rounded"
                    style={{
                      background: draft.premiumType === k ? "var(--accent)" : "var(--bg)",
                      color: draft.premiumType === k ? "#fff" : "var(--ink)",
                      border: "1px solid var(--line)",
                      fontWeight: 600,
                    }}>
                    {pt.labels[lang] || pt.labels.tr}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
              <div>
                <div className="label mb-1">{lang === "en" ? "Monthly Total (TL)" : "Aylık Toplam (TL)"}</div>
                <MoneyInput className="input w-full mono text-right"
                  value={draft.premiumMonthly || ""}
                  onChange={v => setDraft({ ...draft, premiumMonthly: v === '' ? 0 : v })}/>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Employer Share (TL)" : "İşveren Payı (TL)"}</div>
                <MoneyInput className="input w-full mono text-right"
                  value={draft.employerShare || ""}
                  onChange={v => setDraft({ ...draft, employerShare: v === '' ? 0 : v })}/>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Employee Share (TL)" : "Çalışan Payı (TL)"}</div>
                <MoneyInput className="input w-full mono text-right"
                  value={draft.employeeShare || ""}
                  onChange={v => setDraft({ ...draft, employeeShare: v === '' ? 0 : v })}/>
              </div>
            </div>

            {/* Otomatik toplam butonu */}
            <button type="button" onClick={recalcTotal} className="text-xs px-2 py-1 rounded"
              style={{ background: "var(--bg-alt)", color: "var(--ink)", fontWeight: 600 }}>
              ⚡ {lang === "en" ? "Auto-calc total = employer + employee" : "Otomatik toplam = işveren + çalışan"}
            </button>

            {/* Bordro bileşeni linki */}
            <div className="card p-3" style={{ background: "#dbeafe", border: "1px solid #1d4ed8" }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: "#1d4ed8", marginBottom: 8 }}>
                🔗 {lang === "en" ? "Linked Payroll Component" : "Bağlı Bordro Bileşeni"}
              </div>
              <div className="text-xs mb-2" style={{ color: "var(--ink-mute)" }}>
                {lang === "en"
                  ? "When payroll is calculated, the amount from this contract will automatically be used as the value for the selected component."
                  : "Bordro hesaplanırken, bu sözleşmedeki tutar seçili bileşenin değeri olarak otomatik kullanılır."}
              </div>
              <select className="input w-full" value={draft.linkedComponentCode || ""}
                onChange={e => setDraft({ ...draft, linkedComponentCode: e.target.value })}>
                <option value="">— {lang === "en" ? "No link (info only)" : "Bağlama yok (sadece bilgi)"} —</option>
                {components.filter(c => c.category === "special_income" || c.category === "special_deduction").map(c => (
                  <option key={c.code} value={c.code}>
                    {c.category === "special_income" ? "+ " : "- "}{c.code} — {c.name?.tr || c.code}
                  </option>
                ))}
              </select>
              {draft.linkedComponentCode && (
                <div className="text-xs mt-2" style={{ color: "#1d4ed8" }}>
                  ✓ {lang === "en" ? "Will auto-feed component" : "Bileşene otomatik beslenecek"}: <b>{draft.linkedComponentCode}</b>
                </div>
              )}
            </div>
          </div>
        )}

        {/* KAPSAM */}
        {tab === "coverage" && (
          <div className="space-y-3">
            <div className="flex items-center justify-between flex-wrap gap-2">
              <div style={{ fontSize: 12, fontWeight: 700 }}>
                👥 {lang === "en" ? "Covered Employees" : "Kapsama Alınan Çalışanlar"}
                <span className="chip ml-2" style={{ background: "var(--accent-soft)", color: "var(--accent)", padding: "1px 6px", fontWeight: 700 }}>
                  {draft.coveredEmployeeIds?.length || 0} / {employees.length}
                </span>
              </div>
              <div className="flex items-center gap-1">
                <button type="button" onClick={selectAll} className="text-xs px-2 py-1 rounded"
                  style={{ background: "var(--positive-soft)", color: "var(--positive)", fontWeight: 600 }}>
                  ✓ {lang === "en" ? "Select All" : "Tümünü Seç"}
                </button>
                <button type="button" onClick={selectNone} className="text-xs px-2 py-1 rounded"
                  style={{ background: "var(--bg-alt)", color: "var(--ink-mute)", fontWeight: 600 }}>
                  ☐ {lang === "en" ? "Clear" : "Temizle"}
                </button>
              </div>
            </div>

            <div className="card overflow-y-auto" style={{ maxHeight: 350 }}>
              {employees.length === 0 ? (
                <div className="p-4 text-center text-xs" style={{ color: "var(--ink-mute)" }}>
                  {lang === "en" ? "No active employees" : "Aktif çalışan yok"}
                </div>
              ) : (
                <table className="w-full" style={{ fontSize: 11.5 }}>
                  <tbody>
                    {employees.map(emp => {
                      const selected = (draft.coveredEmployeeIds || []).includes(emp.id);
                      return (
                        <tr key={emp.id}
                          onClick={() => toggleEmployee(emp.id)}
                          style={{
                            cursor: "pointer",
                            background: selected ? "var(--accent-soft)" : "transparent",
                            borderTop: "1px solid var(--line-soft)",
                          }}>
                          <td className="p-2" style={{ width: 30 }}>
                            <input type="checkbox" checked={selected} readOnly/>
                          </td>
                          <td className="p-2">
                            <div style={{ fontWeight: 600 }}>{emp.firstName} {emp.lastName}</div>
                            <div style={{ fontSize: 10, color: "var(--ink-mute)" }}>{emp.email}</div>
                          </td>
                          <td className="text-right p-2 mono" style={{ fontSize: 10 }}>
                            {fmtTL(emp.brutSalary || 0)} ₺
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              )}
            </div>

            {/* Otomatik toplam ipucu */}
            {draft.premiumType === "per_employee" && draft.coveredEmployeeIds?.length > 0 && (
              <div className="card p-2 text-xs" style={{ background: "#fef3c7", color: "#854d0e" }}>
                💡 <b>{lang === "en" ? "Per-person calculation" : "Kişi başı hesap"}:</b> {fmtTL(draft.premiumMonthly || 0)} × {draft.coveredEmployeeIds.length} = <b className="mono">{fmtTL((draft.premiumMonthly || 0) * draft.coveredEmployeeIds.length)} ₺</b> {lang === "en" ? "monthly total" : "aylık toplam"}
              </div>
            )}
          </div>
        )}

        {/* DETAYLAR (Tipe özel alanlar) */}
        {tab === "details" && (
          <div className="space-y-3">
            <div className="card p-3" style={{ background: bt.color + "10", border: `1px solid ${bt.color}40` }}>
              <div className="flex items-center gap-2 mb-2">
                <span style={{ fontSize: 22 }}>{bt.icon}</span>
                <div>
                  <div style={{ fontSize: 13, fontWeight: 700 }}>
                    {bt.labels[lang] || bt.labels.tr}
                  </div>
                  <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
                    {lang === "en" ? "Type-specific fields" : "Tipe özel alanlar"}
                  </div>
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              {(bt.fields || []).map(f => (
                <div key={f.key}>
                  <div className="label mb-1">{f.label[lang] || f.label.tr}</div>
                  {f.type === "boolean" ? (
                    <label className="flex items-center gap-2 cursor-pointer" style={{ paddingTop: 4 }}>
                      <input type="checkbox" checked={!!draft.details?.[f.key]}
                        onChange={e => setDraft({ ...draft, details: { ...(draft.details || {}), [f.key]: e.target.checked } })}/>
                      <span style={{ fontSize: 12 }}>{lang === "en" ? "Yes" : "Evet"}</span>
                    </label>
                  ) : f.type === "number" ? (
                    <input type="number" step="0.01" className="input w-full mono"
                      value={draft.details?.[f.key] || ""}
                      onChange={e => setDraft({ ...draft, details: { ...(draft.details || {}), [f.key]: parseFloat(e.target.value) || 0 } })}/>
                  ) : (
                    <input className="input w-full"
                      value={draft.details?.[f.key] || ""}
                      onChange={e => setDraft({ ...draft, details: { ...(draft.details || {}), [f.key]: e.target.value } })}/>
                  )}
                </div>
              ))}
            </div>

            {/* Tip-spesifik ipuçları */}
            {draft.type === "meal_card" && draft.details?.dailyAmount > 0 && (
              <div className="card p-2 text-xs" style={{ background: "#dcfce7", color: "#15803d" }}>
                💡 {lang === "en"
                  ? `Daily ${fmtTL(draft.details.dailyAmount)} × 22 workdays = ${fmtTL(draft.details.dailyAmount * 22)} ₺ avg monthly`
                  : `Günlük ${fmtTL(draft.details.dailyAmount)} × 22 iş günü = ${fmtTL(draft.details.dailyAmount * 22)} ₺ ortalama aylık`}
              </div>
            )}
            {draft.type === "bes" && draft.details?.companyMatchRate > 0 && (
              <div className="card p-2 text-xs" style={{ background: "#ddd6fe", color: "#7c3aed" }}>
                💡 {lang === "en"
                  ? `Employer matches ${draft.details.companyMatchRate}% of employee BES contributions`
                  : `İşveren çalışan BES katkısının %${draft.details.companyMatchRate}'ini eşleştirir`}
              </div>
            )}
          </div>
        )}
      </div>
    </Modal>
  );
}

/* =====================================================================
   ÇALIŞAN SELF-SERVICE PORTAL
   ---------------------------------------------------------------------
   • Çalışan kendi bilgilerini görüntüler, izin talep eder, bordrolarını okur
   • Sadece kendi datasını görür (RBAC kısıtlı)
   • Yöneticiler "Self-Servis" butonu ile bu görünüme geçebilir
===================================================================== */

/* ---------- Ana Sayfa (Karşılama + Özet) ---------- */

/* ---------- İzinlerim ---------- */

/* ---------- Self-Service İzin Talep Modal ---------- */

/* ---------- Bordrolarım ---------- */

/* ---------- Puantajım (read-only takvim) ---------- */

/* ---------- Profilim ---------- */
/* =====================================================================
   TALEPLER YÖNETİMİ (RequestsManager)
   ---------------------------------------------------------------------
   3 talep tipi (avans/masraf/zimmet) için unified yönetim
   • Tip bazlı sekme + durum filtreleri
   • Yeni talep ekleme (yönetici de oluşturabilir)
   • Onay/Red/Ödeme/Teslim akışı
   • Avans → bordroya otomatik taksit yansıtma
===================================================================== */
function RequestsManager({ data, session, users = [], canAct, lang, onChange, logAudit, notify }) {
  const [kindTab, setKindTab] = useState("advance");
  const [statusFilter, setStatusFilter] = useState("pending");
  const [searchTerm, setSearchTerm] = useState("");
  const [modal, setModal] = useState(null);

  const canManage = canAct("hr.employees.update");
  const employees = (data?.hrEmployees || []).filter(e => e.status === "active");
  const requests = data?.hrRequests || [];

  // Tip + status filtreleme
  const filtered = useMemo(() => {
    let list = requests.filter(r => r.kind === kindTab);
    if (statusFilter !== "all") list = list.filter(r => r.status === statusFilter);
    if (searchTerm) {
      const q = searchTerm.toLowerCase();
      list = list.filter(r => {
        const emp = employees.find(e => e.id === r.employeeId);
        const empName = emp ? `${emp.firstName} ${emp.lastName}`.toLowerCase() : "";
        return empName.includes(q) || (r.reason || "").toLowerCase().includes(q) || (r.vendorName || "").toLowerCase().includes(q);
      });
    }
    return list.sort((a, b) => new Date(b.requestedAt || 0) - new Date(a.requestedAt || 0));
  }, [requests, kindTab, statusFilter, searchTerm, employees]);

  // Sayım (tip içinde)
  const statusCounts = useMemo(() => {
    const k = requests.filter(r => r.kind === kindTab);
    return {
      all: k.length,
      pending:    k.filter(r => r.status === "pending").length,
      approved:   k.filter(r => r.status === "approved").length,
      rejected:   k.filter(r => r.status === "rejected").length,
      cancelled:  k.filter(r => r.status === "cancelled").length,
      paid:       k.filter(r => r.status === "paid").length,
      delivered:  k.filter(r => r.status === "delivered").length,
      returned:   k.filter(r => r.status === "returned").length,
    };
  }, [requests, kindTab]);

  // CRUD
  const saveRequest = async (draft) => {
    const isNew = !draft.id;
    const item = isNew ? {
      ...draft,
      id: "req_" + Date.now() + "_" + Math.random().toString(36).slice(2, 5),
      status: draft.status || "pending",
      requestedAt: new Date().toISOString(),
      requestedBy: session.username,
    } : draft;
    const next = isNew ? [...requests, item] : requests.map(r => r.id === item.id ? item : r);

    // Pending bildirim — yöneticilere
    let nextNotifications = data?.hrNotifications || [];
    if (isNew && item.status === "pending") {
      const emp = employees.find(e => e.id === item.employeeId);
      const mgrUserId = getEmployeeManagerUserId(emp, data);
      const recipients = [];
      if (mgrUserId && mgrUserId !== session.username) recipients.push(mgrUserId);
      const hrMgrs = getHrManagerUserIds(users);
      hrMgrs.forEach(uid => { if (uid !== session.username && !recipients.includes(uid)) recipients.push(uid); });
      const kindInfo = REQUEST_KINDS[item.kind];
      recipients.forEach(uid => {
        nextNotifications = createNotification(nextNotifications, {
          recipientUserId: uid,
          kind: "request_pending",
          title: `⏳ ${lang === "en" ? "New" : "Yeni"} ${kindInfo.labels[lang] || kindInfo.labels.tr}`,
          body: `${emp?.firstName} ${emp?.lastName}${item.amount > 0 ? ` · ${fmtTL(item.amount)} ₺` : ""}${item.reason ? ` · ${item.reason.slice(0, 60)}` : ""}`,
          link: { type: "request", id: item.id },
          createdBy: session.username,
          meta: { kind: item.kind, amount: item.amount },
        });
      });
    }

    // === ONAY AKIŞI: Avans/Masraf tutarı eşik üzerindeyse otomatik approval request ===
    let updatedData = { ...data, hrRequests: next, hrNotifications: nextNotifications };
    let approvalCreated = false;
    let approvalRuleName = null;
    if (isNew && item.status === "pending" && Number(item.amount) > 0
        && (item.kind === "advance" || item.kind === "expense")) {
      const emp = employees.find(e => e.id === item.employeeId);
      const empName = emp ? `${emp.firstName} ${emp.lastName}` : "";
      const approvalResult = maybeCreateApprovalRequest({
        entityType: item.kind,  // "advance" veya "expense"
        entity: item,
        amount: Number(item.amount),
        currency: item.currency || "TRY",
        summary: `${empName} - ${item.reason || (item.kind === "advance" ? "Avans" : "Masraf")}`,
      }, data, session, users);

      if (approvalResult.requiresApproval) {
        item.approvalStatus = "pending";
        item.approvalRequestId = approvalResult.request.id;
        const idx = next.findIndex(x => x.id === item.id);
        if (idx >= 0) next[idx] = item;
        updatedData = {
          ...data,
          hrRequests: next,
          hrNotifications: nextNotifications,
          approvalRequests: approvalResult.newRequests,
          notifications: approvalResult.newNotifications,  // approval bildirimleri ayrı array
        };
        approvalCreated = true;
        approvalRuleName = approvalResult.rule.name;
      }
    }

    await onChange(updatedData);
    await logAudit && logAudit(`request_${item.kind}_${isNew ? "create" : "update"}`, { id: item.id, employeeId: item.employeeId });
    if (approvalCreated) {
      notify(lang === "en"
        ? `Request saved → Approval required ("${approvalRuleName}")`
        : `Talep kaydedildi → Onay gerekiyor ("${approvalRuleName}")`);
    } else {
      notify(lang === "en" ? "Request saved" : "Talep kaydedildi");
    }
    setModal(null);
  };

  // Onayla — avans için: payrollComponentCode otomatik atanır
  const approveRequest = async (request, note) => {
    const updated = {
      ...request,
      status: "approved",
      approvedAt: new Date().toISOString(),
      approvedBy: session.username,
      approverNote: note || "",
    };
    if (request.kind === "advance" && !updated.payrollComponentCode) {
      updated.payrollComponentCode = "AVANS";
    }
    const next = requests.map(r => r.id === request.id ? updated : r);

    // Çalışana bildirim
    let nextNotifications = data?.hrNotifications || [];
    const emp = employees.find(e => e.id === request.employeeId);
    if (emp?.userId && emp.userId !== session.username) {
      const kindInfo = REQUEST_KINDS[request.kind];
      nextNotifications = createNotification(nextNotifications, {
        recipientUserId: emp.userId,
        kind: "request_approved",
        title: `✓ ${lang === "en" ? "Your" : ""} ${kindInfo.labels[lang] || kindInfo.labels.tr} ${lang === "en" ? "approved" : "onaylandı"}`,
        body: `${request.amount > 0 ? fmtTL(request.amount) + " ₺ · " : ""}${note ? `"${note.slice(0, 80)}"` : ""}`,
        link: { type: "request", id: request.id },
        createdBy: session.username,
        meta: { kind: request.kind, amount: request.amount, status: "approved" },
      });
    }

    await onChange({ ...data, hrRequests: next, hrNotifications: nextNotifications });
    await logAudit && logAudit(`request_${request.kind}_approve`, { id: request.id });
    notify(lang === "en" ? "Approved" : "Onaylandı");
    setModal(null);
  };

  const rejectRequest = async (request, reason) => {
    if (!reason) {
      notify(lang === "en" ? "Rejection reason required" : "Red sebebi zorunlu", "err");
      return;
    }
    const updated = {
      ...request,
      status: "rejected",
      rejectedAt: new Date().toISOString(),
      rejectedBy: session.username,
      rejectionReason: reason,
    };
    const next = requests.map(r => r.id === request.id ? updated : r);

    // Çalışana bildirim
    let nextNotifications = data?.hrNotifications || [];
    const emp = employees.find(e => e.id === request.employeeId);
    if (emp?.userId && emp.userId !== session.username) {
      const kindInfo = REQUEST_KINDS[request.kind];
      nextNotifications = createNotification(nextNotifications, {
        recipientUserId: emp.userId,
        kind: "request_rejected",
        title: `✗ ${lang === "en" ? "Your" : ""} ${kindInfo.labels[lang] || kindInfo.labels.tr} ${lang === "en" ? "rejected" : "reddedildi"}`,
        body: reason.slice(0, 120),
        link: { type: "request", id: request.id },
        createdBy: session.username,
        meta: { kind: request.kind, status: "rejected" },
      });
    }

    await onChange({ ...data, hrRequests: next, hrNotifications: nextNotifications });
    await logAudit && logAudit(`request_${request.kind}_reject`, { id: request.id });
    notify(lang === "en" ? "Rejected" : "Reddedildi");
    setModal(null);
  };

  const markPaid = async (request, paymentRef) => {
    const updated = {
      ...request,
      status: "paid",
      paidAt: new Date().toISOString(),
      paidBy: session.username,
      paymentRef: paymentRef || "",
    };
    const next = requests.map(r => r.id === request.id ? updated : r);

    // Çalışana bildirim
    let nextNotifications = data?.hrNotifications || [];
    const emp = employees.find(e => e.id === request.employeeId);
    if (emp?.userId && emp.userId !== session.username) {
      const kindInfo = REQUEST_KINDS[request.kind];
      nextNotifications = createNotification(nextNotifications, {
        recipientUserId: emp.userId,
        kind: "request_paid",
        title: `💸 ${kindInfo.labels[lang] || kindInfo.labels.tr}: ${lang === "en" ? "Paid" : "Ödendi"}`,
        body: `${fmtTL(request.amount)} ${request.currency || "₺"}${paymentRef ? ` · Ref: ${paymentRef}` : ""}`,
        link: { type: "request", id: request.id },
        createdBy: session.username,
        meta: { kind: request.kind, amount: request.amount, status: "paid" },
      });
    }

    await onChange({ ...data, hrRequests: next, hrNotifications: nextNotifications });
    await logAudit && logAudit(`request_${request.kind}_paid`, { id: request.id, amount: request.amount });
    notify(lang === "en" ? "Marked as paid" : "Ödendi olarak işaretlendi");
  };

  const markDelivered = async (request) => {
    const updated = {
      ...request,
      status: "delivered",
      deliveredAt: new Date().toISOString(),
      deliveredBy: session.username,
    };
    let nextAssets = data?.hrAssets || [];
    if (request.linkedAssetId) {
      nextAssets = nextAssets.map(a =>
        a.id === request.linkedAssetId
          ? { ...a, status: "assigned", assignedEmployeeId: request.employeeId, assignedDate: new Date().toISOString().slice(0,10) }
          : a
      );
    }
    const next = requests.map(r => r.id === request.id ? updated : r);

    // Çalışana bildirim
    let nextNotifications = data?.hrNotifications || [];
    const emp = employees.find(e => e.id === request.employeeId);
    if (emp?.userId && emp.userId !== session.username) {
      const assetTypeInfo = ASSET_TYPES[request.assetType] || ASSET_TYPES.other;
      nextNotifications = createNotification(nextNotifications, {
        recipientUserId: emp.userId,
        kind: "request_delivered",
        title: `📦 ${lang === "en" ? "Asset delivered" : "Zimmet teslim edildi"}`,
        body: `${assetTypeInfo.icon} ${request.assetBrand || ""} ${request.assetModel || ""}`.trim(),
        link: { type: "request", id: request.id },
        createdBy: session.username,
        meta: { kind: "asset", status: "delivered" },
      });
    }

    await onChange({ ...data, hrRequests: next, hrAssets: nextAssets, hrNotifications: nextNotifications });
    await logAudit && logAudit(`request_asset_delivered`, { id: request.id });
    notify(lang === "en" ? "Asset delivered" : "Zimmet teslim edildi");
  };

  const markReturned = async (request) => {
    const updated = {
      ...request,
      status: "returned",
      returnedAt: new Date().toISOString(),
      returnedBy: session.username,
    };
    let nextAssets = data?.hrAssets || [];
    if (request.linkedAssetId) {
      nextAssets = nextAssets.map(a =>
        a.id === request.linkedAssetId
          ? { ...a, status: "in_stock", assignedEmployeeId: null, returnedDate: new Date().toISOString().slice(0,10) }
          : a
      );
    }
    const next = requests.map(r => r.id === request.id ? updated : r);

    // Çalışana bildirim
    let nextNotifications = data?.hrNotifications || [];
    const emp = employees.find(e => e.id === request.employeeId);
    if (emp?.userId && emp.userId !== session.username) {
      nextNotifications = createNotification(nextNotifications, {
        recipientUserId: emp.userId,
        kind: "request_returned",
        title: `↩ ${lang === "en" ? "Asset returned" : "Zimmet iade alındı"}`,
        body: `${request.assetBrand || ""} ${request.assetModel || ""}`.trim(),
        link: { type: "request", id: request.id },
        createdBy: session.username,
        meta: { kind: "asset", status: "returned" },
      });
    }

    await onChange({ ...data, hrRequests: next, hrAssets: nextAssets, hrNotifications: nextNotifications });
    await logAudit && logAudit(`request_asset_returned`, { id: request.id });
    notify(lang === "en" ? "Asset returned" : "Zimmet iade edildi");
  };

  const cancelRequest = async (request) => {
    if (!confirm(lang === "en" ? "Cancel this request?" : "Bu talebi iptal edilsin mi?")) return;
    const updated = {
      ...request,
      status: "cancelled",
      cancelledAt: new Date().toISOString(),
      cancelledBy: session.username,
    };
    const next = requests.map(r => r.id === request.id ? updated : r);
    await onChange({ ...data, hrRequests: next });
    notify(lang === "en" ? "Cancelled" : "İptal edildi");
  };

  const deleteRequest = async (request) => {
    if (request.status === "approved" || request.status === "paid" || request.status === "delivered") {
      notify(lang === "en" ? "Cannot delete (cancel instead)" : "Silinemez (iptal edin)", "err");
      return;
    }
    if (!confirm(lang === "en" ? "Delete this request?" : "Bu talebi silmek istediğinize emin misiniz?")) return;
    await onChange({ ...data, hrRequests: requests.filter(r => r.id !== request.id) });
    notify(lang === "en" ? "Deleted" : "Silindi");
  };

  const statusOptionsForKind = (kind) => {
    const base = ["all", "pending", "approved", "rejected", "cancelled"];
    if (kind === "advance" || kind === "expense") return [...base, "paid"];
    if (kind === "asset") return [...base, "delivered", "returned"];
    return base;
  };

  const kindInfo = REQUEST_KINDS[kindTab];

  return (
    <div className="space-y-3">
      {/* Bilgi şeridi */}
      <div className="card p-3" style={{ background: kindInfo.color + "10", border: `1px solid ${kindInfo.color}40` }}>
        <div className="flex items-start gap-2">
          <span style={{ fontSize: 20 }}>{kindInfo.icon}</span>
          <div style={{ fontSize: 11.5, color: kindInfo.color }}>
            <b>{kindInfo.labels[lang] || kindInfo.labels.tr}</b>
            <div style={{ marginTop: 4, color: "var(--ink-soft)", fontWeight: 400 }}>
              {kindInfo.description[lang] || kindInfo.description.tr}
              {kindTab === "advance" && (
                <span style={{ display: "block", marginTop: 2 }}>
                  💡 {lang === "en"
                    ? "Approved advances will be automatically deducted from payroll over the specified installments."
                    : "Onaylanan avanslar belirtilen taksitle bordrodan otomatik kesilir."}
                </span>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Tip sekmeleri */}
      <div className="card p-3">
        <div className="flex items-center gap-2 flex-wrap">
          {Object.entries(REQUEST_KINDS).map(([k, info]) => {
            const count = requests.filter(r => r.kind === k).length;
            const pending = requests.filter(r => r.kind === k && r.status === "pending").length;
            const active = kindTab === k;
            return (
              <button key={k} onClick={() => { setKindTab(k); setStatusFilter("pending"); }}
                className="px-3 py-2 rounded text-xs flex items-center gap-2"
                style={{
                  background: active ? info.color : info.color + "15",
                  color: active ? "#fff" : info.color,
                  fontWeight: 600,
                  border: `1px solid ${info.color}40`,
                }}>
                <span style={{ fontSize: 14 }}>{info.icon}</span>
                <span>{info.labels[lang] || info.labels.tr}</span>
                {count > 0 && (
                  <span style={{
                    background: active ? "#ffffff30" : info.color + "30",
                    color: active ? "#fff" : info.color,
                    padding: "1px 6px", borderRadius: 3,
                    fontSize: 9.5, fontWeight: 700,
                  }}>{count}</span>
                )}
                {pending > 0 && (
                  <span style={{
                    background: "#dc2626", color: "#fff",
                    padding: "1px 5px", borderRadius: 3,
                    fontSize: 9, fontWeight: 700,
                  }}>{pending}</span>
                )}
              </button>
            );
          })}
        </div>
      </div>

      {/* Status filtreleri + Toolbar */}
      <div className="card p-3">
        <div className="flex items-center gap-2 flex-wrap">
          {statusOptionsForKind(kindTab).map(s => {
            const info = s === "all" ? { color: "var(--ink-mute)", icon: "📋", labels: { tr: "Tümü", en: "All" } } : REQUEST_STATUS[s];
            const count = statusCounts[s] || 0;
            const active = statusFilter === s;
            return (
              <button key={s} onClick={() => setStatusFilter(s)}
                className="text-xs px-2 py-1 rounded flex items-center gap-1"
                style={{
                  background: active ? info.color : info.color + "15",
                  color: active ? "#fff" : info.color,
                  fontWeight: 600,
                  border: `1px solid ${info.color}40`,
                }}>
                <span>{info.icon}</span>
                {info.labels[lang] || info.labels.tr}
                <span style={{
                  background: active ? "#ffffff30" : info.color + "30",
                  color: active ? "#fff" : info.color,
                  padding: "1px 5px", borderRadius: 3, fontSize: 9.5, fontWeight: 700,
                }}>{count}</span>
              </button>
            );
          })}

          <input className="input text-xs ml-auto" style={{ width: 180 }}
            placeholder={lang === "en" ? "Search..." : "Ara..."}
            value={searchTerm} onChange={e => setSearchTerm(e.target.value)}/>

          {canManage && (
            <button onClick={() => {
              const baseDraft = {
                kind: kindTab,
                employeeId: "",
                amount: 0,
                currency: "TRY",
                reason: "",
                notes: "",
                status: "pending",
              };
              if (kindTab === "advance") {
                baseDraft.installments = 1;
                baseDraft.payrollMonth = new Date().toISOString().slice(0, 7);
                baseDraft.payrollComponentCode = "AVANS";
              } else if (kindTab === "expense") {
                baseDraft.expenseCategory = "travel";
                baseDraft.receiptDate = new Date().toISOString().slice(0, 10);
                baseDraft.vendorName = "";
                baseDraft.vatAmount = 0;
              } else if (kindTab === "asset") {
                baseDraft.assetType = "laptop";
                baseDraft.assetBrand = "";
                baseDraft.assetModel = "";
                baseDraft.assetSerial = "";
                baseDraft.assignmentDate = new Date().toISOString().slice(0, 10);
              }
              setModal({ mode: "new", draft: baseDraft });
            }} className="btn btn-primary text-xs">
              <Plus size={11}/> {lang === "en" ? "New" : "Yeni"}
            </button>
          )}
        </div>
      </div>

      {/* Liste */}
      {filtered.length === 0 ? (
        <EmptyState icon={ClipboardList}
          title={lang === "en" ? "No requests" : "Talep yok"}
          message={lang === "en" ? "Create a new request" : "Yeni talep oluşturun"}/>
      ) : (
        <div className="space-y-2">
          {filtered.map(req => (
            <RequestCard key={req.id} request={req}
              employees={employees}
              data={data}
              canManage={canManage}
              lang={lang}
              session={session}
              users={users}
              onChange={onChange}
              onEdit={() => setModal({ mode: "edit", draft: req })}
              onReview={(action) => setModal({ mode: "review", draft: req, action })}
              onPaid={(ref) => markPaid(req, ref)}
              onDelivered={() => markDelivered(req)}
              onReturned={() => markReturned(req)}
              onCancel={() => cancelRequest(req)}
              onDelete={() => deleteRequest(req)}/>
          ))}
        </div>
      )}

      {/* Form Modal */}
      {(modal?.mode === "new" || modal?.mode === "edit") && (
        <RequestFormModal
          draft={modal.draft}
          setDraft={(d) => setModal({ ...modal, draft: d })}
          employees={employees}
          assets={(data?.hrAssets || []).filter(a => a.status === "in_stock")}
          data={data}
          lang={lang}
          onClose={() => setModal(null)}
          onSave={() => saveRequest(modal.draft)}/>
      )}

      {/* Review Modal */}
      {modal?.mode === "review" && (
        <RequestReviewModal
          request={modal.draft}
          action={modal.action}
          employees={employees}
          data={data}
          lang={lang}
          onClose={() => setModal(null)}
          onApprove={(note) => approveRequest(modal.draft, note)}
          onReject={(reason) => rejectRequest(modal.draft, reason)}/>
      )}
    </div>
  );
}

/* ---------- Talep Kartı ---------- */
function RequestCard({ request, employees, data, canManage, lang, session, users, onChange, onEdit, onReview, onPaid, onDelivered, onReturned, onCancel, onDelete }) {
  const emp = employees.find(e => e.id === request.employeeId);
  const kindInfo = REQUEST_KINDS[request.kind] || REQUEST_KINDS.advance;
  const statusInfo = REQUEST_STATUS[request.status] || REQUEST_STATUS.pending;
  const isPending = request.status === "pending";
  const isApproved = request.status === "approved";
  const isPaid = request.status === "paid";
  const isDelivered = request.status === "delivered";
  const advanceInfo = request.kind === "advance" && (isApproved || isPaid) ? getAdvanceRemaining(request, data) : null;

  return (
    <div className="card p-3" style={{ borderLeft: `4px solid ${statusInfo.color}` }}>
      <div className="flex items-start justify-between gap-3 flex-wrap">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <span style={{ fontSize: 16 }}>{kindInfo.icon}</span>
            <span style={{ fontSize: 13, fontWeight: 700 }}>{emp?.firstName} {emp?.lastName}</span>
            <span className="chip" style={{ background: kindInfo.color + "20", color: kindInfo.color, padding: "1px 6px", fontSize: 10, fontWeight: 600 }}>
              {kindInfo.labels[lang] || kindInfo.labels.tr}
            </span>
            <span className="chip" style={{ background: statusInfo.color + "20", color: statusInfo.color, padding: "1px 6px", fontSize: 10, fontWeight: 700, border: `1px solid ${statusInfo.color}40` }}>
              {statusInfo.icon} {(statusInfo.labels[lang] || statusInfo.labels.tr).toUpperCase()}
            </span>
          </div>

          {request.amount > 0 && (
            <div className="flex items-center gap-3 mt-2">
              <div className="mono" style={{ fontSize: 16, fontWeight: 700, color: kindInfo.color }}>
                {fmtTL(request.amount)} {request.currency || "₺"}
              </div>
              {request.kind === "advance" && request.installments > 1 && (
                <div className="chip" style={{ background: "var(--bg-alt)", color: "var(--ink-mute)", padding: "2px 8px", fontSize: 10, fontWeight: 600 }}>
                  📊 {request.installments} {lang === "en" ? "installments" : "taksit"} × <span className="mono">{fmtTL(request.amount / request.installments)}</span>
                </div>
              )}
              {request.kind === "expense" && request.expenseCategory && EXPENSE_CATEGORIES[request.expenseCategory] && (
                <div className="chip" style={{
                  background: EXPENSE_CATEGORIES[request.expenseCategory].color + "20",
                  color: EXPENSE_CATEGORIES[request.expenseCategory].color,
                  padding: "1px 6px", fontSize: 10, fontWeight: 600,
                }}>
                  {EXPENSE_CATEGORIES[request.expenseCategory].icon} {EXPENSE_CATEGORIES[request.expenseCategory].labels[lang] || request.expenseCategory}
                </div>
              )}
            </div>
          )}

          {request.kind === "asset" && (
            <div className="flex items-center gap-2 mt-2 flex-wrap">
              {request.assetType && ASSET_TYPES[request.assetType] && (
                <div className="chip" style={{
                  background: ASSET_TYPES[request.assetType].color + "20",
                  color: ASSET_TYPES[request.assetType].color,
                  padding: "2px 8px", fontSize: 11, fontWeight: 600,
                }}>
                  {ASSET_TYPES[request.assetType].icon} {ASSET_TYPES[request.assetType].labels[lang] || request.assetType}
                </div>
              )}
              {request.assetBrand && (
                <div className="text-xs" style={{ color: "var(--ink-soft)" }}>
                  <b>{request.assetBrand}</b>
                  {request.assetModel && ` ${request.assetModel}`}
                  {request.assetSerial && <span className="mono ml-1" style={{ fontSize: 10, color: "var(--ink-mute)" }}>#{request.assetSerial}</span>}
                </div>
              )}
            </div>
          )}

          {advanceInfo && advanceInfo.deductedMonths > 0 && (
            <div className="card p-2 mt-2 text-xs" style={{ background: "#fef3c7", color: "#854d0e" }}>
              📊 <b>{lang === "en" ? "Installment status" : "Taksit durumu"}:</b>{" "}
              {advanceInfo.deductedMonths}/{advanceInfo.installments} {lang === "en" ? "deducted" : "kesildi"}{" — "}
              {lang === "en" ? "Remaining" : "Kalan"}: <span className="mono">{fmtTL(advanceInfo.remaining)} ₺</span>
            </div>
          )}

          {(request.payrollMonth || request.receiptDate || request.assignmentDate) && (
            <div className="text-xs mt-2" style={{ color: "var(--ink-mute)" }}>
              {request.kind === "advance" && request.payrollMonth && (
                <span>📅 {lang === "en" ? "Starts" : "Başlangıç"}: <b>{request.payrollMonth}</b></span>
              )}
              {request.kind === "expense" && request.receiptDate && (
                <span>🧾 {lang === "en" ? "Receipt" : "Belge"}: <b>{request.receiptDate}</b>
                  {request.vendorName && <span> · {request.vendorName}</span>}
                </span>
              )}
              {request.kind === "asset" && request.assignmentDate && (
                <span>📅 {request.assignmentDate}</span>
              )}
            </div>
          )}

          {request.reason && (
            <div className="mt-2" style={{ fontSize: 11.5, color: "var(--ink-soft)" }}>
              💬 {request.reason}
            </div>
          )}

          {isApproved && request.approverNote && (
            <div className="card p-2 mt-2" style={{ background: "#dcfce7", fontSize: 10.5, color: "#15803d" }}>
              <b>✓ {lang === "en" ? "Approver" : "Onay"}:</b> {request.approverNote}
            </div>
          )}
          {request.status === "rejected" && request.rejectionReason && (
            <div className="card p-2 mt-2" style={{ background: "#fee2e2", fontSize: 10.5, color: "#b91c1c" }}>
              <b>✗ {lang === "en" ? "Reason" : "Sebep"}:</b> {request.rejectionReason}
            </div>
          )}

          <div className="flex items-center gap-3 mt-2 text-xs" style={{ color: "var(--ink-mute)", fontSize: 10 }}>
            <span>📝 {fmtDate(request.requestedAt, { lang: "tr", time: true })} — {request.requestedBy}</span>
            {request.approvedAt && <span>✓ {fmtDate(request.approvedAt, { lang: "tr", time: true })}</span>}
            {request.paidAt && <span style={{ color: "#0891b2", fontWeight: 600 }}>💸 {fmtDate(request.paidAt, { lang: "tr", time: true })}</span>}
          </div>
        </div>

        <div className="flex flex-col items-end gap-1">
          {isPending && canManage && (
            <>
              <button onClick={() => onReview("approve")} className="text-xs px-3 py-1.5 rounded" style={{ background: "#15803d", color: "#fff", fontWeight: 700 }}>
                ✓ {lang === "en" ? "Approve" : "Onayla"}
              </button>
              <button onClick={() => onReview("reject")} className="text-xs px-3 py-1.5 rounded" style={{ background: "#b91c1c", color: "#fff", fontWeight: 700 }}>
                ✗ {lang === "en" ? "Reject" : "Reddet"}
              </button>
            </>
          )}
          {isApproved && request.kind === "expense" && canManage && (
            <button onClick={() => {
              const ref = prompt(lang === "en" ? "Payment reference (optional):" : "Ödeme referansı (opsiyonel):");
              if (ref !== null) onPaid(ref);
            }} className="text-xs px-3 py-1.5 rounded" style={{ background: "#0891b2", color: "#fff", fontWeight: 700 }}>
              💸 {lang === "en" ? "Paid" : "Ödendi"}
            </button>
          )}
          {isApproved && request.kind === "asset" && canManage && (
            <button onClick={onDelivered} className="text-xs px-3 py-1.5 rounded" style={{ background: "#7c3aed", color: "#fff", fontWeight: 700 }}>
              📦 {lang === "en" ? "Deliver" : "Teslim"}
            </button>
          )}
          {isDelivered && request.kind === "asset" && canManage && (
            <button onClick={onReturned} className="text-xs px-3 py-1.5 rounded" style={{ background: "#475569", color: "#fff", fontWeight: 700 }}>
              ↩ {lang === "en" ? "Return" : "İade"}
            </button>
          )}
          {(isPending || isApproved) && canManage && (
            <button onClick={onCancel} className="text-xs px-2 py-1 rounded" style={{ background: "var(--bg-alt)", color: "var(--ink-mute)", fontWeight: 600 }}>
              ⊘ {lang === "en" ? "Cancel" : "İptal"}
            </button>
          )}
          {isPending && canManage && (
            <button onClick={onEdit} className="text-xs px-2 py-1 rounded" style={{ background: "var(--accent-soft)", color: "var(--accent)", fontWeight: 600 }}>
              <Edit3 size={10} style={{ display: "inline" }}/> {lang === "en" ? "Edit" : "Düzenle"}
            </button>
          )}
          {(request.status === "cancelled" || request.status === "rejected") && canManage && (
            <button onClick={onDelete} className="text-xs px-2 py-1 rounded" style={{ background: "var(--negative-soft)", color: "var(--negative)" }}>
              <Trash2 size={10}/>
            </button>
          )}
        </div>
      </div>

      {/* Yorum thread'i */}
      {session && onChange && (
        <div className="mt-3" style={{ borderTop: "1px solid var(--line-soft)", paddingTop: 8 }}>
          <CommentThread
            parentType="request"
            parentId={request.id}
            parentOwnerEmployeeId={request.employeeId}
            session={session}
            users={users}
            data={data}
            onChange={onChange}
            lang={lang}
            compactMode={true}/>
        </div>
      )}
    </div>
  );
}

/* ---------- Talep Form Modal ---------- */
function RequestFormModal({ draft, setDraft, employees, assets, data, lang, onClose, onSave }) {
  const kindInfo = REQUEST_KINDS[draft.kind];
  const [tab, setTab] = useState("basic");

  return (
    <Modal
      title={draft.id
        ? `✏️ ${lang === "en" ? "Edit" : "Düzenle"} — ${kindInfo.labels[lang] || kindInfo.labels.tr}`
        : `${kindInfo.icon} ${lang === "en" ? "New" : "Yeni"} ${kindInfo.labels[lang] || kindInfo.labels.tr}`}
      icon={ClipboardList} maxWidth="max-w-2xl"
      onClose={onClose} onSave={onSave}>
      <div className="space-y-3">
        <div className="flex items-center gap-1" style={{ borderBottom: "1px solid var(--line)" }}>
          {[
            { id: "basic", icon: Info, label: { tr: "Temel", en: "Basic" } },
            { id: "details", icon: Settings, label: { tr: "Detaylar", en: "Details" } },
          ].map(t => {
            const active = tab === t.id;
            return (
              <button key={t.id} type="button" onClick={() => setTab(t.id)}
                className="flex items-center gap-1.5"
                style={{
                  padding: "6px 10px", fontSize: 11.5,
                  fontWeight: active ? 600 : 500,
                  color: active ? "var(--accent)" : "var(--ink-mute)",
                  borderBottom: active ? "2px solid var(--accent)" : "2px solid transparent",
                  marginBottom: -1,
                }}>
                <t.icon size={11}/>
                {t.label[lang] || t.label.tr}
              </button>
            );
          })}
        </div>

        {tab === "basic" && (
          <div className="space-y-3">
            <div>
              <div className="label mb-1">{lang === "en" ? "Employee" : "Çalışan"} *</div>
              <select className="input w-full" value={draft.employeeId || ""}
                onChange={e => setDraft({ ...draft, employeeId: e.target.value })}>
                <option value="">— {lang === "en" ? "Select" : "Seçin"} —</option>
                {employees.map(e => <option key={e.id} value={e.id}>{e.firstName} {e.lastName}</option>)}
              </select>
            </div>

            {kindInfo.requiresAmount && (
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <div className="label mb-1">{lang === "en" ? "Amount" : "Tutar"} *</div>
                  <MoneyInput className="input w-full mono text-right"
                    value={draft.amount || ""}
                    onChange={v => setDraft({ ...draft, amount: v === '' ? 0 : v })}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Currency" : "Para"}</div>
                  <select className="input w-full" value={draft.currency || "TRY"}
                    onChange={e => setDraft({ ...draft, currency: e.target.value })}>
                    <option value="TRY">₺ TRY</option>
                    <option value="USD">$ USD</option>
                    <option value="EUR">€ EUR</option>
                    <option value="GBP">£ GBP</option>
                  </select>
                </div>
              </div>
            )}

            <div>
              <div className="label mb-1">{lang === "en" ? "Reason / Purpose" : "Sebep / Amaç"} *</div>
              <textarea className="input w-full" rows="2" style={{ fontSize: 11.5 }}
                value={draft.reason || ""}
                onChange={e => setDraft({ ...draft, reason: e.target.value })}/>
            </div>

            <div>
              <div className="label mb-1">{lang === "en" ? "Notes" : "Notlar"}</div>
              <textarea className="input w-full" rows="2" style={{ fontSize: 11.5 }}
                value={draft.notes || ""}
                onChange={e => setDraft({ ...draft, notes: e.target.value })}/>
            </div>
          </div>
        )}

        {tab === "details" && (
          <div className="space-y-3">
            {/* AVANS */}
            {draft.kind === "advance" && (
              <>
                <div className="card p-3" style={{ background: "#fef3c7", border: "1px solid #ca8a04" }}>
                  <div style={{ fontSize: 12, color: "#854d0e", fontWeight: 700 }}>
                    💰 {lang === "en" ? "Advance Details" : "Avans Detayları"}
                  </div>
                  <div style={{ fontSize: 10.5, color: "var(--ink-mute)", marginTop: 4 }}>
                    {lang === "en"
                      ? "Will be auto-deducted from payroll in equal installments."
                      : "Bordrodan eşit taksitlerle otomatik kesilir."}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Installments (months)" : "Taksit (ay)"} *</div>
                    <input type="number" min="1" max="36" className="input w-full mono text-center"
                      value={draft.installments || 1}
                      onChange={e => setDraft({ ...draft, installments: parseInt(e.target.value) || 1 })}/>
                  </div>
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Start Month" : "Başlangıç Ayı"} *</div>
                    <input type="month" className="input w-full mono"
                      value={draft.payrollMonth || ""}
                      onChange={e => setDraft({ ...draft, payrollMonth: e.target.value })}/>
                  </div>
                </div>
                {draft.amount > 0 && draft.installments > 0 && (
                  <div className="card p-2 text-xs" style={{ background: "var(--accent-soft)", color: "var(--accent)" }}>
                    <b>📊 {lang === "en" ? "Monthly" : "Aylık kesinti"}:</b>{" "}
                    <span className="mono font-bold">{fmtTL(draft.amount / draft.installments)} ₺</span>
                    <span style={{ color: "var(--ink-mute)" }}> × {draft.installments} = {fmtTL(draft.amount)} ₺</span>
                  </div>
                )}
                <div>
                  <div className="label mb-1">{lang === "en" ? "Payroll Component" : "Bordro Bileşeni"}</div>
                  <select className="input w-full" value={draft.payrollComponentCode || "AVANS"}
                    onChange={e => setDraft({ ...draft, payrollComponentCode: e.target.value })}>
                    <option value="AVANS">AVANS — {lang === "en" ? "Default" : "Varsayılan"}</option>
                    {(data?.hrPayrollComponents || []).filter(c => c.category === "special_deduction" && c.active && c.code !== "AVANS").map(c => (
                      <option key={c.code} value={c.code}>{c.code} — {c.name?.tr || c.code}</option>
                    ))}
                  </select>
                </div>
              </>
            )}

            {/* MASRAF */}
            {draft.kind === "expense" && (
              <>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Category" : "Kategori"} *</div>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-1">
                    {Object.entries(EXPENSE_CATEGORIES).map(([k, ec]) => (
                      <button key={k} type="button"
                        onClick={() => setDraft({ ...draft, expenseCategory: k })}
                        className="text-xs p-2 rounded text-left"
                        style={{
                          background: draft.expenseCategory === k ? ec.color : "var(--bg)",
                          color: draft.expenseCategory === k ? "#fff" : ec.color,
                          border: `1px solid ${ec.color}40`,
                          fontWeight: 600,
                        }}>
                        {ec.icon} {ec.labels[lang] || ec.labels.tr}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Receipt Date" : "Belge Tarihi"} *</div>
                    <input type="date" className="input w-full"
                      value={draft.receiptDate || ""}
                      onChange={e => setDraft({ ...draft, receiptDate: e.target.value })}/>
                  </div>
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Vendor" : "Sağlayıcı"}</div>
                    <input className="input w-full"
                      value={draft.vendorName || ""}
                      onChange={e => setDraft({ ...draft, vendorName: e.target.value })}/>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <div className="label mb-1">{lang === "en" ? "VAT" : "KDV"}</div>
                    <MoneyInput className="input w-full mono text-right"
                      value={draft.vatAmount || ""}
                      onChange={v => setDraft({ ...draft, vatAmount: v === '' ? 0 : v })}/>
                  </div>
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Receipt URL" : "Belge URL"}</div>
                    <input className="input w-full" placeholder="https://..."
                      value={draft.receiptUrl || ""}
                      onChange={e => setDraft({ ...draft, receiptUrl: e.target.value })}/>
                  </div>
                </div>
              </>
            )}

            {/* ZİMMET */}
            {draft.kind === "asset" && (
              <>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Asset Type" : "Zimmet Tipi"} *</div>
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-1">
                    {Object.entries(ASSET_TYPES).map(([k, at]) => (
                      <button key={k} type="button"
                        onClick={() => setDraft({ ...draft, assetType: k })}
                        className="text-xs p-2 rounded text-left"
                        style={{
                          background: draft.assetType === k ? at.color : "var(--bg)",
                          color: draft.assetType === k ? "#fff" : at.color,
                          border: `1px solid ${at.color}40`,
                          fontWeight: 600,
                        }}>
                        {at.icon} {at.labels[lang] || at.labels.tr}
                      </button>
                    ))}
                  </div>
                </div>

                {assets.length > 0 && (
                  <div className="card p-3" style={{ background: "var(--accent-soft)" }}>
                    <div style={{ fontSize: 11.5, color: "var(--accent)", fontWeight: 700, marginBottom: 6 }}>
                      📦 {lang === "en" ? "Link to stock asset (optional)" : "Stoktan zimmet bağla"}
                    </div>
                    <select className="input w-full" value={draft.linkedAssetId || ""}
                      onChange={e => {
                        const asset = assets.find(a => a.id === e.target.value);
                        setDraft({
                          ...draft,
                          linkedAssetId: e.target.value || null,
                          ...(asset && {
                            assetType: asset.type || draft.assetType,
                            assetBrand: asset.brand || "",
                            assetModel: asset.model || "",
                            assetSerial: asset.serial || "",
                          }),
                        });
                      }}>
                      <option value="">— {lang === "en" ? "New / not linked" : "Yeni / bağlama yok"} —</option>
                      {assets.filter(a => !draft.assetType || a.type === draft.assetType).map(a => (
                        <option key={a.id} value={a.id}>
                          {ASSET_TYPES[a.type]?.icon} {a.brand} {a.model} {a.serial ? `#${a.serial}` : ""}
                        </option>
                      ))}
                    </select>
                  </div>
                )}

                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Brand" : "Marka"}</div>
                    <input className="input w-full"
                      value={draft.assetBrand || ""}
                      onChange={e => setDraft({ ...draft, assetBrand: e.target.value })}/>
                  </div>
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Model" : "Model"}</div>
                    <input className="input w-full"
                      value={draft.assetModel || ""}
                      onChange={e => setDraft({ ...draft, assetModel: e.target.value })}/>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Serial" : "Seri No"}</div>
                    <input className="input w-full mono"
                      value={draft.assetSerial || ""}
                      onChange={e => setDraft({ ...draft, assetSerial: e.target.value })}/>
                  </div>
                  <div>
                    <div className="label mb-1">{lang === "en" ? "Assignment Date" : "Zimmet Tarihi"}</div>
                    <input type="date" className="input w-full"
                      value={draft.assignmentDate || ""}
                      onChange={e => setDraft({ ...draft, assignmentDate: e.target.value })}/>
                  </div>
                </div>
              </>
            )}
          </div>
        )}
      </div>
    </Modal>
  );
}

/* ---------- Talep Onay/Red Modal ---------- */
function RequestReviewModal({ request, action, employees, data, lang, onClose, onApprove, onReject }) {
  const [note, setNote] = useState("");
  const emp = employees.find(e => e.id === request.employeeId);
  const kindInfo = REQUEST_KINDS[request.kind];
  const isApprove = action === "approve";

  return (
    <Modal
      title={isApprove
        ? `✓ ${lang === "en" ? "Approve Request" : "Talebi Onayla"}`
        : `✗ ${lang === "en" ? "Reject Request" : "Talebi Reddet"}`}
      icon={isApprove ? Check : X} maxWidth="max-w-lg"
      onClose={onClose}
      onSave={() => isApprove ? onApprove(note) : onReject(note)}
      saveLabel={isApprove ? (lang === "en" ? "Approve" : "Onayla") : (lang === "en" ? "Reject" : "Reddet")}>
      <div className="space-y-3">
        <div className="card p-3" style={{ background: kindInfo.color + "10", border: `1px solid ${kindInfo.color}40` }}>
          <div className="flex items-center gap-2">
            <span style={{ fontSize: 22 }}>{kindInfo.icon}</span>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700 }}>{emp?.firstName} {emp?.lastName}</div>
              <div className="chip" style={{ background: kindInfo.color, color: "#fff", padding: "1px 6px", fontSize: 10, fontWeight: 600 }}>
                {kindInfo.labels[lang] || kindInfo.labels.tr}
              </div>
            </div>
          </div>

          {request.amount > 0 && (
            <div className="mt-2">
              <span style={{ fontSize: 10, color: "var(--ink-mute)" }}>{lang === "en" ? "Amount" : "Tutar"}:</span>{" "}
              <span className="mono font-bold" style={{ fontSize: 16, color: kindInfo.color }}>
                {fmtTL(request.amount)} {request.currency || "₺"}
              </span>
              {request.kind === "advance" && request.installments > 1 && (
                <span style={{ fontSize: 11, color: "var(--ink-mute)" }}>
                  {" "}({request.installments} × {fmtTL(request.amount / request.installments)})
                </span>
              )}
            </div>
          )}

          {request.reason && (
            <div className="mt-2 text-xs" style={{ color: "var(--ink-soft)" }}>
              💬 <b>{lang === "en" ? "Reason" : "Sebep"}:</b> {request.reason}
            </div>
          )}
        </div>

        <div>
          <div className="label mb-1">
            {isApprove
              ? (lang === "en" ? "Approver Note (optional)" : "Onay Notu (opsiyonel)")
              : (lang === "en" ? "Rejection Reason *" : "Red Sebebi *")}
          </div>
          <textarea className="input w-full" rows="3" style={{ fontSize: 11.5 }}
            value={note}
            onChange={e => setNote(e.target.value)}/>
        </div>

        {isApprove && request.kind === "advance" && (
          <div className="card p-2 text-xs" style={{ background: "#fef3c7", color: "#854d0e" }}>
            ℹ️ <b>{lang === "en" ? "On approval:" : "Onay sonrası:"}</b>
            <ul style={{ marginTop: 4, marginLeft: 16 }}>
              <li>{lang === "en"
                ? `${fmtTL(request.amount / request.installments)} ₺ deducted starting ${request.payrollMonth}`
                : `${request.payrollMonth} bordrosundan ${fmtTL(request.amount / request.installments)} ₺ otomatik kesilir`}</li>
            </ul>
          </div>
        )}
      </div>
    </Modal>
  );
}

