/* =====================================================================
   RECRUITMENT — İŞE ALIM YÖNETİMİ
   ---------------------------------------------------------------------
   4 alt-bölüm: Genel Bakış, Pozisyonlar, Adaylar, Pipeline, Mülakatlar
===================================================================== */
function RecruitmentManager({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const [view, setView] = useState("dashboard");
  const canManagePositions  = canAct ? canAct("hr.positions.create") || canAct("hr.positions.update") || can(session.role, "manage_positions") : can(session.role, "manage_positions");
  const canManageCandidates = canAct ? canAct("hr.candidates.create") || canAct("hr.candidates.update") || can(session.role, "manage_candidates") : can(session.role, "manage_candidates");
  const canManageInterviews = canAct ? canAct("hr.interviews.create") || canAct("hr.interviews.update") || can(session.role, "manage_interviews") : can(session.role, "manage_interviews");

  const positions    = data.hrPositions    || [];
  const candidates   = data.hrCandidates   || [];
  const applications = data.hrApplications || [];
  const interviews   = data.hrInterviews   || [];
  const departments  = data.hrDepartments  || [];

  // İstatistikler
  const stats = useMemo(() => {
    const openPositions = positions.filter(p => p.status === "open");
    const activeApps = applications.filter(a => !["hired","rejected","withdrawn"].includes(a.stage));
    const hiredThisMonth = applications.filter(a => {
      if (a.stage !== "hired" || !a.hiredAt) return false;
      const d = new Date(a.hiredAt);
      const now = new Date();
      return d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth();
    });
    const upcomingInterviews = interviews.filter(i => {
      if (i.status === "completed" || i.status === "cancelled") return false;
      const d = new Date(i.dateTime);
      return d >= new Date();
    });
    // Açık pozisyonların tahmini aylık brüt maliyeti
    const monthlyBudget = openPositions.reduce((sum, p) => {
      const brut = (Number(p.brutMinSalary) + Number(p.brutMaxSalary)) / 2 || 0;
      const cost = computeEmployerCost(brut);
      return sum + (cost * (Number(p.headcount) || 1));
    }, 0);
    return {
      openPositions: openPositions.length,
      totalApplications: applications.length,
      activeApplications: activeApps.length,
      hiredThisMonth: hiredThisMonth.length,
      upcomingInterviews: upcomingInterviews.length,
      candidatePool: candidates.length,
      monthlyBudget,
    };
  }, [positions, candidates, applications, interviews]);

  return (
    <div className="space-y-4">
      {/* İç sekme bar */}
      <div className="flex items-center gap-1 overflow-x-auto pb-1" style={{ borderBottom: "1px solid var(--line)" }}>
        {[
          { id: "dashboard",  icon: LayoutDashboard, labelKey: "rec.dashboard" },
          { id: "positions",  icon: Briefcase,       labelKey: "rec.positions",  badge: stats.openPositions },
          { id: "postings",   icon: Send,            label: lang === "en" ? "Job Postings" : lang === "de" ? "Stellenanzeigen" : lang === "ar" ? "إعلانات الوظائف" : "İlanlar", badge: (data.hrJobPostings || []).filter(p => p.status === "published").length },
          { id: "applications", icon: FileText,      label: lang === "en" ? "Applications" : lang === "de" ? "Bewerbungen" : lang === "ar" ? "الطلبات" : "Başvurular", badge: (data.hrApplications || []).filter(a => a.jobPostingId && (a.status === "new" || !a.status)).length },
          { id: "candidates", icon: Users,           labelKey: "rec.candidates", badge: stats.candidatePool },
          { id: "pipeline",   icon: Layers,          labelKey: "rec.pipeline",   badge: stats.activeApplications },
          { id: "interviews", icon: CalendarClock,   labelKey: "rec.interviews", badge: stats.upcomingInterviews },
          { id: "questions",  icon: MessageCircle,   label: lang === "en" ? "Question Bank" : lang === "de" ? "Fragenbank" : lang === "ar" ? "بنك الأسئلة" : "Soru Havuzu", badge: (data.hrQuestions || []).length },
          { id: "kits",       icon: ClipboardList,   label: lang === "en" ? "Interview Kits" : lang === "de" ? "Interview-Kits" : lang === "ar" ? "حزم المقابلات" : "Mülakat Kitleri", badge: (data.hrInterviewKits || []).length },
        ].map(tab => {
          const active = view === tab.id;
          return (
            <button key={tab.id} onClick={() => setView(tab.id)}
              className="flex items-center gap-1.5 transition-all relative"
              style={{
                padding: "8px 12px",
                fontSize: 12,
                fontWeight: active ? 600 : 500,
                color: active ? "var(--accent)" : "var(--ink-mute)",
                borderBottom: active ? "2px solid var(--accent)" : "2px solid transparent",
                marginBottom: -1,
                whiteSpace: "nowrap",
              }}>
              <tab.icon size={12} strokeWidth={active ? 2 : 1.5}/>
              {tab.labelKey ? t(tab.labelKey, lang) : tab.label}
              {tab.badge > 0 && (
                <span style={{
                  fontSize: 10,
                  padding: "1px 5px",
                  borderRadius: 3,
                  background: active ? "var(--accent)" : "var(--bg-alt)",
                  color: active ? "#fff" : "var(--ink-mute)",
                  fontWeight: 600,
                  fontVariantNumeric: "tabular-nums",
                }}>{tab.badge}</span>
              )}
            </button>
          );
        })}
      </div>

      {view === "dashboard" && (
        <RecruitmentDashboard data={data} stats={stats} setView={setView} lang={lang}/>
      )}
      {view === "positions" && (
        <PositionsList data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify}
          canManage={canManagePositions} departments={departments}/>
      )}
      {view === "postings" && (
        <JobPostingsManager data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify} canManage={canManagePositions}/>
      )}
      {view === "applications" && (
        <ApplicationsManager data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify} canManage={canManageCandidates}/>
      )}
      {view === "candidates" && (
        <CandidatesList data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify}
          canManage={canManageCandidates}/>
      )}
      {view === "pipeline" && (
        <RecruitmentPipeline data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify}/>
      )}
      {view === "interviews" && (
        <InterviewsList data={data} session={session} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify} canManage={canManageInterviews}/>
      )}
      {view === "questions" && (
        <QuestionBankManager data={data} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify} canManage={canManagePositions}/>
      )}
      {view === "kits" && (
        <InterviewKitManager data={data} onChange={onChange} lang={lang}
          logAudit={logAudit} notify={notify} canManage={canManagePositions}/>
      )}
    </div>
  );
}

/* ---------- Genel Bakış (Dashboard) ---------- */
function RecruitmentDashboard({ data, stats, setView, lang }) {
  const positions    = data.hrPositions    || [];
  const applications = data.hrApplications || [];
  const interviews   = data.hrInterviews   || [];
  const candidates   = data.hrCandidates   || [];

  // Bu hafta yapılacak mülakatlar
  const now = new Date();
  const weekEnd = new Date(now.getTime() + 7 * 86400000);
  const upcoming = interviews
    .filter(i => {
      const d = new Date(i.dateTime);
      return d >= now && d <= weekEnd && i.status !== "cancelled";
    })
    .sort((a,b) => new Date(a.dateTime) - new Date(b.dateTime));

  // Açık pozisyonların aday sayıları
  const positionStats = positions.filter(p => p.status === "open").map(pos => {
    const apps = applications.filter(a => a.positionId === pos.id);
    return {
      ...pos,
      totalApps: apps.length,
      activeApps: apps.filter(a => !["hired","rejected","withdrawn"].includes(a.stage)).length,
      inOffer: apps.filter(a => a.stage === "offer").length,
    };
  });

  return (
    <div className="space-y-4">
      {/* KPI kartları */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <StatBlock label="Açık Pozisyon" value={stats.openPositions} color="#0ea5e9" large/>
        <StatBlock label="Aktif Süreç" value={stats.activeApplications} color="#8b5cf6" large/>
        <StatBlock label="Bekleyen Mülakat" value={stats.upcomingInterviews} color="#f59e0b" large/>
        <StatBlock label="Bu Ay İşe Alınan" value={stats.hiredThisMonth} color="#15803d" large/>
      </div>

      {/* Bütçe öngörüsü */}
      {stats.monthlyBudget > 0 && (
        <div className="card p-4" style={{ background: "linear-gradient(135deg, #fef3c7 0%, #fde68a 100%)" }}>
          <div className="flex items-center justify-between flex-wrap gap-2">
            <div>
              <div className="text-xs font-semibold" style={{ color: "#854d0e" }}>
                📊 Açık Pozisyonların Tahmini Aylık Maliyeti
              </div>
              <div className="display text-2xl mt-1" style={{ color: "#854d0e" }}>
                ≈ {fmtTL(stats.monthlyBudget)} ₺/ay
              </div>
              <div className="text-xs mt-1" style={{ color: "#92400e" }}>
                Brüt maaş ortalaması + işveren SGK + işsizlik primi dahil (yaklaşık)
              </div>
            </div>
            <button onClick={() => setView("positions")} className="btn btn-ghost text-xs">
              Detay <ChevronRight size={12}/>
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
        {/* Açık pozisyonlar özet */}
        <div className="card p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="font-semibold text-sm flex items-center gap-2">
              <Briefcase size={14}/> Açık Pozisyonlar
            </div>
            <button onClick={() => setView("positions")} className="text-xs hover:underline" style={{ color: "var(--accent)" }}>
              Tümü →
            </button>
          </div>
          {positionStats.length === 0 ? (
            <div className="text-xs text-center py-4" style={{ color: "var(--ink-mute)" }}>
              Henüz açık pozisyon yok
            </div>
          ) : (
            <div className="space-y-2">
              {positionStats.slice(0, 5).map(pos => (
                <div key={pos.id} className="flex items-center justify-between p-2 rounded"
                  style={{ background: "var(--bg)" }}>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">{pos.title}</div>
                    <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
                      {pos.departmentName || "—"} · {pos.headcount || 1} kişi aranıyor
                    </div>
                  </div>
                  <div className="text-right flex-shrink-0 ml-3">
                    <div className="text-sm font-semibold" style={{ color: "var(--accent)" }}>
                      {pos.activeApps}
                    </div>
                    <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
                      aktif aday
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Yaklaşan mülakatlar */}
        <div className="card p-4">
          <div className="flex items-center justify-between mb-3">
            <div className="font-semibold text-sm flex items-center gap-2">
              <CalendarClock size={14}/> Bu Haftaki Mülakatlar
            </div>
            <button onClick={() => setView("interviews")} className="text-xs hover:underline" style={{ color: "var(--accent)" }}>
              Tümü →
            </button>
          </div>
          {upcoming.length === 0 ? (
            <div className="text-xs text-center py-4" style={{ color: "var(--ink-mute)" }}>
              Bu hafta planlanmış mülakat yok
            </div>
          ) : (
            <div className="space-y-2">
              {upcoming.slice(0, 5).map(iv => {
                const cand = candidates.find(c => c.id === iv.candidateId);
                const pos = positions.find(p => p.id === iv.positionId);
                const dt = new Date(iv.dateTime);
                return (
                  <div key={iv.id} className="flex items-center gap-3 p-2 rounded"
                    style={{ background: "var(--bg)" }}>
                    <div className="text-center flex-shrink-0" style={{ minWidth: 50 }}>
                      <div className="text-xs font-bold" style={{ color: "var(--accent)" }}>
                        {dt.toLocaleDateString("tr-TR", { day: "2-digit", month: "short" })}
                      </div>
                      <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
                        {dt.toLocaleTimeString("tr-TR", { hour: "2-digit", minute: "2-digit" })}
                      </div>
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-medium truncate">
                        {cand ? `${cand.firstName} ${cand.lastName}` : "?"}
                      </div>
                      <div className="text-xs truncate" style={{ color: "var(--ink-mute)" }}>
                        {pos?.title || "?"} · {iv.interviewType || "Mülakat"}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* ---------- Açık Pozisyonlar Listesi ---------- */
function PositionsList({ data, session, onChange, logAudit, notify, canManage, departments, lang }) {
  const [showModal, setShowModal] = useState(null);  // null | {} (yeni) | position obj (düzenle)
  const [filter, setFilter] = useState({ status: "open", department: "" });

  const positions    = data.hrPositions    || [];
  const applications = data.hrApplications || [];

  // Departman adlarını çözümle
  const positionsWithDept = useMemo(() => positions.map(p => ({
    ...p,
    departmentName: departments.find(d => d.id === p.departmentId)?.name || "—",
    departmentColor: departments.find(d => d.id === p.departmentId)?.color || "#737373",
    applicationsCount: applications.filter(a => a.positionId === p.id).length,
    activeAppsCount: applications.filter(a => a.positionId === p.id && !["hired","rejected","withdrawn"].includes(a.stage)).length,
  })), [positions, applications, departments]);

  const filtered = useMemo(() => {
    return positionsWithDept.filter(p => {
      if (filter.status !== "all" && p.status !== filter.status) return false;
      if (filter.department && p.departmentId !== filter.department) return false;
      return true;
    }).sort((a,b) => (b.openedAt || "").localeCompare(a.openedAt || ""));
  }, [positionsWithDept, filter]);

  const savePosition = async (draft) => {
    if (!draft.title?.trim()) { alert("Pozisyon adı zorunlu"); return; }
    if (!draft.departmentId) { alert("Departman seçimi zorunlu"); return; }

    const isEdit = !!draft.id;
    const pos = isEdit ? draft : {
      id: "pos_" + Date.now() + "_" + Math.random().toString(36).slice(2, 5),
      ...draft,
      status: draft.status || "open",
      openedAt: new Date().toISOString().slice(0, 10),
      openedBy: session.username,
    };
    // Sayısal alanları normalize et
    pos.headcount       = Number(draft.headcount) || 1;
    pos.brutMinSalary   = parseTRNumber(draft.brutMinSalary) || 0;
    pos.brutMaxSalary   = parseTRNumber(draft.brutMaxSalary) || pos.brutMinSalary;
    pos.experienceYears = Number(draft.experienceYears) || 0;
    pos.title           = draft.title.trim();
    pos.jobDescription  = (draft.jobDescription || "").trim();
    pos.requirements    = (draft.requirements || "").trim();
    pos.location        = (draft.location || "").trim();

    const nextList = isEdit
      ? positions.map(p => p.id === pos.id ? pos : p)
      : [...positions, pos];
    await onChange({ ...data, hrPositions: nextList });
    await logAudit(isEdit ? "position_edit" : "position_add", {
      pozisyon: pos.title, departman: positionsWithDept.find(d => d.id === pos.id)?.departmentName,
    });
    notify(isEdit ? "Pozisyon güncellendi" : "Pozisyon eklendi");
    setShowModal(null);
  };

  const removePosition = async (pos) => {
    const appCount = applications.filter(a => a.positionId === pos.id).length;
    const msg = appCount > 0
      ? `"${pos.title}" pozisyonunu ve bağlı ${appCount} başvuruyu silmek istediğinizden emin misiniz?`
      : `"${pos.title}" pozisyonunu silmek istediğinizden emin misiniz?`;
    if (!confirm(msg)) return;
    await onChange({
      ...data,
      hrPositions: positions.filter(p => p.id !== pos.id),
      hrApplications: applications.filter(a => a.positionId !== pos.id),
    });
    await logAudit("position_delete", { pozisyon: pos.title });
    notify(t("toast.jt.deleted", lang));
  };

  return (
    <div className="space-y-3">
      {/* Toolbar */}
      <div className="flex items-center gap-2 flex-wrap">
        <select className="input text-xs" value={filter.status}
          onChange={e => setFilter({ ...filter, status: e.target.value })}>
          <option value="all">{t("emp.allStatus", lang)}</option>
          {Object.entries(POSITION_STATUS).map(([k, v]) => (
            <option key={k} value={k}>{v.label}</option>
          ))}
        </select>
        <select className="input text-xs" value={filter.department}
          onChange={e => setFilter({ ...filter, department: e.target.value })}>
          <option value="">{lang === "en" ? "All Departments" : lang === "de" ? "Alle Abteilungen" : lang === "ar" ? "جميع الأقسام" : "Tüm Departmanlar"}</option>
          {departments.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
        </select>
        <div className="ml-auto flex items-center gap-2">
          <span className="text-xs" style={{ color: "var(--ink-mute)" }}>
            {filtered.length} {lang === "en" ? "positions" : lang === "de" ? "Positionen" : lang === "ar" ? "منصب" : "pozisyon"}
          </span>
          {canManage && (
            <button onClick={() => setShowModal({ status: "open", headcount: 1, employmentType: "full_time", workMode: "office", currency: "TRY", experienceYears: 0 })}
              className="btn btn-primary">
              <Plus size={13}/> {t("pos.new", lang)}
            </button>
          )}
        </div>
      </div>

      {/* Pozisyon kartları */}
      {filtered.length === 0 ? (
        <div className="text-center py-12 card">
          <Briefcase size={32} className="mx-auto mb-3" style={{ color: "var(--ink-mute)" }}/>
          <div className="font-semibold mb-1">{lang === "en" ? "No Positions Found" : lang === "de" ? "Keine Positionen gefunden" : lang === "ar" ? "لم يتم العثور على مناصب" : "Pozisyon Bulunamadı"}</div>
          <div className="text-xs mb-4" style={{ color: "var(--ink-mute)" }}>
            {lang === "en" ? "Change filter or add a new position" : lang === "de" ? "Filter ändern oder neue Position hinzufügen" : lang === "ar" ? "غيّر الفلتر أو أضف منصباً جديداً" : "Filtreyi değiştirin veya yeni pozisyon ekleyin"}
          </div>
          {canManage && (
            <button onClick={() => setShowModal({ status: "open", headcount: 1, employmentType: "full_time", workMode: "office", currency: "TRY", experienceYears: 0 })}
              className="btn btn-primary inline-flex items-center">
              <Plus size={13}/> {lang === "en" ? "Add First Position" : lang === "de" ? "Erste Position hinzufügen" : lang === "ar" ? "إضافة أول منصب" : "İlk Pozisyonu Ekle"}
            </button>
          )}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3">
          {filtered.map(pos => (
            <PositionCard key={pos.id} position={pos} canManage={canManage}
              onEdit={() => setShowModal(pos)}
              onDelete={() => removePosition(pos)}/>
          ))}
        </div>
      )}

      {/* Modal */}
      {showModal && (
        <PositionFormModal draft={showModal} setDraft={setShowModal}
          departments={departments} lang={lang}
          onClose={() => setShowModal(null)}
          onSave={() => savePosition(showModal)}/>
      )}
    </div>
  );
}

/* ---------- Pozisyon Kartı ---------- */
function PositionCard({ position, canManage, onEdit, onDelete }) {
  const statusInfo = POSITION_STATUS[position.status] || POSITION_STATUS.open;
  const monthlyEmployerCost = computeEmployerCost((position.brutMinSalary + position.brutMaxSalary) / 2 || 0);

  return (
    <div className="card p-4 space-y-3 hover:shadow-md transition-shadow"
      style={{ borderLeft: `4px solid ${position.departmentColor}` }}>
      {/* Header */}
      <div className="flex items-start justify-between gap-2">
        <div className="flex-1 min-w-0">
          <div className="font-semibold text-sm truncate">{position.title}</div>
          <div className="text-xs flex items-center gap-2 mt-0.5" style={{ color: "var(--ink-mute)" }}>
            <span style={{ color: position.departmentColor }}>● {position.departmentName}</span>
            {position.location && <span>· <MapPin size={9} style={{display:"inline"}}/> {position.location}</span>}
          </div>
        </div>
        <span className="text-xs px-2 py-0.5 rounded font-medium"
          style={{ background: statusInfo.color + "22", color: statusInfo.color }}>
          {statusInfo.label}
        </span>
      </div>

      {/* Detaylar */}
      <div className="grid grid-cols-2 gap-2 text-xs">
        <div>
          <div style={{ color: "var(--ink-mute)" }}>Aranan Kişi</div>
          <div className="font-medium">{position.headcount} kişi</div>
        </div>
        <div>
          <div style={{ color: "var(--ink-mute)" }}>Çalışma Şekli</div>
          <div className="font-medium">{EMPLOYMENT_TYPES[position.employmentType] || "?"}</div>
        </div>
        {position.experienceYears > 0 && (
          <div>
            <div style={{ color: "var(--ink-mute)" }}>Deneyim</div>
            <div className="font-medium">{position.experienceYears}+ yıl</div>
          </div>
        )}
        <div>
          <div style={{ color: "var(--ink-mute)" }}>Yer</div>
          <div className="font-medium">{WORK_MODES[position.workMode] || "?"}</div>
        </div>
      </div>

      {/* Maaş aralığı + tahmini maliyet */}
      {(position.brutMinSalary > 0 || position.brutMaxSalary > 0) && (
        <div className="p-2 rounded text-xs" style={{ background: "var(--bg)" }}>
          <div className="flex items-center justify-between">
            <span style={{ color: "var(--ink-mute)" }}>Brüt Maaş</span>
            <span className="font-medium mono">
              {fmtTL(position.brutMinSalary)} – {fmtTL(position.brutMaxSalary)} {position.currency}
            </span>
          </div>
          <div className="flex items-center justify-between mt-1">
            <span style={{ color: "var(--ink-mute)" }}>İşveren Maliyeti</span>
            <span className="font-semibold mono" style={{ color: "#854d0e" }}>
              ≈ {fmtTL(monthlyEmployerCost)} {position.currency}/ay
            </span>
          </div>
        </div>
      )}

      {/* Aday özet */}
      <div className="flex items-center justify-between text-xs pt-2 border-t" style={{ borderColor: "var(--line-soft)" }}>
        <span style={{ color: "var(--ink-mute)" }}>
          {position.applicationsCount} başvuru · <b style={{ color: "var(--ink)" }}>{position.activeAppsCount}</b> aktif
        </span>
        {canManage && (
          <div className="flex items-center gap-1">
            <button onClick={onEdit} className="p-1 rounded hover:bg-stone-100" title="Düzenle">
              <Edit3 size={10}/>
            </button>
            <button onClick={onDelete} className="p-1 rounded hover:bg-red-50" title="Sil">
              <Trash2 size={10} style={{ color: "var(--negative)" }}/>
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

/* =====================================================================
   CV PARSE & SKORLAMA UTILITY FONKSİYONLARI
   ---------------------------------------------------------------------
   • loadTesseract(): Tesseract.js'i CDN'den lazy-load eder
   • extractTextFromFile(): PDF/JPG/PNG'den metin çıkarır (OCR)
   • parseCV(): Düz metinden yapılandırılmış veri çıkarır (email, telefon,
     eğitim, yıllar, skiller)
   • scoreApplication(): Pozisyon gereksinimleri ile CV verisini karşılaştırıp
     0-100 arası skor üretir
===================================================================== */

// Tesseract.js CDN yükleyici (lazy)
let __tesseractPromise = null;
async function loadTesseract() {
  if (typeof window === "undefined") throw new Error("Browser only");
  if (window.Tesseract) return window.Tesseract;
  if (__tesseractPromise) return __tesseractPromise;
  __tesseractPromise = new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/tesseract.js@5.0.4/dist/tesseract.min.js";
    s.onload = () => resolve(window.Tesseract);
    s.onerror = () => reject(new Error("Tesseract.js yüklenemedi"));
    document.head.appendChild(s);
  });
  return __tesseractPromise;
}

// PDF.js CDN yükleyici (PDF text extraction için)
let __pdfjsPromise = null;
async function loadPdfJs() {
  if (typeof window === "undefined") throw new Error("Browser only");
  if (window.pdfjsLib) return window.pdfjsLib;
  if (__pdfjsPromise) return __pdfjsPromise;
  __pdfjsPromise = new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = "https://cdn.jsdelivr.net/npm/pdfjs-dist@4.0.379/build/pdf.min.mjs";
    s.type = "module";
    s.onload = () => {
      // ES module yüklendi
      setTimeout(() => {
        if (window.pdfjsLib) resolve(window.pdfjsLib);
        else reject(new Error("PDF.js yüklenemedi (window.pdfjsLib yok)"));
      }, 100);
    };
    s.onerror = () => reject(new Error("PDF.js yüklenemedi"));
    document.head.appendChild(s);
  });
  return __pdfjsPromise;
}

// Dosyadan metin çıkar (PDF için PDF.js, görsel için Tesseract OCR)
async function extractTextFromFile(file, onProgress) {
  if (!file) return "";
  const name = (file.name || "").toLowerCase();
  const isPdf = name.endsWith(".pdf") || file.type === "application/pdf";
  const isImage = file.type?.startsWith("image/") || /\.(jpe?g|png|gif|bmp|webp)$/.test(name);
  const isText = file.type === "text/plain" || name.endsWith(".txt");

  // Text → direkt oku
  if (isText) {
    return await file.text();
  }

  // PDF — önce PDF.js ile dene (vektörel metin için hızlı), olmazsa OCR fallback
  if (isPdf) {
    try {
      // Önce basit FileReader ile text dene (bazı PDF'ler ham metin içerebilir, az ihtimal)
      const buffer = await file.arrayBuffer();
      // PDF.js dene
      try {
        // pdfjs-dist global'i window.pdfjsLib olarak gelmeyebilir; ES module fetch ile içe aktarmayı dene
        const mod = await import(/* @vite-ignore */ "https://cdn.jsdelivr.net/npm/pdfjs-dist@4.0.379/build/pdf.min.mjs");
        mod.GlobalWorkerOptions.workerSrc = "https://cdn.jsdelivr.net/npm/pdfjs-dist@4.0.379/build/pdf.worker.min.mjs";
        const pdf = await mod.getDocument({ data: buffer }).promise;
        let text = "";
        for (let i = 1; i <= pdf.numPages; i++) {
          if (onProgress) onProgress({ status: "pdf_page", current: i, total: pdf.numPages });
          const page = await pdf.getPage(i);
          const content = await page.getTextContent();
          text += content.items.map(it => it.str).join(" ") + "\n";
        }
        if (text.trim().length > 50) return text;
        // Çok az metin → görsel PDF olabilir, OCR'a düş
      } catch (e) {
        console.warn("PDF.js başarısız, OCR'a geçiliyor", e);
      }
      // OCR fallback (PDF görsel ise — basit, ilk sayfayı görsele çevirir)
      // Not: tarayıcıda PDF'i image'a render etmek için canvas gerekir; basitlik için OCR direct skip
      return ""; // PDF.js çalışmadıysa boş döner — kullanıcı manuel girer
    } catch (e) {
      console.error("PDF extraction error", e);
      return "";
    }
  }

  // Görsel → OCR
  if (isImage) {
    try {
      const Tesseract = await loadTesseract();
      if (onProgress) onProgress({ status: "ocr_start" });
      const { data } = await Tesseract.recognize(file, "tur+eng", {
        logger: m => onProgress && onProgress({ status: "ocr", progress: m.progress, message: m.status }),
      });
      return data.text || "";
    } catch (e) {
      console.error("OCR error", e);
      return "";
    }
  }

  return "";
}

// CV metnini yapılandırılmış veriye çevir
function parseCV(rawText) {
  if (!rawText || typeof rawText !== "string") return null;
  const text = rawText.replace(/\s+/g, " ");
  const lower = text.toLowerCase();

  // Email
  const emailMatch = text.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/i);
  // Telefon (TR + uluslararası)
  const phoneMatch = text.match(/(\+?9?0?\s?\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{2}[\s.-]?\d{2})|(\+\d{1,3}[\s.-]?\d{3,4}[\s.-]?\d{3,4}[\s.-]?\d{3,4})/);
  // LinkedIn URL
  const linkedinMatch = text.match(/linkedin\.com\/in\/[a-z0-9-]+/i);

  // Yıl aralıkları (2018-2023, 2020-Halen, vb.) — toplam deneyim tahmini
  const yearRanges = [];
  const yearRegex = /(\d{4})\s*[-–]\s*(\d{4}|halen|present|şu an|current|devam)/gi;
  let m;
  while ((m = yearRegex.exec(text)) !== null) {
    const start = parseInt(m[1]);
    const end = /halen|present|şu an|current|devam/i.test(m[2]) ? new Date().getFullYear() : parseInt(m[2]);
    if (start >= 1980 && end >= start && end <= new Date().getFullYear() + 1) {
      yearRanges.push({ start, end, years: end - start });
    }
  }
  const totalYears = yearRanges.reduce((s, r) => s + r.years, 0);
  // Aralıkların kesişimini sayma; basit toplam (yaklaşık)

  // Üniversiteler
  const foundUniversities = [];
  UNIVERSITY_HINTS_TR.forEach(u => {
    const re = new RegExp(`\\b${u.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
    if (re.test(text)) foundUniversities.push(u);
  });

  // Eğitim seviyesi tahmini
  let highestEdu = null;
  if (/\b(phd|doktora|doctorate)\b/i.test(lower)) highestEdu = "phd";
  else if (/\b(master|yüksek lisans|msc|mba|ma\.?)\b/i.test(lower)) highestEdu = "master";
  else if (/\b(bachelor|lisans|bsc|b\.?a\.?|bs\.?)\b/i.test(lower)) highestEdu = "bachelor";
  else if (/\b(önlisans|associate|önlisansı)\b/i.test(lower)) highestEdu = "associate";
  else if (/\b(lise|high school)\b/i.test(lower)) highestEdu = "high_school";

  // Beceriler
  const foundSkills = [];
  COMMON_SKILLS_HINTS.forEach(s => {
    const re = new RegExp(`\\b${s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
    if (re.test(text)) foundSkills.push(s);
  });

  // Dil seviyeleri (CEFR)
  const langLevels = {};
  ["İngilizce", "English", "Almanca", "German", "Deutsch", "Fransızca", "French"].forEach(lng => {
    const re = new RegExp(`${lng}[^\\n.]{0,40}?(A1|A2|B1|B2|C1|C2|native|anadil|fluent|akıcı|orta|intermediate|advanced|ileri)`, "i");
    const r = re.exec(text);
    if (r) {
      const lv = r[2].toUpperCase();
      const cefr = ["A1","A2","B1","B2","C1","C2"].includes(lv) ? lv :
                   /native|anadil/i.test(lv) ? "C2" :
                   /fluent|akıcı|advanced|ileri/i.test(lv) ? "C1" :
                   /intermediate|orta/i.test(lv) ? "B2" : null;
      if (cefr) langLevels[lng.toLowerCase()] = cefr;
    }
  });

  return {
    email: emailMatch ? emailMatch[0] : null,
    phone: phoneMatch ? phoneMatch[0] : null,
    linkedIn: linkedinMatch ? "https://" + linkedinMatch[0] : null,
    totalYears: Math.min(totalYears, 50),
    yearRanges,
    universities: foundUniversities,
    highestEdu,
    skills: foundSkills,
    languages: langLevels,
    rawTextSnippet: text.slice(0, 500),
    rawTextLength: rawText.length,
  };
}

// Bir başvuruyu pozisyon gereksinimlerine göre skorla — 0-100
function scoreApplication(parsedCV, position) {
  if (!parsedCV || !position) {
    return { total: 0, breakdown: {}, matches: {}, gaps: [] };
  }
  const reqs = position.dynamicRequirements || [];
  if (reqs.length === 0) {
    // Gereksinim yoksa minimum şartlar üzerinden basit skor
    const expYears = Number(position.experienceYears) || 0;
    const expScore = expYears === 0 ? 100 : Math.min(100, Math.round((parsedCV.totalYears / expYears) * 100));
    return {
      total: expScore,
      breakdown: { experience: expScore },
      matches: { experience: parsedCV.totalYears + " yıl / " + expYears + " yıl beklenen" },
      gaps: [],
    };
  }

  // Her bir requirement'a göre puan ver (0 veya 100)
  // Ağırlıklı ortalama: zorunluların ağırlığı 2x tercihen
  let totalWeight = 0;
  let earnedWeight = 0;
  const matches = {};
  const gaps = [];
  const breakdown = {};

  reqs.forEach((req, idx) => {
    const weight = req.required ? 2 : 1;
    totalWeight += weight;
    let matched = false;
    let matchInfo = "";

    if (req.kind === "skill" && req.value) {
      const skillLower = String(req.value).toLowerCase();
      matched = (parsedCV.skills || []).some(s => s.toLowerCase() === skillLower || s.toLowerCase().includes(skillLower) || skillLower.includes(s.toLowerCase()));
      matchInfo = matched ? `✓ ${req.value} CV'de bulundu` : "";
    } else if (req.kind === "experience") {
      const minYears = Number(req.value) || 0;
      matched = parsedCV.totalYears >= minYears;
      matchInfo = `${parsedCV.totalYears} yıl deneyim / ${minYears} yıl beklenen`;
    } else if (req.kind === "education" && req.value) {
      // value: "bachelor", "master", vb. → CV'deki highestEdu'dan büyük veya eşit
      const levels = ["high_school", "associate", "bachelor", "master", "phd"];
      const needIdx = levels.indexOf(req.value);
      const haveIdx = levels.indexOf(parsedCV.highestEdu);
      matched = haveIdx >= 0 && needIdx >= 0 && haveIdx >= needIdx;
      matchInfo = matched ? `✓ ${parsedCV.highestEdu} ≥ ${req.value}` : `✗ ${parsedCV.highestEdu || "?"} < ${req.value}`;
    } else if (req.kind === "language" && req.value) {
      const lower = String(req.value).toLowerCase();
      const haveLvl = parsedCV.languages?.[lower];
      const cefrOrder = ["A1","A2","B1","B2","C1","C2"];
      const need = req.minLevel || "B2";
      matched = haveLvl && cefrOrder.indexOf(haveLvl) >= cefrOrder.indexOf(need);
      matchInfo = matched ? `✓ ${req.value}: ${haveLvl}` : `✗ ${req.value}: ${haveLvl || "yok"} < ${need}`;
    } else if (req.kind === "certificate" && req.value) {
      matched = new RegExp(req.value, "i").test(parsedCV.rawTextSnippet || "");
      matchInfo = matched ? `✓ ${req.value} bulundu` : "";
    } else if (req.kind === "other" && req.value) {
      matched = new RegExp(req.value, "i").test(parsedCV.rawTextSnippet || "");
      matchInfo = matched ? `✓ ${req.value}` : "";
    }

    if (matched) {
      earnedWeight += weight;
      matches[req.id || `r_${idx}`] = matchInfo;
    } else {
      gaps.push({
        kind: req.kind,
        label: req.label || req.value,
        required: req.required,
      });
    }
    breakdown[req.id || `r_${idx}`] = matched ? 100 : 0;
  });

  const total = totalWeight > 0 ? Math.round((earnedWeight / totalWeight) * 100) : 0;
  return { total, breakdown, matches, gaps };
}

