function TopBar({ session, onLogout, view, setView, data, onChangeData, canAct, lang, changeLang, theme, changeTheme, linkedEmployee, onSwitchToSelfService }) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [companyMenuOpen, setCompanyMenuOpen] = useState(false);
  const [langMenuOpen, setLangMenuOpen] = useState(false);
  const [themeMenuOpen, setThemeMenuOpen] = useState(false);

  const THEMES = [
    { code: "classic",  name: lang === "en" ? "Classic" : "Klasik",      icon: "🎨", color: "#0a4d4a", desc: lang === "en" ? "Corporate green" : "Kurumsal yeşil" },
    { code: "modern",   name: lang === "en" ? "Modern" : "Modern",       icon: "💎", color: "#0891b2", desc: lang === "en" ? "Cyan light" : "Cyan açık" },
    { code: "dark",     name: lang === "en" ? "Dark" : "Karanlık",       icon: "🌙", color: "#1c1917", desc: lang === "en" ? "Dark mode" : "Karanlık mod" },
    { code: "midnight", name: lang === "en" ? "Midnight" : "Gece",       icon: "🌌", color: "#0f172a", desc: lang === "en" ? "Navy night" : "Lacivert gece" },
  ];

  // Bildirim sayısı: 7 gün içinde vadesi olan veya geçmiş açık faturalar
  const invoiceAlertCount = useMemo(() => {
    const today = new Date(); today.setHours(0,0,0,0);
    const limit = new Date(today); limit.setDate(limit.getDate() + 7);
    let count = 0;
    (data.invoices || []).forEach(inv => {
      if (!inv.dueDate) return;
      const remaining = (Number(inv.total) || 0) - (Number(inv.paidAmount) || 0);
      if (remaining <= 0.01) return;
      const due = new Date(inv.dueDate);
      if (isNaN(due.getTime())) return;
      if (due <= limit) count++; // bugünden 7 gün sonrasına kadar + geçmişler
    });
    return count;
  }, [data.invoices]);

  const items = [
    { id: "dashboard",  label: t("menu.dashboard", lang),  icon: LayoutDashboard, perm: "view_dashboard", resource: "finance.dashboard" },
    { id: "cashflow_dashboard", label: lang === "en" ? "Cash Flow" : lang === "de" ? "Cashflow" : lang === "ar" ? "التدفق النقدي" : "Nakit Akışı", icon: LineChartIcon, perm: "view_dashboard", resource: "finance.dashboard" },
    { id: "grid",       label: t("menu.cashflow", lang),   icon: Table2,          perm: "view_grid",      resource: "finance.cashflow" },
    { id: "banks",      label: t("menu.banks", lang),      icon: Landmark,        perm: "view_banks",     resource: "finance.banks" },
    { id: "kasa",       label: t("menu.kasa", lang),       icon: Wallet,          perm: "view_kasa",      resource: "finance.kasa" },
    { id: "loans",      label: t("menu.loans", lang),      icon: Banknote,        perm: "view_loans",     resource: "finance.loans" },
    { id: "invoices",   label: t("menu.invoices", lang),   icon: Receipt,         perm: "view_invoices",  resource: "finance.invoices", badge: invoiceAlertCount },
    { id: "payments",   label: t("menu.payments", lang),   icon: CreditCard,      perm: "view_invoices",  resource: "finance.payments" },
    { id: "transfers",  label: t("menu.transfers", lang),  icon: ArrowLeftRight,  perm: "view_transfers", resource: "finance.transfers" },
    { id: "parties",    label: lang === "en" ? "Parties (AR/AP)" : lang === "de" ? "Geschäftspartner" : lang === "ar" ? "العملاء" : "Cari Yönetimi", icon: Building2, perm: "view_accounting", resource: "accounting.parties" },
    { id: "hr",         label: t("menu.hr", lang),         icon: Briefcase,       perm: "view_hr",        resource: "hr.organization" },
    { id: "accounting", label: lang === "en" ? "Accounting" : lang === "de" ? "Buchhaltung" : lang === "ar" ? "المحاسبة" : "Muhasebe", icon: ClipboardList, perm: "manage_categories", resource: "accounting.coa" },
    { id: "fx",         label: t("menu.fx", lang),         icon: TrendingUp,      perm: "view_fx_revaluation", resource: "finance.fx" },
    { id: "ai",         label: t("menu.ai", lang),         icon: Sparkles,        perm: "view_ai_prediction",  resource: "finance.ai_prediction" },
    { id: "reports",    label: lang === "en" ? "Reports Center" : "Rapor Merkezi",    icon: BarChart3,       perm: "view_dashboard",   resource: "finance.dashboard" },
    { id: "categories", label: t("menu.categories", lang), icon: FolderTree,      perm: "manage_categories", resource: "finance.categories" },
    { id: "users",      label: t("menu.users", lang),      icon: Users,           perm: "manage_users",   resource: "system.users" },
    { id: "audit",      label: t("menu.audit", lang),      icon: History,         perm: "view_audit",     resource: "system.audit" },
    { id: "settings",   label: t("menu.settings", lang),   icon: Settings,        perm: "system_settings", resource: "system.settings" },
  ];

  const setDisplayCurrency = async (cur) => {
    await onChangeData({ ...data, displayCurrency: cur });
  };

  const switchCompany = async (companyId) => {
    await onChangeData({ ...data, activeCompanyId: companyId });
    setCompanyMenuOpen(false);
  };

  // Görünür item'lar: yeni resource.action varsa onu kontrol et, yoksa eski perm
  // canAct sayesinde custom rol grant'leri de devreye girer
  const visibleItems = items.filter(i => {
    if (canAct && i.resource && canAct(`${i.resource}.view`)) return true;
    return can(session.role, i.perm);
  });
  const currentItem = visibleItems.find(i => i.id === view);
  const companies = data.companies || [];
  const activeCompany = companies.find(c => c.id === data.activeCompanyId) || companies[0];

  return (
    <div className="sticky top-0 z-30" style={{ background: "var(--paper)", borderBottom: "1px solid var(--line)" }}>
      <div className="max-w-[1440px] mx-auto px-3 md:px-5 h-12 flex items-center gap-2 md:gap-4">
        {/* Logo */}
        <div className="flex items-center gap-2 flex-shrink-0">
          <Logo size={22}/>
          <div className="hidden sm:block"><Wordmark size={16}/></div>
        </div>

        {/* Şirket seçici */}
        {companies.length > 0 && activeCompany && (
          <div className="relative flex-shrink-0">
            <button onClick={() => setCompanyMenuOpen(!companyMenuOpen)}
              className="flex items-center gap-1.5 px-2 md:px-2.5 py-1 rounded font-medium transition-colors"
              style={{ background: "var(--bg-alt)", color: "var(--ink)", fontSize: 11.5 }}>
              <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ background: activeCompany.color }}/>
              <span className="hidden md:inline truncate max-w-[140px]">{activeCompany.name}</span>
              <ChevronDown size={10} className={`transition-transform ${companyMenuOpen ? "rotate-180" : ""}`}/>
            </button>
            {companyMenuOpen && (
              <>
                <div className="fixed inset-0 z-20" onClick={() => setCompanyMenuOpen(false)}/>
                <div className="absolute left-0 mt-1 rounded shadow-lg z-30 min-w-[240px]"
                  style={{ background: "var(--paper)", border: "1px solid var(--line)" }}>
                  <div className="p-2 border-b" style={{ borderColor: "var(--line-soft)" }}>
                    <div className="label">Aktif Şirket</div>
                  </div>
                  <div className="max-h-80 overflow-y-auto py-1">
                    {companies.map(c => (
                      <button key={c.id} onClick={() => switchCompany(c.id)}
                        className="w-full flex items-center gap-2 px-3 py-2 text-left text-sm hover:bg-stone-50">
                        <span className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ background: c.color }}/>
                        <span className="flex-1 truncate">{c.name}</span>
                        {c.taxNo && <span className="text-xs mono" style={{ color: "var(--ink-mute)" }}>{c.taxNo}</span>}
                        {c.id === data.activeCompanyId && <Check size={12} style={{ color: "var(--accent)" }}/>}
                      </button>
                    ))}
                  </div>
                  {can(session.role, "manage_companies") && (
                    <div className="p-2 border-t" style={{ borderColor: "var(--line-soft)" }}>
                      <button onClick={() => { setCompanyMenuOpen(false); setView("settings"); }}
                        className="w-full flex items-center gap-2 px-2 py-1.5 rounded text-xs hover:bg-stone-50"
                        style={{ color: "var(--accent)" }}>
                        <Settings size={11}/> Şirketleri Yönet
                      </button>
                    </div>
                  )}
                </div>
              </>
            )}
          </div>
        )}

        {/* Mobil aktif sayfa göstergesi */}
        {currentItem && (
          <div className="md:hidden flex items-center gap-1.5 text-xs font-medium flex-1 truncate">
            <currentItem.icon size={13}/>
            <span className="truncate">{currentItem.label}</span>
          </div>
        )}

        {/* Boş alan — eskiden desktop nav vardı, artık sol sidebar'da */}
        <div className="flex-1"/>

        {/* Sağ taraf */}
        <div className="flex items-center gap-1.5 md:gap-2 flex-shrink-0">
          {/* Para birimi seçici — sm+ */}
          <div className="hidden sm:flex items-center rounded" style={{ background: "var(--bg-alt)", padding: 1 }}>
            {["TRY", "USD", "EUR"].map(c => (
              <button key={c} onClick={() => setDisplayCurrency(c)}
                className="px-1.5 py-0.5 rounded font-medium transition-colors"
                style={{
                  background: data.displayCurrency === c ? "var(--accent)" : "transparent",
                  color: data.displayCurrency === c ? "#fff" : "var(--ink-mute)",
                  fontSize: 11,
                }}>
                {CURRENCY_SYMBOLS[c]}<span className="hidden lg:inline"> {c}</span>
              </button>
            ))}
          </div>
          {/* Dil seçici */}
          {changeLang && (
            <div className="relative">
              <button onClick={() => setLangMenuOpen(!langMenuOpen)}
                className="btn btn-ghost flex items-center gap-1"
                title={t("common.language", lang)}>
                <span style={{ fontSize: 14 }}>{LANGUAGES[lang]?.flag}</span>
                <span className="hidden md:inline text-xs font-medium uppercase">{lang}</span>
                <ChevronDown size={10} className={`transition-transform ${langMenuOpen ? "rotate-180" : ""}`}/>
              </button>
              {langMenuOpen && (
                <>
                  <div className="fixed inset-0 z-20" onClick={() => setLangMenuOpen(false)}/>
                  <div className="absolute right-0 mt-1 rounded shadow-lg z-30 min-w-[180px]"
                    style={{ background: "var(--paper)", border: "1px solid var(--line)" }}>
                    <div className="p-2 border-b" style={{ borderColor: "var(--line-soft)" }}>
                      <div className="label">{t("common.language", lang)}</div>
                    </div>
                    <div className="py-1">
                      {Object.values(LANGUAGES).map(L => (
                        <button key={L.code} onClick={() => { changeLang(L.code); setLangMenuOpen(false); }}
                          className="w-full flex items-center gap-2 px-3 py-2 text-left text-sm hover:bg-stone-50">
                          <span style={{ fontSize: 16 }}>{L.flag}</span>
                          <span className="flex-1">{L.nameNative}</span>
                          {L.code === lang && <Check size={12} style={{ color: "var(--accent)" }}/>}
                        </button>
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>
          )}
          {/* Tema Seçici */}
          {changeTheme && (
            <div className="relative">
              <button onClick={() => setThemeMenuOpen(!themeMenuOpen)}
                className="btn btn-ghost flex items-center gap-1"
                style={{ padding: "4px 8px" }}
                title={lang === "en" ? "Theme" : "Tema"}>
                <span style={{ fontSize: 14 }}>
                  {THEMES.find(t => t.code === theme)?.icon || "🎨"}
                </span>
                <ChevronDown size={10} className={`transition-transform ${themeMenuOpen ? "rotate-180" : ""}`}/>
              </button>
              {themeMenuOpen && (
                <>
                  <div className="fixed inset-0 z-20" onClick={() => setThemeMenuOpen(false)}/>
                  <div className="absolute right-0 mt-1 rounded shadow-lg z-30 min-w-[200px]"
                    style={{ background: "var(--paper)", border: "1px solid var(--line)" }}>
                    <div className="p-2 border-b" style={{ borderColor: "var(--line-soft)" }}>
                      <div className="label">{lang === "en" ? "Theme" : "Tema"}</div>
                    </div>
                    <div className="py-1">
                      {THEMES.map(T => (
                        <button key={T.code}
                          onClick={() => { changeTheme(T.code); setThemeMenuOpen(false); }}
                          className="w-full flex items-center gap-2 px-3 py-2 text-left text-sm hover:bg-stone-50"
                          style={{ background: T.code === theme ? "var(--bg-alt)" : "transparent" }}>
                          <span style={{
                            width: 22, height: 22, borderRadius: 4,
                            background: T.color,
                            display: "flex", alignItems: "center", justifyContent: "center",
                            fontSize: 12,
                            flexShrink: 0,
                          }}>
                            {T.icon}
                          </span>
                          <div style={{ flex: 1, minWidth: 0 }}>
                            <div style={{ fontWeight: 600, fontSize: 12 }}>{T.name}</div>
                            <div style={{ fontSize: 10, color: "var(--ink-mute)" }}>{T.desc}</div>
                          </div>
                          {T.code === theme && <Check size={12} style={{ color: "var(--accent)" }}/>}
                        </button>
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>
          )}

          {/* Bildirimler (Bell) */}
          <div className="hidden md:inline-flex">
            <NotificationBell session={session} data={data} onChange={onChangeData} lang={lang}
              onNavigate={(link) => {
                if (link?.type === "request" || link?.type === "leave") {
                  setView("hr");
                }
              }}/>
          </div>
          {linkedEmployee && onSwitchToSelfService && (
            <button onClick={onSwitchToSelfService} className="btn btn-ghost hidden md:inline-flex"
              title={lang === "en" ? "Switch to Self-Service Portal" : "Self-Servis Portala Geç"}
              style={{ color: "#7c3aed" }}>
              <Users size={13}/>
              <span className="ml-1 text-xs">{lang === "en" ? "Self-Service" : "Self-Servis"}</span>
            </button>
          )}
          <button onClick={onLogout} className="btn btn-ghost hidden md:inline-flex" title={t("login.submit", lang)}>
            <LogOut size={13}/>
          </button>
          {/* Mobil bell */}
          <div className="md:hidden">
            <NotificationBell session={session} data={data} onChange={onChangeData} lang={lang}
              onNavigate={(link) => {
                if (link?.type === "request" || link?.type === "leave") setView("hr");
              }}/>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   MUHASEBE MODÜLÜ — ANA WRAPPER (Tab Navigation)
   ---------------------------------------------------------------------
   Hesap Planı | Yevmiye Fişleri | Mizan | Bilanço | Gelir Tablosu
===================================================================== */
function AccountingModule({ data, session, canAct, lang, onChange, logAudit, notify, activeTab: activeTabProp, setActiveTab: setActiveTabProp }) {
  const [activeTabState, setActiveTabState] = useState("coa");
  const activeTab = activeTabProp ?? activeTabState;
  const setActiveTab = setActiveTabProp ?? setActiveTabState;

  // Çek/Senet veya başka modülden yönlendirme: localStorage kontrolü
  useEffect(() => {
    try {
      const targetVoucher = localStorage.getItem("prometa_goto_journal_voucher");
      if (targetVoucher) {
        setActiveTab("journal");
        // Voucher no'yu temizlemiyoruz; JournalEntriesManager kendi okuyup highlight edecek
      }
    } catch (e) {}
  }, []);

  const tabs = [
    { id: "coa",       label: { tr: "Hesap Planı",      en: "Chart of Accounts" }, icon: ClipboardList },
    { id: "journal",   label: { tr: "Yevmiye Fişleri",  en: "Journal Entries" },   icon: FileText },
    { id: "ledger",    label: { tr: "Defter-i Kebir",   en: "General Ledger" },    icon: BookOpen },
    { id: "trial",     label: { tr: "Mizan",            en: "Trial Balance" },     icon: Scale },
    { id: "balance",   label: { tr: "Bilanço",          en: "Balance Sheet" },     icon: Landmark },
    { id: "income",    label: { tr: "Gelir Tablosu",    en: "Income Statement" },  icon: TrendingUp },
    { id: "cashflow",  label: { tr: "Nakit Akış",       en: "Cash Flow" },         icon: Banknote },
    { id: "yearend",   label: { tr: "Yıl Kapanışı",     en: "Year-End Close" },    icon: Lock,      accent: "#b91c1c" },
    { id: "ai",        label: { tr: "AI Öğrenme",       en: "AI Learning" },       icon: Sparkles,  accent: "#7c3aed" },
  ];

  const activeTabConfig = tabs.find(t => t.id === activeTab) || tabs[0];

  return (
    <div className="space-y-3">
      {/* Modül başlığı */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <div>
          <div className="label">{lang === "en" ? "Accounting" : "Muhasebe"}</div>
          <h1 className="display text-2xl md:text-3xl">
            {lang === "en" ? "General Ledger" : "Genel Muhasebe"}
          </h1>
        </div>
      </div>

      {/* İçerik — alt sekme navigasyonu menüye taşındı (akordeon) */}
      <div className="flex gap-3" style={{ minHeight: 600 }}>
        {/* Sağ İçerik */}
        <div style={{ flex: 1, minWidth: 0 }}>
          {activeTab === "coa" && (
            <ChartOfAccountsManager
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "journal" && (
            <JournalEntriesManager
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "trial" && (
            <TrialBalanceManager
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "ledger" && (
            <GeneralLedgerReport
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "balance" && (
            <BalanceSheetReport
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "income" && (
            <IncomeStatementReport
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "cashflow" && (
            <CashFlowStatementReport
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "yearend" && (
            <YearEndCloseManager
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
          {activeTab === "ai" && (
            <AILearningDashboard
              data={data} session={session} canAct={canAct} lang={lang}
              onChange={onChange} logAudit={logAudit} notify={notify}
            />
          )}
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   YEVMİYE FİŞLERİ YÖNETİCİSİ (Journal Entries Manager)
   ---------------------------------------------------------------------
   Liste + Filtre + Yeni Fiş + Düzenle + Onayla/İptal
===================================================================== */
function JournalEntriesManager({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];

  const canEdit = canAct ? canAct("accounting.journal.update") || can(session.role, "edit_cells") : can(session.role, "edit_cells");
  const canDelete = canAct ? canAct("accounting.journal.delete") || can(session.role, "edit_cells") : can(session.role, "edit_cells");

  // UI state
  const [search, setSearch] = useState("");
  const [filterType, setFilterType] = useState("all");
  const [filterStatus, setFilterStatus] = useState("all");
  const [filterSource, setFilterSource] = useState("all");
  const [filterDateFrom, setFilterDateFrom] = useState("");
  const [filterDateTo, setFilterDateTo] = useState("");
  const [editingEntry, setEditingEntry] = useState(null); // { mode, data }
  const [viewingEntry, setViewingEntry] = useState(null);
  const [highlightVoucherNo, setHighlightVoucherNo] = useState(null);
  const [showEdefter, setShowEdefter] = useState(false); // e-Defter XBRL-GL üretim modalı

  // Çek/Senet modülünden yönlendirme: localStorage'dan hedef fişi al
  useEffect(() => {
    try {
      const targetVoucher = localStorage.getItem("prometa_goto_journal_voucher");
      if (targetVoucher) {
        localStorage.removeItem("prometa_goto_journal_voucher");
        // Search'e voucher no koy + highlight ver
        setSearch(targetVoucher);
        setHighlightVoucherNo(targetVoucher);
        // 4 sn sonra highlight'ı temizle
        const t = setTimeout(() => setHighlightVoucherNo(null), 4000);
        // Scroll: fişe doğru kaydır
        setTimeout(() => {
          const el = document.querySelector(`[data-voucher-no="${targetVoucher}"]`);
          if (el) el.scrollIntoView({ behavior: "smooth", block: "center" });
        }, 200);
        return () => clearTimeout(t);
      }
    } catch (e) {}
  }, []);

  // === İşlemler ===
  const handleNew = (voucherType = "compound") => {
    setEditingEntry({ mode: "create", voucherType, data: null });
  };

  const handleEdit = (entry) => {
    if (entry.status === "posted") {
      notify(lang === "en" ? "Posted entries cannot be edited. Cancel first." : "Onaylı fişler düzenlenemez. Önce iptal edin.", "err");
      return;
    }
    setEditingEntry({ mode: "edit", voucherType: entry.voucherType, data: entry });
  };

  const handlePost = async (entry) => {
    if (entry.status === "posted") return;
    const validation = validateJournalEntry(entry, accounts);
    if (!validation.valid) {
      notify(validation.error, "err");
      return;
    }
    // GİB asgari-bilgi denetimi (Elektronik Muhasebe Fişi Kılavuzu, Bölüm 2)
    const gib = validateGibFis(entry);
    if (!gib.valid) {
      notify((lang === "en" ? "GİB required fields missing: " : "GİB zorunlu alanları eksik: ") + gib.missing.join(", "), "err");
      return;
    }
    const next = entries.map(e => e.id === entry.id ? {
      ...e,
      status: "posted",
      entryTime: e.entryTime || nowHHMM(),
      postedAt: new Date().toISOString(),
      postedBy: session.username,
      approvedByName: session.fullName || session.username, // GİB: fişi onaylayanın adı soyadı
    } : e);
    await onChange({ ...data, accJournalEntries: next });
    logAudit && logAudit("post", "journal_entry", { voucherNo: entry.voucherNo });
    if (gib.warnings && gib.warnings.length) {
      notify((lang === "en" ? "Posted. Pending: " : "Onaylandı. Eksik (deftere işlenince tamamlanır): ") + gib.warnings.join(", "));
    } else {
      notify(lang === "en" ? "Entry posted" : "Fiş onaylandı");
    }
  };

  const handleCancel = async (entry) => {
    if (entry.status === "cancelled") return;
    if (!confirm(lang === "en"
      ? `Cancel entry ${entry.voucherNo}?`
      : `${entry.voucherNo} numaralı fiş iptal edilsin mi?`)) return;
    const next = entries.map(e => e.id === entry.id ? {
      ...e,
      status: "cancelled",
      cancelledAt: new Date().toISOString(),
      cancelledBy: session.username,
    } : e);
    await onChange({ ...data, accJournalEntries: next });
    logAudit && logAudit("cancel", "journal_entry", { voucherNo: entry.voucherNo });
    notify(lang === "en" ? "Entry cancelled" : "Fiş iptal edildi");
  };

  // Reverse: Ters bir fiş üret (orijinal kalır, audit için doğru pratik)
  const handleReverse = async (entry) => {
    if (entry.status !== "posted") {
      notify(lang === "en" ? "Only posted entries can be reversed" : "Sadece onaylı fişler geri alınabilir", "err");
      return;
    }
    // Daha önce geri alınmış mı?
    const alreadyReversed = entries.some(e => e.reversesEntryId === entry.id && e.status !== "cancelled");
    if (alreadyReversed) {
      notify(lang === "en"
        ? "This entry has already been reversed"
        : "Bu fiş zaten geri alınmış", "err");
      return;
    }

    if (!confirm(lang === "en"
      ? `Reverse entry ${entry.voucherNo}? A new entry with swapped debit/credit will be created.`
      : `${entry.voucherNo} numaralı fiş geri alınsın mı? Borç/alacak tersi yeni bir fiş oluşturulacak.`)) return;

    // Ters fişi üret
    const reverseEntry = generateReverseVoucher(entry, session, entries);
    const next = [...entries, reverseEntry];
    await onChange({ ...data, accJournalEntries: next });
    logAudit && logAudit("reverse", "journal_entry", {
      original: entry.voucherNo,
      reverse: reverseEntry.voucherNo,
    });
    notify(lang === "en"
      ? `Reversed: ${reverseEntry.voucherNo} created`
      : `Geri alındı: ${reverseEntry.voucherNo} oluşturuldu`);
  };

  const handleDelete = async (entry) => {
    if (entry.status === "posted") {
      notify(lang === "en" ? "Cannot delete posted entries" : "Onaylı fişler silinemez", "err");
      return;
    }
    if (!confirm(lang === "en"
      ? `Delete entry ${entry.voucherNo}? This cannot be undone.`
      : `${entry.voucherNo} numaralı fiş silinsin mi? Bu işlem geri alınamaz.`)) return;
    const next = entries.filter(e => e.id !== entry.id);
    await onChange({ ...data, accJournalEntries: next });
    logAudit && logAudit("delete", "journal_entry", { voucherNo: entry.voucherNo });
    notify(lang === "en" ? "Entry deleted" : "Fiş silindi");
  };

  const handleSave = async (formData) => {
    let next;
    const totals = calculateEntryTotals(formData.lines);
    if (editingEntry.mode === "create") {
      const year = new Date(formData.date).getFullYear();
      const voucherNo = formData.voucherNo || generateVoucherNo(formData.voucherType, year, entries);
      const newEntry = {
        id: "je_" + Date.now(),
        voucherNo,
        voucherType: formData.voucherType,
        date: formData.date,
        entryTime: formData.entryTime || nowHHMM(),
        yevmiyeMaddeNo: formData.yevmiyeMaddeNo || "",
        description: formData.description || "",
        projectId: formData.projectId || null,
        lines: formData.lines,
        totalDebit: totals.totalDebit,
        totalCredit: totals.totalCredit,
        status: formData.status || "draft",
        source: formData.source || "manual",
        sourceId: formData.sourceId || null,
        tags: formData.tags || [],
        attachments: formData.attachments || [],
        createdAt: new Date().toISOString(),
        createdBy: session.username,
      };
      if (newEntry.status === "posted") {
        const gib = validateGibFis(newEntry);
        if (!gib.valid) {
          notify((lang === "en" ? "GİB required fields missing: " : "GİB zorunlu alanları eksik: ") + gib.missing.join(", "), "err");
          return;
        }
        newEntry.postedAt = new Date().toISOString();
        newEntry.postedBy = session.username;
        newEntry.approvedByName = session.fullName || session.username; // GİB: fişi onaylayanın adı soyadı
      }
      next = [...entries, newEntry];
      logAudit && logAudit("create", "journal_entry", { voucherNo });
      notify(lang === "en" ? "Entry created" : "Yevmiye fişi oluşturuldu");
    } else {
      const updated = {
        ...editingEntry.data,
        voucherType: formData.voucherType,
        date: formData.date,
        entryTime: formData.entryTime || editingEntry.data.entryTime || nowHHMM(),
        yevmiyeMaddeNo: formData.yevmiyeMaddeNo || "",
        description: formData.description || "",
        projectId: formData.projectId || null,
        lines: formData.lines,
        totalDebit: totals.totalDebit,
        totalCredit: totals.totalCredit,
        status: formData.status || "draft",
        updatedAt: new Date().toISOString(),
        updatedBy: session.username,
      };
      // Taslak → Onaylı geçişinde GİB denetimi + onay bilgisi
      if (updated.status === "posted" && editingEntry.data.status !== "posted") {
        const gib = validateGibFis(updated);
        if (!gib.valid) {
          notify((lang === "en" ? "GİB required fields missing: " : "GİB zorunlu alanları eksik: ") + gib.missing.join(", "), "err");
          return;
        }
        updated.postedAt = new Date().toISOString();
        updated.postedBy = session.username;
        updated.approvedByName = session.fullName || session.username;
      }
      next = entries.map(e => e.id === editingEntry.data.id ? updated : e);
      logAudit && logAudit("update", "journal_entry", { voucherNo: editingEntry.data.voucherNo });
      notify(lang === "en" ? "Entry updated" : "Yevmiye fişi güncellendi");
    }

    await onChange({ ...data, accJournalEntries: next });
    setEditingEntry(null);
  };

  // === e-Defter / GİB dışa aktarım (Elektronik Muhasebe Fişi Kılavuzu, Bölüm 3) ===
  const gibDownload = (content, filename, mime, bom = false) => {
    const blob = new Blob([bom ? "﻿" + content : content], { type: mime });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = filename;
    a.click();
    setTimeout(() => URL.revokeObjectURL(a.href), 1000);
  };

  const handleGibExport = (format) => {
    const list = filteredEntries.filter(e => e.status !== "cancelled");
    if (list.length === 0) {
      notify(lang === "en" ? "No entries to export" : "Dışa aktarılacak fiş yok", "err");
      return;
    }
    const mukellef = gibMukellef(data);
    const stamp = new Date().toISOString().slice(0, 10);
    if (format === "csv") {
      gibDownload(buildGibFisCsv(list, mukellef, accounts), `muhasebe_fisleri_${stamp}.csv`, "text/csv;charset=utf-8", true);
    } else if (format === "json") {
      gibDownload(buildGibFisJson(list, mukellef, accounts), `muhasebe_fisleri_${stamp}.json`, "application/json;charset=utf-8");
    } else if (format === "xml") {
      gibDownload(buildGibFisXml(list, mukellef, accounts), `muhasebe_fisleri_${stamp}.xml`, "application/xml;charset=utf-8");
    } else if (format === "pdf") {
      const win = window.open("", "_blank", "width=900,height=700");
      if (!win) { notify(lang === "en" ? "Popup blocked!" : "Popup engellendi! İzin verin.", "err"); return; }
      win.document.write(buildGibFisPrintHtml(list, mukellef, accounts, lang));
      win.document.close();
    }
    logAudit && logAudit("export", "journal_entry", { format, count: list.length });
    notify(lang === "en" ? `Exported ${list.length} entries (${format.toUpperCase()})` : `${list.length} fiş dışa aktarıldı (${format.toUpperCase()})`);
  };

  // === Filtreleme ===
  const filteredEntries = useMemo(() => {
    let list = entries;

    if (search.trim()) {
      const q = search.toLowerCase().trim();
      list = list.filter(e =>
        (e.voucherNo || "").toLowerCase().includes(q) ||
        (e.description || "").toLowerCase().includes(q) ||
        (e.lines || []).some(l =>
          (l.accountCode || "").toLowerCase().includes(q) ||
          (l.description || "").toLowerCase().includes(q)
        )
      );
    }

    if (filterType !== "all") list = list.filter(e => e.voucherType === filterType);
    if (filterStatus !== "all") list = list.filter(e => e.status === filterStatus);
    if (filterSource !== "all") list = list.filter(e => (e.source || "manual") === filterSource);
    if (filterDateFrom) list = list.filter(e => e.date >= filterDateFrom);
    if (filterDateTo) list = list.filter(e => e.date <= filterDateTo);

    // Tarihe göre son fiş önde
    list = [...list].sort((a, b) => {
      if (a.date !== b.date) return b.date.localeCompare(a.date);
      return (b.voucherNo || "").localeCompare(a.voucherNo || "");
    });
    return list;
  }, [entries, search, filterType, filterStatus, filterSource, filterDateFrom, filterDateTo]);

  // === İstatistikler ===
  const stats = useMemo(() => {
    const total = entries.length;
    const draft = entries.filter(e => e.status === "draft").length;
    const posted = entries.filter(e => e.status === "posted").length;
    const cancelled = entries.filter(e => e.status === "cancelled").length;
    const totalDebitPosted = entries
      .filter(e => e.status === "posted")
      .reduce((s, e) => s + (Number(e.totalDebit) || 0), 0);
    return { total, draft, posted, cancelled, totalDebitPosted };
  }, [entries]);

  return (
    <div className="space-y-3">
      {/* Toolbar */}
      <div className="card p-3">
        <div className="flex flex-wrap items-center gap-2 mb-2">
          {/* Arama */}
          <div className="relative flex-1 min-w-[200px]">
            <Search size={12} style={{ position: "absolute", left: 8, top: "50%", transform: "translateY(-50%)", color: "var(--ink-mute)" }}/>
            <input
              type="search"
              placeholder={lang === "en" ? "Search voucher, account, description..." : "Fiş no, hesap, açıklama ara..."}
              value={search}
              onChange={e => setSearch(e.target.value)}
              className="input w-full"
              style={{ paddingLeft: 26 }}
            />
          </div>

          {/* Tip filtresi */}
          <select value={filterType} onChange={e => setFilterType(e.target.value)} className="input text-xs" style={{ minWidth: 130 }}>
            <option value="all">{lang === "en" ? "All Types" : "Tüm Tipler"}</option>
            {Object.entries(VOUCHER_TYPES).map(([key, t]) => (
              <option key={key} value={key}>{t.label[lang] || t.label.tr}</option>
            ))}
          </select>

          {/* Durum filtresi */}
          <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)} className="input text-xs" style={{ minWidth: 120 }}>
            <option value="all">{lang === "en" ? "All Statuses" : "Tüm Durumlar"}</option>
            {Object.entries(VOUCHER_STATUS).map(([key, s]) => (
              <option key={key} value={key}>{s.label[lang] || s.label.tr}</option>
            ))}
          </select>

          {/* Kaynak filtresi */}
          <select value={filterSource} onChange={e => setFilterSource(e.target.value)} className="input text-xs" style={{ minWidth: 110 }}>
            <option value="all">{lang === "en" ? "All Sources" : "Tüm Kaynaklar"}</option>
            {Object.entries(VOUCHER_SOURCES).map(([key, s]) => (
              <option key={key} value={key}>{s.label[lang] || s.label.tr}</option>
            ))}
          </select>

          {/* e-Defter / GİB dışa aktarım */}
          <select
            className="input text-xs ml-auto"
            style={{ minWidth: 150 }}
            value=""
            onChange={e => { if (e.target.value) { handleGibExport(e.target.value); e.target.value = ""; } }}
            title={lang === "en" ? "Export per GİB e-Ledger voucher format" : "GİB Elektronik Muhasebe Fişi formatında dışa aktar"}
          >
            <option value="">⬇ {lang === "en" ? "e-Ledger Export" : "e-Defter Dışa Aktar"}</option>
            <option value="xml">XML</option>
            <option value="csv">CSV</option>
            <option value="json">JSON</option>
            <option value="pdf">PDF {lang === "en" ? "(print)" : "(yazdır)"}</option>
          </select>

          {/* e-Defter XBRL-GL üretimi (Faz 2) */}
          <button
            onClick={() => setShowEdefter(true)}
            className="btn btn-ghost text-xs"
            title={lang === "en" ? "Generate e-Ledger (XBRL-GL) journal & ledger books" : "e-Defter (XBRL-GL) Yevmiye & Kebir üret"}
          >
            <BookOpen size={13}/> e-Defter
          </button>

          {/* Yeni fiş butonları */}
          {canEdit && (
            <div className="flex items-center gap-1">
              <NewVoucherDropdown onNew={handleNew} lang={lang}/>
            </div>
          )}
        </div>

        {/* Tarih filtresi */}
        <div className="flex flex-wrap items-center gap-2 text-xs">
          <span style={{ color: "var(--ink-mute)" }}>{lang === "en" ? "Date range:" : "Tarih aralığı:"}</span>
          <input type="date" className="input mono" value={filterDateFrom}
            onChange={e => setFilterDateFrom(e.target.value)} style={{ width: 140 }}/>
          <span style={{ color: "var(--ink-mute)" }}>—</span>
          <input type="date" className="input mono" value={filterDateTo}
            onChange={e => setFilterDateTo(e.target.value)} style={{ width: 140 }}/>
          {(filterDateFrom || filterDateTo) && (
            <button onClick={() => { setFilterDateFrom(""); setFilterDateTo(""); }}
              className="btn btn-ghost text-xs">
              {lang === "en" ? "Clear" : "Temizle"}
            </button>
          )}

          <div className="ml-auto flex items-center gap-3" style={{ color: "var(--ink-mute)" }}>
            <span>
              {lang === "en" ? "Total" : "Toplam"}: <b>{stats.total}</b>
            </span>
            <span>
              {lang === "en" ? "Draft" : "Taslak"}: <b style={{ color: "#737373" }}>{stats.draft}</b>
            </span>
            <span>
              {lang === "en" ? "Posted" : "Onaylı"}: <b style={{ color: "#15803d" }}>{stats.posted}</b>
            </span>
            <span>
              {lang === "en" ? "Cancelled" : "İptal"}: <b style={{ color: "#b91c1c" }}>{stats.cancelled}</b>
            </span>
          </div>
        </div>
      </div>

      {/* Liste */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        {/* Header */}
        <div
          className="flex items-center gap-2"
          style={{
            background: "var(--bg-alt)",
            borderBottom: "2px solid var(--line)",
            padding: "8px 12px",
            fontSize: 10,
            fontWeight: 700,
            color: "var(--ink-mute)",
            textTransform: "uppercase",
            letterSpacing: 0.4,
          }}
        >
          <div style={{ width: 130, flexShrink: 0 }}>{lang === "en" ? "Voucher No" : "Fiş No"}</div>
          <div style={{ width: 90, flexShrink: 0 }}>{lang === "en" ? "Date" : "Tarih"}</div>
          <div style={{ width: 90, flexShrink: 0 }}>{lang === "en" ? "Type" : "Tipi"}</div>
          <div className="flex-1 min-w-0">{lang === "en" ? "Description" : "Açıklama"}</div>
          <div style={{ width: 110, textAlign: "right", flexShrink: 0 }}>{lang === "en" ? "Debit" : "Borç"}</div>
          <div style={{ width: 110, textAlign: "right", flexShrink: 0 }}>{lang === "en" ? "Credit" : "Alacak"}</div>
          <div style={{ width: 90, flexShrink: 0 }}>{lang === "en" ? "Status" : "Durum"}</div>
          <div style={{ width: 90, flexShrink: 0 }}/>
        </div>

        {/* Rows */}
        <div style={{ maxHeight: "calc(100vh - 420px)", overflowY: "auto" }}>
          {filteredEntries.length === 0 ? (
            <div className="p-10 text-center" style={{ color: "var(--ink-mute)" }}>
              <ClipboardList size={40} style={{ margin: "0 auto", opacity: 0.3 }}/>
              <div className="text-sm mt-2">
                {entries.length === 0
                  ? (lang === "en" ? "No journal entries yet. Click \"New\" to create one." : "Henüz yevmiye fişi yok. \"Yeni\" butonu ile oluşturun.")
                  : (lang === "en" ? "No entries match your filters" : "Filtreye uyan fiş bulunamadı")}
              </div>
            </div>
          ) : (
            filteredEntries.map(entry => {
              const typeCfg = VOUCHER_TYPES[entry.voucherType] || VOUCHER_TYPES.compound;
              const statusCfg = VOUCHER_STATUS[entry.status] || VOUCHER_STATUS.draft;
              const isHighlighted = highlightVoucherNo === entry.voucherNo;
              return (
                <div key={entry.id}
                  data-voucher-no={entry.voucherNo}
                  className="flex items-center gap-2 border-b hover:bg-bgAlt transition-colors group"
                  style={{
                    borderColor: "var(--line)",
                    padding: "8px 12px",
                    opacity: entry.status === "cancelled" ? 0.55 : 1,
                    background: isHighlighted ? "#fef3c7" : "transparent",
                    boxShadow: isHighlighted ? "0 0 0 2px #ca8a04 inset" : "none",
                    transition: "background 0.3s, box-shadow 0.3s",
                  }}
                >
                  <div className="mono" style={{ width: 130, fontSize: 11, fontWeight: 700, color: typeCfg.color, flexShrink: 0 }}>
                    {entry.voucherNo}
                  </div>
                  <div className="mono" style={{ width: 90, fontSize: 11, flexShrink: 0 }}>
                    {entry.date}
                  </div>
                  <div style={{ width: 90, flexShrink: 0 }}>
                    <span style={{
                      padding: "2px 6px", fontSize: 9, fontWeight: 700, borderRadius: 3,
                      color: typeCfg.color, border: `1px solid ${typeCfg.color}`,
                      textTransform: "uppercase",
                    }}>
                      {typeCfg.label[lang] || typeCfg.label.tr}
                    </span>
                  </div>
                  <div className="flex-1 min-w-0 truncate" style={{ fontSize: 11.5 }}>
                    {entry.description || "—"}
                    {entry.source && entry.source !== "manual" && (
                      <span className="ml-2 chip" style={{
                        background: "#7c3aed20", color: "#7c3aed",
                        padding: "1px 5px", fontSize: 9, fontWeight: 600,
                      }}>
                        {(VOUCHER_SOURCES[entry.source]?.label[lang] || entry.source).toUpperCase()}
                      </span>
                    )}
                    {/* Reverse rozetleri */}
                    {entry.reversesEntryId && (
                      <span className="ml-2 chip" style={{
                        background: "#fef3c7", color: "#92400e",
                        padding: "1px 5px", fontSize: 9, fontWeight: 700,
                      }} title={lang === "en" ? "This is a reverse entry" : "Bu bir geri alma fişidir"}>
                        ↺ {lang === "en" ? "REVERSE" : "GERİ ALMA"}
                      </span>
                    )}
                    {(data.accJournalEntries || []).some(x => x.reversesEntryId === entry.id && x.status !== "cancelled") && (
                      <span className="ml-2 chip" style={{
                        background: "#fee2e2", color: "#b91c1c",
                        padding: "1px 5px", fontSize: 9, fontWeight: 700,
                      }} title={lang === "en" ? "This entry has been reversed" : "Bu fiş geri alınmıştır"}>
                        {lang === "en" ? "REVERSED" : "GERİ ALINDI"}
                      </span>
                    )}
                  </div>
                  <div className="mono text-right" style={{ width: 110, fontSize: 11, fontWeight: 600, flexShrink: 0 }}>
                    {fmtTL(Number(entry.totalDebit) || 0)} ₺
                  </div>
                  <div className="mono text-right" style={{ width: 110, fontSize: 11, fontWeight: 600, flexShrink: 0 }}>
                    {fmtTL(Number(entry.totalCredit) || 0)} ₺
                  </div>
                  <div style={{ width: 90, flexShrink: 0 }}>
                    <span style={{
                      padding: "2px 6px", fontSize: 9, fontWeight: 700, borderRadius: 3,
                      color: statusCfg.color, background: statusCfg.bg,
                      textTransform: "uppercase",
                    }}>
                      {statusCfg.label[lang] || statusCfg.label.tr}
                    </span>
                  </div>
                  <div className="flex items-center gap-0.5 flex-shrink-0 opacity-0 group-hover:opacity-100 transition-opacity" style={{ width: 90 }}>
                    <button onClick={() => setViewingEntry(entry)} className="p-1 rounded hover:bg-bg" title={lang === "en" ? "View" : "Görüntüle"}>
                      <Eye size={11}/>
                    </button>
                    {canEdit && entry.status === "draft" && (
                      <>
                        <button onClick={() => handleEdit(entry)} className="p-1 rounded hover:bg-bg" title={lang === "en" ? "Edit" : "Düzenle"}>
                          <Edit3 size={11}/>
                        </button>
                        <button onClick={() => handlePost(entry)} className="p-1 rounded hover:bg-bg" title={lang === "en" ? "Post" : "Onayla"} style={{ color: "#15803d" }}>
                          <Check size={11}/>
                        </button>
                      </>
                    )}
                    {canEdit && entry.status === "posted" && (
                      <>
                        <button
                          onClick={() => handleReverse(entry)}
                          className="p-1 rounded hover:bg-bg"
                          title={lang === "en" ? "Reverse (create reverse entry)" : "Geri Al (ters fiş üret)"}
                          style={{ color: "#7c3aed" }}
                        >
                          <RefreshCw size={11}/>
                        </button>
                        <button onClick={() => handleCancel(entry)} className="p-1 rounded hover:bg-bg" title={lang === "en" ? "Cancel (soft)" : "İptal Et (yumuşak)"} style={{ color: "#ca8a04" }}>
                          <X size={11}/>
                        </button>
                      </>
                    )}
                    {canDelete && entry.status !== "posted" && (
                      <button onClick={() => handleDelete(entry)} className="p-1 rounded hover:bg-bg" title={lang === "en" ? "Delete" : "Sil"} style={{ color: "#b91c1c" }}>
                        <Trash2 size={11}/>
                      </button>
                    )}
                  </div>
                </div>
              );
            })
          )}
        </div>
      </div>

      {/* Fiş Önizleme Modal */}
      {viewingEntry && (
        <JournalEntryViewModal
          entry={viewingEntry}
          accounts={accounts}
          lang={lang}
          onClose={() => setViewingEntry(null)}
          onEdit={() => { setViewingEntry(null); handleEdit(viewingEntry); }}
        />
      )}

      {/* Yeni/Düzenle Modal */}
      {editingEntry && (
        <JournalEntryFormModal
          mode={editingEntry.mode}
          voucherType={editingEntry.voucherType}
          entryData={editingEntry.data}
          accounts={accounts}
          entries={entries}
          projects={data.projects || []}
          lang={lang}
          onClose={() => setEditingEntry(null)}
          onSave={handleSave}
        />
      )}

      {/* e-Defter (XBRL-GL) Üretim Modalı */}
      {showEdefter && (
        <EdefterGenerateModal
          data={data}
          session={session}
          entries={entries}
          accounts={accounts}
          lang={lang}
          notify={notify}
          logAudit={logAudit}
          onClose={() => setShowEdefter(false)}
        />
      )}
    </div>
  );
}

/* ---------- e-Defter (XBRL-GL) Üretim Modalı (Faz 2) ---------- */
function EdefterGenerateModal({ data, session, entries, accounts, lang, notify, logAudit, onClose }) {
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [profile, setProfile] = useState(() => gibProfile(data));

  const setP = (k, v) => setProfile(p => ({ ...p, [k]: v }));
  const setAdr = (k, v) => setProfile(p => ({ ...p, address: { ...p.address, [k]: v } }));
  const setAcc = (k, v) => setProfile(p => ({ ...p, accountant: { ...p.accountant, [k]: v } }));

  const periodEntries = useMemo(
    () => selectPeriodEntries(entries, year, month),
    [entries, year, month],
  );
  const missing = useMemo(() => missingProfileFields(profile), [profile]);

  const download = (xml, filename) => {
    const blob = new Blob([xml], { type: "application/xml;charset=utf-8" });
    const a = document.createElement("a");
    a.href = URL.createObjectURL(blob);
    a.download = filename;
    a.click();
    setTimeout(() => URL.revokeObjectURL(a.href), 1000);
  };

  const generate = (kind) => {
    if (periodEntries.length === 0) {
      notify(lang === "en" ? "No posted entries in this period" : "Bu dönemde onaylı fiş yok", "err");
      return;
    }
    if (!profile.vkn) {
      notify(lang === "en" ? "VKN/TCKN required" : "VKN/TCKN zorunlu", "err");
      return;
    }
    if (kind === "yevmiye" || kind === "both") {
      download(buildYevmiyeXbrl({ profile, year, month, entries, accounts }),
        gibDefterFileName(profile.vkn, year, month, "Y"));
    }
    if (kind === "kebir" || kind === "both") {
      download(buildKebirXbrl({ profile, year, month, entries, accounts }),
        gibDefterFileName(profile.vkn, year, month, "K"));
    }
    logAudit && logAudit("export", "edefter_xbrl", { kind, period: `${year}-${month}`, count: periodEntries.length });
    notify(lang === "en" ? "e-Ledger XML generated" : "e-Defter XML üretildi (imzasız)");
  };

  const [signing, setSigning] = useState(false);
  // Faz 3: imzasız defteri backend'e gönder, Mali Mühür ile imzalat, imzalı
  // defter + beratı indir. Sertifika yoksa backend 503 döner (anlamlı mesaj).
  const signViaBackend = async (kind) => {
    if (periodEntries.length === 0) {
      notify(lang === "en" ? "No posted entries in this period" : "Bu dönemde onaylı fiş yok", "err");
      return;
    }
    if (!profile.vkn || profile.vkn.length < 10) {
      notify(lang === "en" ? "VKN/TCKN required" : "VKN/TCKN zorunlu", "err");
      return;
    }
    const apiBase = (typeof window !== "undefined" && window.PROMETCF_API) || "";
    const token = session?.token || (typeof localStorage !== "undefined" ? localStorage.getItem("promet_access_token") : "") || "";
    const unsignedDefterXml = kind === "journal"
      ? buildYevmiyeXbrl({ profile, year, month, entries, accounts })
      : buildKebirXbrl({ profile, year, month, entries, accounts });
    setSigning(true);
    try {
      const res = await fetch(`${apiBase}/v1/finance/edefter/sign`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify({ kind, unsignedDefterXml, profile, year, month }),
      });
      if (res.status === 503) {
        const j = await res.json().catch(() => ({}));
        notify(j.message || (lang === "en" ? "Mali Mühür certificate not configured" : "Mali Mühür sertifikası yapılandırılmamış"), "err");
        return;
      }
      if (!res.ok) {
        const j = await res.json().catch(() => ({}));
        notify(j.message || (lang === "en" ? "Signing failed" : "İmzalama başarısız"), "err");
        return;
      }
      const j = await res.json();
      download(j.signedDefterXml, j.defterFileName);
      download(j.signedBeratXml, j.beratFileName);
      logAudit && logAudit("sign", "edefter_xbrl", { kind, period: `${year}-${month}` });
      notify(lang === "en" ? "Signed ledger + berat downloaded" : "İmzalı defter + berat indirildi");
    } catch (e) {
      notify((lang === "en" ? "Backend unreachable: " : "Backend'e ulaşılamadı: ") + (e?.message || ""), "err");
    } finally {
      setSigning(false);
    }
  };

  const inp = (label, value, onChange, ph) => (
    <div>
      <div className="label mb-1">{label}</div>
      <input className="input w-full" value={value || ""} onChange={e => onChange(e.target.value)} placeholder={ph || ""}/>
    </div>
  );

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl max-h-[92vh] flex flex-col overflow-hidden">
        <div className="px-5 py-3 border-b flex items-center justify-between" style={{ background: "#0f766e10" }}>
          <div className="flex items-center gap-2">
            <BookOpen size={18} style={{ color: "#0f766e" }}/>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700 }}>e-Defter (XBRL-GL) {lang === "en" ? "Generate" : "Üret"}</div>
              <div style={{ fontSize: 10.5, color: "var(--ink-mute)" }}>
                {lang === "en" ? "Journal & Ledger books — unsigned XBRL-GL instance" : "Yevmiye & Kebir — imzasız XBRL-GL örneği"}
              </div>
            </div>
          </div>
          <button onClick={onClose} className="p-1 rounded hover:bg-bg"><X size={16}/></button>
        </div>

        <div className="p-4 overflow-y-auto flex-1 space-y-3">
          {/* Dönem */}
          <div className="grid grid-cols-3 gap-2">
            <div>
              <div className="label mb-1">{lang === "en" ? "Year" : "Yıl"}</div>
              <input type="number" className="input w-full mono" value={year}
                onChange={e => setYear(Number(e.target.value))}/>
            </div>
            <div>
              <div className="label mb-1">{lang === "en" ? "Month" : "Ay"}</div>
              <select className="input w-full" value={month} onChange={e => setMonth(Number(e.target.value))}>
                {Array.from({ length: 12 }, (_, i) => i + 1).map(m => (
                  <option key={m} value={m}>{String(m).padStart(2, "0")}</option>
                ))}
              </select>
            </div>
            <div>
              <div className="label mb-1">{lang === "en" ? "Posted entries" : "Onaylı fiş"}</div>
              <div className="input w-full" style={{ display: "flex", alignItems: "center", fontWeight: 700,
                color: periodEntries.length ? "#15803d" : "#b91c1c" }}>
                {periodEntries.length}
              </div>
            </div>
          </div>

          {/* Eksik alan uyarısı */}
          {missing.length > 0 && (
            <div className="card p-2" style={{ background: "#fef3c7", border: "1px solid #ca8a04", fontSize: 11.5 }}>
              ⚠ {lang === "en" ? "GİB-required fields missing (file won't validate until completed):" : "GİB zorunlu alanları eksik (tamamlanmadan doğrulamadan geçmez):"} <b>{missing.join(", ")}</b>
            </div>
          )}

          {/* Mükellef bilgileri */}
          <div className="label" style={{ fontWeight: 700, marginTop: 4 }}>{lang === "en" ? "Taxpayer info" : "Mükellef Bilgileri"}</div>
          <div className="grid grid-cols-2 gap-2">
            {inp(lang === "en" ? "Legal name" : "Unvan", profile.unvan, v => setP("unvan", v))}
            {inp("VKN/TCKN", profile.vkn, v => setP("vkn", v.replace(/\D/g, "")))}
            {inp(lang === "en" ? "Phone" : "Telefon", profile.phone, v => setP("phone", v))}
            {inp(lang === "en" ? "Email" : "E-posta", profile.email, v => setP("email", v))}
            {inp(lang === "en" ? "Building no" : "Bina No", profile.address.buildingNumber, v => setAdr("buildingNumber", v))}
            {inp(lang === "en" ? "Street" : "Cadde/Sokak", profile.address.street, v => setAdr("street", v))}
            {inp(lang === "en" ? "City" : "İl", profile.address.city, v => setAdr("city", v))}
            {inp(lang === "en" ? "Zip" : "Posta Kodu", profile.address.zip, v => setAdr("zip", v))}
            {inp(lang === "en" ? "Accountant (SMMM)" : "Muhasebeci (SMMM)", profile.accountant.name, v => setAcc("name", v))}
            {inp(lang === "en" ? "Engagement" : "Sözleşme/İlişki", profile.accountant.engagement, v => setAcc("engagement", v))}
          </div>

          <div className="card p-2" style={{ background: "var(--bg-alt)", fontSize: 11, color: "var(--ink-mute)" }}>
            {lang === "en"
              ? "Note: This is the unsigned XBRL-GL instance. To upload to GİB it must be signed with your Mali Mühür/NES (XAdES) and a berat created — that is Faz 3 and requires your certificate."
              : "Not: Bu imzasız XBRL-GL örneğidir. GİB'e yüklemek için Mali Mühür/NES (XAdES) ile imzalanıp berat üretilmelidir — bu Faz 3'tür ve sertifikanızı gerektirir."}
          </div>
        </div>

        <div className="px-4 py-3 border-t flex items-center justify-end gap-2">
          <button onClick={onClose} className="btn btn-ghost text-xs">{lang === "en" ? "Close" : "Kapat"}</button>
          <button onClick={() => generate("yevmiye")} className="btn text-xs">
            <Download size={12}/> {lang === "en" ? "Journal (Y)" : "Yevmiye (Y)"}
          </button>
          <button onClick={() => generate("kebir")} className="btn text-xs">
            <Download size={12}/> {lang === "en" ? "Ledger (K)" : "Kebir (K)"}
          </button>
          <button onClick={() => generate("both")} className="btn text-xs">
            <Download size={12}/> {lang === "en" ? "Both (unsigned)" : "İkisi (imzasız)"}
          </button>
          <button onClick={() => signViaBackend("journal")} disabled={signing} className="btn btn-primary text-xs"
            title={lang === "en" ? "Sign journal book + berat with Mali Mühür (backend)" : "Yevmiye + beratı Mali Mühür ile imzala (backend)"}>
            <Lock size={12}/> {signing ? (lang === "en" ? "Signing…" : "İmzalanıyor…") : (lang === "en" ? "Sign (Mali Mühür)" : "Mali Mühür ile İmzala")}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------- Yeni Fiş Dropdown'u ---------- */
function NewVoucherDropdown({ onNew, lang }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);
  useEffect(() => {
    const handleClick = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  return (
    <div ref={ref} className="relative">
      <button onClick={() => setOpen(!open)} className="btn btn-primary text-xs">
        <Plus size={11}/> {lang === "en" ? "New Entry" : "Yeni Fiş"}
        <ChevronDown size={11}/>
      </button>
      {open && (
        <div className="absolute right-0 mt-1 z-20 bg-white rounded-lg shadow-lg border" style={{
          minWidth: 180, borderColor: "var(--line)",
        }}>
          {Object.entries(VOUCHER_TYPES).map(([key, t]) => (
            <button
              key={key}
              onClick={() => { onNew(key); setOpen(false); }}
              className="w-full text-left px-3 py-2 hover:bg-bgAlt text-xs flex items-center gap-2"
              style={{ borderBottom: "1px solid var(--line)" }}
            >
              <span style={{
                width: 6, height: 6, borderRadius: "50%", background: t.color, flexShrink: 0,
              }}/>
              <span style={{ fontWeight: 600 }}>{t.label[lang] || t.label.tr}</span>
              <span className="mono ml-auto" style={{ fontSize: 10, color: "var(--ink-mute)" }}>{t.prefix}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

