/* =====================================================================
   YEVMİYE FİŞİ FORM MODAL — AI Destekli (Adım 4B)
   ---------------------------------------------------------------------
   - Dinamik satır tablosu
   - AI hesap önerileri (keyword matching)
   - Karşı hesap önerileri (manual + öğrenilmiş)
   - Benzer geçmiş fişler
   - Otomatik dengeleme (auto-balance)
   - Real-time validation
===================================================================== */
function JournalEntryFormModal({ mode, voucherType, entryData, accounts, entries, projects = [], lang, onClose, onSave }) {
  const isEdit = mode === "edit";
  const typeCfg = VOUCHER_TYPES[voucherType] || VOUCHER_TYPES.compound;

  // === Form state ===
  const today = new Date().toISOString().split("T")[0];
  const [form, setForm] = useState(() => {
    if (isEdit && entryData) {
      return {
        voucherNo: entryData.voucherNo,
        voucherType: entryData.voucherType,
        date: entryData.date,
        entryTime: entryData.entryTime || nowHHMM(),
        yevmiyeMaddeNo: entryData.yevmiyeMaddeNo || "",
        description: entryData.description || "",
        source: entryData.source || "manual",
        projectId: entryData.projectId || "",
        lines: (entryData.lines || []).map((l, i) => ({
          id: l.id || `line_${i}_${Date.now()}`,
          accountCode: l.accountCode || "",
          description: l.description || "",
          debit: l.debit || 0,
          credit: l.credit || 0,
          currency: l.currency || "TRY",
          foreignAmount: l.foreignAmount || null,
          exchangeRate: l.exchangeRate || null,
        })),
      };
    }
    return {
      voucherNo: "",
      voucherType,
      date: today,
      entryTime: nowHHMM(),
      yevmiyeMaddeNo: "",
      description: "",
      source: "manual",
      projectId: "",
      lines: [
        { id: `line_1_${Date.now()}`, accountCode: "", description: "", debit: 0, credit: 0, currency: "TRY", foreignAmount: null, exchangeRate: null },
        { id: `line_2_${Date.now()}`, accountCode: "", description: "", debit: 0, credit: 0, currency: "TRY", foreignAmount: null, exchangeRate: null },
      ],
    };
  });

  const [error, setError] = useState("");
  const [activeLineId, setActiveLineId] = useState(null); // AI önerisinin gösterileceği aktif satır
  const [showSimilarPanel, setShowSimilarPanel] = useState(true);

  // === Hesaplamalar ===
  const totals = useMemo(() => calculateEntryTotals(form.lines), [form.lines]);

  // AI: Benzer geçmiş fişler
  const similarEntries = useMemo(() => {
    if (!form.description.trim()) return [];
    return findSimilarEntries(form.description, entries, 3);
  }, [form.description, entries]);

  // AI: Açıklamadan hesap önerisi (genel)
  const descBasedSuggestions = useMemo(() => {
    if (!form.description.trim() || form.description.length < 3) return [];
    return suggestAccountByDescription(form.description, accounts, 5);
  }, [form.description, accounts]);

  // === Satır işlemleri ===
  const addLine = () => {
    setForm({
      ...form,
      lines: [
        ...form.lines,
        {
          id: `line_${form.lines.length + 1}_${Date.now()}`,
          accountCode: "", description: "", debit: 0, credit: 0,
          currency: "TRY", foreignAmount: null, exchangeRate: null,
        },
      ],
    });
  };

  const removeLine = (id) => {
    if (form.lines.length <= 2) {
      setError(lang === "en" ? "Minimum 2 lines required" : "En az 2 satır gerekli");
      return;
    }
    setForm({ ...form, lines: form.lines.filter(l => l.id !== id) });
  };

  const updateLine = (id, updates) => {
    setForm({
      ...form,
      lines: form.lines.map(l => l.id === id ? { ...l, ...updates } : l),
    });
  };

  // === AI Aksiyonları ===

  // Bir satıra hesap öner (focus olduğunda)
  const lineAccountSuggestions = useMemo(() => {
    if (!activeLineId) return [];
    const activeLine = form.lines.find(l => l.id === activeLineId);
    if (!activeLine) return [];

    // 1. Satır açıklamasından öner
    if (activeLine.description && activeLine.description.length >= 3) {
      const fromDesc = suggestAccountByDescription(activeLine.description, accounts, 5);
      if (fromDesc.length > 0) return fromDesc;
    }

    // 2. Genel açıklamadan öner
    if (form.description && form.description.length >= 3) {
      return descBasedSuggestions;
    }

    return [];
  }, [activeLineId, form.lines, form.description, accounts, descBasedSuggestions]);

  // Bir hesap için karşı hesap önerileri
  const getOffsetSuggestionsForLine = (line) => {
    if (!line.accountCode) return [];
    return suggestOffsetAccounts(line.accountCode, accounts, entries, 3);
  };

  // Otomatik dengeleme: Tek satır boş ise diff'i oraya yaz
  const autoBalance = () => {
    if (totals.isBalanced) {
      setError(lang === "en" ? "Already balanced" : "Zaten dengeli");
      setTimeout(() => setError(""), 2000);
      return;
    }
    const diff = totals.balance; // Pozitif: alacak fazla; negatif: borç fazla
    // Boş satır var mı?
    const emptyLines = form.lines.filter(l => !l.accountCode && (Number(l.debit) || 0) === 0 && (Number(l.credit) || 0) === 0);
    if (emptyLines.length === 0) {
      setError(lang === "en"
        ? "Add an empty line first, then auto-balance will fill it"
        : "Önce boş satır ekle, otomatik dengeleme onu doldursun");
      return;
    }
    // Diff'i ilk boş satıra koy
    const targetLine = emptyLines[0];
    if (diff > 0) {
      // Borç fazla → karşı taraf alacak olmalı
      updateLine(targetLine.id, { debit: 0, credit: Math.abs(diff) });
    } else {
      updateLine(targetLine.id, { debit: Math.abs(diff), credit: 0 });
    }
    setError("");
  };

  // Geçmiş fişten satırları kopyala
  const copyFromEntry = (sourceEntry) => {
    const newLines = (sourceEntry.lines || []).map((l, i) => ({
      id: `line_${i + 1}_${Date.now()}`,
      accountCode: l.accountCode,
      description: l.description || "",
      debit: l.debit || 0,
      credit: l.credit || 0,
      currency: l.currency || "TRY",
      foreignAmount: null,
      exchangeRate: null,
    }));
    setForm({
      ...form,
      description: form.description || sourceEntry.description,
      lines: newLines,
    });
  };

  // === Validation & Submit ===
  const handleSubmit = (postNow = false) => {
    // Boş satırları temizle
    const cleanLines = form.lines.filter(l =>
      l.accountCode || (Number(l.debit) || 0) > 0 || (Number(l.credit) || 0) > 0
    );
    const cleanForm = { ...form, lines: cleanLines, status: postNow ? "posted" : "draft" };

    if (postNow) {
      // Validate
      const validation = validateJournalEntry(cleanForm, accounts);
      if (!validation.valid) {
        setError(validation.error);
        return;
      }
    } else {
      // Taslak için minimum kontrol
      if (cleanLines.length === 0) {
        setError(lang === "en" ? "Add at least one line" : "En az bir satır ekleyin");
        return;
      }
      if (!cleanForm.date) {
        setError(lang === "en" ? "Date is required" : "Tarih zorunlu");
        return;
      }
    }
    onSave(cleanForm);
  };

  const title = isEdit
    ? (lang === "en" ? `Edit ${typeCfg.label[lang] || typeCfg.label.tr}` : `${typeCfg.label[lang] || typeCfg.label.tr} Düzenle`)
    : (lang === "en" ? `New ${typeCfg.label[lang] || typeCfg.label.tr}` : `Yeni ${typeCfg.label[lang] || typeCfg.label.tr}`);

  // Önizleme fiş no
  const previewVoucherNo = useMemo(() => {
    if (isEdit) return form.voucherNo;
    const year = form.date ? new Date(form.date).getFullYear() : new Date().getFullYear();
    return generateVoucherNo(form.voucherType, year, entries);
  }, [form.voucherType, form.date, entries, isEdit, form.voucherNo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-2 sm:p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-6xl max-h-[95vh] flex flex-col overflow-hidden">

        {/* Header */}
        <div className="px-5 py-3 border-b flex items-center justify-between" style={{ background: typeCfg.color + "10" }}>
          <div className="flex items-center gap-3">
            <span style={{ width: 10, height: 10, borderRadius: "50%", background: typeCfg.color }}/>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700 }}>{title}</div>
              <div className="mono" style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
                {previewVoucherNo}
              </div>
            </div>
          </div>
          <button onClick={onClose} className="p-1 rounded hover:bg-bg">
            <X size={16}/>
          </button>
        </div>

        {/* Body: Sol (form) + Sağ (AI panel) */}
        <div className="flex-1 flex overflow-hidden">

          {/* SOL: Form */}
          <div className="flex-1 overflow-y-auto p-4 space-y-3" style={{ minWidth: 0 }}>

            {/* Error */}
            {error && (
              <div className="card p-2" style={{ background: "#fee2e2", border: "1px solid #b91c1c", color: "#b91c1c", fontSize: 12 }}>
                {error}
              </div>
            )}

            {/* Fiş Bilgileri */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-2">
              <div>
                <div className="label mb-1">{lang === "en" ? "Date" : "Tarih"} *</div>
                <input
                  type="date"
                  className="input w-full mono"
                  value={form.date}
                  onChange={e => setForm({ ...form, date: e.target.value })}
                />
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Time (HH:mm)" : "Saat (SS:DD)"} *</div>
                <input
                  type="time"
                  className="input w-full mono"
                  value={form.entryTime || ""}
                  onChange={e => setForm({ ...form, entryTime: e.target.value })}
                  title={lang === "en" ? "GİB: voucher issue time" : "GİB: fişin düzenleme zamanı (zorunlu)"}
                />
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Journal Line No" : "Yevmiye Madde No"}</div>
                <input
                  className="input w-full mono"
                  value={form.yevmiyeMaddeNo || ""}
                  onChange={e => setForm({ ...form, yevmiyeMaddeNo: e.target.value })}
                  placeholder={lang === "en" ? "Assigned when posted to ledger" : "Deftere işlenince atanır"}
                  title={lang === "en" ? "GİB: related journal line number" : "GİB: fişin ait olduğu yevmiye madde numarası"}
                />
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Voucher Type" : "Fiş Tipi"} *</div>
                <select
                  className="input w-full"
                  value={form.voucherType}
                  onChange={e => setForm({ ...form, voucherType: e.target.value })}
                  disabled={isEdit}
                >
                  {Object.entries(VOUCHER_TYPES).map(([key, t]) => (
                    <option key={key} value={key}>{t.label[lang] || t.label.tr}</option>
                  ))}
                </select>
              </div>
              <div>
                <div className="label mb-1">{lang === "en" ? "Source" : "Kaynak"}</div>
                <select
                  className="input w-full"
                  value={form.source}
                  onChange={e => setForm({ ...form, source: e.target.value })}
                  disabled={isEdit}
                >
                  {Object.entries(VOUCHER_SOURCES).map(([key, s]) => (
                    <option key={key} value={key}>{s.label[lang] || s.label.tr}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Açıklama */}
            <div>
              <div className="label mb-1">{lang === "en" ? "Description" : "Açıklama"}</div>
              <input
                className="input w-full"
                value={form.description}
                onChange={e => setForm({ ...form, description: e.target.value })}
                placeholder={lang === "en"
                  ? "e.g. Office rent payment - May 2026"
                  : "örn. Ofis kira ödemesi - Mayıs 2026"}
              />
            </div>

            {/* PROJE TAHSİSİ (opsiyonel) */}
            {projects.length > 0 && (
              <div>
                <div className="label mb-1">
                  📈 {lang === "en" ? "Project (cost/revenue allocation, optional)" : "Proje (gelir/maliyet tahsisi, opsiyonel)"}
                </div>
                <select className="input w-full"
                  value={form.projectId || ""}
                  onChange={e => setForm({ ...form, projectId: e.target.value })}>
                  <option value="">— {lang === "en" ? "No project" : "Proje yok"} —</option>
                  {projects
                    .filter(p => !["completed", "cancelled"].includes(p.status))
                    .sort((a, b) => (a.code || "").localeCompare(b.code || ""))
                    .map(p => (
                      <option key={p.id} value={p.id}>{p.code} · {p.name}</option>
                    ))}
                  <optgroup label={lang === "en" ? "Completed/Cancelled" : "Tamamlanan/İptal"}>
                    {projects
                      .filter(p => ["completed", "cancelled"].includes(p.status))
                      .map(p => (
                        <option key={p.id} value={p.id}>
                          {p.code} · {p.name} {p.status === "completed" ? "✓" : "✗"}
                        </option>
                      ))}
                  </optgroup>
                </select>
                {form.projectId && (
                  <p className="text-xs mt-1" style={{ color: "#0891b2", fontWeight: 600 }}>
                    ✓ {lang === "en" ? "Posting will be allocated to this project" : "Bu fiş projeye tahsis edilecek"}
                  </p>
                )}
              </div>
            )}

            {/* Satır Tablosu */}
            <div className="card" style={{ padding: 0, overflow: "hidden", border: "1px solid var(--line)" }}>
              {/* Tablo Header */}
              <div
                className="flex items-center gap-2"
                style={{
                  background: "var(--bg-alt)",
                  borderBottom: "2px solid var(--line)",
                  padding: "6px 8px",
                  fontSize: 9.5,
                  fontWeight: 700,
                  color: "var(--ink-mute)",
                  textTransform: "uppercase",
                  letterSpacing: 0.3,
                }}
              >
                <div style={{ width: 28, flexShrink: 0, textAlign: "center" }}>#</div>
                <div style={{ width: 110, flexShrink: 0 }}>{lang === "en" ? "Account" : "Hesap"}</div>
                <div className="flex-1 min-w-0">{lang === "en" ? "Description" : "Açıklama"}</div>
                <div style={{ width: 110, flexShrink: 0, textAlign: "right" }}>{lang === "en" ? "Debit" : "Borç"}</div>
                <div style={{ width: 110, flexShrink: 0, textAlign: "right" }}>{lang === "en" ? "Credit" : "Alacak"}</div>
                <div style={{ width: 26, flexShrink: 0 }}/>
              </div>

              {/* Satırlar */}
              {form.lines.map((line, idx) => {
                const acc = accounts.find(a => a.code === line.accountCode);
                const isActive = activeLineId === line.id;
                return (
                  <JournalEntryLineRow
                    key={line.id}
                    line={line}
                    idx={idx}
                    account={acc}
                    accounts={accounts}
                    entries={entries}
                    isActive={isActive}
                    onFocus={() => setActiveLineId(line.id)}
                    onUpdate={(updates) => updateLine(line.id, updates)}
                    onRemove={() => removeLine(line.id)}
                    canRemove={form.lines.length > 2}
                    lang={lang}
                  />
                );
              })}

              {/* Toplam Satırı */}
              <div
                className="flex items-center gap-2"
                style={{
                  background: totals.isBalanced ? "#dcfce7" : "#fef3c7",
                  borderTop: "2px solid var(--line)",
                  padding: "8px",
                  fontSize: 12,
                  fontWeight: 700,
                }}
              >
                <div style={{ width: 28, flexShrink: 0 }}/>
                <div style={{ width: 110, flexShrink: 0, color: "var(--ink-mute)", fontSize: 10, textTransform: "uppercase" }}>
                  {lang === "en" ? "TOTAL" : "TOPLAM"}
                </div>
                <div className="flex-1 min-w-0">
                  {totals.isBalanced ? (
                    <span style={{ color: "#15803d", fontSize: 11, fontWeight: 700 }}>
                      ✓ {lang === "en" ? "BALANCED" : "DENGELİ"}
                    </span>
                  ) : (
                    <span style={{ color: "#ca8a04", fontSize: 11, fontWeight: 700 }}>
                      ⚠ {lang === "en" ? "Difference" : "Fark"}: {fmtTL(Math.abs(totals.balance))} ₺
                    </span>
                  )}
                </div>
                <div className="mono text-right" style={{ width: 110, flexShrink: 0, color: "#0f766e" }}>
                  {fmtTL(totals.totalDebit)} ₺
                </div>
                <div className="mono text-right" style={{ width: 110, flexShrink: 0, color: "#b91c1c" }}>
                  {fmtTL(totals.totalCredit)} ₺
                </div>
                <div style={{ width: 26, flexShrink: 0 }}/>
              </div>
            </div>

            {/* Aksiyon: Satır ekle + Otomatik dengele */}
            <div className="flex gap-2">
              <button onClick={addLine} className="btn btn-ghost text-xs">
                <Plus size={11}/> {lang === "en" ? "Add Line" : "Satır Ekle"}
              </button>
              {!totals.isBalanced && (
                <button onClick={autoBalance} className="btn text-xs" style={{
                  background: "#1d4ed8", color: "#fff", padding: "5px 10px",
                  fontWeight: 600, borderRadius: 4,
                }}>
                  <Sparkles size={11}/> {lang === "en" ? "Auto-Balance" : "Otomatik Dengele"}
                </button>
              )}
            </div>
          </div>

          {/* SAĞ: AI Panel */}
          <div
            className="hidden lg:flex flex-col overflow-y-auto"
            style={{
              width: 280,
              flexShrink: 0,
              borderLeft: "1px solid var(--line)",
              background: "var(--bg-alt)",
            }}
          >
            <div className="p-3 border-b" style={{ background: "linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)", color: "#fff" }}>
              <div className="flex items-center gap-2">
                <Sparkles size={14}/>
                <span style={{ fontSize: 12, fontWeight: 700 }}>
                  {lang === "en" ? "AI Suggestions" : "AI Önerileri"}
                </span>
              </div>
              <div style={{ fontSize: 10, opacity: 0.9, marginTop: 2 }}>
                {lang === "en"
                  ? "Smart recommendations based on history"
                  : "Geçmişe dayalı akıllı öneriler"}
              </div>
            </div>

            <div className="p-3 space-y-3 flex-1">

              {/* Benzer geçmiş fişler */}
              {similarEntries.length > 0 && (
                <div>
                  <div className="label mb-1.5 flex items-center justify-between">
                    <span>{lang === "en" ? "Similar Past Entries" : "Benzer Geçmiş Fişler"}</span>
                    <button onClick={() => setShowSimilarPanel(!showSimilarPanel)}>
                      {showSimilarPanel ? <ChevronDown size={11}/> : <ChevronRight size={11}/>}
                    </button>
                  </div>
                  {showSimilarPanel && (
                    <div className="space-y-1.5">
                      {similarEntries.map(e => (
                        <div key={e.id} className="card p-2" style={{ background: "var(--bg)", border: "1px solid var(--line)" }}>
                          <div className="mono" style={{ fontSize: 10, fontWeight: 700, color: VOUCHER_TYPES[e.voucherType]?.color }}>
                            {e.voucherNo}
                          </div>
                          <div style={{ fontSize: 10.5, marginTop: 2, color: "var(--ink)", lineHeight: 1.3 }}>
                            {e.description || "—"}
                          </div>
                          <div className="flex items-center justify-between mt-1.5">
                            <span className="mono" style={{ fontSize: 9.5, color: "var(--ink-mute)" }}>
                              {e.date} · {fmtTL(Number(e.totalDebit) || 0)} ₺
                            </span>
                            <button
                              onClick={() => copyFromEntry(e)}
                              className="text-xs"
                              style={{
                                padding: "2px 6px", background: "#1d4ed8", color: "#fff",
                                borderRadius: 3, fontSize: 9.5, fontWeight: 600,
                              }}
                            >
                              {lang === "en" ? "Copy" : "Kopyala"}
                            </button>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              )}

              {/* Hesap önerileri (aktif satır için) */}
              {activeLineId && lineAccountSuggestions.length > 0 && (
                <div>
                  <div className="label mb-1.5">
                    {lang === "en" ? "Suggested Accounts" : "Önerilen Hesaplar"}
                    <span style={{ fontSize: 9, color: "var(--ink-mute)", marginLeft: 4 }}>
                      ({lang === "en" ? "for active line" : "aktif satır için"})
                    </span>
                  </div>
                  <div className="space-y-1">
                    {lineAccountSuggestions.map(acc => (
                      <button
                        key={acc.code}
                        onClick={() => {
                          updateLine(activeLineId, {
                            accountCode: acc.code,
                            description: form.lines.find(l => l.id === activeLineId)?.description || acc.defaultDescription || "",
                          });
                        }}
                        className="w-full text-left p-2 rounded hover:bg-bg"
                        style={{ background: "var(--bg)", border: "1px solid var(--line)" }}
                      >
                        <div className="mono" style={{ fontSize: 10.5, fontWeight: 700, color: ACCOUNT_TYPES[acc.type]?.color }}>
                          {acc.code}
                        </div>
                        <div className="truncate" style={{ fontSize: 10.5, marginTop: 1 }}>
                          {acc.name}
                        </div>
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {/* Karşı hesap önerileri (eğer aktif satırda hesap seçili ise) */}
              {activeLineId && (() => {
                const activeLine = form.lines.find(l => l.id === activeLineId);
                if (!activeLine?.accountCode) return null;
                const offsets = getOffsetSuggestionsForLine(activeLine);
                if (offsets.length === 0) return null;
                return (
                  <div>
                    <div className="label mb-1.5">{lang === "en" ? "Offset Accounts" : "Karşı Hesap Önerileri"}</div>
                    <div className="space-y-1">
                      {offsets.map(acc => (
                        <button
                          key={acc.code}
                          onClick={() => {
                            // İlk boş satıra koy
                            const emptyLine = form.lines.find(l => !l.accountCode);
                            if (emptyLine) {
                              updateLine(emptyLine.id, { accountCode: acc.code });
                            } else {
                              // Yeni satır ekle
                              const newId = `line_${form.lines.length + 1}_${Date.now()}`;
                              setForm({
                                ...form,
                                lines: [
                                  ...form.lines,
                                  { id: newId, accountCode: acc.code, description: "", debit: 0, credit: 0, currency: "TRY", foreignAmount: null, exchangeRate: null },
                                ],
                              });
                              setActiveLineId(newId);
                            }
                          }}
                          className="w-full text-left p-2 rounded hover:bg-bg"
                          style={{ background: "var(--bg)", border: "1px solid var(--line)" }}
                        >
                          <div className="mono" style={{ fontSize: 10.5, fontWeight: 700, color: ACCOUNT_TYPES[acc.type]?.color }}>
                            {acc.code}
                          </div>
                          <div className="truncate" style={{ fontSize: 10.5, marginTop: 1 }}>
                            {acc.name}
                          </div>
                        </button>
                      ))}
                    </div>
                  </div>
                );
              })()}

              {/* Boş durum */}
              {similarEntries.length === 0 && lineAccountSuggestions.length === 0 && (
                <div className="text-center py-6" style={{ color: "var(--ink-mute)" }}>
                  <Sparkles size={24} style={{ margin: "0 auto", opacity: 0.3 }}/>
                  <div style={{ fontSize: 11, marginTop: 6 }}>
                    {lang === "en"
                      ? "Type a description or focus on a line to see AI suggestions."
                      : "Açıklama yaz veya satır seç, AI önerileri görünecek."}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t flex items-center justify-between gap-2" style={{ background: "var(--bg-alt)" }}>
          <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
            {form.lines.length} {lang === "en" ? "lines" : "satır"} ·
            {totals.isBalanced ? (
              <span style={{ color: "#15803d", fontWeight: 700, marginLeft: 4 }}>
                {lang === "en" ? "Balanced" : "Dengeli"}
              </span>
            ) : (
              <span style={{ color: "#ca8a04", fontWeight: 700, marginLeft: 4 }}>
                {lang === "en" ? "Not balanced" : "Dengeli değil"}
              </span>
            )}
          </div>
          <div className="flex gap-2">
            <button onClick={onClose} className="btn btn-ghost text-xs">
              {lang === "en" ? "Cancel" : "İptal"}
            </button>
            <button onClick={() => handleSubmit(false)} className="btn btn-ghost text-xs">
              <Save size={11}/> {lang === "en" ? "Save as Draft" : "Taslak Kaydet"}
            </button>
            <button
              onClick={() => handleSubmit(true)}
              className="btn btn-primary text-xs"
              disabled={!totals.isBalanced}
              style={!totals.isBalanced ? { opacity: 0.5, cursor: "not-allowed" } : {}}
            >
              <Check size={11}/> {lang === "en" ? "Save & Post" : "Kayıt + Onayla"}
            </button>
          </div>
        </div>

      </div>
    </div>
  );
}

/* ---------- Yevmiye Fişi Satır Bileşeni ---------- */
function JournalEntryLineRow({ line, idx, account, accounts, entries = [], isActive, onFocus, onUpdate, onRemove, canRemove, lang }) {
  const [accountSearch, setAccountSearch] = useState("");
  const [showAccountDropdown, setShowAccountDropdown] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClick = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setShowAccountDropdown(false);
      }
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  // Hesap arama sonuçları
  const accountMatches = useMemo(() => {
    if (!accountSearch.trim()) {
      // Boşken: yaprak ve aktif hesaplardan ilk 20'yi göster
      return accounts
        .filter(a => a.allowTransaction !== false && a.active !== false)
        .slice(0, 20);
    }
    const q = accountSearch.toLowerCase().trim();
    return accounts
      .filter(a =>
        a.allowTransaction !== false &&
        a.active !== false &&
        (
          String(a.code).toLowerCase().includes(q) ||
          a.name.toLowerCase().includes(q) ||
          (a.nameEn || "").toLowerCase().includes(q)
        )
      )
      .slice(0, 20);
  }, [accountSearch, accounts]);

  const handleAccountSelect = (acc) => {
    onUpdate({
      accountCode: acc.code,
      description: line.description || acc.defaultDescription || "",
    });
    setShowAccountDropdown(false);
    setAccountSearch("");
  };

  return (
    <div
      className="flex items-center gap-2 border-b"
      style={{
        borderColor: "var(--line)",
        padding: "5px 8px",
        background: isActive ? "var(--accent-soft)" : "transparent",
        transition: "background 0.15s",
      }}
      onMouseDown={onFocus}
    >
      {/* # */}
      <div style={{ width: 28, flexShrink: 0, textAlign: "center", fontSize: 10, color: "var(--ink-mute)" }}>
        {idx + 1}
      </div>

      {/* Hesap */}
      <div ref={dropdownRef} className="relative" style={{ width: 110, flexShrink: 0 }}>
        <input
          className="input w-full mono text-xs"
          style={{ padding: "4px 6px", fontSize: 11, fontWeight: 700 }}
          value={line.accountCode}
          onFocus={() => { setShowAccountDropdown(true); onFocus(); }}
          onChange={e => {
            const v = e.target.value;
            onUpdate({ accountCode: v });
            setAccountSearch(v);
            setShowAccountDropdown(true);
          }}
          placeholder={lang === "en" ? "Code" : "Kod"}
        />
        {showAccountDropdown && (
          <div className="absolute left-0 right-0 mt-1 z-30 bg-white rounded shadow-lg border max-h-64 overflow-y-auto"
            style={{ borderColor: "var(--line)", minWidth: 320, width: 320 }}>
            <input
              autoFocus
              className="input w-full text-xs"
              style={{ borderRadius: 0, borderTop: "none", borderLeft: "none", borderRight: "none" }}
              placeholder={lang === "en" ? "Search account..." : "Hesap ara..."}
              value={accountSearch}
              onChange={e => setAccountSearch(e.target.value)}
            />
            {accountMatches.length === 0 ? (
              <div className="p-3 text-center text-xs" style={{ color: "var(--ink-mute)" }}>
                {lang === "en" ? "No accounts found" : "Hesap bulunamadı"}
              </div>
            ) : accountMatches.map(acc => (
              <button
                key={acc.code}
                onClick={() => handleAccountSelect(acc)}
                className="w-full text-left p-2 hover:bg-bgAlt border-b"
                style={{ borderColor: "var(--line)" }}
              >
                <div className="flex items-center gap-2">
                  <span className="mono" style={{ fontSize: 11, fontWeight: 700, color: ACCOUNT_TYPES[acc.type]?.color, minWidth: 70 }}>
                    {acc.code}
                  </span>
                  <span className="truncate" style={{ fontSize: 11 }}>{acc.name}</span>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Açıklama + Hesap adı (alt satırda) */}
      <div className="flex-1 min-w-0">
        <input
          className="input w-full text-xs"
          style={{ padding: "4px 6px", fontSize: 11 }}
          value={line.description}
          onChange={e => onUpdate({ description: e.target.value })}
          onFocus={onFocus}
          placeholder={account ? account.name : (lang === "en" ? "Line description" : "Satır açıklaması")}
        />
        {account && (
          <div className="truncate" style={{ fontSize: 9.5, color: "var(--ink-mute)", marginTop: 1, paddingLeft: 4 }}>
            {account.name}
          </div>
        )}
        {/* AI hesap önerisi - sadece focus durumunda ve açıklama doluyken */}
        {isActive && line.description && line.description.length >= 3 && !line.accountCode && (
          <JournalAccountSuggester
            description={line.description}
            entries={entries}
            accounts={accounts}
            lang={lang}
            onApply={(code) => onUpdate({ accountCode: code })}
          />
        )}
      </div>

      {/* Borç */}
      <div style={{ width: 110, flexShrink: 0 }}>
        <MoneyInput
          className="input w-full mono text-right text-xs"
          style={{ padding: "4px 6px", fontSize: 11, color: line.debit > 0 ? "#0f766e" : "var(--ink)" }}
          value={line.debit || ""}
          onFocus={onFocus}
          onChange={val => {
            const v = val === '' ? 0 : val;
            onUpdate({ debit: v, credit: v > 0 ? 0 : line.credit });
          }}
          placeholder="0,00"
        />
      </div>

      {/* Alacak */}
      <div style={{ width: 110, flexShrink: 0 }}>
        <MoneyInput
          className="input w-full mono text-right text-xs"
          style={{ padding: "4px 6px", fontSize: 11, color: line.credit > 0 ? "#b91c1c" : "var(--ink)" }}
          value={line.credit || ""}
          onFocus={onFocus}
          onChange={val => {
            const v = val === '' ? 0 : val;
            onUpdate({ credit: v, debit: v > 0 ? 0 : line.debit });
          }}
          placeholder="0,00"
        />
      </div>

      {/* Sil */}
      <button
        onClick={onRemove}
        disabled={!canRemove}
        className="p-1 rounded hover:bg-bg"
        style={{ width: 26, flexShrink: 0, opacity: canRemove ? 1 : 0.3, color: "#b91c1c" }}
        title={lang === "en" ? "Remove line" : "Satırı sil"}
      >
        <Trash2 size={11}/>
      </button>
    </div>
  );
}

/* =====================================================================
   AUTO-VOUCHER PREVIEW MODAL — Otomatik üretilen fişi onaylamadan göster
   ---------------------------------------------------------------------
   Kullanım: Kasa/Banka/Fatura hareketinden üretilen fişi göstermek
===================================================================== */
function AutoVoucherPreviewModal({ voucher, accounts, lang, sourceLabel, onClose, onPost, onEditFirst }) {
  if (!voucher) return null;

  const typeCfg = VOUCHER_TYPES[voucher.voucherType] || VOUCHER_TYPES.compound;
  const [editableVoucher, setEditableVoucher] = useState(voucher);
  const [postNow, setPostNow] = useState(false);

  const totals = useMemo(() => calculateEntryTotals(editableVoucher.lines), [editableVoucher.lines]);

  const handlePost = (asPosted) => {
    const validation = validateJournalEntry(editableVoucher, accounts);
    if (asPosted && !validation.valid) {
      alert(validation.error);
      return;
    }
    onPost({ ...editableVoucher, status: asPosted ? "posted" : "draft" });
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl max-h-[92vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="px-5 py-4 border-b" style={{ background: typeCfg.color + "10" }}>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <Sparkles size={18} style={{ color: "#7c3aed" }}/>
              <div>
                <div style={{ fontSize: 14, fontWeight: 700 }}>
                  {lang === "en" ? "AI Auto-Generated Voucher" : "AI Otomatik Yevmiye Fişi"}
                </div>
                <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
                  {lang === "en"
                    ? `From: ${sourceLabel} · Review and post`
                    : `Kaynak: ${sourceLabel} · İnceleyin ve onaylayın`}
                </div>
              </div>
            </div>
            <button onClick={onClose} className="p-1 rounded hover:bg-bg">
              <X size={16}/>
            </button>
          </div>
        </div>

        {/* Voucher Meta */}
        <div className="px-5 py-3 border-b" style={{ background: "var(--bg-alt)" }}>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <div>
              <div className="label">{lang === "en" ? "Voucher No" : "Fiş No"}</div>
              <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: typeCfg.color }}>
                {editableVoucher.voucherNo}
              </div>
            </div>
            <div>
              <div className="label">{lang === "en" ? "Type" : "Tipi"}</div>
              <div style={{ fontSize: 12, fontWeight: 600 }}>{typeCfg.label[lang] || typeCfg.label.tr}</div>
            </div>
            <div>
              <div className="label">{lang === "en" ? "Date" : "Tarih"}</div>
              <input
                type="date"
                className="input w-full mono text-xs"
                value={editableVoucher.date}
                onChange={e => setEditableVoucher({ ...editableVoucher, date: e.target.value })}
              />
            </div>
            <div>
              <div className="label">{lang === "en" ? "Source" : "Kaynak"}</div>
              <div>
                <span style={{
                  padding: "3px 8px", fontSize: 10, fontWeight: 700, borderRadius: 3,
                  background: "#7c3aed20", color: "#7c3aed", textTransform: "uppercase",
                }}>
                  {(VOUCHER_SOURCES[editableVoucher.source]?.label[lang] || editableVoucher.source).toUpperCase()}
                </span>
              </div>
            </div>
          </div>

          {/* Açıklama */}
          <div className="mt-3">
            <div className="label mb-1">{lang === "en" ? "Description" : "Açıklama"}</div>
            <input
              className="input w-full text-xs"
              value={editableVoucher.description}
              onChange={e => setEditableVoucher({ ...editableVoucher, description: e.target.value })}
            />
          </div>
        </div>

        {/* Lines */}
        <div className="px-5 py-3 flex-1 overflow-y-auto">
          <div className="label mb-2">{lang === "en" ? "Lines (AI suggested)" : "Satırlar (AI önerisi)"}</div>
          <div className="card" style={{ padding: 0, overflow: "hidden", border: "1px solid var(--line)" }}>
            <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
                  <th style={{ padding: 6, textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 30 }}>#</th>
                  <th style={{ padding: 6, textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                    {lang === "en" ? "Account" : "Hesap"}
                  </th>
                  <th style={{ padding: 6, textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                    {lang === "en" ? "Description" : "Açıklama"}
                  </th>
                  <th style={{ padding: 6, textAlign: "right", fontSize: 10, fontWeight: 700, color: "#0f766e", textTransform: "uppercase", width: 110 }}>
                    {lang === "en" ? "Debit" : "Borç"}
                  </th>
                  <th style={{ padding: 6, textAlign: "right", fontSize: 10, fontWeight: 700, color: "#b91c1c", textTransform: "uppercase", width: 110 }}>
                    {lang === "en" ? "Credit" : "Alacak"}
                  </th>
                </tr>
              </thead>
              <tbody>
                {(editableVoucher.lines || []).map((line, i) => {
                  const acc = accounts.find(a => a.code === line.accountCode);
                  return (
                    <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                      <td style={{ padding: 6, color: "var(--ink-mute)", fontSize: 10 }}>{i + 1}</td>
                      <td style={{ padding: 6 }}>
                        <div className="mono" style={{ fontSize: 11, fontWeight: 700, color: ACCOUNT_TYPES[acc?.type]?.color || "var(--ink)" }}>
                          {line.accountCode}
                        </div>
                        <div className="truncate" style={{ fontSize: 10, color: "var(--ink-mute)" }}>
                          {acc?.name || "—"}
                        </div>
                      </td>
                      <td style={{ padding: 6, fontSize: 11 }}>{line.description || "—"}</td>
                      <td className="mono text-right" style={{ padding: 6, fontSize: 11, color: line.debit > 0 ? "#0f766e" : "var(--ink-mute)", opacity: line.debit > 0 ? 1 : 0.3, fontWeight: line.debit > 0 ? 600 : 400 }}>
                        {line.debit > 0 ? fmtTL(line.debit) : "—"}
                      </td>
                      <td className="mono text-right" style={{ padding: 6, fontSize: 11, color: line.credit > 0 ? "#b91c1c" : "var(--ink-mute)", opacity: line.credit > 0 ? 1 : 0.3, fontWeight: line.credit > 0 ? 600 : 400 }}>
                        {line.credit > 0 ? fmtTL(line.credit) : "—"}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot>
                <tr style={{
                  background: totals.isBalanced ? "#dcfce7" : "#fef3c7",
                  borderTop: "2px solid var(--ink)", fontWeight: 700,
                }}>
                  <td colSpan="3" style={{ padding: 8, fontSize: 11, textAlign: "right", textTransform: "uppercase" }}>
                    {totals.isBalanced
                      ? (lang === "en" ? "✓ BALANCED" : "✓ DENGELİ")
                      : (lang === "en" ? "⚠ NOT BALANCED" : "⚠ DENGELİ DEĞİL")}
                  </td>
                  <td className="mono text-right" style={{ padding: 8, fontSize: 12, color: "#0f766e", fontWeight: 700 }}>
                    {fmtTL(totals.totalDebit)} ₺
                  </td>
                  <td className="mono text-right" style={{ padding: 8, fontSize: 12, color: "#b91c1c", fontWeight: 700 }}>
                    {fmtTL(totals.totalCredit)} ₺
                  </td>
                </tr>
              </tfoot>
            </table>
          </div>

          {/* AI Bilgi */}
          <div className="card p-3 mt-3" style={{ background: "#dbeafe", border: "1px solid #1d4ed8" }}>
            <div style={{ fontSize: 11, color: "#1d4ed8", lineHeight: 1.5 }}>
              <b>{lang === "en" ? "How AI selected accounts" : "AI hesapları nasıl seçti"}:</b><br/>
              {lang === "en"
                ? "Based on the source module type, keywords in the description, and the chart of accounts configurations (moduleSources, keywords, commonOffsetAccounts). You can edit if needed."
                : "Kaynak modül tipi, açıklamadaki anahtar kelimeler ve hesap planı ayarlarına (moduleSources, keywords, commonOffsetAccounts) göre seçildi. Gerekirse düzenleyebilirsiniz."}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t flex items-center justify-between" style={{ background: "var(--bg-alt)" }}>
          <button onClick={onClose} className="btn btn-ghost text-xs">
            {lang === "en" ? "Cancel" : "İptal"}
          </button>
          <div className="flex gap-2">
            {onEditFirst && (
              <button onClick={() => onEditFirst(editableVoucher)} className="btn btn-ghost text-xs">
                <Edit3 size={11}/> {lang === "en" ? "Edit in Full Form" : "Tam Formda Düzenle"}
              </button>
            )}
            <button onClick={() => handlePost(false)} className="btn btn-ghost text-xs">
              <Save size={11}/> {lang === "en" ? "Save as Draft" : "Taslak Kaydet"}
            </button>
            <button
              onClick={() => handlePost(true)}
              disabled={!totals.isBalanced}
              className="btn btn-primary text-xs"
              style={!totals.isBalanced ? { opacity: 0.5, cursor: "not-allowed" } : {}}
            >
              <Check size={11}/> {lang === "en" ? "Save & Post" : "Kayıt + Onayla"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   POST TO ACCOUNTING BUTTON — Tek tıkla muhasebeleştir
   ---------------------------------------------------------------------
   Kasa/Banka/Fatura modüllerinde kullanılır
===================================================================== */
function PostToAccountingButton({ source, sourceData, data, session, lang, onChange, logAudit, notify, compact = false }) {
  const [showPreview, setShowPreview] = useState(false);
  const [generatedVoucher, setGeneratedVoucher] = useState(null);
  const [error, setError] = useState("");

  // Bu kaynağın zaten muhasebeleştirilmiş bir fişi var mı?
  const existingVoucher = useMemo(() => {
    return (data.accJournalEntries || []).find(e =>
      e.source === source && e.sourceId === sourceData.id && e.status !== "cancelled"
    );
  }, [data.accJournalEntries, source, sourceData.id]);

  const handleClick = () => {
    if (existingVoucher) {
      // Zaten muhasebeleştirildi
      notify(
        lang === "en"
          ? `Already posted: ${existingVoucher.voucherNo}`
          : `Zaten muhasebeleştirildi: ${existingVoucher.voucherNo}`,
        "info"
      );
      return;
    }

    const accounts = data.accChartOfAccounts || [];
    const entries = data.accJournalEntries || [];

    let result;
    switch (source) {
      case "bank":
        result = generateVoucherFromBankEntry(sourceData, data.bankAccounts || [], accounts, entries);
        break;
      case "kasa":
        result = generateVoucherFromKasaEntry(sourceData, data.kasaAccounts || [], accounts, entries);
        break;
      case "invoice":
        result = generateVoucherFromInvoice(sourceData, accounts, entries);
        break;
      default:
        setError(lang === "en" ? "Unknown source" : "Bilinmeyen kaynak");
        return;
    }

    if (!result.success) {
      notify(result.error, "err");
      return;
    }

    setGeneratedVoucher(result.voucher);
    setShowPreview(true);
  };

  const handlePost = async (voucher) => {
    const finalVoucher = {
      ...voucher,
      id: "je_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
      createdAt: new Date().toISOString(),
      createdBy: session.username,
    };
    if (voucher.status === "posted") {
      finalVoucher.postedAt = new Date().toISOString();
      finalVoucher.postedBy = session.username;
    }
    const next = [...(data.accJournalEntries || []), finalVoucher];
    await onChange({ ...data, accJournalEntries: next });
    logAudit && logAudit("auto_post", "journal_entry", {
      source, sourceId: sourceData.id, voucherNo: finalVoucher.voucherNo,
    });
    notify(
      lang === "en"
        ? `Voucher ${finalVoucher.voucherNo} created${voucher.status === "posted" ? " and posted" : ""}`
        : `${finalVoucher.voucherNo} numaralı fiş ${voucher.status === "posted" ? "oluşturuldu ve onaylandı" : "taslak olarak oluşturuldu"}`
    );
    setShowPreview(false);
    setGeneratedVoucher(null);
  };

  const sourceLabels = {
    bank: lang === "en" ? "Bank Transaction" : "Banka Hareketi",
    kasa: lang === "en" ? "Cash Transaction" : "Kasa Hareketi",
    invoice: lang === "en" ? "Invoice" : "Fatura",
  };

  if (existingVoucher) {
    return (
      <span style={{
        padding: "3px 8px", fontSize: 10, fontWeight: 700, borderRadius: 3,
        background: "#dcfce7", color: "#15803d", textTransform: "uppercase",
        display: "inline-flex", alignItems: "center", gap: 4,
      }}
      title={lang === "en" ? `Already posted: ${existingVoucher.voucherNo}` : `Muhasebeleştirildi: ${existingVoucher.voucherNo}`}
      >
        <Check size={10}/>
        {lang === "en" ? "POSTED" : "MUHASEBE"}
      </span>
    );
  }

  return (
    <>
      <button
        onClick={handleClick}
        className={compact ? "p-1 rounded hover:bg-bg" : "btn btn-ghost text-xs"}
        title={lang === "en" ? "Post to accounting (AI auto-generates)" : "Muhasebeleştir (AI otomatik üretir)"}
        style={{ color: "#7c3aed" }}
      >
        <Sparkles size={compact ? 12 : 11}/>
        {!compact && (lang === "en" ? "Post" : "Muhasebeleştir")}
      </button>

      {showPreview && generatedVoucher && (
        <AutoVoucherPreviewModal
          voucher={generatedVoucher}
          accounts={data.accChartOfAccounts || []}
          lang={lang}
          sourceLabel={sourceLabels[source]}
          onClose={() => { setShowPreview(false); setGeneratedVoucher(null); }}
          onPost={handlePost}
        />
      )}
    </>
  );
}

/* =====================================================================
   BULK POSTING — Toplu Muhasebeleştirme
   ---------------------------------------------------------------------
   Kasa/Banka/Fatura için toplu muhasebeleştirme modal'ı
===================================================================== */

// Modal içinde tutarı satır-içi düzenleme hücresi
function BulkAmountCell({ amount, onSave, lang }) {
  const [editing, setEditing] = useState(false);
  const [val, setVal] = useState(String(amount ?? ""));

  if (!editing) {
    return (
      <div className="flex items-center justify-end gap-1">
        <span>{fmtTL(amount)} ₺</span>
        <button
          onClick={() => { setVal(String(amount ?? "")); setEditing(true); }}
          className="p-0.5 rounded hover:bg-stone-100"
          title={lang === "en" ? "Edit amount" : "Tutarı düzenle"}
        >
          <Edit3 size={11}/>
        </button>
      </div>
    );
  }

  const commit = () => {
    const n = Number(val);
    if (!Number.isFinite(n)) return;
    onSave(n);
    setEditing(false);
  };

  return (
    <div className="flex items-center justify-end gap-1">
      <input
        type="number"
        step="0.01"
        value={val}
        autoFocus
        onChange={e => setVal(e.target.value)}
        onKeyDown={e => { if (e.key === "Enter") commit(); if (e.key === "Escape") setEditing(false); }}
        className="input"
        style={{ width: 90, fontSize: 11, padding: "2px 4px", textAlign: "right" }}
      />
      <button onClick={commit} className="p-0.5 rounded hover:bg-green-50" title={lang === "en" ? "Save" : "Kaydet"}>
        <Check size={12} style={{ color: "var(--positive)" }}/>
      </button>
      <button onClick={() => setEditing(false)} className="p-0.5 rounded hover:bg-stone-100" title={lang === "en" ? "Cancel" : "İptal"}>
        <X size={12}/>
      </button>
    </div>
  );
}

// Eksik hesap kodları için hesap planından manuel seçim
function MissingAccountPicker({ missing, expected, accountOptions, value, onPick, lang }) {
  const roles = [
    { key: "party", label: lang === "en" ? "Party" : "Cari" },
    { key: "main", label: lang === "en" ? "Main" : "Ana" },
    { key: "vat", label: "KDV" },
  ].filter(r => missing[r.key]);

  return (
    <div className="flex flex-col gap-1">
      {roles.map(r => (
        <div key={r.key} className="flex items-center gap-1">
          <span style={{ fontSize: 9, color: "var(--ink-mute)", width: 34 }}>{r.label}</span>
          <select
            value={(value && value[r.key]) || ""}
            onChange={e => onPick(r.key, e.target.value)}
            className="input"
            style={{ fontSize: 10, padding: "2px 4px", flex: 1, minWidth: 0,
                     borderColor: (value && value[r.key]) ? "var(--positive)" : "#b91c1c" }}
          >
            <option value="">
              {(lang === "en" ? "Select" : "Hesap seç")}{expected?.[r.key] ? ` (${expected[r.key]}…)` : ""}
            </option>
            {accountOptions.map(a => (
              <option key={a.code} value={a.code}>{a.code} — {a.name}</option>
            ))}
          </select>
        </div>
      ))}
    </div>
  );
}

function BulkPostingButton({ source, items, data, session, lang, onChange, logAudit, notify, onPatchItem, onEditItem, onDeleteItem }) {
  const [showModal, setShowModal] = useState(false);

  // Muhasebeleşmemiş kayıtları say
  const unpostedCount = useMemo(() => {
    const existingSourceIds = new Set(
      (data.accJournalEntries || [])
        .filter(e => e.source === source && e.status !== "cancelled")
        .map(e => e.sourceId)
    );
    return items.filter(item => !existingSourceIds.has(item.id)).length;
  }, [items, data.accJournalEntries, source]);

  if (unpostedCount === 0) return null;

  return (
    <>
      <button
        onClick={() => setShowModal(true)}
        className="btn text-xs"
        style={{
          background: "#7c3aed",
          color: "#fff",
          padding: "5px 10px",
          fontWeight: 600,
          borderRadius: 4,
        }}
        title={lang === "en" ? "Bulk post to accounting" : "Toplu muhasebeleştir"}
      >
        <Sparkles size={11}/>
        {lang === "en" ? `Bulk Post (${unpostedCount})` : `Toplu Muhasebeleştir (${unpostedCount})`}
      </button>

      {showModal && (
        <BulkPostingModal
          source={source}
          items={items}
          data={data}
          session={session}
          lang={lang}
          onChange={onChange}
          logAudit={logAudit}
          notify={notify}
          onPatchItem={onPatchItem}
          onEditItem={onEditItem}
          onDeleteItem={onDeleteItem}
          onClose={() => setShowModal(false)}
        />
      )}
    </>
  );
}

function BulkPostingModal({ source, items, data, session, lang, onChange, logAudit, notify, onPatchItem, onEditItem, onDeleteItem, onClose }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];

  // Fatura kaynağı için satır-içi düzenle/sil ve manuel hesap kodu seçimi
  const canEditItems = source === "invoice";

  // Manuel hesap kodu seçimleri: { [itemId]: { party, main, vat } }
  const [overrides, setOverrides] = useState({});

  // Hesap planından işlem yapılabilen hesaplar (manuel seçim için)
  const accountOptions = useMemo(() =>
    accounts
      .filter(a => a.allowTransaction !== false)
      .slice()
      .sort((a, b) => String(a.code).localeCompare(String(b.code), undefined, { numeric: true })),
  [accounts]);

  // Muhasebeleşmiş source ID'leri set
  const existingSourceIds = useMemo(() => new Set(
    entries
      .filter(e => e.source === source && e.status !== "cancelled")
      .map(e => e.sourceId)
  ), [entries, source]);

  // Aday işlemleri çıkar (muhasebeleşmemişler)
  const candidates = useMemo(() => {
    return items.filter(item => !existingSourceIds.has(item.id));
  }, [items, existingSourceIds]);

  // Her aday için fiş üretmeyi dene (preview)
  const generated = useMemo(() => {
    return candidates.map(item => {
      let result;
      const enrichedItem = source === "kasa"
        ? { ...item, kasaAccountId: item.kasaAccountId || item._kasaAccountId }
        : item;
      try {
        switch (source) {
          case "bank":
            result = generateVoucherFromBankEntry(enrichedItem, data.bankAccounts || [], accounts, entries);
            break;
          case "kasa":
            result = generateVoucherFromKasaEntry(enrichedItem, data.kasaAccounts || [], accounts, entries);
            break;
          case "invoice":
            result = generateVoucherFromInvoice(enrichedItem, accounts, entries, overrides[item.id]);
            break;
          default:
            result = { success: false, error: "Bilinmeyen kaynak" };
        }
      } catch (err) {
        result = { success: false, error: err.message };
      }
      return { item, result };
    });
  }, [candidates, source, data.bankAccounts, data.kasaAccounts, accounts, entries, overrides]);

  // Selection state — başlangıçta tüm başarılılar seçili
  const [selected, setSelected] = useState(() => {
    const set = new Set();
    generated.forEach(({ item, result }) => {
      if (result.success) set.add(item.id);
    });
    return set;
  });

  const [postMode, setPostMode] = useState("posted"); // draft | posted
  const [isProcessing, setIsProcessing] = useState(false);
  const [processedCount, setProcessedCount] = useState(0);

  const successCount = generated.filter(g => g.result.success).length;
  const errorCount = generated.filter(g => !g.result.success).length;
  const selectedCount = selected.size;

  const toggleAll = () => {
    if (selected.size === successCount) {
      setSelected(new Set());
    } else {
      const all = new Set();
      generated.forEach(({ item, result }) => {
        if (result.success) all.add(item.id);
      });
      setSelected(all);
    }
  };

  const toggleItem = (id) => {
    setSelected(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  // Manuel hesap kodu seçimi — seçilince fiş yeniden üretilir, satır otomatik işaretlenir
  const handlePick = (id, role, code) => {
    setOverrides(prev => ({ ...prev, [id]: { ...(prev[id] || {}), [role]: code } }));
    if (code) setSelected(prev => new Set(prev).add(id));
  };

  // Satır-içi tutar düzenleme (fatura kaynağı)
  const handlePatchAmount = (item, total) => {
    if (!onPatchItem) return;
    onPatchItem(item.id, { total });
  };

  const handleProcess = async () => {
    if (selected.size === 0) {
      notify(lang === "en" ? "Select at least one item" : "En az bir öğe seçin", "err");
      return;
    }

    if (!confirm(
      lang === "en"
        ? `Post ${selected.size} ${source} transactions as ${postMode === "posted" ? "POSTED" : "DRAFT"}?`
        : `${selected.size} adet ${source === "bank" ? "banka" : source === "kasa" ? "kasa" : "fatura"} hareketi ${postMode === "posted" ? "ONAYLI" : "TASLAK"} olarak muhasebeleştirilsin mi?`
    )) return;

    setIsProcessing(true);
    setProcessedCount(0);

    const newVouchers = [];
    let currentEntries = [...entries];

    for (const { item, result } of generated) {
      if (!selected.has(item.id) || !result.success) continue;

      // Bu fiş için tekrar voucher no üret (çakışmaları engellemek için)
      const year = new Date(item.date || result.voucher.date).getFullYear();
      const voucherNo = generateVoucherNo(result.voucher.voucherType, year, currentEntries);

      const finalVoucher = {
        ...result.voucher,
        id: "je_" + Date.now() + "_" + Math.random().toString(36).slice(2, 8) + "_" + newVouchers.length,
        voucherNo,
        status: postMode,
        createdAt: new Date().toISOString(),
        createdBy: session.username,
      };
      if (postMode === "posted") {
        finalVoucher.postedAt = new Date().toISOString();
        finalVoucher.postedBy = session.username;
      }
      newVouchers.push(finalVoucher);
      currentEntries.push(finalVoucher);
      setProcessedCount(c => c + 1);
    }

    const updatedEntries = [...entries, ...newVouchers];
    await onChange({ ...data, accJournalEntries: updatedEntries });
    logAudit && logAudit("bulk_post", "journal_entry", {
      source, count: newVouchers.length, mode: postMode,
    });

    setIsProcessing(false);
    notify(
      lang === "en"
        ? `${newVouchers.length} vouchers created${postMode === "posted" ? " and posted" : " as drafts"}`
        : `${newVouchers.length} fiş ${postMode === "posted" ? "oluşturuldu ve onaylandı" : "taslak olarak oluşturuldu"}`
    );
    onClose();
  };

  const sourceLabels = {
    bank: lang === "en" ? "Bank Transactions" : "Banka Hareketleri",
    kasa: lang === "en" ? "Cash Transactions" : "Kasa Hareketleri",
    invoice: lang === "en" ? "Invoices" : "Faturalar",
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-4xl max-h-[92vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="px-5 py-4 border-b" style={{ background: "linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)", color: "#fff" }}>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <Sparkles size={20}/>
              <div>
                <div style={{ fontSize: 15, fontWeight: 700 }}>
                  {lang === "en" ? "Bulk Post to Accounting" : "Toplu Muhasebeleştirme"}
                </div>
                <div style={{ fontSize: 11, opacity: 0.9, marginTop: 2 }}>
                  {sourceLabels[source]} · {candidates.length} {lang === "en" ? "candidates" : "aday"}
                </div>
              </div>
            </div>
            <button onClick={onClose} className="p-1 rounded hover:bg-white/10">
              <X size={18}/>
            </button>
          </div>
        </div>

        {/* Özet Kartlar */}
        <div className="px-5 py-3 border-b" style={{ background: "var(--bg-alt)" }}>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            <div className="card p-2" style={{ borderLeft: "4px solid #737373" }}>
              <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Total Candidates" : "Toplam Aday"}
              </div>
              <div className="mono" style={{ fontSize: 18, fontWeight: 700 }}>{candidates.length}</div>
            </div>
            <div className="card p-2" style={{ borderLeft: "4px solid #15803d" }}>
              <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Will Process" : "İşlenecek"}
              </div>
              <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#15803d" }}>{selectedCount}</div>
            </div>
            <div className="card p-2" style={{ borderLeft: "4px solid #b91c1c" }}>
              <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Errors" : "Hata"}
              </div>
              <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#b91c1c" }}>{errorCount}</div>
            </div>
            <div className="card p-2" style={{ borderLeft: "4px solid #ca8a04" }}>
              <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Skipped" : "Atlanacak"}
              </div>
              <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#ca8a04" }}>{successCount - selectedCount}</div>
            </div>
          </div>

          {/* Mod seçimi */}
          <div className="mt-3 flex items-center gap-3 flex-wrap">
            <div style={{ fontSize: 12, fontWeight: 600 }}>
              {lang === "en" ? "Save as" : "Kaydetme Şekli"}:
            </div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              <button onClick={() => setPostMode("draft")} className="text-xs"
                style={{
                  padding: "5px 12px",
                  background: postMode === "draft" ? "#737373" : "var(--bg)",
                  color: postMode === "draft" ? "#fff" : "var(--ink)",
                  fontWeight: 600, cursor: "pointer",
                  borderRight: "1px solid var(--line)",
                }}>
                {lang === "en" ? "Draft" : "Taslak"}
              </button>
              <button onClick={() => setPostMode("posted")} className="text-xs"
                style={{
                  padding: "5px 12px",
                  background: postMode === "posted" ? "#15803d" : "var(--bg)",
                  color: postMode === "posted" ? "#fff" : "var(--ink)",
                  fontWeight: 600, cursor: "pointer",
                }}>
                {lang === "en" ? "Posted (Final)" : "Onaylı (Kesin)"}
              </button>
            </div>

            <button onClick={toggleAll} className="btn btn-ghost text-xs ml-auto">
              {selected.size === successCount
                ? (lang === "en" ? "Deselect All" : "Tümünü Bırak")
                : (lang === "en" ? "Select All Valid" : "Geçerlileri Seç")}
            </button>
          </div>
        </div>

        {/* İşlem Listesi */}
        <div className="flex-1 overflow-y-auto">
          <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)", position: "sticky", top: 0, zIndex: 5 }}>
                <th style={{ padding: "8px 6px", textAlign: "center", width: 40 }}>
                  <input
                    type="checkbox"
                    checked={selectedCount === successCount && successCount > 0}
                    onChange={toggleAll}
                  />
                </th>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>
                  {lang === "en" ? "Date" : "Tarih"}
                </th>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Description" : "Açıklama"}
                </th>
                <th style={{ padding: "8px 6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 120 }}>
                  {lang === "en" ? "Amount" : "Tutar"}
                </th>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 240 }}>
                  {lang === "en" ? "Suggested Accounts" : "Önerilen Hesaplar"}
                </th>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                  {lang === "en" ? "Status" : "Durum"}
                </th>
                {canEditItems && (
                  <th style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 70 }}>
                    {lang === "en" ? "Actions" : "İşlem"}
                  </th>
                )}
              </tr>
            </thead>
            <tbody>
              {generated.length === 0 ? (
                <tr><td colSpan={canEditItems ? 7 : 6} style={{ padding: 30, textAlign: "center", color: "var(--ink-mute)" }}>
                  {lang === "en" ? "No items to process" : "İşlenecek öğe yok"}
                </td></tr>
              ) : generated.map(({ item, result }, idx) => {
                const success = result.success;
                const isSelected = selected.has(item.id);
                const amount = Number(item.total ?? item.amount ?? item.totalAmount ?? item.grossAmount) || 0;
                const desc = item.description || item.invoiceNo || item.counterparty || item.partyName || "";
                const date = item.date || item.invoiceDate || item.dueDate || "—";

                return (
                  <tr key={item.id || idx}
                    style={{
                      borderBottom: "1px solid var(--line)",
                      background: !success ? "#fee2e2" : (isSelected ? "#dcfce7" : "transparent"),
                      opacity: !success ? 0.85 : 1,
                    }}
                  >
                    <td style={{ padding: "5px 6px", textAlign: "center" }}>
                      {success ? (
                        <input
                          type="checkbox"
                          checked={isSelected}
                          onChange={() => toggleItem(item.id)}
                        />
                      ) : (
                        <span style={{ color: "#b91c1c", fontWeight: 700 }}>✗</span>
                      )}
                    </td>
                    <td className="mono" style={{ padding: "5px 6px", fontSize: 10.5 }}>{date}</td>
                    <td style={{ padding: "5px 6px", fontSize: 11 }} className="truncate">
                      {desc || "—"}
                      {item.type && (
                        <span className="ml-1.5 chip" style={{
                          background: item.type === "in" ? "#dcfce7" : "#fee2e2",
                          color: item.type === "in" ? "#15803d" : "#b91c1c",
                          padding: "1px 5px", fontSize: 9, fontWeight: 600,
                        }}>
                          {item.type === "in" ? (lang === "en" ? "IN" : "GİRİŞ") : (lang === "en" ? "OUT" : "ÇIKIŞ")}
                        </span>
                      )}
                    </td>
                    <td className="mono text-right" style={{ padding: "5px 6px", fontSize: 11, fontWeight: 600 }}>
                      {canEditItems && onPatchItem ? (
                        <BulkAmountCell amount={amount} lang={lang} onSave={(v) => handlePatchAmount(item, v)} />
                      ) : (
                        `${fmtTL(amount)} ₺`
                      )}
                    </td>
                    <td style={{ padding: "5px 6px", fontSize: 10 }}>
                      {success && result.suggestedAccounts ? (
                        <div className="flex flex-col gap-0.5">
                          {Object.entries(result.suggestedAccounts).filter(([k, v]) => v).map(([key, acc]) => (
                            <div key={key} className="mono" style={{ fontSize: 9.5 }}>
                              <span style={{ color: "var(--ink-mute)" }}>{key}:</span>
                              <b style={{ color: ACCOUNT_TYPES[acc.type]?.color, marginLeft: 4 }}>{acc.code}</b>
                              <span style={{ color: "var(--ink-mute)", marginLeft: 4 }}>{acc.name.substring(0, 24)}</span>
                            </div>
                          ))}
                        </div>
                      ) : result.reason === "missing_account" && canEditItems ? (
                        <div className="flex flex-col gap-1">
                          <div style={{ fontSize: 9, color: "#b91c1c", fontWeight: 600 }}>
                            {lang === "en" ? "Account not found — pick manually:" : "Hesap bulunamadı — manuel seçin:"}
                          </div>
                          <MissingAccountPicker
                            missing={result.missing}
                            expected={result.expected}
                            accountOptions={accountOptions}
                            value={overrides[item.id]}
                            onPick={(role, code) => handlePick(item.id, role, code)}
                            lang={lang}
                          />
                        </div>
                      ) : result.reason === "zero_amount" ? (
                        <div style={{ fontSize: 10, color: "#b45309", fontWeight: 600 }}>
                          {lang === "en"
                            ? "Amount is zero/negative — edit the amount or delete the invoice."
                            : "Tutar sıfır/negatif — tutarı düzenleyin ya da faturayı silin."}
                        </div>
                      ) : (
                        <div style={{ fontSize: 10, color: "#b91c1c", fontWeight: 600 }}>
                          {result.error || (lang === "en" ? "Cannot generate" : "Üretilemedi")}
                        </div>
                      )}
                    </td>
                    <td style={{ padding: "5px 6px" }}>
                      {success ? (
                        <span style={{
                          padding: "2px 6px", fontSize: 9, fontWeight: 700, borderRadius: 3,
                          color: "#15803d", background: "#dcfce7", textTransform: "uppercase",
                        }}>
                          ✓ {lang === "en" ? "READY" : "HAZIR"}
                        </span>
                      ) : (
                        <span style={{
                          padding: "2px 6px", fontSize: 9, fontWeight: 700, borderRadius: 3,
                          color: "#b91c1c", background: "#fee2e2", textTransform: "uppercase",
                        }}>
                          ✗ {lang === "en" ? "ERROR" : "HATA"}
                        </span>
                      )}
                    </td>
                    {canEditItems && (
                      <td style={{ padding: "5px 6px", textAlign: "center", whiteSpace: "nowrap" }}>
                        {onEditItem && (
                          <button
                            onClick={() => onEditItem(item)}
                            className="p-1 rounded hover:bg-stone-100"
                            title={lang === "en" ? "Open full invoice form" : "Tam fatura formunu aç"}
                          >
                            <Edit3 size={12}/>
                          </button>
                        )}
                        {onDeleteItem && (
                          <button
                            onClick={() => onDeleteItem(item)}
                            className="p-1 rounded hover:bg-red-50"
                            title={lang === "en" ? "Delete invoice" : "Faturayı sil"}
                          >
                            <Trash2 size={12} style={{ color: "var(--negative)" }}/>
                          </button>
                        )}
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t flex items-center justify-between gap-2" style={{ background: "var(--bg-alt)" }}>
          {isProcessing ? (
            <div className="flex items-center gap-2">
              <RefreshCw size={14} className="animate-spin"/>
              <span style={{ fontSize: 12, fontWeight: 600 }}>
                {lang === "en" ? `Processing... ${processedCount}/${selectedCount}` : `İşleniyor... ${processedCount}/${selectedCount}`}
              </span>
            </div>
          ) : (
            <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
              {errorCount > 0 && (
                <span style={{ color: "#b91c1c" }}>
                  ⚠ {lang === "en"
                    ? `${errorCount} items have errors and will be skipped. Add module sources to your chart of accounts.`
                    : `${errorCount} öğe hatalı, atlanacak. Hesap planına modül kaynağı ekleyin.`}
                </span>
              )}
            </div>
          )}
          <div className="flex gap-2">
            <button onClick={onClose} disabled={isProcessing} className="btn btn-ghost text-xs">
              {lang === "en" ? "Cancel" : "İptal"}
            </button>
            <button
              onClick={handleProcess}
              disabled={selectedCount === 0 || isProcessing}
              className="btn btn-primary text-xs"
              style={selectedCount === 0 ? { opacity: 0.5, cursor: "not-allowed" } : {}}
            >
              <Sparkles size={11}/>
              {lang === "en"
                ? `Process ${selectedCount} ${postMode === "posted" ? "and Post" : "as Drafts"}`
                : `${selectedCount} Öğeyi ${postMode === "posted" ? "Onayla" : "Taslak Yap"}`}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   REVERSE — Yevmiye fişini geri al / iptal et
   ---------------------------------------------------------------------
   2 mod:
   - cancel: Fiş status="cancelled" yapılır (mevcut handleCancel'a benzer)
   - reverse: Aynı tarihli ters bir fiş üretilir (audit/finans için doğru)
===================================================================== */
function generateReverseVoucher(originalEntry, session, allEntries) {
  // Borç ↔ Alacak yer değiştirir
  const reversedLines = (originalEntry.lines || []).map((line, i) => ({
    id: `line_${i + 1}_${Date.now()}`,
    accountCode: line.accountCode,
    description: `[REVERSE] ${line.description || ""}`,
    debit: Number(line.credit) || 0,
    credit: Number(line.debit) || 0,
    currency: line.currency || "TRY",
  }));

  const today = new Date().toISOString().split("T")[0];
  const year = new Date(today).getFullYear();
  const voucherNo = generateVoucherNo(originalEntry.voucherType, year, allEntries);

  return {
    id: "je_rev_" + Date.now() + "_" + Math.random().toString(36).slice(2, 6),
    voucherNo,
    voucherType: originalEntry.voucherType,
    date: today,
    description: `[GERİ ALMA] ${originalEntry.voucherNo} - ${originalEntry.description || ""}`,
    source: "manual",
    sourceId: null,
    reversesEntryId: originalEntry.id,  // Hangi fişin tersi
    lines: reversedLines,
    totalDebit: originalEntry.totalCredit,
    totalCredit: originalEntry.totalDebit,
    status: "posted",
    createdAt: new Date().toISOString(),
    createdBy: session.username,
    postedAt: new Date().toISOString(),
    postedBy: session.username,
  };
}

/* =====================================================================
   MİZAN (Trial Balance) — Kapsamlı Filtreli Rapor
   ---------------------------------------------------------------------
   Sütunlar:
   - Önceki Devir Borç / Alacak
   - Dönem Borç / Alacak
   - Toplam Borç / Alacak
   - Borç Bakiye / Alacak Bakiye
===================================================================== */
function TrialBalanceManager({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];

  // === Filtre state ===
  const today = new Date();
  const firstOfYear = `${today.getFullYear()}-01-01`;
  const todayStr = today.toISOString().split("T")[0];

  const [periodPreset, setPeriodPreset] = useState("ytd"); // ytd | this_month | last_month | q1..q4 | h1 | h2 | year | custom
  const [dateFrom, setDateFrom] = useState(firstOfYear);
  const [dateTo, setDateTo] = useState(todayStr);
  const [includeOpening, setIncludeOpening] = useState(true);

  const [maxLevel, setMaxLevel] = useState(3); // 1=Sınıf, 2=Grup, 3=Ana, 4-5=Alt
  const [codeFrom, setCodeFrom] = useState("");
  const [codeTo, setCodeTo] = useState("");
  const [filterType, setFilterType] = useState("all");
  const [filterStatement, setFilterStatement] = useState("all"); // all | balance_sheet | income_statement
  const [filterBalance, setFilterBalance] = useState("non_zero"); // all | non_zero | debit_only | credit_only | zero_only
  const [filterActive, setFilterActive] = useState("active");
  const [filterMovement, setFilterMovement] = useState("all"); // all | with_movement | without_movement

  const [groupByType, setGroupByType] = useState(false);
  const [showSubtotals, setShowSubtotals] = useState(true);
  const [aggregateChildren, setAggregateChildren] = useState(true); // Alt hesapları üst hesaba topla
  const [displayCurrency, setDisplayCurrency] = useState("TRY");

  const [sortBy, setSortBy] = useState("code"); // code | name | debit_balance | credit_balance
  const [sortDir, setSortDir] = useState("asc");
  const [search, setSearch] = useState("");
  const [expandedNodes, setExpandedNodes] = useState(new Set());

  // === Preset bazlı tarih ayarı ===
  const applyPreset = (preset) => {
    setPeriodPreset(preset);
    const y = today.getFullYear();
    const m = today.getMonth();
    switch (preset) {
      case "ytd":
        setDateFrom(`${y}-01-01`);
        setDateTo(todayStr);
        break;
      case "this_month": {
        const first = new Date(y, m, 1).toISOString().split("T")[0];
        const last = new Date(y, m + 1, 0).toISOString().split("T")[0];
        setDateFrom(first); setDateTo(last);
        break;
      }
      case "last_month": {
        const first = new Date(y, m - 1, 1).toISOString().split("T")[0];
        const last = new Date(y, m, 0).toISOString().split("T")[0];
        setDateFrom(first); setDateTo(last);
        break;
      }
      case "q1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-03-31`); break;
      case "q2": setDateFrom(`${y}-04-01`); setDateTo(`${y}-06-30`); break;
      case "q3": setDateFrom(`${y}-07-01`); setDateTo(`${y}-09-30`); break;
      case "q4": setDateFrom(`${y}-10-01`); setDateTo(`${y}-12-31`); break;
      case "h1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-06-30`); break;
      case "h2": setDateFrom(`${y}-07-01`); setDateTo(`${y}-12-31`); break;
      case "year":
        setDateFrom(`${y}-01-01`); setDateTo(`${y}-12-31`);
        break;
      case "last_year": {
        const ly = y - 1;
        setDateFrom(`${ly}-01-01`); setDateTo(`${ly}-12-31`);
        break;
      }
      case "custom":
      default:
        break;
    }
  };

  // === Hesap bazlı bakiye hesaplamaları ===
  // Önceki Devir: dateFrom'dan ÖNCEKİ tüm hareketler (openingBalance dahil)
  // Dönem: dateFrom ile dateTo arası hareketler
  // Toplam: Önceki Devir + Dönem
  const accountBalances = useMemo(() => {
    const result = {};
    accounts.forEach(acc => {
      let prevDebit = 0, prevCredit = 0;
      let periodDebit = 0, periodCredit = 0;

      entries.forEach(entry => {
        if (entry.status === "cancelled") return;
        const isOpening = entry.voucherType === "opening";
        const include = includeOpening ? true : !isOpening;
        if (!include) return;

        (entry.lines || []).forEach(line => {
          if (line.accountCode !== acc.code) return;
          const d = Number(line.debit) || 0;
          const c = Number(line.credit) || 0;

          if (entry.date < dateFrom) {
            prevDebit += d;
            prevCredit += c;
          } else if (entry.date <= dateTo) {
            periodDebit += d;
            periodCredit += c;
          }
        });
      });

      const totalDebit = prevDebit + periodDebit;
      const totalCredit = prevCredit + periodCredit;
      const balance = totalDebit - totalCredit;

      result[acc.code] = {
        prevDebit, prevCredit,
        periodDebit, periodCredit,
        totalDebit, totalCredit,
        balance,
        debitBalance: balance > 0 ? balance : 0,
        creditBalance: balance < 0 ? -balance : 0,
        hasMovement: prevDebit > 0 || prevCredit > 0 || periodDebit > 0 || periodCredit > 0,
      };
    });
    return result;
  }, [accounts, entries, dateFrom, dateTo, includeOpening]);

  // === aggregateChildren açıksa: üst hesapların bakiyesini alt hesaplardan topla ===
  const aggregatedBalances = useMemo(() => {
    if (!aggregateChildren) return accountBalances;
    const result = {};
    accounts.forEach(acc => {
      result[acc.code] = { ...accountBalances[acc.code] };
    });
    // Alt → Üst toplama
    const sortedByLevel = [...accounts].sort((a, b) => (b.level || 0) - (a.level || 0));
    sortedByLevel.forEach(acc => {
      if (acc.parentCode && result[acc.parentCode]) {
        const ch = result[acc.code];
        const par = result[acc.parentCode];
        par.prevDebit += ch.prevDebit;
        par.prevCredit += ch.prevCredit;
        par.periodDebit += ch.periodDebit;
        par.periodCredit += ch.periodCredit;
        par.totalDebit += ch.totalDebit;
        par.totalCredit += ch.totalCredit;
        par.hasMovement = par.hasMovement || ch.hasMovement;
      }
    });
    // Bakiye yeniden hesapla
    Object.values(result).forEach(b => {
      b.balance = b.totalDebit - b.totalCredit;
      b.debitBalance = b.balance > 0 ? b.balance : 0;
      b.creditBalance = b.balance < 0 ? -b.balance : 0;
    });
    return result;
  }, [accountBalances, accounts, aggregateChildren]);

  // === Filtreleme ===
  const filteredAccounts = useMemo(() => {
    let list = accounts;

    // Seviye filtresi
    list = list.filter(a => (a.level || 1) <= maxLevel);

    // Aktif filtresi
    if (filterActive === "active") list = list.filter(a => a.active !== false);
    else if (filterActive === "inactive") list = list.filter(a => a.active === false);

    // Tip filtresi
    if (filterType !== "all") list = list.filter(a => a.type === filterType);

    // Mali tablo filtresi
    if (filterStatement !== "all") list = list.filter(a => a.statement === filterStatement);

    // Kod aralığı
    if (codeFrom.trim()) {
      list = list.filter(a => String(a.code).localeCompare(codeFrom.trim(), "tr", { numeric: true }) >= 0);
    }
    if (codeTo.trim()) {
      list = list.filter(a => String(a.code).localeCompare(codeTo.trim(), "tr", { numeric: true }) <= 0);
    }

    // Arama (kod veya ad)
    if (search.trim()) {
      const q = search.toLowerCase().trim();
      list = list.filter(a =>
        String(a.code).toLowerCase().includes(q) ||
        a.name.toLowerCase().includes(q) ||
        (a.nameEn || "").toLowerCase().includes(q)
      );
    }

    // Bakiye filtresi
    if (filterBalance !== "all") {
      list = list.filter(a => {
        const b = aggregatedBalances[a.code];
        if (!b) return false;
        if (filterBalance === "non_zero") return Math.abs(b.balance) > 0.01;
        if (filterBalance === "debit_only") return b.debitBalance > 0.01;
        if (filterBalance === "credit_only") return b.creditBalance > 0.01;
        if (filterBalance === "zero_only") return Math.abs(b.balance) < 0.01 && b.hasMovement;
        return true;
      });
    }

    // Hareket filtresi
    if (filterMovement !== "all") {
      list = list.filter(a => {
        const b = aggregatedBalances[a.code];
        if (!b) return false;
        if (filterMovement === "with_movement") return b.hasMovement;
        if (filterMovement === "without_movement") return !b.hasMovement;
        return true;
      });
    }

    // Sıralama
    list = [...list].sort((a, b) => {
      const dir = sortDir === "asc" ? 1 : -1;
      switch (sortBy) {
        case "code":
          return dir * String(a.code).localeCompare(String(b.code), "tr", { numeric: true });
        case "name":
          return dir * (a.name || "").localeCompare(b.name || "", "tr");
        case "debit_balance":
          return dir * ((aggregatedBalances[a.code]?.debitBalance || 0) - (aggregatedBalances[b.code]?.debitBalance || 0));
        case "credit_balance":
          return dir * ((aggregatedBalances[a.code]?.creditBalance || 0) - (aggregatedBalances[b.code]?.creditBalance || 0));
        default:
          return 0;
      }
    });

    return list;
  }, [accounts, maxLevel, filterActive, filterType, filterStatement, codeFrom, codeTo, search, filterBalance, filterMovement, aggregatedBalances, sortBy, sortDir]);

  // === Toplamlar ===
  const totals = useMemo(() => {
    let prevDebit = 0, prevCredit = 0;
    let periodDebit = 0, periodCredit = 0;
    let totalDebit = 0, totalCredit = 0;
    let debitBalance = 0, creditBalance = 0;

    // aggregateChildren açıksa sadece seviye 1 hesaplarını topla (yoksa duplicate olur)
    // değilse tümünü topla
    const accountsForTotal = aggregateChildren
      ? filteredAccounts.filter(a => (a.level || 1) === 1)
      : filteredAccounts;

    accountsForTotal.forEach(a => {
      const b = aggregatedBalances[a.code];
      if (!b) return;
      prevDebit += b.prevDebit;
      prevCredit += b.prevCredit;
      periodDebit += b.periodDebit;
      periodCredit += b.periodCredit;
      totalDebit += b.totalDebit;
      totalCredit += b.totalCredit;
      debitBalance += b.debitBalance;
      creditBalance += b.creditBalance;
    });

    return {
      prevDebit, prevCredit,
      periodDebit, periodCredit,
      totalDebit, totalCredit,
      debitBalance, creditBalance,
      isBalanced: Math.abs(totalDebit - totalCredit) < 0.01,
    };
  }, [filteredAccounts, aggregatedBalances, aggregateChildren]);

  // === Para birimi dönüşümü ===
  const rates = data.exchangeRates || {};
  const sym = CURRENCY_SYMBOLS[displayCurrency] || "₺";
  const showSym = displayCurrency !== "TRY";
  const conv = (v) => convertFromTRY(v, displayCurrency, rates);

  // === Excel export ===
  const handleExportExcel = () => {
    try {
      const rows = [
        [
          lang === "en" ? "Code" : "Kod",
          lang === "en" ? "Account Name" : "Hesap Adı",
          lang === "en" ? "Type" : "Tip",
          lang === "en" ? "Prev Debit" : "Önceki Borç",
          lang === "en" ? "Prev Credit" : "Önceki Alacak",
          lang === "en" ? "Period Debit" : "Dönem Borç",
          lang === "en" ? "Period Credit" : "Dönem Alacak",
          lang === "en" ? "Total Debit" : "Toplam Borç",
          lang === "en" ? "Total Credit" : "Toplam Alacak",
          lang === "en" ? "Debit Balance" : "Borç Bakiye",
          lang === "en" ? "Credit Balance" : "Alacak Bakiye",
        ],
      ];
      filteredAccounts.forEach(a => {
        const b = aggregatedBalances[a.code];
        if (!b) return;
        rows.push([
          a.code, a.name, ACCOUNT_TYPES[a.type]?.label.tr || a.type,
          conv(b.prevDebit), conv(b.prevCredit),
          conv(b.periodDebit), conv(b.periodCredit),
          conv(b.totalDebit), conv(b.totalCredit),
          conv(b.debitBalance), conv(b.creditBalance),
        ]);
      });
      // Toplam satırı
      rows.push([
        "", lang === "en" ? "TOTAL" : "TOPLAM", "",
        conv(totals.prevDebit), conv(totals.prevCredit),
        conv(totals.periodDebit), conv(totals.periodCredit),
        conv(totals.totalDebit), conv(totals.totalCredit),
        conv(totals.debitBalance), conv(totals.creditBalance),
      ]);

      const csv = rows.map(r => r.map(c => {
        if (typeof c === "number") return c.toFixed(2);
        const s = String(c || "");
        return s.includes(",") || s.includes("\"") || s.includes("\n")
          ? `"${s.replace(/"/g, '""')}"` : s;
      }).join(",")).join("\n");

      const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
      const url = URL.createObjectURL(blob);
      const a = document.createElement("a");
      a.href = url;
      a.download = `mizan_${dateFrom}_${dateTo}.csv`;
      a.click();
      URL.revokeObjectURL(url);
      notify(lang === "en" ? "Trial balance exported" : "Mizan dışa aktarıldı");
    } catch (err) {
      notify(lang === "en" ? "Export failed: " + err.message : "Dışa aktarım başarısız: " + err.message, "err");
    }
  };

  // === Yazdır ===
  const handlePrint = () => {
    window.print();
  };

  // === Filtreleri sıfırla ===
  const resetFilters = () => {
    applyPreset("ytd");
    setMaxLevel(3);
    setCodeFrom(""); setCodeTo("");
    setFilterType("all"); setFilterStatement("all");
    setFilterBalance("non_zero"); setFilterActive("active");
    setFilterMovement("all");
    setGroupByType(false); setAggregateChildren(true);
    setSearch("");
  };

  // === Render ===
  return (
    <div className="space-y-3">
      {/* Alt başlık */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <p className="text-sm" style={{ color: "var(--ink-mute)" }}>
          {lang === "en"
            ? `Trial Balance · ${dateFrom} — ${dateTo}`
            : `Mizan · ${dateFrom} — ${dateTo}`}
        </p>
        <div className="flex items-center gap-2">
          <button onClick={resetFilters} className="btn btn-ghost text-xs">
            <RefreshCw size={11}/> {lang === "en" ? "Reset" : "Sıfırla"}
          </button>
          <button onClick={handlePrint} className="btn btn-ghost text-xs">
            {lang === "en" ? "Print" : "Yazdır"}
          </button>
          <button onClick={handleExportExcel} className="btn btn-primary text-xs">
            <FileSpreadsheet size={11}/> {lang === "en" ? "Export" : "Dışa Aktar"}
          </button>
        </div>
      </div>

      {/* === FİLTRE PANELİ === */}
      <div className="card p-3 space-y-3">
        {/* Hızlı Dönem Seçimi */}
        <div>
          <div className="label mb-1.5">{lang === "en" ? "Period" : "Dönem"}</div>
          <div className="flex flex-wrap gap-1">
            {[
              { id: "ytd", label: { tr: "Yıl Başından", en: "YTD" } },
              { id: "this_month", label: { tr: "Bu Ay", en: "This Month" } },
              { id: "last_month", label: { tr: "Geçen Ay", en: "Last Month" } },
              { id: "q1", label: { tr: "1. Çeyrek", en: "Q1" } },
              { id: "q2", label: { tr: "2. Çeyrek", en: "Q2" } },
              { id: "q3", label: { tr: "3. Çeyrek", en: "Q3" } },
              { id: "q4", label: { tr: "4. Çeyrek", en: "Q4" } },
              { id: "h1", label: { tr: "1. Yarı", en: "H1" } },
              { id: "h2", label: { tr: "2. Yarı", en: "H2" } },
              { id: "year", label: { tr: "Bu Yıl", en: "This Year" } },
              { id: "last_year", label: { tr: "Geçen Yıl", en: "Last Year" } },
              { id: "custom", label: { tr: "Özel", en: "Custom" } },
            ].map(p => (
              <button
                key={p.id}
                onClick={() => applyPreset(p.id)}
                className="text-xs"
                style={{
                  padding: "4px 10px",
                  background: periodPreset === p.id ? "var(--accent)" : "var(--bg)",
                  color: periodPreset === p.id ? "#fff" : "var(--ink)",
                  border: `1px solid ${periodPreset === p.id ? "var(--accent)" : "var(--line)"}`,
                  borderRadius: 3,
                  fontWeight: periodPreset === p.id ? 600 : 400,
                  cursor: "pointer",
                }}
              >
                {p.label[lang] || p.label.tr}
              </button>
            ))}
          </div>
        </div>

        {/* Tarih + Açılış */}
        <div className="flex flex-wrap items-end gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "From" : "Başlangıç"}</div>
            <input type="date" className="input mono text-xs" value={dateFrom}
              onChange={e => { setDateFrom(e.target.value); setPeriodPreset("custom"); }}
              style={{ width: 140 }}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "To" : "Bitiş"}</div>
            <input type="date" className="input mono text-xs" value={dateTo}
              onChange={e => { setDateTo(e.target.value); setPeriodPreset("custom"); }}
              style={{ width: 140 }}/>
          </div>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={includeOpening}
              onChange={e => setIncludeOpening(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Include opening entries" : "Açılış fişlerini dahil et"}
            </span>
          </label>
        </div>

        {/* Filtre satırı 1 */}
        <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-2">
          {/* Hesap tipi */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Type" : "Tip"}</div>
            <select className="input w-full text-xs" value={filterType} onChange={e => setFilterType(e.target.value)}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              {Object.entries(ACCOUNT_TYPES).map(([key, t]) => (
                <option key={key} value={key}>{t.label[lang] || t.label.tr}</option>
              ))}
            </select>
          </div>

          {/* Mali tablo */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Statement" : "Mali Tablo"}</div>
            <select className="input w-full text-xs" value={filterStatement} onChange={e => setFilterStatement(e.target.value)}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="balance_sheet">{lang === "en" ? "Balance Sheet" : "Bilanço"}</option>
              <option value="income_statement">{lang === "en" ? "Income Stmt" : "Gelir Tablosu"}</option>
              <option value="none">{lang === "en" ? "None (Nazım)" : "Yok (Nazım)"}</option>
            </select>
          </div>

          {/* Bakiye */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Balance" : "Bakiye"}</div>
            <select className="input w-full text-xs" value={filterBalance} onChange={e => setFilterBalance(e.target.value)}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="non_zero">{lang === "en" ? "Non-zero only" : "Sadece bakiyeliler"}</option>
              <option value="debit_only">{lang === "en" ? "Debit only" : "Sadece borç bakiye"}</option>
              <option value="credit_only">{lang === "en" ? "Credit only" : "Sadece alacak bakiye"}</option>
              <option value="zero_only">{lang === "en" ? "Zero balance" : "Sıfır bakiye"}</option>
            </select>
          </div>

          {/* Hareket */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Movement" : "Hareket"}</div>
            <select className="input w-full text-xs" value={filterMovement} onChange={e => setFilterMovement(e.target.value)}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="with_movement">{lang === "en" ? "With movement" : "Hareket olanlar"}</option>
              <option value="without_movement">{lang === "en" ? "Without movement" : "Hareket olmayanlar"}</option>
            </select>
          </div>

          {/* Aktif */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Status" : "Durum"}</div>
            <select className="input w-full text-xs" value={filterActive} onChange={e => setFilterActive(e.target.value)}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="active">{lang === "en" ? "Active" : "Aktif"}</option>
              <option value="inactive">{lang === "en" ? "Inactive" : "Pasif"}</option>
            </select>
          </div>

          {/* Maksimum seviye */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Max Level" : "Maks Seviye"}</div>
            <select className="input w-full text-xs" value={maxLevel} onChange={e => setMaxLevel(Number(e.target.value))}>
              <option value="1">1 — {lang === "en" ? "Class" : "Sınıf"}</option>
              <option value="2">2 — {lang === "en" ? "Group" : "Grup"}</option>
              <option value="3">3 — {lang === "en" ? "Main" : "Ana"}</option>
              <option value="4">4 — {lang === "en" ? "Sub" : "Alt"}</option>
              <option value="5">5 — {lang === "en" ? "Sub-Sub" : "Alt-Alt"}</option>
            </select>
          </div>
        </div>

        {/* Filtre satırı 2 — Kod aralığı + Arama */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-2">
          <div>
            <div className="label mb-1">{lang === "en" ? "Code From" : "Kod (Başlangıç)"}</div>
            <input className="input w-full mono text-xs" value={codeFrom}
              onChange={e => setCodeFrom(e.target.value)} placeholder="100"/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Code To" : "Kod (Bitiş)"}</div>
            <input className="input w-full mono text-xs" value={codeTo}
              onChange={e => setCodeTo(e.target.value)} placeholder="299"/>
          </div>
          <div className="md:col-span-2">
            <div className="label mb-1">{lang === "en" ? "Search" : "Ara"}</div>
            <input className="input w-full text-xs" value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder={lang === "en" ? "Code or account name..." : "Kod veya hesap adı..."}/>
          </div>
        </div>

        {/* Filtre satırı 3 — Görüntüleme seçenekleri */}
        <div className="flex flex-wrap items-end gap-3 pt-2" style={{ borderTop: "1px solid var(--line)" }}>
          {/* Para birimi */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Currency" : "Para Birimi"}</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              {["TRY", "USD", "EUR"].map(cur => (
                <button key={cur} onClick={() => setDisplayCurrency(cur)} className="text-xs"
                  style={{
                    padding: "5px 10px",
                    background: displayCurrency === cur ? "var(--accent)" : "var(--bg)",
                    color: displayCurrency === cur ? "#fff" : "var(--ink)",
                    fontWeight: 600,
                    borderRight: cur !== "EUR" ? "1px solid var(--line)" : "none",
                    cursor: "pointer",
                  }}>
                  {CURRENCY_SYMBOLS[cur] || ""} {cur}
                </button>
              ))}
            </div>
          </div>

          {/* Sıralama */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Sort By" : "Sıralama"}</div>
            <select className="input text-xs" value={sortBy} onChange={e => setSortBy(e.target.value)}
              style={{ minWidth: 130 }}>
              <option value="code">{lang === "en" ? "Code" : "Kod"}</option>
              <option value="name">{lang === "en" ? "Name" : "Ad"}</option>
              <option value="debit_balance">{lang === "en" ? "Debit Balance" : "Borç Bakiye"}</option>
              <option value="credit_balance">{lang === "en" ? "Credit Balance" : "Alacak Bakiye"}</option>
            </select>
          </div>
          <button onClick={() => setSortDir(sortDir === "asc" ? "desc" : "asc")} className="btn btn-ghost text-xs">
            {sortDir === "asc" ? "↑ A-Z" : "↓ Z-A"}
          </button>

          {/* Toggles */}
          <label className="flex items-center gap-2 cursor-pointer ml-auto">
            <input type="checkbox" checked={aggregateChildren}
              onChange={e => setAggregateChildren(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Aggregate sub-accounts" : "Alt hesapları topla"}
            </span>
          </label>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={showSubtotals}
              onChange={e => setShowSubtotals(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Class subtotals" : "Sınıf alt toplamları"}
            </span>
          </label>
        </div>
      </div>

      {/* === RAPOR TABLOSU === */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", minWidth: 1200, fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{
                background: "var(--bg-alt)",
                borderBottom: "2px solid var(--line)",
                position: "sticky",
                top: 0,
                zIndex: 5,
              }}>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", minWidth: 80 }}>
                  {lang === "en" ? "Code" : "Kod"}
                </th>
                <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", minWidth: 200 }}>
                  {lang === "en" ? "Account Name" : "Hesap Adı"}
                </th>
                <th colSpan="2" style={{ padding: "4px 6px", textAlign: "center", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", borderLeft: "1px solid var(--line)", background: "#fef3c7" }}>
                  {lang === "en" ? "Previous" : "Önceki Devir"}
                </th>
                <th colSpan="2" style={{ padding: "4px 6px", textAlign: "center", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", borderLeft: "1px solid var(--line)", background: "#dbeafe" }}>
                  {lang === "en" ? "Period" : "Dönem"}
                </th>
                <th colSpan="2" style={{ padding: "4px 6px", textAlign: "center", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", borderLeft: "1px solid var(--line)", background: "#e0e7ff" }}>
                  {lang === "en" ? "Total" : "Toplam"}
                </th>
                <th colSpan="2" style={{ padding: "4px 6px", textAlign: "center", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", borderLeft: "1px solid var(--line)", background: "#dcfce7" }}>
                  {lang === "en" ? "Balance" : "Bakiye"}
                </th>
              </tr>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)", position: "sticky", top: 28, zIndex: 5 }}>
                <th colSpan="2"/>
                {/* Önceki */}
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#0f766e", borderLeft: "1px solid var(--line)" }}>
                  {lang === "en" ? "Debit" : "Borç"}
                </th>
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#b91c1c" }}>
                  {lang === "en" ? "Credit" : "Alacak"}
                </th>
                {/* Dönem */}
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#0f766e", borderLeft: "1px solid var(--line)" }}>
                  {lang === "en" ? "Debit" : "Borç"}
                </th>
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#b91c1c" }}>
                  {lang === "en" ? "Credit" : "Alacak"}
                </th>
                {/* Toplam */}
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#0f766e", borderLeft: "1px solid var(--line)" }}>
                  {lang === "en" ? "Debit" : "Borç"}
                </th>
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#b91c1c" }}>
                  {lang === "en" ? "Credit" : "Alacak"}
                </th>
                {/* Bakiye */}
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#0f766e", borderLeft: "1px solid var(--line)" }}>
                  {lang === "en" ? "Debit Bal." : "Borç Bk."}
                </th>
                <th style={{ padding: "4px 6px", textAlign: "right", fontSize: 9, fontWeight: 600, color: "#b91c1c" }}>
                  {lang === "en" ? "Credit Bal." : "Alacak Bk."}
                </th>
              </tr>
            </thead>
            <tbody>
              {filteredAccounts.length === 0 ? (
                <tr>
                  <td colSpan="10" style={{ padding: 30, textAlign: "center", color: "var(--ink-mute)" }}>
                    <div style={{ fontSize: 13 }}>
                      {lang === "en" ? "No accounts match your filters" : "Filtreye uyan hesap yok"}
                    </div>
                  </td>
                </tr>
              ) : (
                filteredAccounts.map((acc, idx) => {
                  const b = aggregatedBalances[acc.code];
                  if (!b) return null;
                  const typeCfg = ACCOUNT_TYPES[acc.type] || ACCOUNT_TYPES.aktif;
                  const lc = {
                    1: { fontSize: 12, fontWeight: 700, bg: typeCfg.color + "15", padding: 8 },
                    2: { fontSize: 11.5, fontWeight: 700, bg: typeCfg.color + "08", padding: 7 },
                    3: { fontSize: 11, fontWeight: 600, bg: "transparent", padding: 6 },
                    4: { fontSize: 10.5, fontWeight: 500, bg: "transparent", padding: 5 },
                    5: { fontSize: 10, fontWeight: 500, bg: "transparent", padding: 4 },
                  }[acc.level] || { fontSize: 10, fontWeight: 500, bg: "transparent", padding: 4 };

                  const indentPx = ((acc.level || 1) - 1) * 10;

                  return (
                    <tr key={acc.id || acc.code}
                      style={{
                        background: lc.bg,
                        borderBottom: "1px solid var(--line)",
                        opacity: acc.active === false ? 0.6 : 1,
                      }}
                    >
                      <td style={{ padding: lc.padding + "px 6px", paddingLeft: 6 + indentPx, fontSize: lc.fontSize, fontWeight: lc.fontWeight, color: typeCfg.color }} className="mono">
                        {acc.code}
                      </td>
                      <td style={{ padding: lc.padding + "px 6px", fontSize: lc.fontSize, fontWeight: lc.fontWeight }}>
                        {acc.name}
                      </td>
                      {/* Önceki Borç */}
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, borderLeft: "1px solid var(--line)", color: b.prevDebit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.prevDebit > 0 ? 1 : 0.3 }} className="mono">
                        {b.prevDebit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.prevDebit))}` : "—"}
                      </td>
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, color: b.prevCredit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.prevCredit > 0 ? 1 : 0.3 }} className="mono">
                        {b.prevCredit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.prevCredit))}` : "—"}
                      </td>
                      {/* Dönem Borç */}
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, borderLeft: "1px solid var(--line)", color: b.periodDebit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.periodDebit > 0 ? 1 : 0.3 }} className="mono">
                        {b.periodDebit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.periodDebit))}` : "—"}
                      </td>
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, color: b.periodCredit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.periodCredit > 0 ? 1 : 0.3 }} className="mono">
                        {b.periodCredit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.periodCredit))}` : "—"}
                      </td>
                      {/* Toplam */}
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, fontWeight: 600, borderLeft: "1px solid var(--line)", color: b.totalDebit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.totalDebit > 0 ? 1 : 0.3 }} className="mono">
                        {b.totalDebit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.totalDebit))}` : "—"}
                      </td>
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, fontWeight: 600, color: b.totalCredit > 0 ? "var(--ink)" : "var(--ink-mute)", opacity: b.totalCredit > 0 ? 1 : 0.3 }} className="mono">
                        {b.totalCredit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.totalCredit))}` : "—"}
                      </td>
                      {/* Bakiye */}
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, fontWeight: 700, borderLeft: "1px solid var(--line)", color: b.debitBalance > 0 ? "#0f766e" : "var(--ink-mute)", opacity: b.debitBalance > 0 ? 1 : 0.3 }} className="mono">
                        {b.debitBalance > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.debitBalance))}` : "—"}
                      </td>
                      <td style={{ padding: lc.padding + "px 6px", textAlign: "right", fontSize: lc.fontSize, fontWeight: 700, color: b.creditBalance > 0 ? "#b91c1c" : "var(--ink-mute)", opacity: b.creditBalance > 0 ? 1 : 0.3 }} className="mono">
                        {b.creditBalance > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(b.creditBalance))}` : "—"}
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
            <tfoot>
              <tr style={{
                background: totals.isBalanced ? "#dcfce7" : "#fee2e2",
                borderTop: "3px solid var(--ink)",
                fontWeight: 700,
              }}>
                <td colSpan="2" style={{ padding: "10px 6px", fontSize: 12, fontWeight: 700, textTransform: "uppercase" }}>
                  {lang === "en" ? "TOTAL" : "GENEL TOPLAM"}
                  {!totals.isBalanced && (
                    <span style={{ marginLeft: 8, color: "#b91c1c", fontSize: 11 }}>
                      ⚠ {lang === "en" ? "Not balanced!" : "Dengeli değil!"}
                    </span>
                  )}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5, borderLeft: "1px solid var(--line)" }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.prevDebit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5 }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.prevCredit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5, borderLeft: "1px solid var(--line)" }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.periodDebit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5 }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.periodCredit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5, borderLeft: "1px solid var(--line)" }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.totalDebit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5 }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.totalCredit))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5, color: "#0f766e", borderLeft: "1px solid var(--line)" }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.debitBalance))}
                </td>
                <td style={{ padding: "10px 6px", textAlign: "right", fontSize: 11.5, color: "#b91c1c" }} className="mono">
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.creditBalance))}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      {/* Footer info */}
      <div className="flex items-center justify-between text-xs" style={{ color: "var(--ink-mute)" }}>
        <span>
          {filteredAccounts.length} {lang === "en" ? "accounts shown" : "hesap gösteriliyor"}
        </span>
        <span>
          {totals.isBalanced
            ? (lang === "en" ? "✓ Trial balance is balanced" : "✓ Mizan dengeli")
            : (lang === "en" ? "⚠ Trial balance is not balanced" : "⚠ Mizan dengeli değil")}
        </span>
      </div>
    </div>
  );
}

/* =====================================================================
   BİLANÇO (Balance Sheet) — Aktif/Pasif klasik formatta
   ---------------------------------------------------------------------
   AKTIF: 1-Dönen Varlıklar, 2-Duran Varlıklar
   PASIF: 3-Kısa Vadeli, 4-Uzun Vadeli, 5-Özkaynaklar
===================================================================== */
function BalanceSheetReport({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];
  const rates = data.exchangeRates || {};

  const today = new Date();
  const [reportDate, setReportDate] = useState(today.toISOString().split("T")[0]);
  const [compareDate, setCompareDate] = useState(""); // Karşılaştırma tarihi
  const [showCompare, setShowCompare] = useState(false);
  const [maxLevel, setMaxLevel] = useState(3); // 1-2-3
  const [hideZero, setHideZero] = useState(true);
  const [displayCurrency, setDisplayCurrency] = useState("TRY");
  const [showOnlyMain, setShowOnlyMain] = useState(false); // Sadece ana grup başlıkları

  const sym = CURRENCY_SYMBOLS[displayCurrency] || "₺";
  const showSym = displayCurrency !== "TRY";
  const conv = (v) => convertFromTRY(v, displayCurrency, rates);

  // Belirli tarih için hesap bakiyesi
  const getBalanceForDate = (accountCode, asOfDate) => {
    let debit = 0, credit = 0;
    entries.forEach(entry => {
      if (entry.status === "cancelled") return;
      if (entry.date > asOfDate) return;
      (entry.lines || []).forEach(line => {
        if (line.accountCode !== accountCode) return;
        debit += Number(line.debit) || 0;
        credit += Number(line.credit) || 0;
      });
    });
    return { debit, credit, balance: debit - credit };
  };

  // Recursive (alt hesaplar dahil)
  const getRecursiveBalanceForDate = (accountCode, asOfDate) => {
    let result = getBalanceForDate(accountCode, asOfDate);
    accounts.filter(a => a.parentCode === accountCode).forEach(child => {
      const childB = getRecursiveBalanceForDate(child.code, asOfDate);
      result.debit += childB.debit;
      result.credit += childB.credit;
    });
    result.balance = result.debit - result.credit;
    return result;
  };

  // Bir sınıf veya hesap için "net bakiye" (mali tablo tarafında gösterilen)
  // Aktif tipinde: Borç bakiye pozitif gösterilir
  // Pasif tipinde: Alacak bakiye pozitif gösterilir
  const getNetBalance = (accountCode, asOfDate, accountType) => {
    const b = getRecursiveBalanceForDate(accountCode, asOfDate);
    if (accountType === "aktif") {
      return b.balance; // Borç bakiye + ise pozitif
    } else if (accountType === "pasif" || accountType === "ozkaynak") {
      return -b.balance; // Alacak bakiye + ise pozitif
    }
    return b.balance;
  };

  // Bilanço için: Sınıf 1+2 = Aktif, 3+4+5 = Pasif
  // Aktif tipi açısından doğru hesaplama:
  // Sınıf 1: aktif → borç bakiye
  // Sınıf 2: aktif → borç bakiye
  // Sınıf 3: pasif → alacak bakiye
  // Sınıf 4: pasif → alacak bakiye
  // Sınıf 5: özkaynak → alacak bakiye
  // Eksi (-) hesaplar: alacak bakiye normal, bilançoda aktiften düşülür

  // Aktif sınıfları (1-2)
  const aktifClasses = useMemo(() => {
    return accounts
      .filter(a => (a.level || 1) === 1 && (a.code === "1" || a.code === "2"))
      .sort((a, b) => String(a.code).localeCompare(String(b.code)));
  }, [accounts]);

  // Pasif sınıfları (3-4-5)
  const pasifClasses = useMemo(() => {
    return accounts
      .filter(a => (a.level || 1) === 1 && (a.code === "3" || a.code === "4" || a.code === "5"))
      .sort((a, b) => String(a.code).localeCompare(String(b.code)));
  }, [accounts]);

  // Dönem net kâr/zarar hesaplama (5. sınıf için ekleme)
  // 6. sınıf (Gelir) - 7. sınıf giderler/(6X giderler) = Dönem kâr/zarar
  const calculatePeriodResult = (asOfDate) => {
    // Yılbaşı dene
    const year = new Date(asOfDate).getFullYear();
    const yearStart = `${year}-01-01`;

    let revenue = 0;  // 6X gelir hesapları
    let expense = 0;  // 6X gider hesapları + 7X maliyet hesapları
    entries.forEach(entry => {
      if (entry.status === "cancelled") return;
      if (entry.date < yearStart || entry.date > asOfDate) return;
      (entry.lines || []).forEach(line => {
        const acc = accounts.find(a => a.code === line.accountCode);
        if (!acc) return;
        const d = Number(line.debit) || 0;
        const c = Number(line.credit) || 0;
        if (acc.type === "gelir" || acc.type === "satis") {
          revenue += c - d;
        } else if (acc.type === "gider" || acc.type === "maliyet") {
          expense += d - c;
        }
      });
    });
    return revenue - expense;
  };

  // Aktif/Pasif toplamları
  const totals = useMemo(() => {
    let aktifTotal = 0, pasifTotal = 0;
    aktifClasses.forEach(c => { aktifTotal += getNetBalance(c.code, reportDate, "aktif"); });
    pasifClasses.forEach(c => {
      const type = c.code === "5" ? "ozkaynak" : "pasif";
      pasifTotal += getNetBalance(c.code, reportDate, type);
    });
    // Dönem kâr/zarar → pasif tarafına eklenir (özkaynaklar altında)
    const periodResult = calculatePeriodResult(reportDate);
    pasifTotal += periodResult;

    let aktifCompare = 0, pasifCompare = 0, periodResultCompare = 0;
    if (showCompare && compareDate) {
      aktifClasses.forEach(c => { aktifCompare += getNetBalance(c.code, compareDate, "aktif"); });
      pasifClasses.forEach(c => {
        const type = c.code === "5" ? "ozkaynak" : "pasif";
        pasifCompare += getNetBalance(c.code, compareDate, type);
      });
      periodResultCompare = calculatePeriodResult(compareDate);
      pasifCompare += periodResultCompare;
    }

    return {
      aktifTotal, pasifTotal,
      aktifCompare, pasifCompare,
      periodResult, periodResultCompare,
      isBalanced: Math.abs(aktifTotal - pasifTotal) < 1,
    };
  }, [aktifClasses, pasifClasses, reportDate, compareDate, showCompare, entries, accounts]);

  // Bir bölgeyi render et (Aktif veya Pasif)
  const renderSide = (classes, accountTypeFn, title, color) => {
    const lines = [];
    classes.forEach(cls => {
      const clsType = accountTypeFn(cls);
      const clsBalance = getNetBalance(cls.code, reportDate, clsType);
      const clsCompare = showCompare && compareDate ? getNetBalance(cls.code, compareDate, clsType) : 0;
      if (hideZero && Math.abs(clsBalance) < 1 && Math.abs(clsCompare) < 1) return;

      // Sınıf satırı (level 1)
      lines.push({
        type: "class",
        code: cls.code,
        name: cls.name,
        balance: clsBalance,
        compare: clsCompare,
      });

      if (showOnlyMain) return;

      // Grup satırları (level 2)
      const groups = accounts
        .filter(a => a.parentCode === cls.code && (a.level || 1) === 2)
        .sort((a, b) => String(a.code).localeCompare(String(b.code)));

      groups.forEach(grp => {
        const grpBalance = getNetBalance(grp.code, reportDate, clsType);
        const grpCompare = showCompare && compareDate ? getNetBalance(grp.code, compareDate, clsType) : 0;
        if (hideZero && Math.abs(grpBalance) < 1 && Math.abs(grpCompare) < 1) return;

        lines.push({
          type: "group",
          code: grp.code,
          name: grp.name,
          balance: grpBalance,
          compare: grpCompare,
        });

        if (maxLevel < 3) return;

        // Ana hesap satırları (level 3)
        const mainAccs = accounts
          .filter(a => a.parentCode === grp.code && (a.level || 1) === 3)
          .sort((a, b) => String(a.code).localeCompare(String(b.code)));

        mainAccs.forEach(ma => {
          const maBalance = getNetBalance(ma.code, reportDate, clsType);
          const maCompare = showCompare && compareDate ? getNetBalance(ma.code, compareDate, clsType) : 0;
          if (hideZero && Math.abs(maBalance) < 1 && Math.abs(maCompare) < 1) return;
          lines.push({
            type: "main",
            code: ma.code,
            name: ma.name,
            balance: maBalance,
            compare: maCompare,
          });
        });
      });
    });
    return lines;
  };

  const aktifLines = renderSide(aktifClasses, () => "aktif", "AKTİF", "#0f766e");
  const pasifLines = renderSide(pasifClasses, (cls) => cls.code === "5" ? "ozkaynak" : "pasif", "PASİF", "#b91c1c");

  // Dönem kâr/zarar pasifte özel satır
  const periodResultLine = totals.periodResult !== 0 || (showCompare && totals.periodResultCompare !== 0)
    ? {
        type: "period_result",
        code: "59",
        name: totals.periodResult >= 0
          ? (lang === "en" ? "Period Net Profit" : "Dönem Net Kârı")
          : (lang === "en" ? "Period Net Loss" : "Dönem Net Zararı"),
        balance: totals.periodResult,
        compare: totals.periodResultCompare,
      }
    : null;

  // Excel export
  const handleExport = () => {
    const rows = [
      [lang === "en" ? "Balance Sheet" : "BİLANÇO"],
      [reportDate],
      [],
      [lang === "en" ? "ASSETS" : "AKTİF"],
      [lang === "en" ? "Code" : "Kod", lang === "en" ? "Name" : "Hesap", lang === "en" ? "Amount" : "Tutar"],
    ];
    aktifLines.forEach(l => rows.push([l.code, l.name, conv(l.balance).toFixed(2)]));
    rows.push(["", lang === "en" ? "ASSETS TOTAL" : "AKTİF TOPLAM", conv(totals.aktifTotal).toFixed(2)]);
    rows.push([]);
    rows.push([lang === "en" ? "LIABILITIES & EQUITY" : "PASİF"]);
    rows.push([lang === "en" ? "Code" : "Kod", lang === "en" ? "Name" : "Hesap", lang === "en" ? "Amount" : "Tutar"]);
    pasifLines.forEach(l => rows.push([l.code, l.name, conv(l.balance).toFixed(2)]));
    if (periodResultLine) rows.push([periodResultLine.code, periodResultLine.name, conv(periodResultLine.balance).toFixed(2)]);
    rows.push(["", lang === "en" ? "LIABILITIES TOTAL" : "PASİF TOPLAM", conv(totals.pasifTotal).toFixed(2)]);

    const csv = rows.map(r => r.map(c => {
      const s = String(c || "");
      return s.includes(",") || s.includes("\"") ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");

    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `bilanco_${reportDate}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    notify(lang === "en" ? "Balance sheet exported" : "Bilanço dışa aktarıldı");
  };

  // Satır render
  const renderLine = (line) => {
    const styles = {
      class: { fontSize: 12.5, fontWeight: 700, bg: "#f3f4f6", indent: 0 },
      group: { fontSize: 11.5, fontWeight: 600, bg: "transparent", indent: 16 },
      main:  { fontSize: 11, fontWeight: 400, bg: "transparent", indent: 32 },
      period_result: { fontSize: 12, fontWeight: 700, bg: "#dcfce7", indent: 0 },
    };
    const s = styles[line.type] || styles.main;
    return (
      <tr key={line.code} style={{ background: s.bg, borderBottom: "1px solid var(--line)" }}>
        <td style={{ padding: "5px 6px", paddingLeft: 6 + s.indent, fontSize: s.fontSize, fontWeight: s.fontWeight }} className="mono">
          {line.code}
        </td>
        <td style={{ padding: "5px 6px", fontSize: s.fontSize, fontWeight: s.fontWeight }}>
          {line.name}
        </td>
        <td className="mono" style={{ padding: "5px 6px", textAlign: "right", fontSize: s.fontSize, fontWeight: s.fontWeight, color: line.balance < 0 ? "#b91c1c" : "var(--ink)" }}>
          {Math.abs(line.balance) < 1 ? "—" : `${showSym ? sym + " " : ""}${fmtTL(conv(line.balance))}`}
        </td>
        {showCompare && compareDate && (
          <td className="mono" style={{ padding: "5px 6px", textAlign: "right", fontSize: s.fontSize, fontWeight: s.fontWeight, color: line.compare < 0 ? "#b91c1c" : "var(--ink-mute)" }}>
            {Math.abs(line.compare) < 1 ? "—" : `${showSym ? sym + " " : ""}${fmtTL(conv(line.compare))}`}
          </td>
        )}
      </tr>
    );
  };

  return (
    <div className="space-y-3">
      {/* Başlık */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <p className="text-sm" style={{ color: "var(--ink-mute)" }}>
          {lang === "en" ? `Balance Sheet as of ${reportDate}` : `Bilanço · ${reportDate} tarihli`}
        </p>
        <button onClick={handleExport} className="btn btn-primary text-xs">
          <FileSpreadsheet size={11}/> {lang === "en" ? "Export" : "Dışa Aktar"}
        </button>
      </div>

      {/* Filtreler */}
      <div className="card p-3">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Report Date" : "Rapor Tarihi"}</div>
            <input type="date" className="input w-full mono text-xs" value={reportDate}
              onChange={e => setReportDate(e.target.value)}/>
          </div>

          <div>
            <div className="label mb-1 flex items-center justify-between">
              <span>{lang === "en" ? "Compare With" : "Karşılaştır"}</span>
              <input type="checkbox" checked={showCompare}
                onChange={e => setShowCompare(e.target.checked)}/>
            </div>
            <input type="date" className="input w-full mono text-xs" value={compareDate}
              onChange={e => setCompareDate(e.target.value)} disabled={!showCompare}/>
          </div>

          <div>
            <div className="label mb-1">{lang === "en" ? "Detail Level" : "Detay Seviyesi"}</div>
            <select className="input w-full text-xs" value={maxLevel} onChange={e => setMaxLevel(Number(e.target.value))}>
              <option value="1">1 — {lang === "en" ? "Class only" : "Sadece Sınıf"}</option>
              <option value="2">2 — {lang === "en" ? "Class + Group" : "Sınıf + Grup"}</option>
              <option value="3">3 — {lang === "en" ? "Full Detail" : "Tam Detay"}</option>
            </select>
          </div>

          <div>
            <div className="label mb-1">{lang === "en" ? "Currency" : "Para Birimi"}</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              {["TRY", "USD", "EUR"].map(cur => (
                <button key={cur} onClick={() => setDisplayCurrency(cur)} className="text-xs"
                  style={{
                    padding: "5px 10px", flex: 1,
                    background: displayCurrency === cur ? "var(--accent)" : "var(--bg)",
                    color: displayCurrency === cur ? "#fff" : "var(--ink)",
                    fontWeight: 600, cursor: "pointer",
                    borderRight: cur !== "EUR" ? "1px solid var(--line)" : "none",
                  }}>
                  {CURRENCY_SYMBOLS[cur] || ""} {cur}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="flex flex-wrap items-center gap-3 mt-3 pt-3" style={{ borderTop: "1px solid var(--line)" }}>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={hideZero}
              onChange={e => setHideZero(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Hide zero balances" : "Sıfır bakiyeleri gizle"}
            </span>
          </label>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={showOnlyMain}
              onChange={e => setShowOnlyMain(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Show only main classes" : "Sadece ana sınıfları göster"}
            </span>
          </label>
        </div>
      </div>

      {/* Bilanço Tablosu — İki Sütun */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-3">
        {/* AKTİF */}
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "10px 12px", background: "#0f766e", color: "#fff", fontSize: 14, fontWeight: 700 }}>
            {lang === "en" ? "ASSETS" : "AKTİF"}
          </div>
          <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)" }}>
                <th style={{ padding: 6, textAlign: "left", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 70 }}>
                  {lang === "en" ? "Code" : "Kod"}
                </th>
                <th style={{ padding: 6, textAlign: "left", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Account" : "Hesap"}
                </th>
                <th style={{ padding: 6, textAlign: "right", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                  {reportDate.slice(5)}
                </th>
                {showCompare && compareDate && (
                  <th style={{ padding: 6, textAlign: "right", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                    {compareDate.slice(5)}
                  </th>
                )}
              </tr>
            </thead>
            <tbody>
              {aktifLines.length === 0 ? (
                <tr><td colSpan={showCompare && compareDate ? 4 : 3} style={{ padding: 30, textAlign: "center", color: "var(--ink-mute)" }}>
                  {lang === "en" ? "No data" : "Veri yok"}
                </td></tr>
              ) : aktifLines.map(renderLine)}
            </tbody>
            <tfoot>
              <tr style={{ background: "#0f766e", color: "#fff", borderTop: "2px solid #0f766e" }}>
                <td colSpan="2" style={{ padding: "8px 6px", fontSize: 12, fontWeight: 700, textTransform: "uppercase" }}>
                  {lang === "en" ? "TOTAL ASSETS" : "AKTİF TOPLAM"}
                </td>
                <td className="mono" style={{ padding: "8px 6px", textAlign: "right", fontSize: 12, fontWeight: 700 }}>
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.aktifTotal))}
                </td>
                {showCompare && compareDate && (
                  <td className="mono" style={{ padding: "8px 6px", textAlign: "right", fontSize: 12, fontWeight: 700, opacity: 0.8 }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(totals.aktifCompare))}
                  </td>
                )}
              </tr>
            </tfoot>
          </table>
        </div>

        {/* PASİF */}
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "10px 12px", background: "#b91c1c", color: "#fff", fontSize: 14, fontWeight: 700 }}>
            {lang === "en" ? "LIABILITIES & EQUITY" : "PASİF"}
          </div>
          <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)" }}>
                <th style={{ padding: 6, textAlign: "left", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 70 }}>
                  {lang === "en" ? "Code" : "Kod"}
                </th>
                <th style={{ padding: 6, textAlign: "left", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Account" : "Hesap"}
                </th>
                <th style={{ padding: 6, textAlign: "right", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                  {reportDate.slice(5)}
                </th>
                {showCompare && compareDate && (
                  <th style={{ padding: 6, textAlign: "right", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                    {compareDate.slice(5)}
                  </th>
                )}
              </tr>
            </thead>
            <tbody>
              {pasifLines.length === 0 ? (
                <tr><td colSpan={showCompare && compareDate ? 4 : 3} style={{ padding: 30, textAlign: "center", color: "var(--ink-mute)" }}>
                  {lang === "en" ? "No data" : "Veri yok"}
                </td></tr>
              ) : (
                <>
                  {pasifLines.map(renderLine)}
                  {periodResultLine && renderLine(periodResultLine)}
                </>
              )}
            </tbody>
            <tfoot>
              <tr style={{ background: "#b91c1c", color: "#fff", borderTop: "2px solid #b91c1c" }}>
                <td colSpan="2" style={{ padding: "8px 6px", fontSize: 12, fontWeight: 700, textTransform: "uppercase" }}>
                  {lang === "en" ? "TOTAL LIABILITIES & EQUITY" : "PASİF TOPLAM"}
                </td>
                <td className="mono" style={{ padding: "8px 6px", textAlign: "right", fontSize: 12, fontWeight: 700 }}>
                  {showSym ? sym + " " : ""}{fmtTL(conv(totals.pasifTotal))}
                </td>
                {showCompare && compareDate && (
                  <td className="mono" style={{ padding: "8px 6px", textAlign: "right", fontSize: 12, fontWeight: 700, opacity: 0.8 }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(totals.pasifCompare))}
                  </td>
                )}
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      {/* Denge kontrolü */}
      <div className="card p-3" style={{
        background: totals.isBalanced ? "#dcfce7" : "#fee2e2",
        border: `1px solid ${totals.isBalanced ? "#15803d" : "#b91c1c"}`,
      }}>
        <div className="flex items-center justify-between">
          <div style={{ fontSize: 13, fontWeight: 700, color: totals.isBalanced ? "#15803d" : "#b91c1c" }}>
            {totals.isBalanced
              ? (lang === "en" ? "✓ Balance Sheet is balanced (Assets = Liabilities + Equity)" : "✓ Bilanço dengeli (Aktif = Pasif)")
              : (lang === "en" ? "⚠ Balance Sheet is not balanced!" : "⚠ Bilanço dengeli değil!")}
          </div>
          {!totals.isBalanced && (
            <div className="mono" style={{ fontSize: 11, color: "#b91c1c" }}>
              {lang === "en" ? "Difference" : "Fark"}: {fmtTL(Math.abs(totals.aktifTotal - totals.pasifTotal))} ₺
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   GELİR TABLOSU (Income Statement) — Türkiye standart formatı
   ---------------------------------------------------------------------
   Brüt Satışlar → Brüt Kâr → Faaliyet Kârı → Olağan Kâr → Net Kâr
===================================================================== */
function IncomeStatementReport({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];
  const rates = data.exchangeRates || {};

  const today = new Date();
  const y = today.getFullYear();
  const [dateFrom, setDateFrom] = useState(`${y}-01-01`);
  const [dateTo, setDateTo] = useState(today.toISOString().split("T")[0]);
  const [periodPreset, setPeriodPreset] = useState("ytd");
  const [showCompare, setShowCompare] = useState(false);
  const [compareDateFrom, setCompareDateFrom] = useState(`${y - 1}-01-01`);
  const [compareDateTo, setCompareDateTo] = useState(`${y - 1}-12-31`);
  const [displayCurrency, setDisplayCurrency] = useState("TRY");
  const [showPercentages, setShowPercentages] = useState(true);

  const sym = CURRENCY_SYMBOLS[displayCurrency] || "₺";
  const showSym = displayCurrency !== "TRY";
  const conv = (v) => convertFromTRY(v, displayCurrency, rates);

  // Preset
  const applyPreset = (preset) => {
    setPeriodPreset(preset);
    const m = today.getMonth();
    switch (preset) {
      case "ytd":
        setDateFrom(`${y}-01-01`); setDateTo(today.toISOString().split("T")[0]);
        break;
      case "this_month":
        setDateFrom(new Date(y, m, 1).toISOString().split("T")[0]);
        setDateTo(new Date(y, m + 1, 0).toISOString().split("T")[0]);
        break;
      case "q1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-03-31`); break;
      case "q2": setDateFrom(`${y}-04-01`); setDateTo(`${y}-06-30`); break;
      case "q3": setDateFrom(`${y}-07-01`); setDateTo(`${y}-09-30`); break;
      case "q4": setDateFrom(`${y}-10-01`); setDateTo(`${y}-12-31`); break;
      case "h1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-06-30`); break;
      case "h2": setDateFrom(`${y}-07-01`); setDateTo(`${y}-12-31`); break;
      case "year": setDateFrom(`${y}-01-01`); setDateTo(`${y}-12-31`); break;
      case "last_year":
        setDateFrom(`${y - 1}-01-01`); setDateTo(`${y - 1}-12-31`); break;
      default: break;
    }
  };

  // Belirli kod prefix'leri için dönem toplamı (recursive)
  const getPeriodTotal = (codePrefix, from, to) => {
    let debit = 0, credit = 0;
    entries.forEach(entry => {
      if (entry.status === "cancelled") return;
      if (entry.date < from || entry.date > to) return;
      (entry.lines || []).forEach(line => {
        if (!String(line.accountCode).startsWith(codePrefix)) return;
        debit += Number(line.debit) || 0;
        credit += Number(line.credit) || 0;
      });
    });
    return { debit, credit, balance: debit - credit };
  };

  // Tek bir sınıf veya grup için bakiye al
  // Gelir hesapları için: Alacak > Borç olur (gelir borçluya yazılır)
  // Gider hesapları için: Borç > Alacak olur (gider borçluya yazılır)
  const calculateStatement = (from, to) => {
    // 60 - Brüt Satışlar
    const t60 = getPeriodTotal("60", from, to);
    const grossSales = t60.credit - t60.debit;

    // 61 - Satış İndirimleri (-)
    const t61 = getPeriodTotal("61", from, to);
    const salesDeductions = t61.debit - t61.credit;

    // Net Satışlar
    const netSales = grossSales - salesDeductions;

    // 62 - Satışların Maliyeti (-)
    const t62 = getPeriodTotal("62", from, to);
    const cogs = t62.debit - t62.credit;

    // Brüt Satış Kârı
    const grossProfit = netSales - cogs;

    // 63 - Faaliyet Giderleri (-)
    const t63 = getPeriodTotal("63", from, to);
    const operatingExpenses = t63.debit - t63.credit;

    // Faaliyet Kârı
    const operatingProfit = grossProfit - operatingExpenses;

    // 64 - Diğer Faaliyetlerden Olağan Gelir
    const t64 = getPeriodTotal("64", from, to);
    const otherOperatingRevenue = t64.credit - t64.debit;

    // 65 - Diğer Faaliyetlerden Olağan Gider (-)
    const t65 = getPeriodTotal("65", from, to);
    const otherOperatingExpense = t65.debit - t65.credit;

    // 66 - Finansman Giderleri (-)
    const t66 = getPeriodTotal("66", from, to);
    const financingExpense = t66.debit - t66.credit;

    // Olağan Kâr
    const ordinaryProfit = operatingProfit + otherOperatingRevenue - otherOperatingExpense - financingExpense;

    // 67 - Olağandışı Gelir
    const t67 = getPeriodTotal("67", from, to);
    const extraordinaryRevenue = t67.credit - t67.debit;

    // 68 - Olağandışı Gider (-)
    const t68 = getPeriodTotal("68", from, to);
    const extraordinaryExpense = t68.debit - t68.credit;

    // Dönem Kârı/Zararı (Vergi öncesi)
    const profitBeforeTax = ordinaryProfit + extraordinaryRevenue - extraordinaryExpense;

    // 691 - Dönem Kârı Vergi Karşılığı (-)
    const t691 = getPeriodTotal("691", from, to);
    const taxProvision = t691.debit - t691.credit;

    // Dönem Net Kârı
    const netProfit = profitBeforeTax - taxProvision;

    return {
      grossSales, salesDeductions, netSales,
      cogs, grossProfit,
      operatingExpenses, operatingProfit,
      otherOperatingRevenue, otherOperatingExpense, financingExpense,
      ordinaryProfit,
      extraordinaryRevenue, extraordinaryExpense,
      profitBeforeTax,
      taxProvision,
      netProfit,
    };
  };

  const current = useMemo(() => calculateStatement(dateFrom, dateTo), [dateFrom, dateTo, entries]);
  const compare = useMemo(() =>
    showCompare ? calculateStatement(compareDateFrom, compareDateTo) : null,
    [showCompare, compareDateFrom, compareDateTo, entries]
  );

  // Yüzdeler (Net Satışlar baz alınır)
  const pct = (v) => current.netSales === 0 ? 0 : (v / current.netSales) * 100;

  // Satır şablonu
  const rows = [
    { type: "section", code: "A", name: lang === "en" ? "REVENUE" : "GELİR", value: null, compareValue: null },
    { type: "item",    code: "60", name: lang === "en" ? "Gross Sales" : "Brüt Satışlar", value: current.grossSales, compareValue: compare?.grossSales },
    { type: "item",    code: "61", name: lang === "en" ? "(-) Sales Deductions" : "(-) Satış İndirimleri", value: -current.salesDeductions, compareValue: compare ? -compare.salesDeductions : null },
    { type: "subtotal", code: "",  name: lang === "en" ? "NET SALES" : "NET SATIŞLAR", value: current.netSales, compareValue: compare?.netSales },
    { type: "spacer" },
    { type: "section", code: "B", name: lang === "en" ? "COST OF GOODS" : "SATIŞLARIN MALİYETİ", value: null, compareValue: null },
    { type: "item",    code: "62", name: lang === "en" ? "(-) Cost of Goods Sold" : "(-) Satışların Maliyeti", value: -current.cogs, compareValue: compare ? -compare.cogs : null },
    { type: "subtotal", code: "",  name: lang === "en" ? "GROSS PROFIT" : "BRÜT SATIŞ KÂRI/ZARARI", value: current.grossProfit, compareValue: compare?.grossProfit, highlight: true },
    { type: "spacer" },
    { type: "section", code: "C", name: lang === "en" ? "OPERATING EXPENSES" : "FAALİYET GİDERLERİ", value: null, compareValue: null },
    { type: "item",    code: "63", name: lang === "en" ? "(-) Operating Expenses" : "(-) Faaliyet Giderleri", value: -current.operatingExpenses, compareValue: compare ? -compare.operatingExpenses : null },
    { type: "subtotal", code: "",  name: lang === "en" ? "OPERATING PROFIT" : "FAALİYET KÂRI/ZARARI", value: current.operatingProfit, compareValue: compare?.operatingProfit, highlight: true },
    { type: "spacer" },
    { type: "section", code: "D", name: lang === "en" ? "OTHER ORDINARY ITEMS" : "DİĞER OLAĞAN GELİR/GİDERLER", value: null, compareValue: null },
    { type: "item",    code: "64", name: lang === "en" ? "(+) Other Ordinary Revenue" : "(+) Diğer Faaliyetlerden Olağan Gelir", value: current.otherOperatingRevenue, compareValue: compare?.otherOperatingRevenue },
    { type: "item",    code: "65", name: lang === "en" ? "(-) Other Ordinary Expense" : "(-) Diğer Faaliyetlerden Olağan Gider", value: -current.otherOperatingExpense, compareValue: compare ? -compare.otherOperatingExpense : null },
    { type: "item",    code: "66", name: lang === "en" ? "(-) Financing Expense" : "(-) Finansman Giderleri", value: -current.financingExpense, compareValue: compare ? -compare.financingExpense : null },
    { type: "subtotal", code: "",  name: lang === "en" ? "ORDINARY PROFIT" : "OLAĞAN KÂR/ZARAR", value: current.ordinaryProfit, compareValue: compare?.ordinaryProfit, highlight: true },
    { type: "spacer" },
    { type: "section", code: "E", name: lang === "en" ? "EXTRAORDINARY ITEMS" : "OLAĞANDIŞI GELİR/GİDERLER", value: null, compareValue: null },
    { type: "item",    code: "67", name: lang === "en" ? "(+) Extraordinary Revenue" : "(+) Olağandışı Gelir", value: current.extraordinaryRevenue, compareValue: compare?.extraordinaryRevenue },
    { type: "item",    code: "68", name: lang === "en" ? "(-) Extraordinary Expense" : "(-) Olağandışı Gider", value: -current.extraordinaryExpense, compareValue: compare ? -compare.extraordinaryExpense : null },
    { type: "subtotal", code: "",  name: lang === "en" ? "PROFIT BEFORE TAX" : "DÖNEM KÂRI (VERGİ ÖNCESİ)", value: current.profitBeforeTax, compareValue: compare?.profitBeforeTax, highlight: true },
    { type: "spacer" },
    { type: "item",    code: "691", name: lang === "en" ? "(-) Tax Provision" : "(-) Vergi Karşılığı", value: -current.taxProvision, compareValue: compare ? -compare.taxProvision : null },
    { type: "total",   code: "",  name: lang === "en" ? "NET PROFIT/LOSS" : "DÖNEM NET KÂR/ZARARI", value: current.netProfit, compareValue: compare?.netProfit },
  ];

  // Export
  const handleExport = () => {
    const rowsCsv = [
      [lang === "en" ? "Income Statement" : "GELİR TABLOSU"],
      [`${dateFrom} — ${dateTo}`],
      [],
      [lang === "en" ? "Code" : "Kod", lang === "en" ? "Item" : "Kalem", lang === "en" ? "Amount" : "Tutar", showPercentages ? "%" : "", showCompare && compare ? lang === "en" ? "Previous" : "Önceki" : ""].filter(Boolean),
    ];
    rows.forEach(r => {
      if (r.type === "spacer") rowsCsv.push([]);
      else if (r.type === "section") rowsCsv.push([r.code, r.name, "", ""]);
      else if (r.value !== null && r.value !== undefined) {
        rowsCsv.push([
          r.code,
          r.name,
          conv(r.value).toFixed(2),
          showPercentages ? pct(r.value).toFixed(1) + "%" : "",
          showCompare && r.compareValue !== null && r.compareValue !== undefined ? conv(r.compareValue).toFixed(2) : "",
        ].filter(c => c !== ""));
      }
    });
    const csv = rowsCsv.map(r => r.map(c => {
      const s = String(c || "");
      return s.includes(",") || s.includes("\"") ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `gelir_tablosu_${dateFrom}_${dateTo}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    notify(lang === "en" ? "Income statement exported" : "Gelir tablosu dışa aktarıldı");
  };

  return (
    <div className="space-y-3">
      {/* Başlık */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <p className="text-sm" style={{ color: "var(--ink-mute)" }}>
          {lang === "en" ? `Income Statement · ${dateFrom} — ${dateTo}` : `Gelir Tablosu · ${dateFrom} — ${dateTo}`}
        </p>
        <button onClick={handleExport} className="btn btn-primary text-xs">
          <FileSpreadsheet size={11}/> {lang === "en" ? "Export" : "Dışa Aktar"}
        </button>
      </div>

      {/* Filtreler */}
      <div className="card p-3 space-y-3">
        {/* Preset */}
        <div>
          <div className="label mb-1.5">{lang === "en" ? "Period" : "Dönem"}</div>
          <div className="flex flex-wrap gap-1">
            {[
              { id: "ytd", label: { tr: "Yıl Başından", en: "YTD" } },
              { id: "this_month", label: { tr: "Bu Ay", en: "This Month" } },
              { id: "q1", label: { tr: "1. Çeyrek", en: "Q1" } },
              { id: "q2", label: { tr: "2. Çeyrek", en: "Q2" } },
              { id: "q3", label: { tr: "3. Çeyrek", en: "Q3" } },
              { id: "q4", label: { tr: "4. Çeyrek", en: "Q4" } },
              { id: "h1", label: { tr: "1. Yarı", en: "H1" } },
              { id: "h2", label: { tr: "2. Yarı", en: "H2" } },
              { id: "year", label: { tr: "Bu Yıl", en: "This Year" } },
              { id: "last_year", label: { tr: "Geçen Yıl", en: "Last Year" } },
              { id: "custom", label: { tr: "Özel", en: "Custom" } },
            ].map(p => (
              <button key={p.id} onClick={() => applyPreset(p.id)} className="text-xs"
                style={{
                  padding: "4px 10px",
                  background: periodPreset === p.id ? "var(--accent)" : "var(--bg)",
                  color: periodPreset === p.id ? "#fff" : "var(--ink)",
                  border: `1px solid ${periodPreset === p.id ? "var(--accent)" : "var(--line)"}`,
                  borderRadius: 3, cursor: "pointer",
                  fontWeight: periodPreset === p.id ? 600 : 400,
                }}>
                {p.label[lang] || p.label.tr}
              </button>
            ))}
          </div>
        </div>

        {/* Tarihler + Karşılaştırma */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "From" : "Başlangıç"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateFrom}
              onChange={e => { setDateFrom(e.target.value); setPeriodPreset("custom"); }}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "To" : "Bitiş"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateTo}
              onChange={e => { setDateTo(e.target.value); setPeriodPreset("custom"); }}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Currency" : "Para Birimi"}</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              {["TRY", "USD", "EUR"].map(cur => (
                <button key={cur} onClick={() => setDisplayCurrency(cur)} className="text-xs"
                  style={{
                    padding: "5px 10px", flex: 1,
                    background: displayCurrency === cur ? "var(--accent)" : "var(--bg)",
                    color: displayCurrency === cur ? "#fff" : "var(--ink)",
                    fontWeight: 600, cursor: "pointer",
                    borderRight: cur !== "EUR" ? "1px solid var(--line)" : "none",
                  }}>
                  {CURRENCY_SYMBOLS[cur] || ""} {cur}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Karşılaştırma */}
        <div className="flex flex-wrap items-end gap-3 pt-3" style={{ borderTop: "1px solid var(--line)" }}>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={showCompare}
              onChange={e => setShowCompare(e.target.checked)}/>
            <span style={{ fontSize: 12, fontWeight: 600 }}>
              {lang === "en" ? "Compare with previous period" : "Önceki dönemle karşılaştır"}
            </span>
          </label>
          {showCompare && (
            <>
              <input type="date" className="input mono text-xs" value={compareDateFrom}
                onChange={e => setCompareDateFrom(e.target.value)} style={{ width: 140 }}/>
              <span style={{ fontSize: 12, color: "var(--ink-mute)" }}>—</span>
              <input type="date" className="input mono text-xs" value={compareDateTo}
                onChange={e => setCompareDateTo(e.target.value)} style={{ width: 140 }}/>
            </>
          )}
          <label className="flex items-center gap-2 cursor-pointer ml-auto">
            <input type="checkbox" checked={showPercentages}
              onChange={e => setShowPercentages(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Show % of net sales" : "Net Satışlara oranı (%)"}
            </span>
          </label>
        </div>
      </div>

      {/* Gelir Tablosu */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <table style={{ width: "100%", fontSize: 12, borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 60 }}>
                {lang === "en" ? "Code" : "Kod"}
              </th>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Item" : "Kalem"}
              </th>
              <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 140 }}>
                {dateFrom.slice(0, 7)}–{dateTo.slice(5)}
              </th>
              {showPercentages && (
                <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 60 }}>
                  %
                </th>
              )}
              {showCompare && compare && (
                <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 140 }}>
                  {compareDateFrom.slice(0, 7)}–{compareDateTo.slice(5)}
                </th>
              )}
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => {
              if (r.type === "spacer") {
                return <tr key={i}><td colSpan="5" style={{ padding: 4, background: "#f3f4f6" }}/></tr>;
              }
              if (r.type === "section") {
                return (
                  <tr key={i} style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                    <td className="mono" style={{ padding: "6px 10px", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)" }}>{r.code}</td>
                    <td style={{ padding: "6px 10px", fontSize: 11, fontWeight: 700, textTransform: "uppercase", color: "var(--ink-mute)" }} colSpan="4">{r.name}</td>
                  </tr>
                );
              }
              if (r.type === "subtotal" || r.type === "total") {
                const isTotal = r.type === "total";
                const isPositive = r.value >= 0;
                const bg = isTotal
                  ? (isPositive ? "#15803d" : "#b91c1c")
                  : (r.highlight ? "#e0e7ff" : "#f3f4f6");
                const color = isTotal ? "#fff" : (isPositive ? "#15803d" : "#b91c1c");
                return (
                  <tr key={i} style={{ background: bg, borderTop: isTotal ? "3px solid #000" : "2px solid var(--line)", borderBottom: "1px solid var(--line)" }}>
                    <td className="mono" style={{ padding: "10px", fontSize: 11, fontWeight: 700, color }}>{r.code}</td>
                    <td style={{ padding: "10px", fontSize: isTotal ? 13 : 12, fontWeight: 700, color }}>
                      {r.name}
                    </td>
                    <td className="mono" style={{ padding: "10px", textAlign: "right", fontSize: isTotal ? 13 : 12, fontWeight: 700, color }}>
                      {showSym ? sym + " " : ""}{fmtTL(conv(r.value))}
                    </td>
                    {showPercentages && (
                      <td className="mono" style={{ padding: "10px", textAlign: "right", fontSize: 11, fontWeight: 700, color }}>
                        {pct(r.value).toFixed(1)}%
                      </td>
                    )}
                    {showCompare && compare && (
                      <td className="mono" style={{ padding: "10px", textAlign: "right", fontSize: 11.5, fontWeight: 700, color, opacity: 0.8 }}>
                        {r.compareValue !== null && r.compareValue !== undefined
                          ? `${showSym ? sym + " " : ""}${fmtTL(conv(r.compareValue))}`
                          : "—"}
                      </td>
                    )}
                  </tr>
                );
              }
              // item
              return (
                <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td className="mono" style={{ padding: "6px 10px", fontSize: 10.5, color: "var(--ink-mute)" }}>{r.code}</td>
                  <td style={{ padding: "6px 10px", fontSize: 11, paddingLeft: 24 }}>{r.name}</td>
                  <td className="mono" style={{ padding: "6px 10px", textAlign: "right", fontSize: 11, color: r.value < 0 ? "#b91c1c" : "var(--ink)" }}>
                    {Math.abs(r.value) < 1 ? "—" : `${showSym ? sym + " " : ""}${fmtTL(conv(r.value))}`}
                  </td>
                  {showPercentages && (
                    <td className="mono" style={{ padding: "6px 10px", textAlign: "right", fontSize: 10.5, color: "var(--ink-mute)" }}>
                      {Math.abs(r.value) < 1 ? "—" : pct(r.value).toFixed(1) + "%"}
                    </td>
                  )}
                  {showCompare && compare && (
                    <td className="mono" style={{ padding: "6px 10px", textAlign: "right", fontSize: 11, color: r.compareValue < 0 ? "#b91c1c" : "var(--ink-mute)" }}>
                      {r.compareValue === null || r.compareValue === undefined || Math.abs(r.compareValue) < 1
                        ? "—"
                        : `${showSym ? sym + " " : ""}${fmtTL(conv(r.compareValue))}`}
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
}

/* =====================================================================
   NAKİT AKIŞ TABLOSU (Cash Flow Statement) — UFRS/TFRS Uyumlu
   ---------------------------------------------------------------------
   Dolaylı Metot (Indirect Method):
   - Net Kâr + Düzeltmeler + Çalışma Sermayesi Değişimleri
   - Faaliyet / Yatırım / Finansman ayrımı
===================================================================== */
function CashFlowStatementReport({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];
  const rates = data.exchangeRates || {};

  const today = new Date();
  const y = today.getFullYear();
  const todayStr = today.toISOString().split("T")[0];

  const [periodPreset, setPeriodPreset] = useState("ytd");
  const [dateFrom, setDateFrom] = useState(`${y}-01-01`);
  const [dateTo, setDateTo] = useState(todayStr);
  const [method, setMethod] = useState("indirect"); // indirect | direct
  const [showCompare, setShowCompare] = useState(false);
  const [compareDateFrom, setCompareDateFrom] = useState(`${y - 1}-01-01`);
  const [compareDateTo, setCompareDateTo] = useState(`${y - 1}-12-31`);
  const [displayCurrency, setDisplayCurrency] = useState("TRY");
  const [hideZero, setHideZero] = useState(true);

  const sym = CURRENCY_SYMBOLS[displayCurrency] || "₺";
  const showSym = displayCurrency !== "TRY";
  const conv = (v) => convertFromTRY(v, displayCurrency, rates);

  // Period preset uygula
  const applyPreset = (preset) => {
    setPeriodPreset(preset);
    const m = today.getMonth();
    switch (preset) {
      case "ytd":
        setDateFrom(`${y}-01-01`); setDateTo(todayStr); break;
      case "this_month":
        setDateFrom(new Date(y, m, 1).toISOString().split("T")[0]);
        setDateTo(new Date(y, m + 1, 0).toISOString().split("T")[0]); break;
      case "q1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-03-31`); break;
      case "q2": setDateFrom(`${y}-04-01`); setDateTo(`${y}-06-30`); break;
      case "q3": setDateFrom(`${y}-07-01`); setDateTo(`${y}-09-30`); break;
      case "q4": setDateFrom(`${y}-10-01`); setDateTo(`${y}-12-31`); break;
      case "h1": setDateFrom(`${y}-01-01`); setDateTo(`${y}-06-30`); break;
      case "h2": setDateFrom(`${y}-07-01`); setDateTo(`${y}-12-31`); break;
      case "year": setDateFrom(`${y}-01-01`); setDateTo(`${y}-12-31`); break;
      case "last_year": setDateFrom(`${y - 1}-01-01`); setDateTo(`${y - 1}-12-31`); break;
      default: break;
    }
  };

  // === HESAPLAMA HELPER'LARI ===

  // Belirli kod prefix'i için dönem değişimi (recursive)
  // Açılış bakiyesi (from'dan önce) ile kapanış bakiyesi (to'da) arası fark
  const getBalanceChange = (codePrefix, fromDate, toDate) => {
    let openingD = 0, openingC = 0;
    let closingD = 0, closingC = 0;
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      (entry.lines || []).forEach(line => {
        if (!String(line.accountCode).startsWith(codePrefix)) return;
        const d = Number(line.debit) || 0;
        const c = Number(line.credit) || 0;
        if (entry.date < fromDate) {
          openingD += d; openingC += c;
        }
        if (entry.date <= toDate) {
          closingD += d; closingC += c;
        }
      });
    });
    const openingBalance = openingD - openingC;
    const closingBalance = closingD - closingC;
    return {
      opening: openingBalance,
      closing: closingBalance,
      change: closingBalance - openingBalance,
    };
  };

  // Belirli dönem için hareketleri topla (sadece dönem içi)
  const getPeriodMovement = (codePrefix, fromDate, toDate) => {
    let debit = 0, credit = 0;
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      if (entry.date < fromDate || entry.date > toDate) return;
      (entry.lines || []).forEach(line => {
        if (!String(line.accountCode).startsWith(codePrefix)) return;
        debit += Number(line.debit) || 0;
        credit += Number(line.credit) || 0;
      });
    });
    return { debit, credit, net: debit - credit };
  };

  // Dönem net kâr/zarar (Gelir Tablosundan)
  const getNetProfit = (fromDate, toDate) => {
    let revenue = 0, expense = 0;
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      if (entry.date < fromDate || entry.date > toDate) return;
      (entry.lines || []).forEach(line => {
        const acc = accounts.find(a => a.code === line.accountCode);
        if (!acc) return;
        const d = Number(line.debit) || 0;
        const c = Number(line.credit) || 0;
        if (acc.type === "gelir" || acc.type === "satis") {
          revenue += c - d;
        } else if (acc.type === "gider" || acc.type === "maliyet") {
          expense += d - c;
        }
      });
    });
    return revenue - expense;
  };

  // === DOLAYLI METOT İLE NAKİT AKIŞINI HESAPLA ===
  const calculateIndirect = (fromDate, toDate) => {
    // 1. NET KÂR (Gelir Tablosundan)
    const netProfit = getNetProfit(fromDate, toDate);

    // 2. DÜZELTMELER (Nakit dışı kalemler)
    // Amortismanlar: 257, 268 (Birikmiş Amortismanlar) - değişim
    // 770/750 üzerinden de gidebilir ama en doğrusu birikmiş amortisman hesaplarındaki artış
    const accumDepreciationChange = getBalanceChange("257", fromDate, toDate).change +
                                     getBalanceChange("268", fromDate, toDate).change;
    // Alacak (-) bakiye = artış = amortisman gideri (nakit dışı)
    // Bakiye değişimi negatife dönerse alacak artışı, geri ekliyoruz
    const depreciation = -accumDepreciationChange;

    // Karşılıklar (370, 372, 379, 472, 479)
    const provisionsChange =
      getBalanceChange("370", fromDate, toDate).change +
      getBalanceChange("372", fromDate, toDate).change +
      getBalanceChange("379", fromDate, toDate).change +
      getBalanceChange("472", fromDate, toDate).change +
      getBalanceChange("479", fromDate, toDate).change;
    // Karşılıklar alacak bakiyeli, artış nakit dışı gider
    const provisions = -provisionsChange;

    // Faiz gideri (660): finansman bölümüne gitmeli, faaliyetten çıkarılır
    const interestExpense = getPeriodMovement("660", fromDate, toDate).net;
    // Faiz geliri (640): yatırım/finansman'a göre, faaliyetten çıkarılır
    const interestIncome = getPeriodMovement("640", fromDate, toDate).net;
    // Net = (-credit) yani -(c-d) = d-c. Gelir hesabı c>d olduğu için negatif olur. -interestIncome = pozitif
    // Düzeltme: net kârdan faiz gelirini çıkar, faiz giderini ekle
    const interestAdjustment = (-interestIncome) - (-interestExpense);
    // Aslında: net kâr içindeki faiz gelirini çıkart (eksi), faiz giderini geri ekle (artı)

    // 3. ÇALIŞMA SERMAYESİ DEĞİŞİMLERİ
    // Ticari Alacaklar (120, 121, 122, 126, 127, 128)
    const receivablesChange =
      getBalanceChange("120", fromDate, toDate).change +
      getBalanceChange("121", fromDate, toDate).change +
      getBalanceChange("122", fromDate, toDate).change +
      getBalanceChange("126", fromDate, toDate).change +
      getBalanceChange("127", fromDate, toDate).change +
      getBalanceChange("128", fromDate, toDate).change;
    // Alacak artarsa nakit azalır (-)
    const receivablesEffect = -receivablesChange;

    // Stoklar (150, 151, 152, 153, 157, 158, 159)
    const inventoriesChange =
      getBalanceChange("15", fromDate, toDate).change;
    const inventoriesEffect = -inventoriesChange;

    // Diğer Dönen Varlıklar (180, 181, 195, 196, 197)
    const otherCurrentAssetsChange =
      getBalanceChange("180", fromDate, toDate).change +
      getBalanceChange("181", fromDate, toDate).change +
      getBalanceChange("195", fromDate, toDate).change +
      getBalanceChange("196", fromDate, toDate).change;
    const otherCurrentAssetsEffect = -otherCurrentAssetsChange;

    // Ticari Borçlar (320, 321, 322, 326)
    const payablesChange =
      getBalanceChange("320", fromDate, toDate).change +
      getBalanceChange("321", fromDate, toDate).change +
      getBalanceChange("322", fromDate, toDate).change +
      getBalanceChange("326", fromDate, toDate).change;
    // Borç artarsa nakit artar (+). Pasif hesap, alacak bakiyeli, change negatif olur, tersini al
    const payablesEffect = -payablesChange;

    // Diğer Kısa Vadeli Yükümlülükler (335, 336, 360, 361, 369, 380, 381)
    const otherCurrentLiabilitiesChange =
      getBalanceChange("335", fromDate, toDate).change +
      getBalanceChange("336", fromDate, toDate).change +
      getBalanceChange("360", fromDate, toDate).change +
      getBalanceChange("361", fromDate, toDate).change +
      getBalanceChange("369", fromDate, toDate).change +
      getBalanceChange("380", fromDate, toDate).change +
      getBalanceChange("381", fromDate, toDate).change;
    const otherCurrentLiabilitiesEffect = -otherCurrentLiabilitiesChange;

    // FAALIYETLERDEN NET NAKIT
    const operatingCash = netProfit + depreciation + provisions
      + receivablesEffect + inventoriesEffect + otherCurrentAssetsEffect
      + payablesEffect + otherCurrentLiabilitiesEffect;

    // 4. YATIRIM FAALİYETLERİ
    // Maddi Duran Varlık değişimi (25X)
    // Maliyet hesapları: 250, 251, 252, 253, 254, 255, 256, 258
    const tangibleAssetsChange =
      getBalanceChange("250", fromDate, toDate).change +
      getBalanceChange("251", fromDate, toDate).change +
      getBalanceChange("252", fromDate, toDate).change +
      getBalanceChange("253", fromDate, toDate).change +
      getBalanceChange("254", fromDate, toDate).change +
      getBalanceChange("255", fromDate, toDate).change +
      getBalanceChange("256", fromDate, toDate).change +
      getBalanceChange("258", fromDate, toDate).change;
    const tangibleAssetsEffect = -tangibleAssetsChange; // Artış = alım = nakit çıkışı

    // Maddi Olmayan Duran Varlıklar (26X, 267 hariç)
    const intangibleAssetsChange =
      getBalanceChange("260", fromDate, toDate).change +
      getBalanceChange("261", fromDate, toDate).change +
      getBalanceChange("262", fromDate, toDate).change +
      getBalanceChange("263", fromDate, toDate).change +
      getBalanceChange("264", fromDate, toDate).change +
      getBalanceChange("267", fromDate, toDate).change;
    const intangibleAssetsEffect = -intangibleAssetsChange;

    // Mali Duran Varlıklar (24X) - iştirakler, hisseler
    const financialAssetsChange =
      getBalanceChange("240", fromDate, toDate).change +
      getBalanceChange("241", fromDate, toDate).change +
      getBalanceChange("242", fromDate, toDate).change +
      getBalanceChange("243", fromDate, toDate).change +
      getBalanceChange("244", fromDate, toDate).change +
      getBalanceChange("245", fromDate, toDate).change +
      getBalanceChange("246", fromDate, toDate).change +
      getBalanceChange("247", fromDate, toDate).change +
      getBalanceChange("248", fromDate, toDate).change;
    const financialAssetsEffect = -financialAssetsChange;

    // Faiz Geliri (yatırım) - gelir tablosundaki etkiyi geri ekle
    // -(c-d) negatif çıktığı için işleme uygun

    const investingCash = tangibleAssetsEffect + intangibleAssetsEffect + financialAssetsEffect + (-interestIncome);

    // 5. FİNANSMAN FAALİYETLERİ
    // Kısa Vadeli Banka Kredileri (300)
    const shortTermBankLoansChange = getBalanceChange("300", fromDate, toDate).change;
    const shortTermBankLoansEffect = -shortTermBankLoansChange; // Pasif, artış = nakit girişi

    // Diğer Mali Borçlar (303, 304, 305, 306, 309)
    const otherShortTermBorrowingsChange =
      getBalanceChange("303", fromDate, toDate).change +
      getBalanceChange("304", fromDate, toDate).change +
      getBalanceChange("305", fromDate, toDate).change +
      getBalanceChange("306", fromDate, toDate).change +
      getBalanceChange("309", fromDate, toDate).change;
    const otherShortTermBorrowingsEffect = -otherShortTermBorrowingsChange;

    // Uzun Vadeli Banka Kredileri (400, 401)
    const longTermBankLoansChange =
      getBalanceChange("400", fromDate, toDate).change +
      getBalanceChange("401", fromDate, toDate).change;
    const longTermBankLoansEffect = -longTermBankLoansChange;

    // Diğer UV Mali Borçlar (403, 404, 405, 407, 408, 409)
    const otherLongTermBorrowingsChange =
      getBalanceChange("403", fromDate, toDate).change +
      getBalanceChange("404", fromDate, toDate).change +
      getBalanceChange("405", fromDate, toDate).change +
      getBalanceChange("407", fromDate, toDate).change +
      getBalanceChange("408", fromDate, toDate).change +
      getBalanceChange("409", fromDate, toDate).change;
    const otherLongTermBorrowingsEffect = -otherLongTermBorrowingsChange;

    // Sermaye değişimi (500, 501, 502, 503)
    const capitalChange =
      getBalanceChange("500", fromDate, toDate).change +
      getBalanceChange("501", fromDate, toDate).change +
      getBalanceChange("502", fromDate, toDate).change +
      getBalanceChange("503", fromDate, toDate).change;
    const capitalEffect = -capitalChange;

    // Temettü ödemeleri (570, 590, 591 — geçmiş yıl kârları/zararları)
    // Geçmiş yıl kârları (570) azalırsa temettü ödenmiş demektir
    const retainedEarningsChange =
      getBalanceChange("570", fromDate, toDate).change +
      getBalanceChange("571", fromDate, toDate).change;
    const dividendPaid = -retainedEarningsChange; // Azalış = temettü

    // Faiz gideri (finansman) - gelir tablosundaki etkiyi geri ekle
    // -interestExpense pozitif değer alır

    const financingCash = shortTermBankLoansEffect + otherShortTermBorrowingsEffect
      + longTermBankLoansEffect + otherLongTermBorrowingsEffect
      + capitalEffect + dividendPaid + (-interestExpense);

    // 6. NET NAKİT DEĞİŞİMİ
    const netCashChange = operatingCash + investingCash + financingCash;

    // 7. DÖNEM BAŞI/SONU NAKİT
    // Kasa (100) + Bankalar (102) açılış ve kapanış
    const cashAccounts = ["100", "101", "102", "103", "108"];
    let openingCash = 0, closingCash = 0;
    cashAccounts.forEach(code => {
      const bal = getBalanceChange(code, fromDate, toDate);
      openingCash += bal.opening;
      closingCash += bal.closing;
    });

    return {
      // A - Faaliyet
      netProfit, depreciation, provisions, interestAdjustment,
      receivablesEffect, inventoriesEffect, otherCurrentAssetsEffect,
      payablesEffect, otherCurrentLiabilitiesEffect,
      operatingCash,
      // B - Yatırım
      tangibleAssetsEffect, intangibleAssetsEffect, financialAssetsEffect,
      interestIncome: -interestIncome,
      investingCash,
      // C - Finansman
      shortTermBankLoansEffect, otherShortTermBorrowingsEffect,
      longTermBankLoansEffect, otherLongTermBorrowingsEffect,
      capitalEffect, dividendPaid,
      interestExpense: -interestExpense,
      financingCash,
      // Net
      netCashChange, openingCash, closingCash,
      calculatedClosing: openingCash + netCashChange,
      isBalanced: Math.abs((openingCash + netCashChange) - closingCash) < 1,
    };
  };

  const current = useMemo(() => calculateIndirect(dateFrom, dateTo),
    [dateFrom, dateTo, entries, accounts]);
  const compare = useMemo(() =>
    showCompare ? calculateIndirect(compareDateFrom, compareDateTo) : null,
    [showCompare, compareDateFrom, compareDateTo, entries, accounts]
  );

  // Satır tipi: section (başlık), item (kalem), subtotal (ara toplam), total (genel toplam), spacer (boşluk)
  const rows = [
    { type: "section", code: "A", name: lang === "en" ? "OPERATING ACTIVITIES" : "İŞLETME FAALİYETLERİ" },
    { type: "item",    code: "1", name: lang === "en" ? "Net Profit/Loss" : "Dönem Net Kâr/Zararı", value: current.netProfit, compareValue: compare?.netProfit, italic: false },
    { type: "section_sub", name: lang === "en" ? "Adjustments (Non-cash items)" : "Düzeltmeler (Nakit dışı kalemler)" },
    { type: "item",    code: "2", name: lang === "en" ? "(+) Depreciation & Amortization" : "(+) Amortisman ve İtfa Payları", value: current.depreciation, compareValue: compare?.depreciation },
    { type: "item",    code: "3", name: lang === "en" ? "(+/-) Provisions" : "(+/-) Karşılıklar (Net)", value: current.provisions, compareValue: compare?.provisions },
    { type: "item",    code: "4", name: lang === "en" ? "(+/-) Interest Adjustments" : "(+/-) Faiz Geliri/Gideri Düzeltmeleri", value: current.interestAdjustment, compareValue: compare?.interestAdjustment },
    { type: "section_sub", name: lang === "en" ? "Working Capital Changes" : "Çalışma Sermayesi Değişimleri" },
    { type: "item",    code: "5", name: lang === "en" ? "(+/-) Trade Receivables" : "(+/-) Ticari Alacaklardaki Değişim", value: current.receivablesEffect, compareValue: compare?.receivablesEffect },
    { type: "item",    code: "6", name: lang === "en" ? "(+/-) Inventories" : "(+/-) Stoklardaki Değişim", value: current.inventoriesEffect, compareValue: compare?.inventoriesEffect },
    { type: "item",    code: "7", name: lang === "en" ? "(+/-) Other Current Assets" : "(+/-) Diğer Dönen Varlıklardaki Değişim", value: current.otherCurrentAssetsEffect, compareValue: compare?.otherCurrentAssetsEffect },
    { type: "item",    code: "8", name: lang === "en" ? "(+/-) Trade Payables" : "(+/-) Ticari Borçlardaki Değişim", value: current.payablesEffect, compareValue: compare?.payablesEffect },
    { type: "item",    code: "9", name: lang === "en" ? "(+/-) Other Current Liabilities" : "(+/-) Diğer Kısa Vadeli Yükümlülüklerdeki Değişim", value: current.otherCurrentLiabilitiesEffect, compareValue: compare?.otherCurrentLiabilitiesEffect },
    { type: "subtotal", code: "A",  name: lang === "en" ? "NET CASH FROM OPERATING" : "İŞLETME FAALİYETLERİNDEN NET NAKİT", value: current.operatingCash, compareValue: compare?.operatingCash, color: "#0f766e" },
    { type: "spacer" },

    { type: "section", code: "B", name: lang === "en" ? "INVESTING ACTIVITIES" : "YATIRIM FAALİYETLERİ" },
    { type: "item",    code: "10", name: lang === "en" ? "(+/-) Tangible Assets" : "(+/-) Maddi Duran Varlıklardaki Değişim", value: current.tangibleAssetsEffect, compareValue: compare?.tangibleAssetsEffect },
    { type: "item",    code: "11", name: lang === "en" ? "(+/-) Intangible Assets" : "(+/-) Maddi Olmayan Duran Varlıklardaki Değişim", value: current.intangibleAssetsEffect, compareValue: compare?.intangibleAssetsEffect },
    { type: "item",    code: "12", name: lang === "en" ? "(+/-) Financial Assets" : "(+/-) Mali Duran Varlıklardaki Değişim", value: current.financialAssetsEffect, compareValue: compare?.financialAssetsEffect },
    { type: "item",    code: "13", name: lang === "en" ? "(+) Interest Income" : "(+) Alınan Faizler", value: current.interestIncome, compareValue: compare?.interestIncome },
    { type: "subtotal", code: "B",  name: lang === "en" ? "NET CASH FROM INVESTING" : "YATIRIM FAALİYETLERİNDEN NET NAKİT", value: current.investingCash, compareValue: compare?.investingCash, color: "#7c3aed" },
    { type: "spacer" },

    { type: "section", code: "C", name: lang === "en" ? "FINANCING ACTIVITIES" : "FİNANSMAN FAALİYETLERİ" },
    { type: "item",    code: "14", name: lang === "en" ? "(+/-) Short-term Bank Loans" : "(+/-) Kısa Vadeli Banka Kredileri", value: current.shortTermBankLoansEffect, compareValue: compare?.shortTermBankLoansEffect },
    { type: "item",    code: "15", name: lang === "en" ? "(+/-) Other Short-term Borrowings" : "(+/-) Diğer Kısa Vadeli Mali Borçlar", value: current.otherShortTermBorrowingsEffect, compareValue: compare?.otherShortTermBorrowingsEffect },
    { type: "item",    code: "16", name: lang === "en" ? "(+/-) Long-term Bank Loans" : "(+/-) Uzun Vadeli Banka Kredileri", value: current.longTermBankLoansEffect, compareValue: compare?.longTermBankLoansEffect },
    { type: "item",    code: "17", name: lang === "en" ? "(+/-) Other Long-term Borrowings" : "(+/-) Diğer Uzun Vadeli Mali Borçlar", value: current.otherLongTermBorrowingsEffect, compareValue: compare?.otherLongTermBorrowingsEffect },
    { type: "item",    code: "18", name: lang === "en" ? "(+) Capital Increase" : "(+) Sermaye Artışları", value: current.capitalEffect, compareValue: compare?.capitalEffect },
    { type: "item",    code: "19", name: lang === "en" ? "(-) Dividends Paid" : "(-) Ödenen Temettüler", value: current.dividendPaid, compareValue: compare?.dividendPaid },
    { type: "item",    code: "20", name: lang === "en" ? "(-) Interest Paid" : "(-) Ödenen Faizler", value: current.interestExpense, compareValue: compare?.interestExpense },
    { type: "subtotal", code: "C",  name: lang === "en" ? "NET CASH FROM FINANCING" : "FİNANSMAN FAALİYETLERİNDEN NET NAKİT", value: current.financingCash, compareValue: compare?.financingCash, color: "#b45309" },
    { type: "spacer" },

    { type: "total",   code: "D",  name: lang === "en" ? "NET CHANGE IN CASH (A+B+C)" : "NET NAKİT DEĞİŞİMİ (A+B+C)", value: current.netCashChange, compareValue: compare?.netCashChange },
    { type: "item",    code: "E",  name: lang === "en" ? "Opening Cash Balance" : "Dönem Başı Nakit ve Nakit Benzerleri", value: current.openingCash, compareValue: compare?.openingCash, isCash: true },
    { type: "total",   code: "F",  name: lang === "en" ? "Closing Cash Balance (D+E)" : "Dönem Sonu Nakit ve Nakit Benzerleri", value: current.closingCash, compareValue: compare?.closingCash, isCash: true },
  ];

  // Excel Export
  const handleExport = () => {
    const csvRows = [
      [lang === "en" ? "Cash Flow Statement" : "NAKİT AKIŞ TABLOSU"],
      [`${dateFrom} — ${dateTo}`],
      [lang === "en" ? `Method: ${method === "indirect" ? "Indirect" : "Direct"}` : `Metot: ${method === "indirect" ? "Dolaylı" : "Doğrudan"}`],
      [],
      [
        lang === "en" ? "Code" : "Kod",
        lang === "en" ? "Item" : "Kalem",
        lang === "en" ? "Amount" : "Tutar",
        showCompare && compare ? (lang === "en" ? "Previous Period" : "Önceki Dönem") : "",
      ].filter(Boolean),
    ];

    rows.forEach(r => {
      if (r.type === "spacer") csvRows.push([]);
      else if (r.type === "section" || r.type === "section_sub") {
        csvRows.push([r.code || "", r.name, "", ""]);
      } else if (r.value !== null && r.value !== undefined) {
        csvRows.push([
          r.code,
          r.name,
          conv(r.value).toFixed(2),
          showCompare && r.compareValue !== null && r.compareValue !== undefined ? conv(r.compareValue).toFixed(2) : "",
        ].filter(c => c !== ""));
      }
    });

    const csv = csvRows.map(r => r.map(c => {
      const s = String(c || "");
      return s.includes(",") || s.includes("\"") ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");

    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `nakit_akis_${dateFrom}_${dateTo}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    notify(lang === "en" ? "Cash flow statement exported" : "Nakit akış tablosu dışa aktarıldı");
  };

  return (
    <div className="space-y-3">
      {/* Başlık */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <p className="text-sm" style={{ color: "var(--ink-mute)" }}>
          {lang === "en"
            ? `Cash Flow Statement (${method === "indirect" ? "Indirect" : "Direct"} Method) · ${dateFrom} — ${dateTo}`
            : `Nakit Akış Tablosu (${method === "indirect" ? "Dolaylı" : "Doğrudan"} Metot) · ${dateFrom} — ${dateTo}`}
        </p>
        <button onClick={handleExport} className="btn btn-primary text-xs">
          <FileSpreadsheet size={11}/> {lang === "en" ? "Export" : "Dışa Aktar"}
        </button>
      </div>

      {/* Filtreler */}
      <div className="card p-3 space-y-3">
        {/* Period Preset */}
        <div>
          <div className="label mb-1.5">{lang === "en" ? "Period" : "Dönem"}</div>
          <div className="flex flex-wrap gap-1">
            {[
              { id: "ytd", label: { tr: "Yıl Başından", en: "YTD" } },
              { id: "this_month", label: { tr: "Bu Ay", en: "This Month" } },
              { id: "q1", label: { tr: "1. Çeyrek", en: "Q1" } },
              { id: "q2", label: { tr: "2. Çeyrek", en: "Q2" } },
              { id: "q3", label: { tr: "3. Çeyrek", en: "Q3" } },
              { id: "q4", label: { tr: "4. Çeyrek", en: "Q4" } },
              { id: "h1", label: { tr: "1. Yarı", en: "H1" } },
              { id: "h2", label: { tr: "2. Yarı", en: "H2" } },
              { id: "year", label: { tr: "Bu Yıl", en: "This Year" } },
              { id: "last_year", label: { tr: "Geçen Yıl", en: "Last Year" } },
              { id: "custom", label: { tr: "Özel", en: "Custom" } },
            ].map(p => (
              <button key={p.id} onClick={() => applyPreset(p.id)} className="text-xs"
                style={{
                  padding: "4px 10px",
                  background: periodPreset === p.id ? "var(--accent)" : "var(--bg)",
                  color: periodPreset === p.id ? "#fff" : "var(--ink)",
                  border: `1px solid ${periodPreset === p.id ? "var(--accent)" : "var(--line)"}`,
                  borderRadius: 3, cursor: "pointer",
                  fontWeight: periodPreset === p.id ? 600 : 400,
                }}>
                {p.label[lang] || p.label.tr}
              </button>
            ))}
          </div>
        </div>

        {/* Tarihler + Para birimi */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "From" : "Başlangıç"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateFrom}
              onChange={e => { setDateFrom(e.target.value); setPeriodPreset("custom"); }}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "To" : "Bitiş"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateTo}
              onChange={e => { setDateTo(e.target.value); setPeriodPreset("custom"); }}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Method" : "Metot"}</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              <button onClick={() => setMethod("indirect")} className="text-xs flex-1"
                style={{
                  padding: "5px 10px",
                  background: method === "indirect" ? "var(--accent)" : "var(--bg)",
                  color: method === "indirect" ? "#fff" : "var(--ink)",
                  fontWeight: 600, cursor: "pointer",
                  borderRight: "1px solid var(--line)",
                }}>
                {lang === "en" ? "Indirect" : "Dolaylı"}
              </button>
              <button onClick={() => notify(lang === "en" ? "Direct method coming soon" : "Doğrudan metot yakında", "info")}
                className="text-xs flex-1"
                style={{
                  padding: "5px 10px",
                  background: method === "direct" ? "var(--accent)" : "var(--bg)",
                  color: method === "direct" ? "#fff" : "var(--ink-mute)",
                  fontWeight: 600, cursor: "pointer", opacity: 0.6,
                }}>
                {lang === "en" ? "Direct" : "Doğrudan"}
              </button>
            </div>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Currency" : "Para Birimi"}</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
              {["TRY", "USD", "EUR"].map(cur => (
                <button key={cur} onClick={() => setDisplayCurrency(cur)} className="text-xs"
                  style={{
                    padding: "5px 10px", flex: 1,
                    background: displayCurrency === cur ? "var(--accent)" : "var(--bg)",
                    color: displayCurrency === cur ? "#fff" : "var(--ink)",
                    fontWeight: 600, cursor: "pointer",
                    borderRight: cur !== "EUR" ? "1px solid var(--line)" : "none",
                  }}>
                  {CURRENCY_SYMBOLS[cur] || ""} {cur}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Karşılaştırma + Diğer */}
        <div className="flex flex-wrap items-end gap-3 pt-3" style={{ borderTop: "1px solid var(--line)" }}>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={showCompare}
              onChange={e => setShowCompare(e.target.checked)}/>
            <span style={{ fontSize: 12, fontWeight: 600 }}>
              {lang === "en" ? "Compare with previous period" : "Önceki dönemle karşılaştır"}
            </span>
          </label>
          {showCompare && (
            <>
              <input type="date" className="input mono text-xs" value={compareDateFrom}
                onChange={e => setCompareDateFrom(e.target.value)} style={{ width: 140 }}/>
              <span style={{ fontSize: 12, color: "var(--ink-mute)" }}>—</span>
              <input type="date" className="input mono text-xs" value={compareDateTo}
                onChange={e => setCompareDateTo(e.target.value)} style={{ width: 140 }}/>
            </>
          )}
          <label className="flex items-center gap-2 cursor-pointer ml-auto">
            <input type="checkbox" checked={hideZero}
              onChange={e => setHideZero(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Hide zero items" : "Sıfırları gizle"}
            </span>
          </label>
        </div>
      </div>

      {/* Bilgi Kartı */}
      <div className="card p-3" style={{ background: "linear-gradient(135deg, #dbeafe 0%, #e0e7ff 100%)", border: "1px solid #1d4ed8" }}>
        <div className="flex items-start gap-3">
          <Info size={16} style={{ color: "#1d4ed8", flexShrink: 0, marginTop: 2 }}/>
          <div style={{ fontSize: 11, color: "#1d4ed8", lineHeight: 1.5 }}>
            <b>{lang === "en" ? "Indirect Method (Dolaylı Metot)" : "Dolaylı Metot Hakkında"}:</b><br/>
            {lang === "en"
              ? "Starts with net profit/loss, adjusts for non-cash items (depreciation, provisions, interest) and changes in working capital to arrive at operating cash flow."
              : "Net kâr/zarardan başlar, nakit dışı kalemler (amortisman, karşılıklar, faizler) ve çalışma sermayesi değişimleri ile düzeltilerek işletme nakit akışı hesaplanır. UFRS/TFRS uyumludur."}
          </div>
        </div>
      </div>

      {/* Özet Kartlar */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
        <div className="card p-3" style={{ borderLeft: "4px solid #0f766e" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Operating Activities" : "İşletme Faaliyetleri"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: current.operatingCash >= 0 ? "#0f766e" : "#b91c1c" }}>
            {showSym ? sym + " " : ""}{fmtTLSign(conv(current.operatingCash))}
          </div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #7c3aed" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Investing Activities" : "Yatırım Faaliyetleri"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: current.investingCash >= 0 ? "#0f766e" : "#b91c1c" }}>
            {showSym ? sym + " " : ""}{fmtTLSign(conv(current.investingCash))}
          </div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #b45309" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Financing Activities" : "Finansman Faaliyetleri"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: current.financingCash >= 0 ? "#0f766e" : "#b91c1c" }}>
            {showSym ? sym + " " : ""}{fmtTLSign(conv(current.financingCash))}
          </div>
        </div>
        <div className="card p-3" style={{ borderLeft: `4px solid ${current.netCashChange >= 0 ? "#0f766e" : "#b91c1c"}`, background: current.netCashChange >= 0 ? "#dcfce7" : "#fee2e2" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Net Cash Change" : "Net Nakit Değişimi"}
          </div>
          <div className="mono" style={{ fontSize: 18, fontWeight: 700, marginTop: 4, color: current.netCashChange >= 0 ? "#0f766e" : "#b91c1c" }}>
            {showSym ? sym + " " : ""}{fmtTLSign(conv(current.netCashChange))}
          </div>
        </div>
      </div>

      {/* Ana Tablo */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <table style={{ width: "100%", fontSize: 12, borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 60 }}>
                {lang === "en" ? "Code" : "Kod"}
              </th>
              <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Item" : "Kalem"}
              </th>
              <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 160 }}>
                {dateFrom.slice(0, 7)} — {dateTo.slice(5)}
              </th>
              {showCompare && compare && (
                <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 160 }}>
                  {compareDateFrom.slice(0, 7)} — {compareDateTo.slice(5)}
                </th>
              )}
            </tr>
          </thead>
          <tbody>
            {rows.map((r, i) => {
              if (r.type === "spacer") {
                return <tr key={i}><td colSpan="4" style={{ padding: 4, background: "#f3f4f6" }}/></tr>;
              }
              if (r.type === "section") {
                return (
                  <tr key={i} style={{ background: "var(--accent)", color: "#fff", borderBottom: "1px solid var(--line)" }}>
                    <td className="mono" style={{ padding: "8px 10px", fontSize: 11, fontWeight: 700 }}>{r.code}</td>
                    <td colSpan="3" style={{ padding: "8px 10px", fontSize: 12, fontWeight: 700, textTransform: "uppercase", letterSpacing: 0.5 }}>{r.name}</td>
                  </tr>
                );
              }
              if (r.type === "section_sub") {
                return (
                  <tr key={i} style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                    <td/>
                    <td colSpan="3" style={{ padding: "5px 10px", fontSize: 10.5, fontWeight: 600, fontStyle: "italic", color: "var(--ink-mute)", textTransform: "uppercase" }}>{r.name}</td>
                  </tr>
                );
              }
              if (r.type === "subtotal") {
                const isPositive = r.value >= 0;
                return (
                  <tr key={i} style={{ background: r.color + "20", borderTop: `2px solid ${r.color}`, borderBottom: `2px solid ${r.color}` }}>
                    <td className="mono" style={{ padding: "10px", fontSize: 12, fontWeight: 700, color: r.color }}>{r.code}</td>
                    <td style={{ padding: "10px", fontSize: 12.5, fontWeight: 700, color: r.color, textTransform: "uppercase" }}>{r.name}</td>
                    <td className="mono text-right" style={{ padding: "10px", fontSize: 13, fontWeight: 700, color: isPositive ? "#0f766e" : "#b91c1c" }}>
                      {showSym ? sym + " " : ""}{fmtTLSign(conv(r.value))}
                    </td>
                    {showCompare && compare && (
                      <td className="mono text-right" style={{ padding: "10px", fontSize: 12, fontWeight: 700, opacity: 0.7 }}>
                        {r.compareValue != null ? `${showSym ? sym + " " : ""}${fmtTLSign(conv(r.compareValue))}` : "—"}
                      </td>
                    )}
                  </tr>
                );
              }
              if (r.type === "total") {
                const isPositive = r.value >= 0;
                const isCashRow = r.isCash;
                return (
                  <tr key={i} style={{
                    background: isCashRow ? "#fef3c7" : (isPositive ? "#15803d" : "#b91c1c"),
                    color: isCashRow ? "var(--ink)" : "#fff",
                    borderTop: "3px solid #000", borderBottom: "1px solid var(--line)",
                  }}>
                    <td className="mono" style={{ padding: "10px", fontSize: 13, fontWeight: 700 }}>{r.code}</td>
                    <td style={{ padding: "10px", fontSize: 13.5, fontWeight: 700, textTransform: "uppercase" }}>{r.name}</td>
                    <td className="mono text-right" style={{ padding: "10px", fontSize: 14, fontWeight: 700 }}>
                      {showSym ? sym + " " : ""}{fmtTLSign(conv(r.value))}
                    </td>
                    {showCompare && compare && (
                      <td className="mono text-right" style={{ padding: "10px", fontSize: 12, fontWeight: 700, opacity: 0.8 }}>
                        {r.compareValue != null ? `${showSym ? sym + " " : ""}${fmtTLSign(conv(r.compareValue))}` : "—"}
                      </td>
                    )}
                  </tr>
                );
              }
              // item
              if (hideZero && Math.abs(r.value || 0) < 1 && (!r.compareValue || Math.abs(r.compareValue) < 1)) {
                return null;
              }
              return (
                <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td className="mono" style={{ padding: "6px 10px", fontSize: 10.5, color: "var(--ink-mute)" }}>{r.code}</td>
                  <td style={{ padding: "6px 10px", fontSize: 11, paddingLeft: 24 }}>{r.name}</td>
                  <td className="mono text-right" style={{ padding: "6px 10px", fontSize: 11.5, fontWeight: 500, color: r.value < 0 ? "#b91c1c" : (r.value > 0 ? "var(--ink)" : "var(--ink-mute)"), opacity: Math.abs(r.value || 0) < 1 ? 0.4 : 1 }}>
                    {Math.abs(r.value || 0) < 1 ? "—" : `${showSym ? sym + " " : ""}${fmtTLSign(conv(r.value))}`}
                  </td>
                  {showCompare && compare && (
                    <td className="mono text-right" style={{ padding: "6px 10px", fontSize: 11, color: r.compareValue < 0 ? "#b91c1c" : "var(--ink-mute)" }}>
                      {r.compareValue == null || Math.abs(r.compareValue) < 1
                        ? "—"
                        : `${showSym ? sym + " " : ""}${fmtTLSign(conv(r.compareValue))}`}
                    </td>
                  )}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Doğrulama Kartı */}
      {!current.isBalanced && (
        <div className="card p-3" style={{ background: "#fef3c7", border: "1px solid #ca8a04" }}>
          <div className="flex items-start gap-3">
            <AlertTriangle size={16} style={{ color: "#92400e", flexShrink: 0, marginTop: 2 }}/>
            <div style={{ fontSize: 11.5, color: "#92400e", lineHeight: 1.5 }}>
              <b>{lang === "en" ? "Reconciliation Warning" : "Mutabakat Uyarısı"}:</b><br/>
              {lang === "en"
                ? `Calculated closing cash (${fmtTL(current.calculatedClosing)}) does not match actual closing cash (${fmtTL(current.closingCash)}). Difference: ${fmtTL(current.calculatedClosing - current.closingCash)}. This may indicate missing journal entries or incorrect account classifications.`
                : `Hesaplanan dönem sonu nakit (${fmtTL(current.calculatedClosing)}) gerçek nakit bakiyesi (${fmtTL(current.closingCash)}) ile uyuşmuyor. Fark: ${fmtTL(current.calculatedClosing - current.closingCash)}. Eksik yevmiye veya hesap sınıflandırma hatası olabilir.`}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/* =====================================================================
   BÜTÇE YÖNETİMİ (Budget Manager)
   ---------------------------------------------------------------------
   - Yıllık bütçe oluşturma (12 aylık)
   - Hesap bazlı bütçe satırları
   - Gerçekleşen vs bütçe karşılaştırması
   - Sapma analizi
   - Trafik ışığı sistemi
===================================================================== */
function BudgetDepartmentView({ budget, departments, lang, onUpdateLineDept, allCategories, accounts }) {
  const lines = budget.lines || [];

  // Departman bazlı yıllık toplamlar
  const deptTotals = useMemo(() => {
    const totals = {};
    lines.forEach(line => {
      const deptKey = line.departmentId || "_general";
      if (!totals[deptKey]) totals[deptKey] = { annual: 0, monthly: new Array(12).fill(0), lineCount: 0 };
      const lineAnnual = (line.monthly || []).reduce((s, v) => s + v, 0);
      totals[deptKey].annual += lineAnnual;
      totals[deptKey].lineCount++;
      (line.monthly || []).forEach((v, i) => {
        totals[deptKey].monthly[i] += v;
      });
    });
    return totals;
  }, [lines]);

  const grandTotal = useMemo(() =>
    Object.values(deptTotals).reduce((s, d) => s + d.annual, 0),
    [deptTotals]
  );

  // Departman listesi: data'da olanlar + "Genel" (eğer "Genel" satır varsa)
  const visibleDepts = useMemo(() => {
    const list = [...departments.map(d => ({ id: d.id, name: d.name, color: "#7c3aed" }))];
    if (deptTotals._general) {
      list.unshift({ id: null, name: lang === "en" ? "General (no dept.)" : "Genel (departmansız)", color: "#737373" });
    }
    return list;
  }, [departments, deptTotals, lang]);

  const monthsShort = ["Oca", "Şub", "Mar", "Nis", "May", "Haz", "Tem", "Ağu", "Eyl", "Eki", "Kas", "Ara"];
  const monthsEn = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const months = lang === "en" ? monthsEn : monthsShort;

  // Line label helper (kategori veya hesap)
  const lineLabel = (line) => {
    if (line.catId) {
      const cat = allCategories.find(c => c.id === line.catId);
      return { label: cat?.name || line.catId, color: cat?.color || "#737373", type: "category" };
    }
    if (line.accountCode) {
      const acc = accounts.find(a => a.code === line.accountCode);
      return { label: `${line.accountCode} - ${acc?.name || ""}`, color: "#1d4ed8", type: "account" };
    }
    return { label: "?", color: "#737373", type: "?" };
  };

  return (
    <div className="space-y-3">
      {/* Departman Özet Kartları */}
      <div className="card p-3">
        <div className="font-bold text-sm mb-2 flex items-center gap-2">
          📊 {lang === "en" ? "Department Summary" : "Departman Özeti"}
          <span className="text-xs" style={{ color: "var(--ink-mute)", fontWeight: 400 }}>
            ({lang === "en" ? "annual totals" : "yıllık toplamlar"})
          </span>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
          {visibleDepts.length === 0 ? (
            <div className="col-span-4 text-center" style={{ padding: 20, color: "var(--ink-mute)", fontStyle: "italic" }}>
              {lang === "en" ? "No department data" : "Departman verisi yok"}
            </div>
          ) : visibleDepts.map(dept => {
            const totals = deptTotals[dept.id || "_general"];
            if (!totals) return null;
            const pct = grandTotal > 0 ? (totals.annual / grandTotal) * 100 : 0;
            return (
              <div key={dept.id || "general"} className="card p-2"
                style={{ background: "var(--bg-alt)", borderLeft: `3px solid ${dept.color}` }}>
                <div className="text-xs font-bold truncate" style={{ color: dept.color }}>
                  {dept.name}
                </div>
                <div className="mono mt-1" style={{ fontSize: 16, fontWeight: 700 }}>
                  {fmtTL(totals.annual)} ₺
                </div>
                <div className="text-xs mt-1" style={{ color: "var(--ink-mute)" }}>
                  {totals.lineCount} {lang === "en" ? "line(s)" : "satır"} · %{pct.toFixed(1)}
                </div>
                {/* Progress bar */}
                <div style={{ height: 3, background: "var(--paper)", borderRadius: 1, marginTop: 4, overflow: "hidden" }}>
                  <div style={{ width: `${pct}%`, height: "100%", background: dept.color }}/>
                </div>
              </div>
            );
          })}
        </div>

        {/* Toplam */}
        <div className="mt-3 pt-3" style={{ borderTop: "1px solid var(--line)" }}>
          <div className="flex justify-between items-center">
            <span className="text-xs" style={{ color: "var(--ink-mute)", fontWeight: 700, textTransform: "uppercase" }}>
              {lang === "en" ? "Grand Total" : "Genel Toplam"}
            </span>
            <span className="mono" style={{ fontSize: 20, fontWeight: 700, color: "var(--accent)" }}>
              {fmtTL(grandTotal)} ₺
            </span>
          </div>
        </div>
      </div>

      {/* Departman × Ay Matriksi */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div className="p-2" style={{ borderBottom: "1px solid var(--line)", background: "var(--bg-alt)" }}>
          <span className="font-bold text-sm">
            🗓 {lang === "en" ? "Department × Month Matrix" : "Departman × Ay Matriksi"}
          </span>
        </div>
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", minWidth: 1100, fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
                <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", minWidth: 200 }}>
                  {lang === "en" ? "Department" : "Departman"}
                </th>
                {months.map((m, i) => (
                  <th key={i} style={{ padding: "8px 4px", textAlign: "center", fontSize: 9.5, fontWeight: 700, color: "var(--ink-mute)" }}>
                    {m}
                  </th>
                ))}
                <th style={{ padding: "8px 6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "#1d4ed8", background: "#dbeafe", textTransform: "uppercase" }}>
                  {lang === "en" ? "Annual" : "Yıllık"}
                </th>
              </tr>
            </thead>
            <tbody>
              {visibleDepts.map(dept => {
                const totals = deptTotals[dept.id || "_general"];
                if (!totals) return null;
                return (
                  <tr key={dept.id || "general"} style={{ borderBottom: "1px solid var(--line)" }}>
                    <td style={{ padding: "8px 10px", fontWeight: 700, color: dept.color }}>
                      {dept.name}
                    </td>
                    {totals.monthly.map((v, mIdx) => (
                      <td key={mIdx} className="mono text-right" style={{ padding: "8px 4px", fontSize: 10.5 }}>
                        {v > 0 ? fmtTL(v) : "—"}
                      </td>
                    ))}
                    <td className="mono text-right" style={{ padding: "8px 6px", fontSize: 12, fontWeight: 700, background: "#dbeafe", color: "#1d4ed8" }}>
                      {fmtTL(totals.annual)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
            <tfoot>
              <tr style={{ background: "var(--accent)", color: "#fff" }}>
                <td style={{ padding: "10px", fontWeight: 700, textTransform: "uppercase" }}>
                  {lang === "en" ? "TOTAL" : "TOPLAM"}
                </td>
                {months.map((_, mIdx) => {
                  const total = lines.reduce((s, l) => s + ((l.monthly || [])[mIdx] || 0), 0);
                  return (
                    <td key={mIdx} className="mono text-right" style={{ padding: "10px 4px", fontWeight: 700 }}>
                      {total > 0 ? fmtTL(total) : "—"}
                    </td>
                  );
                })}
                <td className="mono text-right" style={{ padding: "10px 6px", fontSize: 13, fontWeight: 700 }}>
                  {fmtTL(grandTotal)}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      </div>

      {/* Satır Atama Tablosu — her bütçe satırına departman ata */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div className="p-2" style={{ borderBottom: "1px solid var(--line)", background: "var(--bg-alt)" }}>
          <span className="font-bold text-sm">
            ✏ {lang === "en" ? "Assign Lines to Departments" : "Satırları Departmanlara Ata"}
          </span>
          <span className="text-xs ml-2" style={{ color: "var(--ink-mute)" }}>
            ({lines.length} {lang === "en" ? "line(s)" : "satır"})
          </span>
        </div>
        <div style={{ overflowX: "auto", maxHeight: 400 }}>
          <table className="grid" style={{ width: "100%" }}>
            <thead style={{ position: "sticky", top: 0, background: "var(--bg-alt)" }}>
              <tr>
                <th className="label-cell">{lang === "en" ? "Type" : "Tip"}</th>
                <th className="label-cell">{lang === "en" ? "Line" : "Satır"}</th>
                <th className="text-right">{lang === "en" ? "Annual" : "Yıllık"}</th>
                <th className="label-cell">{lang === "en" ? "Department" : "Departman"}</th>
              </tr>
            </thead>
            <tbody>
              {lines.length === 0 ? (
                <tr><td colSpan={4} className="text-center" style={{ padding: 30, color: "var(--ink-mute)", fontStyle: "italic" }}>
                  {lang === "en" ? "No lines yet" : "Henüz satır yok"}
                </td></tr>
              ) : lines.map((line, idx) => {
                const info = lineLabel(line);
                const annual = (line.monthly || []).reduce((s, v) => s + v, 0);
                return (
                  <tr key={idx}>
                    <td className="label-cell">
                      <span className="chip" style={{
                        background: info.color + "20", color: info.color,
                        padding: "2px 6px", fontSize: 9, fontWeight: 700,
                      }}>
                        {info.type === "category" ? (lang === "en" ? "CAT" : "KAT") : info.type === "account" ? (lang === "en" ? "ACC" : "HSP") : "?"}
                      </span>
                    </td>
                    <td className="label-cell text-xs">{info.label}</td>
                    <td className="mono text-right" style={{ fontWeight: 700 }}>
                      {fmtTL(annual)} ₺
                    </td>
                    <td className="label-cell">
                      <select value={line.departmentId || ""}
                        onChange={e => onUpdateLineDept(idx, e.target.value || null)}
                        className="input text-xs" style={{ padding: "3px 6px", maxWidth: 180 }}>
                        <option value="">— {lang === "en" ? "General" : "Genel"}</option>
                        {departments.map(d => (
                          <option key={d.id} value={d.id}>{d.name}</option>
                        ))}
                      </select>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   MALİ YIL KAPANIŞI (Year-End Close Manager)
   ---------------------------------------------------------------------
   5 Aşamalı süreç:
   1. Kontroller (mizan denkliği, açık fişler, denge)
   2. Gelir Tablosu kapanışı (6XX/7XX → 690 → 590/591)
   3. Kapanış Fişi (Bilanço hesaplarını 999'a kapat)
   4. Açılış Fişi (Yeni yıl 01.01 - bakiyeleri taşı)
   5. Geçmiş Yıl Kâr/Zarar (590/591 → 570)
===================================================================== */
function YearEndCloseManager({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];
  const today = new Date();
  const currentYear = today.getFullYear();

  // === State ===
  const [closingYear, setClosingYear] = useState(currentYear - 1); // Genellikle önceki yıl kapatılır
  const [showWizard, setShowWizard] = useState(false);
  const [wizardStep, setWizardStep] = useState(1); // 1-5
  const [closingResults, setClosingResults] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);

  // Geçmiş kapanışları izle
  const fiscalPeriods = data.accFiscalPeriods || [];

  // === HESAPLAMA: Yıl için denetimler ===
  const yearStart = `${closingYear}-01-01`;
  const yearEnd = `${closingYear}-12-31`;
  const newYearStart = `${closingYear + 1}-01-01`;

  // Bu yıl zaten kapatılmış mı?
  const existingClosing = useMemo(() =>
    fiscalPeriods.find(p => p.year === closingYear && p.status === "closed"),
    [fiscalPeriods, closingYear]
  );

  // Yıl içi yevmiye fişleri
  const yearEntries = useMemo(() =>
    entries.filter(e => e.date >= yearStart && e.date <= yearEnd && e.status !== "cancelled"),
    [entries, yearStart, yearEnd]
  );

  // Yıl içi taslak (draft) fişler
  const draftEntries = useMemo(() =>
    yearEntries.filter(e => e.status === "draft"),
    [yearEntries]
  );

  // Bir hesabın yıl sonu bakiyesini hesapla (recursive)
  const getYearEndBalance = (codePrefix) => {
    let debit = 0, credit = 0;
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      if (entry.date > yearEnd) return;
      (entry.lines || []).forEach(line => {
        if (!String(line.accountCode).startsWith(codePrefix)) return;
        debit += Number(line.debit) || 0;
        credit += Number(line.credit) || 0;
      });
    });
    return { debit, credit, balance: debit - credit };
  };

  // Yıl içi gelir/gider toplamları
  const yearIncome = useMemo(() => {
    const result = {
      revenue: 0,       // 6X gelirler (60, 64, 67)
      expense: 0,       // 6X giderler (61, 62, 63, 65, 66, 68)
      tax: 0,           // 691 vergi karşılığı
      netProfit: 0,
      revenueAccounts: [],
      expenseAccounts: [],
    };

    // Aktif gelir/gider hesaplarını grupla
    accounts.forEach(acc => {
      const acctCode = String(acc.code);
      if (acctCode.length < 3) return; // Sadece detaylı hesaplar

      const bal = getYearEndBalance(acctCode);
      const movementNet = Math.abs(bal.balance);
      if (movementNet < 0.01) return;

      // Gelir hesapları: 60, 64, 67 (Alacak bakiyeli)
      if (acctCode.startsWith("60") || acctCode.startsWith("64") || acctCode.startsWith("67")) {
        const value = bal.credit - bal.debit; // Net gelir
        if (value > 0) {
          result.revenue += value;
          result.revenueAccounts.push({ code: acctCode, name: acc.name, value, debit: bal.debit, credit: bal.credit });
        }
      }
      // Gider hesapları: 61, 62, 63, 65, 66, 68 (Borç bakiyeli)
      else if (acctCode.startsWith("61") || acctCode.startsWith("62") ||
               acctCode.startsWith("63") || acctCode.startsWith("65") ||
               acctCode.startsWith("66") || acctCode.startsWith("68")) {
        const value = bal.debit - bal.credit;
        if (value > 0) {
          result.expense += value;
          result.expenseAccounts.push({ code: acctCode, name: acc.name, value, debit: bal.debit, credit: bal.credit });
        }
      }
      // Vergi karşılığı: 691
      else if (acctCode.startsWith("691")) {
        const value = bal.debit - bal.credit;
        if (value > 0) {
          result.tax += value;
        }
      }
    });

    result.netProfit = result.revenue - result.expense - result.tax;
    return result;
  }, [accounts, entries, yearEnd]);

  // Bilanço hesaplarının kapanış bakiyeleri
  const balanceSheetBalances = useMemo(() => {
    const result = { assets: [], liabilities: [] };
    accounts.forEach(acc => {
      const acctCode = String(acc.code);
      // Aktif: 1X, 2X
      if (acctCode.startsWith("1") || acctCode.startsWith("2")) {
        const bal = getYearEndBalance(acctCode);
        if (Math.abs(bal.balance) > 0.01 && acc.level === 3) { // Sadece ana hesaplar
          result.assets.push({
            code: acctCode, name: acc.name, type: acc.type,
            debit: bal.debit, credit: bal.credit, balance: bal.balance,
          });
        }
      }
      // Pasif: 3X, 4X, 5X
      else if (acctCode.startsWith("3") || acctCode.startsWith("4") || acctCode.startsWith("5")) {
        const bal = getYearEndBalance(acctCode);
        if (Math.abs(bal.balance) > 0.01 && acc.level === 3) {
          result.liabilities.push({
            code: acctCode, name: acc.name, type: acc.type,
            debit: bal.debit, credit: bal.credit, balance: bal.balance,
          });
        }
      }
    });
    return result;
  }, [accounts, entries, yearEnd]);

  // Genel mizan denkliği
  const trialBalanceCheck = useMemo(() => {
    let totalDebit = 0, totalCredit = 0;
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      if (entry.date > yearEnd) return;
      (entry.lines || []).forEach(line => {
        totalDebit += Number(line.debit) || 0;
        totalCredit += Number(line.credit) || 0;
      });
    });
    return {
      totalDebit, totalCredit,
      isBalanced: Math.abs(totalDebit - totalCredit) < 0.01,
      diff: totalDebit - totalCredit,
    };
  }, [entries, yearEnd]);

  // Bilanço denkliği
  const balanceSheetCheck = useMemo(() => {
    let assets = 0, liabilities = 0;
    balanceSheetBalances.assets.forEach(a => { assets += a.balance; }); // Borç bakiye
    balanceSheetBalances.liabilities.forEach(l => { liabilities += -l.balance; }); // Alacak bakiye
    // Dönem kâr/zararı pasife eklenir
    const totalWithProfit = liabilities + yearIncome.netProfit;
    return {
      assets, liabilities: totalWithProfit,
      isBalanced: Math.abs(assets - totalWithProfit) < 1,
      diff: assets - totalWithProfit,
    };
  }, [balanceSheetBalances, yearIncome]);

  // === KAPANIŞ İŞLEMİ ===
  const performYearEndClose = async () => {
    if (existingClosing) {
      notify(lang === "en" ? "This year is already closed" : "Bu yıl zaten kapatılmış", "err");
      return;
    }
    if (!trialBalanceCheck.isBalanced) {
      notify(lang === "en"
        ? `Trial balance not balanced. Difference: ${fmtTL(trialBalanceCheck.diff)}`
        : `Mizan dengeli değil. Fark: ${fmtTL(trialBalanceCheck.diff)} ₺`, "err");
      return;
    }
    if (draftEntries.length > 0) {
      if (!confirm(lang === "en"
        ? `There are ${draftEntries.length} draft entries. They will be ignored. Continue?`
        : `${draftEntries.length} taslak fiş var. Bunlar dikkate alınmayacak. Devam edilsin mi?`)) return;
    }

    setIsProcessing(true);
    const newEntries = [];
    let entryCounter = entries.length;

    // ===== ADIM 1: GELİR-GİDER KAPANIŞI (6XX/7XX → 690) =====
    // Tüm gelir hesaplarını sıfırla (borçlandır) ve 690'a alacak yaz
    // Tüm gider hesaplarını sıfırla (alacaklandır) ve 690'a borç yaz
    const incomeClosingLines = [];

    yearIncome.revenueAccounts.forEach(r => {
      // Gelir hesabı alacak bakiyeli → borçlandır
      incomeClosingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: r.code,
        description: `${closingYear} ${lang === "en" ? "Year-end closing" : "Yıl sonu kapanış"}`,
        debit: r.value,
        credit: 0,
        currency: "TRY",
      });
    });
    yearIncome.expenseAccounts.forEach(e => {
      // Gider hesabı borç bakiyeli → alacaklandır
      incomeClosingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: e.code,
        description: `${closingYear} ${lang === "en" ? "Year-end closing" : "Yıl sonu kapanış"}`,
        debit: 0,
        credit: e.value,
        currency: "TRY",
      });
    });

    // Vergi karşılığı (691)
    if (yearIncome.tax > 0) {
      incomeClosingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "691",
        description: `${closingYear} ${lang === "en" ? "Tax provision close" : "Vergi karşılığı kapanış"}`,
        debit: 0,
        credit: yearIncome.tax,
        currency: "TRY",
      });
    }

    // Net etki 690 hesabına yansıtılır
    // Gelir - Gider - Vergi = Net Kâr/Zarar
    // 690 borcunda gider+vergi var, alacağında gelir var
    // Eğer kâr varsa: 690 Borç, 590 Alacak
    // Eğer zarar varsa: 690 Alacak, 591 Borç
    if (Math.abs(yearIncome.netProfit) > 0.01) {
      if (yearIncome.netProfit > 0) {
        // KÂR durumu
        incomeClosingLines.push({
          id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
          accountCode: "690",
          description: `${closingYear} ${lang === "en" ? "Income summary" : "Dönem Kâr/Zarar"}`,
          debit: yearIncome.netProfit,
          credit: 0,
          currency: "TRY",
        });
        incomeClosingLines.push({
          id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
          accountCode: "590",
          description: `${closingYear} ${lang === "en" ? "Net profit" : "Dönem Net Kârı"}`,
          debit: 0,
          credit: yearIncome.netProfit,
          currency: "TRY",
        });
      } else {
        // ZARAR durumu
        const lossAmt = -yearIncome.netProfit;
        incomeClosingLines.push({
          id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
          accountCode: "591",
          description: `${closingYear} ${lang === "en" ? "Net loss" : "Dönem Net Zararı"}`,
          debit: lossAmt,
          credit: 0,
          currency: "TRY",
        });
        incomeClosingLines.push({
          id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
          accountCode: "690",
          description: `${closingYear} ${lang === "en" ? "Income summary" : "Dönem Kâr/Zarar"}`,
          debit: 0,
          credit: lossAmt,
          currency: "TRY",
        });
      }
    }

    if (incomeClosingLines.length > 0) {
      const totalD = incomeClosingLines.reduce((s, l) => s + (l.debit || 0), 0);
      const totalC = incomeClosingLines.reduce((s, l) => s + (l.credit || 0), 0);
      const incomeVoucher = {
        id: `je_yec_income_${Date.now()}`,
        voucherNo: generateVoucherNo("closing", closingYear, [...entries, ...newEntries]),
        voucherType: "closing",
        date: yearEnd,
        description: `${closingYear} ${lang === "en" ? "Income Statement Closing" : "Gelir Tablosu Kapanışı"}`,
        source: "yearend",
        lines: incomeClosingLines,
        totalDebit: totalD,
        totalCredit: totalC,
        status: "posted",
        createdAt: new Date().toISOString(),
        createdBy: session.username,
        postedAt: new Date().toISOString(),
        postedBy: session.username,
        yearEndType: "income_close",
        fiscalYear: closingYear,
      };
      newEntries.push(incomeVoucher);
    }

    // ===== ADIM 2: KAPANIŞ FİŞİ (Bilanço hesapları → 999) =====
    // Aktifler alacak (sıfırla), 999 borç
    // Pasifler borç (sıfırla), 999 alacak
    const closingLines = [];
    let assetTotal = 0, liabilityTotal = 0;

    balanceSheetBalances.assets.forEach(a => {
      // Aktif borç bakiyeli → alacaklandır
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: a.code,
        description: `${closingYear} ${lang === "en" ? "Closing" : "Kapanış"}`,
        debit: 0,
        credit: a.balance,
        currency: "TRY",
      });
      assetTotal += a.balance;
    });

    balanceSheetBalances.liabilities.forEach(l => {
      // Pasif alacak bakiyeli → borçlandır
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: l.code,
        description: `${closingYear} ${lang === "en" ? "Closing" : "Kapanış"}`,
        debit: -l.balance, // l.balance negatif (alacak bakiye)
        credit: 0,
        currency: "TRY",
      });
      liabilityTotal += -l.balance;
    });

    // 590 Dönem Net Kâr eğer pozitifse → kapanışta borçlandır
    if (yearIncome.netProfit > 0) {
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "590",
        description: `${closingYear} ${lang === "en" ? "Closing - Net Profit" : "Kapanış - Dönem Kârı"}`,
        debit: yearIncome.netProfit,
        credit: 0,
        currency: "TRY",
      });
      liabilityTotal += yearIncome.netProfit;
    } else if (yearIncome.netProfit < 0) {
      // Zarar - 591 alacaklandır
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "591",
        description: `${closingYear} ${lang === "en" ? "Closing - Net Loss" : "Kapanış - Dönem Zararı"}`,
        debit: 0,
        credit: -yearIncome.netProfit,
        currency: "TRY",
      });
      assetTotal += -yearIncome.netProfit; // Zarar aktif tarafa eklenir (pasifi azaltır)
    }

    // Karşı: 999 Kapanış Bilançosu
    if (assetTotal > 0) {
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "999",
        description: `${closingYear} ${lang === "en" ? "Closing Balance Account" : "Kapanış Bilançosu"}`,
        debit: assetTotal,
        credit: 0,
        currency: "TRY",
      });
    }
    if (liabilityTotal > 0) {
      closingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "999",
        description: `${closingYear} ${lang === "en" ? "Closing Balance Account" : "Kapanış Bilançosu"}`,
        debit: 0,
        credit: liabilityTotal,
        currency: "TRY",
      });
    }

    if (closingLines.length > 0) {
      const totalD = closingLines.reduce((s, l) => s + (l.debit || 0), 0);
      const totalC = closingLines.reduce((s, l) => s + (l.credit || 0), 0);
      const closingVoucher = {
        id: `je_yec_close_${Date.now()}`,
        voucherNo: generateVoucherNo("closing", closingYear, [...entries, ...newEntries]),
        voucherType: "closing",
        date: yearEnd,
        description: `${closingYear} ${lang === "en" ? "Year-End Closing Entry" : "Yıl Sonu Kapanış Fişi"}`,
        source: "yearend",
        lines: closingLines,
        totalDebit: totalD,
        totalCredit: totalC,
        status: "posted",
        createdAt: new Date().toISOString(),
        createdBy: session.username,
        postedAt: new Date().toISOString(),
        postedBy: session.username,
        yearEndType: "balance_close",
        fiscalYear: closingYear,
      };
      newEntries.push(closingVoucher);
    }

    // ===== ADIM 3: AÇILIŞ FİŞİ (Yeni yıl 01.01) =====
    // Aktifleri tekrar borçlandır, pasifleri alacaklandır, karşı 999 (Açılış)
    const openingLines = [];
    let openAssetTotal = 0, openLiabilityTotal = 0;

    balanceSheetBalances.assets.forEach(a => {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: a.code,
        description: `${closingYear + 1} ${lang === "en" ? "Opening" : "Açılış"}`,
        debit: a.balance,
        credit: 0,
        currency: "TRY",
      });
      openAssetTotal += a.balance;
    });

    balanceSheetBalances.liabilities.forEach(l => {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: l.code,
        description: `${closingYear + 1} ${lang === "en" ? "Opening" : "Açılış"}`,
        debit: 0,
        credit: -l.balance,
        currency: "TRY",
      });
      openLiabilityTotal += -l.balance;
    });

    // Dönem kâr/zararı: 590/591 → 570 (Geçmiş yıl kârı) veya 580 (Geçmiş yıl zararı)
    // Açılışta direkt 570/580 olarak transfer
    if (yearIncome.netProfit > 0) {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "570",
        description: `${closingYear} ${lang === "en" ? "Prior year profit" : "Geçmiş Yıl Kârı"} (${closingYear})`,
        debit: 0,
        credit: yearIncome.netProfit,
        currency: "TRY",
      });
      openLiabilityTotal += yearIncome.netProfit;
    } else if (yearIncome.netProfit < 0) {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "580",
        description: `${closingYear} ${lang === "en" ? "Prior year loss" : "Geçmiş Yıl Zararı"} (${closingYear})`,
        debit: -yearIncome.netProfit,
        credit: 0,
        currency: "TRY",
      });
      openAssetTotal += -yearIncome.netProfit;
    }

    // Karşı: 999 Açılış
    if (openLiabilityTotal > 0) {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "999",
        description: `${closingYear + 1} ${lang === "en" ? "Opening Balance Account" : "Açılış Bilançosu"}`,
        debit: openLiabilityTotal,
        credit: 0,
        currency: "TRY",
      });
    }
    if (openAssetTotal > 0) {
      openingLines.push({
        id: `line_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
        accountCode: "999",
        description: `${closingYear + 1} ${lang === "en" ? "Opening Balance Account" : "Açılış Bilançosu"}`,
        debit: 0,
        credit: openAssetTotal,
        currency: "TRY",
      });
    }

    if (openingLines.length > 0) {
      const totalD = openingLines.reduce((s, l) => s + (l.debit || 0), 0);
      const totalC = openingLines.reduce((s, l) => s + (l.credit || 0), 0);
      const openingVoucher = {
        id: `je_yec_open_${Date.now()}`,
        voucherNo: generateVoucherNo("opening", closingYear + 1, [...entries, ...newEntries]),
        voucherType: "opening",
        date: newYearStart,
        description: `${closingYear + 1} ${lang === "en" ? "Year Opening Entry" : "Yıl Açılış Fişi"}`,
        source: "yearend",
        lines: openingLines,
        totalDebit: totalD,
        totalCredit: totalC,
        status: "posted",
        createdAt: new Date().toISOString(),
        createdBy: session.username,
        postedAt: new Date().toISOString(),
        postedBy: session.username,
        yearEndType: "year_opening",
        fiscalYear: closingYear + 1,
      };
      newEntries.push(openingVoucher);
    }

    // ===== Fiscal Period Kaydı =====
    const newFiscalPeriod = {
      id: `fp_${closingYear}_${Date.now()}`,
      year: closingYear,
      startDate: yearStart,
      endDate: yearEnd,
      status: "closed",
      closedAt: new Date().toISOString(),
      closedBy: session.username,
      netProfit: yearIncome.netProfit,
      totalRevenue: yearIncome.revenue,
      totalExpense: yearIncome.expense,
      totalTax: yearIncome.tax,
      voucherIds: newEntries.map(e => e.id),
    };

    // Kaydet
    const finalEntries = [...entries, ...newEntries];
    const finalPeriods = [...fiscalPeriods, newFiscalPeriod];

    await onChange({
      ...data,
      accJournalEntries: finalEntries,
      accFiscalPeriods: finalPeriods,
    });

    logAudit && logAudit("year_end_close", "fiscal_period", {
      year: closingYear,
      vouchers: newEntries.length,
      netProfit: yearIncome.netProfit,
    });

    setClosingResults({
      vouchers: newEntries,
      period: newFiscalPeriod,
    });
    setWizardStep(5);
    setIsProcessing(false);
    notify(lang === "en"
      ? `Year ${closingYear} closed successfully (${newEntries.length} vouchers created)`
      : `${closingYear} yılı başarıyla kapatıldı (${newEntries.length} fiş oluşturuldu)`);
  };

  // === GERİ AL ===
  const reopenYear = async () => {
    if (!existingClosing) return;
    if (!confirm(lang === "en"
      ? `Reopen year ${closingYear}? This will reverse all closing vouchers. This action is logged.`
      : `${closingYear} yılı yeniden açılsın mı? Tüm kapanış fişleri ters çevrilecek. Bu işlem kayda alınır.`)) return;

    setIsProcessing(true);

    // Kapanışta üretilen fişleri bul ve iptal et
    const voucherIds = existingClosing.voucherIds || [];
    const newEntries = entries.map(e => {
      if (voucherIds.includes(e.id)) {
        return {
          ...e,
          status: "cancelled",
          cancelledAt: new Date().toISOString(),
          cancelledBy: session.username,
          cancelReason: "year_end_reopen",
        };
      }
      return e;
    });

    // Fiscal period'u kaldır (veya status open)
    const newPeriods = fiscalPeriods.map(p =>
      p.id === existingClosing.id ? { ...p, status: "open", reopenedAt: new Date().toISOString(), reopenedBy: session.username } : p
    );

    await onChange({
      ...data,
      accJournalEntries: newEntries,
      accFiscalPeriods: newPeriods,
    });

    logAudit && logAudit("year_end_reopen", "fiscal_period", { year: closingYear });
    notify(lang === "en"
      ? `Year ${closingYear} reopened. All closing vouchers cancelled.`
      : `${closingYear} yılı yeniden açıldı. Tüm kapanış fişleri iptal edildi.`);
    setIsProcessing(false);
    setClosingResults(null);
    setShowWizard(false);
  };

  // === Render kontroller kartı ===
  const ChecksCard = () => {
    const allOk = trialBalanceCheck.isBalanced && balanceSheetCheck.isBalanced && draftEntries.length === 0;
    return (
      <div className="card p-4" style={{
        background: allOk ? "#dcfce7" : "#fef3c7",
        border: `2px solid ${allOk ? "#15803d" : "#ca8a04"}`,
      }}>
        <div className="flex items-start gap-3">
          {allOk ? <Check size={20} style={{ color: "#15803d", flexShrink: 0 }}/> : <AlertTriangle size={20} style={{ color: "#92400e", flexShrink: 0 }}/>}
          <div className="flex-1">
            <div style={{ fontSize: 14, fontWeight: 700, color: allOk ? "#15803d" : "#92400e" }}>
              {allOk
                ? (lang === "en" ? "✓ Ready for Year-End Close" : "✓ Yıl Sonu Kapanışına Hazır")
                : (lang === "en" ? "⚠ Issues Need Resolution" : "⚠ Çözülmesi Gereken Sorunlar Var")}
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-2 mt-3">
              {/* Mizan denkliği */}
              <div className="card p-2" style={{
                background: trialBalanceCheck.isBalanced ? "#fff" : "#fee2e2",
                borderLeft: `3px solid ${trialBalanceCheck.isBalanced ? "#15803d" : "#b91c1c"}`,
              }}>
                <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
                  {lang === "en" ? "Trial Balance" : "Mizan"}
                </div>
                <div style={{ fontSize: 13, fontWeight: 700, color: trialBalanceCheck.isBalanced ? "#15803d" : "#b91c1c", marginTop: 4 }}>
                  {trialBalanceCheck.isBalanced
                    ? (lang === "en" ? "✓ Balanced" : "✓ Dengeli")
                    : `✗ ${lang === "en" ? "Diff" : "Fark"}: ${fmtTL(Math.abs(trialBalanceCheck.diff))}`}
                </div>
                <div className="text-xs mt-1" style={{ color: "var(--ink-mute)" }}>
                  D: {fmtTL(trialBalanceCheck.totalDebit)} / A: {fmtTL(trialBalanceCheck.totalCredit)}
                </div>
              </div>

              {/* Bilanço denkliği */}
              <div className="card p-2" style={{
                background: balanceSheetCheck.isBalanced ? "#fff" : "#fee2e2",
                borderLeft: `3px solid ${balanceSheetCheck.isBalanced ? "#15803d" : "#b91c1c"}`,
              }}>
                <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
                  {lang === "en" ? "Balance Sheet" : "Bilanço"}
                </div>
                <div style={{ fontSize: 13, fontWeight: 700, color: balanceSheetCheck.isBalanced ? "#15803d" : "#b91c1c", marginTop: 4 }}>
                  {balanceSheetCheck.isBalanced
                    ? (lang === "en" ? "✓ Balanced" : "✓ Dengeli")
                    : `✗ ${lang === "en" ? "Diff" : "Fark"}: ${fmtTL(Math.abs(balanceSheetCheck.diff))}`}
                </div>
                <div className="text-xs mt-1" style={{ color: "var(--ink-mute)" }}>
                  AKT: {fmtTL(balanceSheetCheck.assets)} / PAS: {fmtTL(balanceSheetCheck.liabilities)}
                </div>
              </div>

              {/* Taslak fişler */}
              <div className="card p-2" style={{
                background: draftEntries.length === 0 ? "#fff" : "#fef3c7",
                borderLeft: `3px solid ${draftEntries.length === 0 ? "#15803d" : "#ca8a04"}`,
              }}>
                <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
                  {lang === "en" ? "Draft Entries" : "Taslak Fişler"}
                </div>
                <div style={{ fontSize: 13, fontWeight: 700, color: draftEntries.length === 0 ? "#15803d" : "#92400e", marginTop: 4 }}>
                  {draftEntries.length === 0
                    ? (lang === "en" ? "✓ None" : "✓ Yok")
                    : `⚠ ${draftEntries.length} ${lang === "en" ? "drafts" : "taslak"}`}
                </div>
                {draftEntries.length > 0 && (
                  <div className="text-xs mt-1" style={{ color: "var(--ink-mute)" }}>
                    {lang === "en" ? "Will be ignored" : "Dikkate alınmaz"}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  // === Render Wizard ===
  const renderWizard = () => {
    return (
      <div className="space-y-3">
        <div className="card p-3" style={{ background: "linear-gradient(135deg, #fee2e2 0%, #fef3c7 100%)", border: "1px solid #b91c1c" }}>
          <div className="flex items-center gap-3">
            <Lock size={20} style={{ color: "#b91c1c" }}/>
            <div>
              <div style={{ fontSize: 14, fontWeight: 700, color: "#b91c1c" }}>
                {lang === "en" ? `Year-End Close for ${closingYear}` : `${closingYear} Yılı Sonu Kapanışı`}
              </div>
              <div style={{ fontSize: 11, color: "#92400e", marginTop: 2 }}>
                {lang === "en"
                  ? "This will create closing vouchers and lock the year. Make sure all entries are correct."
                  : "Bu işlem kapanış fişleri oluşturacak ve yılı kilitleyecek. Tüm fişlerin doğru olduğundan emin olun."}
              </div>
            </div>
          </div>
        </div>

        {/* Step indicators */}
        <div className="flex items-center gap-2 mb-2">
          {[1, 2, 3, 4, 5].map(step => (
            <div key={step} className="flex items-center flex-1">
              <div style={{
                width: 28, height: 28, borderRadius: "50%",
                background: wizardStep >= step ? "#b91c1c" : "var(--bg-alt)",
                color: wizardStep >= step ? "#fff" : "var(--ink-mute)",
                display: "flex", alignItems: "center", justifyContent: "center",
                fontWeight: 700, fontSize: 12, flexShrink: 0,
              }}>
                {wizardStep > step ? "✓" : step}
              </div>
              {step < 5 && (
                <div style={{
                  flex: 1, height: 2,
                  background: wizardStep > step ? "#b91c1c" : "var(--line)",
                  margin: "0 4px",
                }}/>
              )}
            </div>
          ))}
        </div>

        {/* Step 1: Kontroller */}
        {wizardStep === 1 && (
          <div className="space-y-3">
            <div style={{ fontSize: 14, fontWeight: 700 }}>
              {lang === "en" ? "Step 1: Pre-Close Checks" : "Adım 1: Kapanış Öncesi Kontroller"}
            </div>
            <ChecksCard/>

            {draftEntries.length > 0 && (
              <div className="card p-3" style={{ background: "#fef3c7" }}>
                <div style={{ fontSize: 12, fontWeight: 700, color: "#92400e", marginBottom: 6 }}>
                  {lang === "en" ? "Draft entries that will be ignored:" : "Dikkate alınmayacak taslak fişler:"}
                </div>
                <div className="max-h-32 overflow-y-auto space-y-1">
                  {draftEntries.slice(0, 10).map(e => (
                    <div key={e.id} className="text-xs flex items-center gap-2">
                      <span className="mono">{e.voucherNo}</span>
                      <span style={{ color: "var(--ink-mute)" }}>{e.date}</span>
                      <span className="truncate flex-1">{e.description}</span>
                      <span className="mono">{fmtTL(e.totalDebit)}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            <div className="flex justify-end">
              <button
                onClick={() => setWizardStep(2)}
                disabled={!trialBalanceCheck.isBalanced}
                className="btn btn-primary text-xs"
                style={!trialBalanceCheck.isBalanced ? { opacity: 0.5, cursor: "not-allowed" } : {}}
              >
                {lang === "en" ? "Next: Review Income Statement" : "İleri: Gelir Tablosunu İncele"} →
              </button>
            </div>
          </div>
        )}

        {/* Step 2: Gelir Tablosu */}
        {wizardStep === 2 && (
          <div className="space-y-3">
            <div style={{ fontSize: 14, fontWeight: 700 }}>
              {lang === "en" ? "Step 2: Income Statement Summary" : "Adım 2: Gelir Tablosu Özeti"}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
              <div className="card p-3" style={{ borderLeft: "4px solid #0f766e" }}>
                <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Revenue" : "Gelir"}
                </div>
                <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#0f766e" }}>
                  {fmtTL(yearIncome.revenue)} ₺
                </div>
                <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
                  {yearIncome.revenueAccounts.length} {lang === "en" ? "accounts" : "hesap"}
                </div>
              </div>
              <div className="card p-3" style={{ borderLeft: "4px solid #b91c1c" }}>
                <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Expense" : "Gider"}
                </div>
                <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#b91c1c" }}>
                  {fmtTL(yearIncome.expense)} ₺
                </div>
                <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
                  {yearIncome.expenseAccounts.length} {lang === "en" ? "accounts" : "hesap"}
                </div>
              </div>
              <div className="card p-3" style={{ borderLeft: "4px solid #b45309" }}>
                <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Tax" : "Vergi"}
                </div>
                <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#b45309" }}>
                  {fmtTL(yearIncome.tax)} ₺
                </div>
              </div>
              <div className="card p-3" style={{
                background: yearIncome.netProfit >= 0 ? "#dcfce7" : "#fee2e2",
                borderLeft: `4px solid ${yearIncome.netProfit >= 0 ? "#15803d" : "#b91c1c"}`,
              }}>
                <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
                  {lang === "en" ? "Net Profit/Loss" : "Net Kâr/Zarar"}
                </div>
                <div className="mono" style={{ fontSize: 18, fontWeight: 700, marginTop: 4, color: yearIncome.netProfit >= 0 ? "#15803d" : "#b91c1c" }}>
                  {fmtTLSign(yearIncome.netProfit)} ₺
                </div>
              </div>
            </div>

            <div className="card p-3">
              <div style={{ fontSize: 12, fontWeight: 700, marginBottom: 8 }}>
                {lang === "en" ? "Closing Action" : "Yapılacak İşlem"}:
              </div>
              <div className="text-xs space-y-1" style={{ color: "var(--ink-soft)", lineHeight: 1.6 }}>
                <div>• {lang === "en" ? "All revenue accounts (6X) will be closed to 690" : "Tüm gelir hesapları (6X) → 690'a kapanacak"}</div>
                <div>• {lang === "en" ? "All expense accounts (6X, 7X) will be closed to 690" : "Tüm gider hesapları (6X, 7X) → 690'a kapanacak"}</div>
                <div>• {lang === "en" ? `Net result (${fmtTL(yearIncome.netProfit)} ₺) will go to 590/591` : `Net sonuç (${fmtTL(yearIncome.netProfit)} ₺) → 590/591'e aktarılacak`}</div>
              </div>
            </div>

            <div className="flex justify-between">
              <button onClick={() => setWizardStep(1)} className="btn btn-ghost text-xs">
                ← {lang === "en" ? "Back" : "Geri"}
              </button>
              <button onClick={() => setWizardStep(3)} className="btn btn-primary text-xs">
                {lang === "en" ? "Next: Review Balance Sheet" : "İleri: Bilançoyu İncele"} →
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Bilanço */}
        {wizardStep === 3 && (
          <div className="space-y-3">
            <div style={{ fontSize: 14, fontWeight: 700 }}>
              {lang === "en" ? "Step 3: Balance Sheet Review" : "Adım 3: Bilanço İncelemesi"}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div className="card p-3">
                <div style={{ fontSize: 12, fontWeight: 700, color: "#0f766e", marginBottom: 6, borderBottom: "1px solid var(--line)", paddingBottom: 4 }}>
                  {lang === "en" ? `Assets (${balanceSheetBalances.assets.length})` : `Aktifler (${balanceSheetBalances.assets.length} hesap)`}
                </div>
                <div className="space-y-1 max-h-64 overflow-y-auto">
                  {balanceSheetBalances.assets.map(a => (
                    <div key={a.code} className="flex items-center justify-between text-xs">
                      <span className="mono">{a.code}</span>
                      <span className="flex-1 mx-2 truncate">{a.name}</span>
                      <span className="mono font-semibold">{fmtTL(a.balance)} ₺</span>
                    </div>
                  ))}
                </div>
                <div style={{ borderTop: "2px solid var(--line)", marginTop: 6, paddingTop: 6 }} className="flex justify-between font-bold">
                  <span className="text-xs">{lang === "en" ? "TOTAL" : "TOPLAM"}</span>
                  <span className="mono">{fmtTL(balanceSheetCheck.assets)} ₺</span>
                </div>
              </div>

              <div className="card p-3">
                <div style={{ fontSize: 12, fontWeight: 700, color: "#b91c1c", marginBottom: 6, borderBottom: "1px solid var(--line)", paddingBottom: 4 }}>
                  {lang === "en" ? `Liabilities & Equity (${balanceSheetBalances.liabilities.length})` : `Pasifler (${balanceSheetBalances.liabilities.length} hesap)`}
                </div>
                <div className="space-y-1 max-h-64 overflow-y-auto">
                  {balanceSheetBalances.liabilities.map(l => (
                    <div key={l.code} className="flex items-center justify-between text-xs">
                      <span className="mono">{l.code}</span>
                      <span className="flex-1 mx-2 truncate">{l.name}</span>
                      <span className="mono font-semibold">{fmtTL(-l.balance)} ₺</span>
                    </div>
                  ))}
                  {yearIncome.netProfit !== 0 && (
                    <div className="flex items-center justify-between text-xs" style={{ fontWeight: 700, color: yearIncome.netProfit > 0 ? "#15803d" : "#b91c1c" }}>
                      <span className="mono">{yearIncome.netProfit > 0 ? "590" : "591"}</span>
                      <span className="flex-1 mx-2 truncate">{yearIncome.netProfit > 0 ? "Dönem Net Kârı" : "Dönem Net Zararı"}</span>
                      <span className="mono">{fmtTLSign(yearIncome.netProfit)} ₺</span>
                    </div>
                  )}
                </div>
                <div style={{ borderTop: "2px solid var(--line)", marginTop: 6, paddingTop: 6 }} className="flex justify-between font-bold">
                  <span className="text-xs">{lang === "en" ? "TOTAL" : "TOPLAM"}</span>
                  <span className="mono">{fmtTL(balanceSheetCheck.liabilities)} ₺</span>
                </div>
              </div>
            </div>

            <div className="card p-3" style={{
              background: balanceSheetCheck.isBalanced ? "#dcfce7" : "#fee2e2",
              border: `1px solid ${balanceSheetCheck.isBalanced ? "#15803d" : "#b91c1c"}`,
            }}>
              <div style={{ fontSize: 13, fontWeight: 700, color: balanceSheetCheck.isBalanced ? "#15803d" : "#b91c1c", textAlign: "center" }}>
                {balanceSheetCheck.isBalanced
                  ? (lang === "en" ? "✓ Balance Sheet is Balanced" : "✓ Bilanço Dengeli (Aktif = Pasif + Net Kâr)")
                  : `⚠ ${lang === "en" ? "Out of balance by" : "Denge dışı"}: ${fmtTL(Math.abs(balanceSheetCheck.diff))} ₺`}
              </div>
            </div>

            <div className="flex justify-between">
              <button onClick={() => setWizardStep(2)} className="btn btn-ghost text-xs">
                ← {lang === "en" ? "Back" : "Geri"}
              </button>
              <button
                onClick={() => setWizardStep(4)}
                disabled={!balanceSheetCheck.isBalanced}
                className="btn btn-primary text-xs"
                style={!balanceSheetCheck.isBalanced ? { opacity: 0.5, cursor: "not-allowed" } : {}}
              >
                {lang === "en" ? "Next: Final Confirmation" : "İleri: Son Onay"} →
              </button>
            </div>
          </div>
        )}

        {/* Step 4: Son Onay */}
        {wizardStep === 4 && (
          <div className="space-y-3">
            <div style={{ fontSize: 14, fontWeight: 700 }}>
              {lang === "en" ? "Step 4: Final Confirmation" : "Adım 4: Son Onay"}
            </div>

            <div className="card p-4" style={{ background: "#fee2e2", border: "2px solid #b91c1c" }}>
              <div className="flex items-start gap-3">
                <AlertTriangle size={24} style={{ color: "#b91c1c", flexShrink: 0 }}/>
                <div>
                  <div style={{ fontSize: 14, fontWeight: 700, color: "#b91c1c" }}>
                    ⚠ {lang === "en" ? "Important Warning" : "Önemli Uyarı"}
                  </div>
                  <div style={{ fontSize: 12, color: "#7f1d1d", marginTop: 6, lineHeight: 1.6 }}>
                    {lang === "en"
                      ? `This will create the following vouchers for fiscal year ${closingYear}:`
                      : `${closingYear} mali yılı için aşağıdaki fişler oluşturulacak:`}
                  </div>
                  <ul style={{ fontSize: 12, color: "#7f1d1d", marginTop: 6, paddingLeft: 20, lineHeight: 1.8 }}>
                    <li><b>{lang === "en" ? "Income Closing Voucher" : "Gelir Tablosu Kapanış Fişi"}</b> (31.12.{closingYear}): 6XX/7XX hesaplarını 690'a kapatır</li>
                    <li><b>{lang === "en" ? "Balance Sheet Closing Voucher" : "Bilanço Kapanış Fişi"}</b> (31.12.{closingYear}): Tüm bilanço hesaplarını 999'a kapatır</li>
                    <li><b>{lang === "en" ? "Year Opening Voucher" : "Yıl Açılış Fişi"}</b> (01.01.{closingYear + 1}): Yeni yıl bakiyelerini açar</li>
                  </ul>
                  <div style={{ fontSize: 11, color: "#7f1d1d", marginTop: 10, fontWeight: 600 }}>
                    {lang === "en"
                      ? `Make a backup before proceeding. You can reopen the year later, but it requires manual verification.`
                      : `Devam etmeden önce yedek alın. Daha sonra yılı yeniden açabilirsiniz ama manuel doğrulama gerekir.`}
                  </div>
                </div>
              </div>
            </div>

            <div className="card p-3">
              <div className="grid grid-cols-2 gap-3 text-xs">
                <div>
                  <div style={{ color: "var(--ink-mute)" }}>{lang === "en" ? "Fiscal Year" : "Mali Yıl"}</div>
                  <div className="font-bold text-base">{closingYear}</div>
                </div>
                <div>
                  <div style={{ color: "var(--ink-mute)" }}>{lang === "en" ? "Net Profit/Loss" : "Net Kâr/Zarar"}</div>
                  <div className="font-bold text-base" style={{ color: yearIncome.netProfit >= 0 ? "#15803d" : "#b91c1c" }}>
                    {fmtTLSign(yearIncome.netProfit)} ₺
                  </div>
                </div>
                <div>
                  <div style={{ color: "var(--ink-mute)" }}>{lang === "en" ? "Total Assets" : "Toplam Aktif"}</div>
                  <div className="font-bold">{fmtTL(balanceSheetCheck.assets)} ₺</div>
                </div>
                <div>
                  <div style={{ color: "var(--ink-mute)" }}>{lang === "en" ? "Vouchers to Create" : "Üretilecek Fiş"}</div>
                  <div className="font-bold">3 {lang === "en" ? "vouchers" : "fiş"}</div>
                </div>
              </div>
            </div>

            <div className="flex justify-between">
              <button onClick={() => setWizardStep(3)} className="btn btn-ghost text-xs" disabled={isProcessing}>
                ← {lang === "en" ? "Back" : "Geri"}
              </button>
              <button
                onClick={performYearEndClose}
                disabled={isProcessing}
                className="btn text-xs"
                style={{
                  background: "#b91c1c", color: "#fff", fontWeight: 700,
                  padding: "8px 20px",
                  opacity: isProcessing ? 0.5 : 1,
                  cursor: isProcessing ? "not-allowed" : "pointer",
                }}
              >
                {isProcessing ? (
                  <><RefreshCw size={11} className="animate-spin"/> {lang === "en" ? "Closing..." : "Kapatılıyor..."}</>
                ) : (
                  <><Lock size={11}/> {lang === "en" ? `CLOSE YEAR ${closingYear}` : `${closingYear} YILINI KAPAT`}</>
                )}
              </button>
            </div>
          </div>
        )}

        {/* Step 5: Sonuç */}
        {wizardStep === 5 && closingResults && (
          <div className="space-y-3">
            <div className="card p-4" style={{ background: "#dcfce7", border: "2px solid #15803d" }}>
              <div className="flex items-start gap-3">
                <Check size={24} style={{ color: "#15803d" }}/>
                <div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: "#15803d" }}>
                    ✓ {lang === "en" ? `Year ${closingYear} Closed Successfully` : `${closingYear} Yılı Başarıyla Kapatıldı`}
                  </div>
                  <div style={{ fontSize: 12, color: "#15803d", marginTop: 4 }}>
                    {closingResults.vouchers.length} {lang === "en" ? "vouchers created" : "fiş oluşturuldu"}
                  </div>
                </div>
              </div>
            </div>

            <div className="space-y-2">
              <div style={{ fontSize: 13, fontWeight: 700 }}>
                {lang === "en" ? "Created Vouchers:" : "Oluşturulan Fişler:"}
              </div>
              {closingResults.vouchers.map(v => (
                <div key={v.id} className="card p-3">
                  <div className="flex items-center justify-between">
                    <div>
                      <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: "var(--accent)" }}>
                        {v.voucherNo}
                      </div>
                      <div style={{ fontSize: 11, marginTop: 2 }}>{v.description}</div>
                      <div style={{ fontSize: 10, color: "var(--ink-mute)", marginTop: 2 }}>
                        {v.date} · {v.lines.length} {lang === "en" ? "lines" : "satır"}
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="mono" style={{ fontSize: 13, fontWeight: 700 }}>
                        {fmtTL(v.totalDebit)} ₺
                      </div>
                      <span className="chip" style={{ background: "#dcfce7", color: "#15803d", fontSize: 9, padding: "1px 6px", fontWeight: 700 }}>
                        POSTED
                      </span>
                    </div>
                  </div>
                </div>
              ))}
            </div>

            <div className="flex justify-end">
              <button onClick={() => { setShowWizard(false); setWizardStep(1); setClosingResults(null); }} className="btn btn-primary text-xs">
                <Check size={11}/> {lang === "en" ? "Done" : "Tamamla"}
              </button>
            </div>
          </div>
        )}
      </div>
    );
  };

  // === Ana Render ===
  if (showWizard) {
    return renderWizard();
  }

  return (
    <div className="space-y-3">
      {/* Başlık */}
      <div className="card p-3" style={{ background: "linear-gradient(135deg, #fee2e2 0%, #fef3c7 100%)" }}>
        <div className="flex items-start gap-3">
          <Lock size={20} style={{ color: "#b91c1c", flexShrink: 0, marginTop: 2 }}/>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: "#b91c1c" }}>
              {lang === "en" ? "Year-End Close" : "Mali Yıl Kapanışı"}
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 4, lineHeight: 1.5 }}>
              {lang === "en"
                ? "Close the fiscal year, generate closing vouchers, and prepare opening vouchers for the new year. This is a sensitive operation - always make a backup first."
                : "Mali yılı kapat, kapanış fişlerini üret ve yeni yıl için açılış fişlerini hazırla. Hassas bir işlem - önce mutlaka yedek al."}
            </div>
          </div>
        </div>
      </div>

      {/* Yıl seçimi */}
      <div className="card p-3">
        <div className="flex items-end gap-3 flex-wrap">
          <div>
            <div className="label mb-1">{lang === "en" ? "Fiscal Year to Close" : "Kapatılacak Mali Yıl"}</div>
            <select
              className="input mono text-xs"
              value={closingYear}
              onChange={e => setClosingYear(Number(e.target.value))}
              style={{ width: 120 }}
            >
              {[currentYear - 5, currentYear - 4, currentYear - 3, currentYear - 2, currentYear - 1, currentYear].map(y => (
                <option key={y} value={y}>{y}</option>
              ))}
            </select>
          </div>

          <div className="text-xs" style={{ color: "var(--ink-mute)" }}>
            <div>{lang === "en" ? "Period" : "Dönem"}: {yearStart} — {yearEnd}</div>
            <div>{lang === "en" ? "Vouchers" : "Fiş Sayısı"}: {yearEntries.length} ({lang === "en" ? "posted" : "onaylı"})</div>
          </div>

          <div className="ml-auto">
            {existingClosing ? (
              <div className="flex items-center gap-2">
                <span className="chip" style={{ background: "#fee2e2", color: "#b91c1c", padding: "4px 10px", fontWeight: 700 }}>
                  <Lock size={10}/> {lang === "en" ? "CLOSED" : "KAPATILDI"}
                </span>
                <button onClick={reopenYear} disabled={isProcessing} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                  <RefreshCw size={11}/> {lang === "en" ? "Reopen" : "Yeniden Aç"}
                </button>
              </div>
            ) : (
              <button onClick={() => { setShowWizard(true); setWizardStep(1); }} className="btn text-xs"
                style={{ background: "#b91c1c", color: "#fff", fontWeight: 700, padding: "8px 16px" }}>
                <Lock size={11}/> {lang === "en" ? "Start Year-End Close" : "Yıl Kapanışını Başlat"}
              </button>
            )}
          </div>
        </div>
      </div>

      {/* Mevcut yıl özeti */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
        <div className="card p-3" style={{ borderLeft: "4px solid #0f766e" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Revenue" : "Toplam Gelir"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#0f766e" }}>
            {fmtTL(yearIncome.revenue)} ₺
          </div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #b91c1c" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Expense" : "Toplam Gider"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#b91c1c" }}>
            {fmtTL(yearIncome.expense)} ₺
          </div>
        </div>
        <div className="card p-3" style={{
          background: yearIncome.netProfit >= 0 ? "#dcfce7" : "#fee2e2",
          borderLeft: `4px solid ${yearIncome.netProfit >= 0 ? "#15803d" : "#b91c1c"}`,
        }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
            {lang === "en" ? "Net Result" : "Net Sonuç"}
          </div>
          <div className="mono" style={{ fontSize: 18, fontWeight: 700, marginTop: 4, color: yearIncome.netProfit >= 0 ? "#15803d" : "#b91c1c" }}>
            {fmtTLSign(yearIncome.netProfit)} ₺
          </div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #1d4ed8" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
            {lang === "en" ? "Total Assets" : "Toplam Aktif"}
          </div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4 }}>
            {fmtTL(balanceSheetCheck.assets)} ₺
          </div>
        </div>
      </div>

      {/* Kontroller */}
      <ChecksCard/>

      {/* Geçmiş kapanışlar */}
      {fiscalPeriods.length > 0 && (
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "10px 14px", background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
            <div style={{ fontSize: 13, fontWeight: 700 }}>
              {lang === "en" ? "Closing History" : "Kapanış Geçmişi"}
            </div>
          </div>
          <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Year" : "Yıl"}
                </th>
                <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Status" : "Durum"}
                </th>
                <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Net Profit" : "Net Sonuç"}
                </th>
                <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Closed By" : "Kapatan"}
                </th>
                <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                  {lang === "en" ? "Date" : "Tarih"}
                </th>
              </tr>
            </thead>
            <tbody>
              {[...fiscalPeriods].reverse().map(p => (
                <tr key={p.id} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td className="mono" style={{ padding: "6px 10px", fontSize: 12, fontWeight: 700 }}>{p.year}</td>
                  <td style={{ padding: "6px 10px" }}>
                    {p.status === "closed" ? (
                      <span className="chip" style={{ background: "#fee2e2", color: "#b91c1c", padding: "2px 8px", fontWeight: 700, fontSize: 9 }}>
                        <Lock size={9}/> {lang === "en" ? "CLOSED" : "KAPATILDI"}
                      </span>
                    ) : (
                      <span className="chip" style={{ background: "#fef3c7", color: "#92400e", padding: "2px 8px", fontWeight: 700, fontSize: 9 }}>
                        {lang === "en" ? "REOPENED" : "YENİDEN AÇILDI"}
                      </span>
                    )}
                  </td>
                  <td className="mono text-right" style={{ padding: "6px 10px", fontWeight: 600, color: p.netProfit >= 0 ? "#15803d" : "#b91c1c" }}>
                    {fmtTLSign(p.netProfit)} ₺
                  </td>
                  <td style={{ padding: "6px 10px", fontSize: 10 }}>{p.closedBy}</td>
                  <td style={{ padding: "6px 10px", fontSize: 10, color: "var(--ink-mute)" }}>
                    {p.closedAt ? p.closedAt.split("T")[0] : "—"}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Önemli notlar */}
      <div className="card p-3" style={{ background: "#dbeafe", border: "1px solid #1d4ed8" }}>
        <div className="flex items-start gap-3">
          <Info size={16} style={{ color: "#1d4ed8", flexShrink: 0, marginTop: 2 }}/>
          <div style={{ fontSize: 11, color: "#1d4ed8", lineHeight: 1.6 }}>
            <b>{lang === "en" ? "Year-End Close Process" : "Yıl Sonu Kapanış Süreci"}:</b>
            <ol style={{ marginTop: 4, paddingLeft: 20, lineHeight: 1.7 }}>
              <li>{lang === "en" ? "Pre-close checks (trial balance, balance sheet equality)" : "Kapanış öncesi kontroller (mizan, bilanço denkliği)"}</li>
              <li>{lang === "en" ? "Income Statement closing - 6XX/7XX → 690 → 590/591" : "Gelir Tablosu kapanışı - 6XX/7XX → 690 → 590/591"}</li>
              <li>{lang === "en" ? "Balance Sheet closing - All accounts → 999" : "Bilanço kapanışı - Tüm hesaplar → 999"}</li>
              <li>{lang === "en" ? "New year opening - Balances transferred to 01.01" : "Yeni yıl açılışı - Bakiyeler 01.01'e taşınır"}</li>
              <li>{lang === "en" ? "Retained earnings - 590/591 → 570 (prior year P&L)" : "Geçmiş yıl kâr/zararı - 590/591 → 570'e aktarılır"}</li>
            </ol>
          </div>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   AI ÖĞRENME DASHBOARDU (AI Learning Dashboard)
   ---------------------------------------------------------------------
   Geçmiş yevmiye fişlerinden örüntü çıkararak:
   - Hesap planı için iyileştirme önerileri
   - Tamlık skorları
   - Anomali tespiti
   - Eğitim istatistikleri
===================================================================== */
function AILearningDashboard({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];

  const [activeSection, setActiveSection] = useState("suggestions"); // suggestions | completeness | anomalies | stats
  const [filterPriority, setFilterPriority] = useState("all"); // all | high | medium
  const [filterCompleteness, setFilterCompleteness] = useState("all"); // all | incomplete | basic | good | excellent
  const [search, setSearch] = useState("");
  const [applyingAll, setApplyingAll] = useState(false);

  // === Hesaplama ===
  const postedEntries = useMemo(() =>
    entries.filter(e => e.status === "posted"),
  [entries]);

  const suggestions = useMemo(() =>
    generateAccountSuggestions(accounts, postedEntries, 2),
  [accounts, postedEntries]);

  const completenessMap = useMemo(() => {
    const map = {};
    accounts.forEach(a => {
      map[a.code] = calculateAccountCompleteness(a);
    });
    return map;
  }, [accounts]);

  const anomalies = useMemo(() =>
    detectAnomalies(postedEntries, accounts),
  [postedEntries, accounts]);

  // === İstatistikler ===
  const stats = useMemo(() => {
    const totalAccounts = accounts.length;
    const activeAccounts = accounts.filter(a => a.active !== false).length;
    const totalEntries = postedEntries.length;

    // AI-ready: en az 3 keyword + module source
    const aiReadyAccounts = accounts.filter(a => {
      const c = completenessMap[a.code];
      return c && c.percentage >= 50;
    }).length;

    // Ortalama tamlık
    const avgCompleteness = accounts.length > 0
      ? Math.round(Object.values(completenessMap).reduce((sum, c) => sum + c.percentage, 0) / accounts.length)
      : 0;

    // En çok kullanılan hesaplar
    const usageCount = {};
    postedEntries.forEach(e => {
      (e.lines || []).forEach(l => {
        if (l.accountCode) {
          usageCount[l.accountCode] = (usageCount[l.accountCode] || 0) + 1;
        }
      });
    });
    const topAccounts = Object.entries(usageCount)
      .map(([code, count]) => ({ code, count, account: accounts.find(a => a.code === code) }))
      .filter(x => x.account)
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    // En sık birlikte kullanılan çiftler
    const pairCount = {};
    postedEntries.forEach(e => {
      const codes = [...new Set((e.lines || []).map(l => l.accountCode).filter(Boolean))];
      for (let i = 0; i < codes.length; i++) {
        for (let j = i + 1; j < codes.length; j++) {
          const pair = [codes[i], codes[j]].sort().join("→");
          pairCount[pair] = (pairCount[pair] || 0) + 1;
        }
      }
    });
    const topPairs = Object.entries(pairCount)
      .map(([pair, count]) => {
        const [a, b] = pair.split("→");
        return { a, b, count, accA: accounts.find(x => x.code === a), accB: accounts.find(x => x.code === b) };
      })
      .filter(x => x.accA && x.accB)
      .sort((a, b) => b.count - a.count)
      .slice(0, 10);

    return {
      totalAccounts, activeAccounts, totalEntries,
      aiReadyAccounts, avgCompleteness,
      topAccounts, topPairs,
    };
  }, [accounts, postedEntries, completenessMap]);

  // === Filter suggestions ===
  const filteredSuggestions = useMemo(() => {
    let list = suggestions;
    if (filterPriority === "high") list = list.filter(s => s.priority >= 5);
    else if (filterPriority === "medium") list = list.filter(s => s.priority >= 3 && s.priority < 5);
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(s =>
        s.account.code.toLowerCase().includes(q) ||
        s.account.name.toLowerCase().includes(q)
      );
    }
    return list;
  }, [suggestions, filterPriority, search]);

  // === Filter completeness ===
  const filteredAccountsByCompleteness = useMemo(() => {
    let list = accounts.filter(a => a.active !== false && a.allowTransaction !== false);
    if (filterCompleteness !== "all") {
      list = list.filter(a => completenessMap[a.code]?.level === filterCompleteness);
    }
    if (search.trim()) {
      const q = search.toLowerCase();
      list = list.filter(a =>
        a.code.toLowerCase().includes(q) ||
        a.name.toLowerCase().includes(q)
      );
    }
    return list.sort((a, b) =>
      (completenessMap[a.code]?.percentage || 0) - (completenessMap[b.code]?.percentage || 0)
    );
  }, [accounts, completenessMap, filterCompleteness, search]);

  // === Tek bir hesabın önerilerini uygula ===
  const applySuggestion = async (suggestion) => {
    const acc = suggestion.account;
    const existingKeywords = Array.isArray(acc.keywords) ? acc.keywords : [];
    const existingOffsets = Array.isArray(acc.commonOffsetAccounts) ? acc.commonOffsetAccounts : [];
    const existingSources = Array.isArray(acc.moduleSources) ? acc.moduleSources : [];

    const updatedAcc = {
      ...acc,
      keywords: [...existingKeywords, ...suggestion.newKeywords.map(k => k.keyword)],
      commonOffsetAccounts: [...existingOffsets, ...suggestion.newOffsets.map(o => o.code)],
      moduleSources: [...existingSources, ...suggestion.newSources.map(s => s.source)],
      updatedAt: new Date().toISOString(),
      updatedBy: session.username,
    };

    const next = accounts.map(a => a.code === acc.code ? updatedAcc : a);
    await onChange({ ...data, accChartOfAccounts: next });
    logAudit && logAudit("ai_apply", "coa", {
      code: acc.code,
      newKeywords: suggestion.newKeywords.length,
      newOffsets: suggestion.newOffsets.length,
      newSources: suggestion.newSources.length,
    });
    notify(lang === "en"
      ? `Updated ${acc.code} - ${acc.name}`
      : `Güncellendi: ${acc.code} - ${acc.name}`);
  };

  // === Tümünü Uygula ===
  const applyAll = async () => {
    if (filteredSuggestions.length === 0) return;
    if (!confirm(lang === "en"
      ? `Apply ${filteredSuggestions.length} AI suggestions? This will update keyword, offset accounts, and module sources for these accounts.`
      : `${filteredSuggestions.length} AI önerisi uygulanacak. Bu işlem hesapların anahtar kelime, karşı hesap ve modül kaynaklarını güncelleyecek. Onaylıyor musunuz?`)) return;

    setApplyingAll(true);
    let updatedAccounts = [...accounts];

    for (const suggestion of filteredSuggestions) {
      const acc = updatedAccounts.find(a => a.code === suggestion.account.code);
      if (!acc) continue;
      const existingKeywords = Array.isArray(acc.keywords) ? acc.keywords : [];
      const existingOffsets = Array.isArray(acc.commonOffsetAccounts) ? acc.commonOffsetAccounts : [];
      const existingSources = Array.isArray(acc.moduleSources) ? acc.moduleSources : [];

      const updatedAcc = {
        ...acc,
        keywords: [...existingKeywords, ...suggestion.newKeywords.map(k => k.keyword)],
        commonOffsetAccounts: [...existingOffsets, ...suggestion.newOffsets.map(o => o.code)],
        moduleSources: [...existingSources, ...suggestion.newSources.map(s => s.source)],
        updatedAt: new Date().toISOString(),
        updatedBy: session.username,
      };
      updatedAccounts = updatedAccounts.map(a => a.code === acc.code ? updatedAcc : a);
    }

    await onChange({ ...data, accChartOfAccounts: updatedAccounts });
    logAudit && logAudit("ai_apply_bulk", "coa", { count: filteredSuggestions.length });
    notify(lang === "en"
      ? `${filteredSuggestions.length} suggestions applied`
      : `${filteredSuggestions.length} öneri uygulandı`);
    setApplyingAll(false);
  };

  // === Section render helpers ===
  const renderSuggestions = () => (
    <div className="space-y-3">
      {/* Filter */}
      <div className="card p-3 flex flex-wrap items-center gap-2">
        <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
          {[
            { id: "all", label: { tr: "Tümü", en: "All" } },
            { id: "high", label: { tr: "Yüksek", en: "High" } },
            { id: "medium", label: { tr: "Orta", en: "Medium" } },
          ].map(p => (
            <button key={p.id} onClick={() => setFilterPriority(p.id)} className="text-xs"
              style={{
                padding: "5px 10px",
                background: filterPriority === p.id ? "#7c3aed" : "var(--bg)",
                color: filterPriority === p.id ? "#fff" : "var(--ink)",
                fontWeight: 600, cursor: "pointer",
                borderRight: p.id !== "medium" ? "1px solid var(--line)" : "none",
              }}>
              {p.label[lang] || p.label.tr}
            </button>
          ))}
        </div>

        <input className="input text-xs flex-1" placeholder={lang === "en" ? "Search account..." : "Hesap ara..."}
          value={search} onChange={e => setSearch(e.target.value)}
          style={{ minWidth: 200, maxWidth: 300 }}/>

        <div className="text-xs ml-auto" style={{ color: "var(--ink-mute)" }}>
          {filteredSuggestions.length} {lang === "en" ? "suggestions" : "öneri"}
        </div>

        {filteredSuggestions.length > 0 && (
          <button onClick={applyAll} disabled={applyingAll}
            className="btn text-xs"
            style={{
              background: "#7c3aed", color: "#fff", fontWeight: 600,
              padding: "5px 12px", borderRadius: 4,
              opacity: applyingAll ? 0.5 : 1,
              cursor: applyingAll ? "not-allowed" : "pointer",
            }}>
            <Sparkles size={11}/>
            {applyingAll
              ? (lang === "en" ? "Applying..." : "Uygulanıyor...")
              : (lang === "en" ? `Apply All (${filteredSuggestions.length})` : `Tümünü Uygula (${filteredSuggestions.length})`)}
          </button>
        )}
      </div>

      {/* Suggestions */}
      {filteredSuggestions.length === 0 ? (
        <div className="card p-10 text-center">
          <Sparkles size={32} style={{ margin: "0 auto", color: "#7c3aed", opacity: 0.5 }}/>
          <div style={{ fontSize: 14, fontWeight: 600, marginTop: 12 }}>
            {lang === "en" ? "No suggestions yet" : "Henüz öneri yok"}
          </div>
          <div style={{ fontSize: 12, color: "var(--ink-mute)", marginTop: 4 }}>
            {lang === "en"
              ? "Once you have posted journal entries, AI will analyze patterns and suggest improvements."
              : "Onaylanmış yevmiye fişleriniz oluştukça, AI örüntüleri analiz ederek öneriler çıkaracak."}
          </div>
        </div>
      ) : (
        <div className="space-y-2">
          {filteredSuggestions.map((s, i) => {
            const typeCfg = ACCOUNT_TYPES[s.account.type] || ACCOUNT_TYPES.aktif;
            return (
              <div key={s.account.code} className="card p-3" style={{ borderLeft: `4px solid ${typeCfg.color}` }}>
                <div className="flex items-start justify-between flex-wrap gap-2 mb-2">
                  <div className="flex items-start gap-3">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className="mono" style={{ fontSize: 13, fontWeight: 700, color: typeCfg.color }}>
                          {s.account.code}
                        </span>
                        <span style={{ fontSize: 13, fontWeight: 600 }}>{s.account.name}</span>
                      </div>
                      <div style={{ fontSize: 10, color: "var(--ink-mute)", marginTop: 2 }}>
                        {s.usageCount} {lang === "en" ? "uses" : "kullanım"} ·
                        {lang === "en" ? " Completeness" : " Tamlık"}: %{s.completeness.percentage}
                      </div>
                    </div>
                  </div>
                  <button onClick={() => applySuggestion(s)}
                    className="btn text-xs"
                    style={{
                      background: "#7c3aed20", color: "#7c3aed",
                      padding: "4px 10px", fontWeight: 600, borderRadius: 4,
                    }}>
                    <Check size={11}/> {lang === "en" ? "Apply" : "Uygula"}
                  </button>
                </div>

                {/* Keywords */}
                {s.newKeywords.length > 0 && (
                  <div className="mb-2">
                    <div className="text-xs mb-1" style={{ fontWeight: 600, color: "var(--ink-mute)" }}>
                      {lang === "en" ? "+ Suggested Keywords" : "+ Önerilen Anahtar Kelimeler"}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {s.newKeywords.map((k, idx) => (
                        <span key={idx} className="chip" style={{
                          background: "#dbeafe", color: "#1d4ed8",
                          fontSize: 10, padding: "2px 7px", fontWeight: 600,
                        }} title={`${k.occurrences} ${lang === "en" ? "occurrences" : "kullanım"} - %${k.confidence}`}>
                          {k.keyword} <small style={{ opacity: 0.7 }}>({k.occurrences})</small>
                        </span>
                      ))}
                    </div>
                  </div>
                )}

                {/* Offset Accounts */}
                {s.newOffsets.length > 0 && (
                  <div className="mb-2">
                    <div className="text-xs mb-1" style={{ fontWeight: 600, color: "var(--ink-mute)" }}>
                      {lang === "en" ? "+ Suggested Offset Accounts" : "+ Önerilen Karşı Hesaplar"}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {s.newOffsets.map((o, idx) => (
                        <span key={idx} className="chip" style={{
                          background: "#dcfce7", color: "#15803d",
                          fontSize: 10, padding: "2px 7px", fontWeight: 600,
                        }} title={`${o.occurrences} ${lang === "en" ? "co-occurrences" : "birlikte kullanım"} - %${o.confidence}`}>
                          <span className="mono" style={{ fontWeight: 700 }}>{o.code}</span> {o.name.substring(0, 25)} <small style={{ opacity: 0.7 }}>({o.occurrences})</small>
                        </span>
                      ))}
                    </div>
                  </div>
                )}

                {/* Module Sources */}
                {s.newSources.length > 0 && (
                  <div>
                    <div className="text-xs mb-1" style={{ fontWeight: 600, color: "var(--ink-mute)" }}>
                      {lang === "en" ? "+ Suggested Module Sources" : "+ Önerilen Modül Kaynakları"}
                    </div>
                    <div className="flex flex-wrap gap-1">
                      {s.newSources.map((src, idx) => (
                        <span key={idx} className="chip" style={{
                          background: "#fef3c7", color: "#92400e",
                          fontSize: 10, padding: "2px 7px", fontWeight: 600,
                        }} title={`${src.occurrences} ${lang === "en" ? "uses" : "kullanım"}`}>
                          {src.source.toUpperCase()} <small style={{ opacity: 0.7 }}>({src.occurrences})</small>
                        </span>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );

  const renderCompleteness = () => (
    <div className="space-y-3">
      <div className="card p-3 flex flex-wrap items-center gap-2">
        <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
          {[
            { id: "all", label: { tr: "Tümü", en: "All" }, color: "#737373" },
            { id: "incomplete", label: { tr: "Eksik", en: "Incomplete" }, color: "#b91c1c" },
            { id: "basic", label: { tr: "Temel", en: "Basic" }, color: "#ca8a04" },
            { id: "good", label: { tr: "İyi", en: "Good" }, color: "#1d4ed8" },
            { id: "excellent", label: { tr: "Mükemmel", en: "Excellent" }, color: "#15803d" },
          ].map(p => (
            <button key={p.id} onClick={() => setFilterCompleteness(p.id)} className="text-xs"
              style={{
                padding: "5px 10px",
                background: filterCompleteness === p.id ? p.color : "var(--bg)",
                color: filterCompleteness === p.id ? "#fff" : "var(--ink)",
                fontWeight: 600, cursor: "pointer",
                borderRight: p.id !== "excellent" ? "1px solid var(--line)" : "none",
              }}>
              {p.label[lang] || p.label.tr}
            </button>
          ))}
        </div>
        <input className="input text-xs flex-1" placeholder={lang === "en" ? "Search..." : "Ara..."}
          value={search} onChange={e => setSearch(e.target.value)} style={{ minWidth: 200 }}/>
        <div className="text-xs ml-auto" style={{ color: "var(--ink-mute)" }}>
          {filteredAccountsByCompleteness.length} {lang === "en" ? "accounts" : "hesap"}
        </div>
      </div>

      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
              <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>
                {lang === "en" ? "Code" : "Kod"}
              </th>
              <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Account" : "Hesap"}
              </th>
              <th style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>
                {lang === "en" ? "Keywords" : "Anh.Kel."}
              </th>
              <th style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>
                {lang === "en" ? "Offsets" : "Karşı Hes."}
              </th>
              <th style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>
                {lang === "en" ? "Modules" : "Modüller"}
              </th>
              <th style={{ padding: "8px 6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 200 }}>
                {lang === "en" ? "Completeness" : "Tamlık"}
              </th>
            </tr>
          </thead>
          <tbody>
            {filteredAccountsByCompleteness.slice(0, 100).map(acc => {
              const c = completenessMap[acc.code];
              const typeCfg = ACCOUNT_TYPES[acc.type] || ACCOUNT_TYPES.aktif;
              const barColor = {
                excellent: "#15803d", good: "#1d4ed8", basic: "#ca8a04", incomplete: "#b91c1c",
              }[c?.level] || "#737373";

              return (
                <tr key={acc.code} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td className="mono" style={{ padding: "6px", fontSize: 11, fontWeight: 700, color: typeCfg.color }}>
                    {acc.code}
                  </td>
                  <td style={{ padding: "6px", fontSize: 11 }}>{acc.name}</td>
                  <td style={{ padding: "6px", textAlign: "center", fontSize: 10 }}>
                    {Array.isArray(acc.keywords) && acc.keywords.length > 0 ? (
                      <span className="chip" style={{ background: "#dbeafe", color: "#1d4ed8", padding: "1px 6px", fontWeight: 600 }}>
                        {acc.keywords.length}
                      </span>
                    ) : <span style={{ color: "var(--ink-mute)" }}>—</span>}
                  </td>
                  <td style={{ padding: "6px", textAlign: "center", fontSize: 10 }}>
                    {Array.isArray(acc.commonOffsetAccounts) && acc.commonOffsetAccounts.length > 0 ? (
                      <span className="chip" style={{ background: "#dcfce7", color: "#15803d", padding: "1px 6px", fontWeight: 600 }}>
                        {acc.commonOffsetAccounts.length}
                      </span>
                    ) : <span style={{ color: "var(--ink-mute)" }}>—</span>}
                  </td>
                  <td style={{ padding: "6px", textAlign: "center", fontSize: 10 }}>
                    {Array.isArray(acc.moduleSources) && acc.moduleSources.length > 0 ? (
                      <span className="chip" style={{ background: "#fef3c7", color: "#92400e", padding: "1px 6px", fontWeight: 600 }}>
                        {acc.moduleSources.length}
                      </span>
                    ) : <span style={{ color: "var(--ink-mute)" }}>—</span>}
                  </td>
                  <td style={{ padding: "6px" }}>
                    <div className="flex items-center gap-2">
                      <div style={{ flex: 1, background: "var(--bg-alt)", borderRadius: 2, height: 8, overflow: "hidden" }}>
                        <div style={{
                          background: barColor,
                          width: `${c?.percentage || 0}%`,
                          height: "100%",
                          transition: "width 0.3s",
                        }}/>
                      </div>
                      <div className="mono" style={{ fontSize: 10, fontWeight: 700, color: barColor, minWidth: 30, textAlign: "right" }}>
                        %{c?.percentage || 0}
                      </div>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filteredAccountsByCompleteness.length > 100 && (
          <div style={{ padding: 8, textAlign: "center", fontSize: 10, color: "var(--ink-mute)", borderTop: "1px solid var(--line)" }}>
            {lang === "en"
              ? `Showing first 100 of ${filteredAccountsByCompleteness.length}`
              : `${filteredAccountsByCompleteness.length} hesabın ilk 100'ü gösteriliyor`}
          </div>
        )}
      </div>
    </div>
  );

  const renderAnomalies = () => (
    <div className="space-y-3">
      {anomalies.length === 0 ? (
        <div className="card p-10 text-center">
          <Check size={32} style={{ margin: "0 auto", color: "#15803d", opacity: 0.5 }}/>
          <div style={{ fontSize: 14, fontWeight: 600, marginTop: 12 }}>
            {lang === "en" ? "No anomalies detected" : "Anomali tespit edilmedi"}
          </div>
          <div style={{ fontSize: 12, color: "var(--ink-mute)", marginTop: 4 }}>
            {lang === "en" ? "All journal entries look normal." : "Tüm yevmiye fişleri normal görünüyor."}
          </div>
        </div>
      ) : (
        <>
          <div className="grid grid-cols-3 gap-2">
            {["error", "warning", "info"].map(sev => {
              const count = anomalies.filter(a => a.severity === sev).length;
              const cfg = {
                error: { color: "#b91c1c", bg: "#fee2e2", label: { tr: "Hata", en: "Errors" } },
                warning: { color: "#92400e", bg: "#fef3c7", label: { tr: "Uyarı", en: "Warnings" } },
                info: { color: "#1d4ed8", bg: "#dbeafe", label: { tr: "Bilgi", en: "Info" } },
              }[sev];
              return (
                <div key={sev} className="card p-3" style={{ background: cfg.bg, borderLeft: `4px solid ${cfg.color}` }}>
                  <div style={{ fontSize: 10, color: cfg.color, textTransform: "uppercase", fontWeight: 700 }}>
                    {cfg.label[lang] || cfg.label.tr}
                  </div>
                  <div className="mono" style={{ fontSize: 22, fontWeight: 700, color: cfg.color }}>{count}</div>
                </div>
              );
            })}
          </div>

          <div className="space-y-2">
            {anomalies.slice(0, 50).map((a, i) => {
              const sevCfg = {
                error: { color: "#b91c1c", bg: "#fee2e2", icon: "⛔" },
                warning: { color: "#92400e", bg: "#fef3c7", icon: "⚠" },
                info: { color: "#1d4ed8", bg: "#dbeafe", icon: "ℹ" },
              }[a.severity];
              return (
                <div key={i} className="card p-3 flex items-start gap-3" style={{ borderLeft: `4px solid ${sevCfg.color}` }}>
                  <div style={{ fontSize: 16 }}>{sevCfg.icon}</div>
                  <div className="flex-1">
                    <div style={{ fontSize: 12, fontWeight: 600, color: sevCfg.color }}>
                      {a.message}
                    </div>
                    <div style={{ fontSize: 10, color: "var(--ink-mute)", marginTop: 4 }}>
                      <span className="mono">{a.entry.voucherNo}</span> · {a.entry.date}
                      {a.entry.description && ` · ${a.entry.description.substring(0, 60)}`}
                    </div>
                  </div>
                </div>
              );
            })}
            {anomalies.length > 50 && (
              <div className="text-center text-xs" style={{ color: "var(--ink-mute)" }}>
                {lang === "en" ? `+ ${anomalies.length - 50} more` : `+ ${anomalies.length - 50} daha`}
              </div>
            )}
          </div>
        </>
      )}
    </div>
  );

  const renderStats = () => (
    <div className="space-y-3">
      {/* Top accounts */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "10px 14px", background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
          <div style={{ fontSize: 13, fontWeight: 700 }}>
            {lang === "en" ? "Most Used Accounts (Top 10)" : "En Çok Kullanılan Hesaplar (İlk 10)"}
          </div>
        </div>
        <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 40 }}>#</th>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>{lang === "en" ? "Code" : "Kod"}</th>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Name" : "Adı"}</th>
              <th style={{ padding: "6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>{lang === "en" ? "Uses" : "Kullanım"}</th>
            </tr>
          </thead>
          <tbody>
            {stats.topAccounts.map((t, i) => {
              const typeCfg = ACCOUNT_TYPES[t.account.type] || ACCOUNT_TYPES.aktif;
              return (
                <tr key={t.code} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td style={{ padding: "6px", color: "var(--ink-mute)", fontWeight: 700 }}>{i + 1}</td>
                  <td className="mono" style={{ padding: "6px", fontSize: 11, fontWeight: 700, color: typeCfg.color }}>{t.code}</td>
                  <td style={{ padding: "6px", fontSize: 11 }}>{t.account.name}</td>
                  <td className="mono text-right" style={{ padding: "6px", fontSize: 11, fontWeight: 700 }}>{t.count}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Top pairs */}
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "10px 14px", background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
          <div style={{ fontSize: 13, fontWeight: 700 }}>
            {lang === "en" ? "Most Common Account Pairs" : "En Sık Birlikte Kullanılan Hesap Çiftleri"}
          </div>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", marginTop: 2 }}>
            {lang === "en" ? "These pairs appear together in journal entries most often" : "Yevmiye fişlerinde en sık birlikte görünen hesap çiftleri"}
          </div>
        </div>
        <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 40 }}>#</th>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Account A" : "Hesap A"}</th>
              <th style={{ padding: "6px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", width: 30 }}>↔</th>
              <th style={{ padding: "6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Account B" : "Hesap B"}</th>
              <th style={{ padding: "6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>{lang === "en" ? "Together" : "Birlikte"}</th>
            </tr>
          </thead>
          <tbody>
            {stats.topPairs.map((p, i) => {
              const typeA = ACCOUNT_TYPES[p.accA.type] || ACCOUNT_TYPES.aktif;
              const typeB = ACCOUNT_TYPES[p.accB.type] || ACCOUNT_TYPES.aktif;
              return (
                <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td style={{ padding: "6px", color: "var(--ink-mute)", fontWeight: 700 }}>{i + 1}</td>
                  <td style={{ padding: "6px" }}>
                    <div className="mono" style={{ fontSize: 11, fontWeight: 700, color: typeA.color }}>{p.a}</div>
                    <div style={{ fontSize: 10, color: "var(--ink-mute)" }}>{p.accA.name.substring(0, 30)}</div>
                  </td>
                  <td style={{ padding: "6px", textAlign: "center", color: "var(--ink-mute)" }}>↔</td>
                  <td style={{ padding: "6px" }}>
                    <div className="mono" style={{ fontSize: 11, fontWeight: 700, color: typeB.color }}>{p.b}</div>
                    <div style={{ fontSize: 10, color: "var(--ink-mute)" }}>{p.accB.name.substring(0, 30)}</div>
                  </td>
                  <td className="mono text-right" style={{ padding: "6px", fontSize: 11, fontWeight: 700 }}>{p.count}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );

  // === Main render ===
  const sections = [
    { id: "suggestions",  label: { tr: "Öneriler",      en: "Suggestions" },  count: suggestions.length,    icon: Sparkles },
    { id: "completeness", label: { tr: "Tamlık",        en: "Completeness" }, count: stats.aiReadyAccounts, icon: Check },
    { id: "anomalies",    label: { tr: "Anomaliler",    en: "Anomalies" },    count: anomalies.length,      icon: AlertTriangle },
    { id: "stats",        label: { tr: "İstatistikler", en: "Statistics" },   count: stats.totalEntries,    icon: BarChart3 },
  ];

  return (
    <div className="space-y-3">
      {/* Üst bilgi */}
      <div className="card p-3" style={{ background: "linear-gradient(135deg, #7c3aed10 0%, #4f46e510 100%)", border: "1px solid #7c3aed40" }}>
        <div className="flex items-start gap-3">
          <Sparkles size={20} style={{ color: "#7c3aed", flexShrink: 0, marginTop: 2 }}/>
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: "#7c3aed" }}>
              {lang === "en" ? "AI Learning System" : "AI Öğrenme Sistemi"}
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 4, lineHeight: 1.5 }}>
              {lang === "en"
                ? `Analyzing ${stats.totalEntries} posted journal entries to improve account suggestions and detect patterns. ${stats.aiReadyAccounts} of ${stats.totalAccounts} accounts are AI-ready (≥50% complete).`
                : `${stats.totalEntries} onaylı yevmiye fişi analiz ediliyor. ${stats.totalAccounts} hesabın ${stats.aiReadyAccounts} tanesi AI-ready (≥%50 tam). Sistem otomatik olarak hesap eşleştirmelerini öğreniyor.`}
            </div>
          </div>
          <div className="text-right">
            <div className="mono" style={{ fontSize: 22, fontWeight: 700, color: "#7c3aed" }}>%{stats.avgCompleteness}</div>
            <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "AVG. Compl." : "ORT. Tamlık"}
            </div>
          </div>
        </div>
      </div>

      {/* Section nav */}
      <div className="flex flex-wrap items-center gap-1" style={{ borderBottom: "1px solid var(--line)" }}>
        {sections.map(s => {
          const isActive = activeSection === s.id;
          const Icon = s.icon;
          return (
            <button
              key={s.id}
              onClick={() => setActiveSection(s.id)}
              style={{
                padding: "8px 14px",
                fontSize: 12,
                fontWeight: isActive ? 700 : 500,
                color: isActive ? "#7c3aed" : "var(--ink)",
                background: isActive ? "var(--bg)" : "transparent",
                borderBottom: isActive ? "2px solid #7c3aed" : "2px solid transparent",
                cursor: "pointer",
                display: "flex", alignItems: "center", gap: 6,
              }}
            >
              <Icon size={12}/>
              {s.label[lang] || s.label.tr}
              {s.count > 0 && (
                <span className="chip" style={{
                  background: isActive ? "#7c3aed" : "var(--bg-alt)",
                  color: isActive ? "#fff" : "var(--ink-mute)",
                  padding: "1px 6px", fontSize: 9, fontWeight: 600, marginLeft: 4,
                }}>
                  {s.count}
                </span>
              )}
            </button>
          );
        })}
      </div>

      {/* Section content */}
      {activeSection === "suggestions" && renderSuggestions()}
      {activeSection === "completeness" && renderCompleteness()}
      {activeSection === "anomalies" && renderAnomalies()}
      {activeSection === "stats" && renderStats()}
    </div>
  );
}

/* =====================================================================
   DEFTER-İ KEBİR (General Ledger) — Hesap bazlı detaylı hareket
   ---------------------------------------------------------------------
   Bir hesap seç → tüm yevmiye satırlarını tarih sırasıyla göster
   Açılış bakiyesi + her satır + yürüyen bakiye
===================================================================== */
function GeneralLedgerReport({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];
  const rates = data.exchangeRates || {};

  const today = new Date();
  const y = today.getFullYear();
  const [selectedAccount, setSelectedAccount] = useState("");
  const [accountSearch, setAccountSearch] = useState("");
  const [showAccountDropdown, setShowAccountDropdown] = useState(false);
  const dropdownRef = useRef(null);

  const [dateFrom, setDateFrom] = useState(`${y}-01-01`);
  const [dateTo, setDateTo] = useState(today.toISOString().split("T")[0]);
  const [includeChildren, setIncludeChildren] = useState(false);
  const [displayCurrency, setDisplayCurrency] = useState("TRY");
  const [search, setSearch] = useState("");

  useEffect(() => {
    const handleClick = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setShowAccountDropdown(false);
      }
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  const sym = CURRENCY_SYMBOLS[displayCurrency] || "₺";
  const showSym = displayCurrency !== "TRY";
  const conv = (v) => convertFromTRY(v, displayCurrency, rates);

  // Hesap arama
  const accountMatches = useMemo(() => {
    const q = accountSearch.toLowerCase().trim();
    let list = accounts.filter(a => a.active !== false);
    if (q) {
      list = list.filter(a =>
        String(a.code).toLowerCase().includes(q) ||
        a.name.toLowerCase().includes(q) ||
        (a.nameEn || "").toLowerCase().includes(q)
      );
    }
    return list.slice(0, 30);
  }, [accountSearch, accounts]);

  const account = useMemo(() => accounts.find(a => a.code === selectedAccount), [selectedAccount, accounts]);

  // İlgili hesap kodlarını bul (includeChildren ise alt hesaplar dahil)
  const relevantCodes = useMemo(() => {
    if (!selectedAccount) return new Set();
    const codes = new Set([selectedAccount]);
    if (includeChildren) {
      const queue = [selectedAccount];
      while (queue.length > 0) {
        const code = queue.shift();
        accounts.filter(a => a.parentCode === code).forEach(child => {
          codes.add(child.code);
          queue.push(child.code);
        });
      }
    }
    return codes;
  }, [selectedAccount, includeChildren, accounts]);

  // Açılış bakiyesi (dateFrom'dan önce)
  const openingBalance = useMemo(() => {
    if (!selectedAccount) return { debit: 0, credit: 0, balance: 0 };
    let debit = 0, credit = 0;
    entries.forEach(entry => {
      if (entry.status === "cancelled") return;
      if (entry.date >= dateFrom) return;
      (entry.lines || []).forEach(line => {
        if (!relevantCodes.has(line.accountCode)) return;
        debit += Number(line.debit) || 0;
        credit += Number(line.credit) || 0;
      });
    });
    return { debit, credit, balance: debit - credit };
  }, [selectedAccount, dateFrom, entries, relevantCodes]);

  // Hareketler (dateFrom ile dateTo arası)
  const movements = useMemo(() => {
    if (!selectedAccount) return [];
    const result = [];
    entries.forEach(entry => {
      if (entry.status === "cancelled") return;
      if (entry.date < dateFrom || entry.date > dateTo) return;
      (entry.lines || []).forEach((line, lineIdx) => {
        if (!relevantCodes.has(line.accountCode)) return;
        // Karşı hesapları topla
        const offsets = (entry.lines || [])
          .filter(l => l !== line && (Number(l.debit) > 0 || Number(l.credit) > 0))
          .map(l => l.accountCode);
        result.push({
          entryId: entry.id,
          voucherNo: entry.voucherNo,
          voucherType: entry.voucherType,
          date: entry.date,
          status: entry.status,
          accountCode: line.accountCode,
          lineDescription: line.description || entry.description || "",
          debit: Number(line.debit) || 0,
          credit: Number(line.credit) || 0,
          offsetAccounts: offsets,
        });
      });
    });
    // Tarih + voucherNo'ya göre sırala
    result.sort((a, b) => {
      if (a.date !== b.date) return a.date.localeCompare(b.date);
      return (a.voucherNo || "").localeCompare(b.voucherNo || "");
    });

    // Yürüyen bakiye hesapla
    let running = openingBalance.balance;
    result.forEach(m => {
      running += m.debit - m.credit;
      m.runningBalance = running;
    });

    return result;
  }, [selectedAccount, dateFrom, dateTo, entries, relevantCodes, openingBalance.balance]);

  // Arama filtresi
  const filteredMovements = useMemo(() => {
    if (!search.trim()) return movements;
    const q = search.toLowerCase().trim();
    return movements.filter(m =>
      (m.voucherNo || "").toLowerCase().includes(q) ||
      (m.lineDescription || "").toLowerCase().includes(q) ||
      m.offsetAccounts.some(c => c.toLowerCase().includes(q))
    );
  }, [movements, search]);

  // Toplamlar
  const totals = useMemo(() => {
    let dDebit = 0, dCredit = 0;
    movements.forEach(m => {
      dDebit += m.debit;
      dCredit += m.credit;
    });
    const closingBalance = openingBalance.balance + (dDebit - dCredit);
    return {
      debit: dDebit, credit: dCredit,
      closingBalance,
      closingDebit: closingBalance > 0 ? closingBalance : 0,
      closingCredit: closingBalance < 0 ? -closingBalance : 0,
    };
  }, [movements, openingBalance.balance]);

  // Export
  const handleExport = () => {
    if (!account) return;
    const rows = [
      [lang === "en" ? "General Ledger" : "DEFTER-İ KEBİR"],
      [`${account.code} - ${account.name}`],
      [`${dateFrom} — ${dateTo}`],
      [],
      [lang === "en" ? "Date" : "Tarih", lang === "en" ? "Voucher" : "Fiş No", lang === "en" ? "Description" : "Açıklama", lang === "en" ? "Offset" : "Karşı Hesap", lang === "en" ? "Debit" : "Borç", lang === "en" ? "Credit" : "Alacak", lang === "en" ? "Balance" : "Bakiye"],
      [lang === "en" ? "Opening" : "Açılış", "", "", "",
       openingBalance.balance > 0 ? conv(openingBalance.balance).toFixed(2) : "",
       openingBalance.balance < 0 ? conv(-openingBalance.balance).toFixed(2) : "",
       conv(openingBalance.balance).toFixed(2)],
    ];
    filteredMovements.forEach(m => {
      rows.push([
        m.date, m.voucherNo, m.lineDescription, m.offsetAccounts.join(", "),
        m.debit > 0 ? conv(m.debit).toFixed(2) : "",
        m.credit > 0 ? conv(m.credit).toFixed(2) : "",
        conv(m.runningBalance).toFixed(2),
      ]);
    });
    rows.push(["", "", "", lang === "en" ? "TOTAL" : "TOPLAM", conv(totals.debit).toFixed(2), conv(totals.credit).toFixed(2), conv(totals.closingBalance).toFixed(2)]);

    const csv = rows.map(r => r.map(c => {
      const s = String(c || "");
      return s.includes(",") || s.includes("\"") ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");
    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `defter_${account.code}_${dateFrom}_${dateTo}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    notify(lang === "en" ? "Ledger exported" : "Defter dışa aktarıldı");
  };

  return (
    <div className="space-y-3">
      {/* Başlık */}
      <div className="flex items-end justify-between flex-wrap gap-3">
        <p className="text-sm" style={{ color: "var(--ink-mute)" }}>
          {account
            ? `${lang === "en" ? "Ledger of" : "Defter-i Kebir"}: ${account.code} - ${account.name}`
            : (lang === "en" ? "Select an account to view its ledger" : "Defterini görmek için bir hesap seçin")}
        </p>
        {account && (
          <button onClick={handleExport} className="btn btn-primary text-xs">
            <FileSpreadsheet size={11}/> {lang === "en" ? "Export" : "Dışa Aktar"}
          </button>
        )}
      </div>

      {/* Filtreler */}
      <div className="card p-3 space-y-3">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          {/* Hesap Seçici */}
          <div className="md:col-span-2" ref={dropdownRef} style={{ position: "relative" }}>
            <div className="label mb-1">{lang === "en" ? "Account" : "Hesap"} *</div>
            <input
              className="input w-full text-xs"
              value={selectedAccount ? `${selectedAccount} — ${account?.name || ""}` : accountSearch}
              onChange={e => { setAccountSearch(e.target.value); setSelectedAccount(""); setShowAccountDropdown(true); }}
              onFocus={() => setShowAccountDropdown(true)}
              placeholder={lang === "en" ? "Search account code or name..." : "Hesap kodu veya adı ara..."}
            />
            {showAccountDropdown && (
              <div className="absolute left-0 right-0 mt-1 z-20 bg-white rounded shadow-lg border max-h-64 overflow-y-auto"
                style={{ borderColor: "var(--line)" }}>
                {accountMatches.length === 0 ? (
                  <div className="p-3 text-center text-xs" style={{ color: "var(--ink-mute)" }}>
                    {lang === "en" ? "No accounts found" : "Hesap bulunamadı"}
                  </div>
                ) : accountMatches.map(acc => (
                  <button
                    key={acc.code}
                    onClick={() => {
                      setSelectedAccount(acc.code);
                      setAccountSearch("");
                      setShowAccountDropdown(false);
                    }}
                    className="w-full text-left p-2 hover:bg-bgAlt border-b"
                    style={{ borderColor: "var(--line)" }}
                  >
                    <div className="flex items-center gap-2">
                      <span className="mono" style={{ fontSize: 11, fontWeight: 700, color: ACCOUNT_TYPES[acc.type]?.color, minWidth: 80 }}>
                        {acc.code}
                      </span>
                      <span className="truncate" style={{ fontSize: 11 }}>{acc.name}</span>
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>

          <div>
            <div className="label mb-1">{lang === "en" ? "From" : "Başlangıç"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateFrom}
              onChange={e => setDateFrom(e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "To" : "Bitiş"}</div>
            <input type="date" className="input w-full mono text-xs" value={dateTo}
              onChange={e => setDateTo(e.target.value)}/>
          </div>
        </div>

        <div className="flex flex-wrap items-center gap-3 pt-2" style={{ borderTop: "1px solid var(--line)" }}>
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={includeChildren}
              onChange={e => setIncludeChildren(e.target.checked)}/>
            <span style={{ fontSize: 12 }}>
              {lang === "en" ? "Include sub-accounts" : "Alt hesapları dahil et"}
            </span>
          </label>

          <input
            className="input text-xs flex-1"
            value={search}
            onChange={e => setSearch(e.target.value)}
            placeholder={lang === "en" ? "Search voucher/description..." : "Fiş no/açıklama ara..."}
            style={{ maxWidth: 300 }}
          />

          <div className="ml-auto flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
            {["TRY", "USD", "EUR"].map(cur => (
              <button key={cur} onClick={() => setDisplayCurrency(cur)} className="text-xs"
                style={{
                  padding: "5px 10px",
                  background: displayCurrency === cur ? "var(--accent)" : "var(--bg)",
                  color: displayCurrency === cur ? "#fff" : "var(--ink)",
                  fontWeight: 600, cursor: "pointer",
                  borderRight: cur !== "EUR" ? "1px solid var(--line)" : "none",
                }}>
                {CURRENCY_SYMBOLS[cur] || ""} {cur}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Defter Tablosu */}
      {!selectedAccount ? (
        <div className="card p-10 text-center" style={{ color: "var(--ink-mute)" }}>
          <ClipboardList size={40} style={{ margin: "0 auto", opacity: 0.3 }}/>
          <div style={{ fontSize: 13, marginTop: 8 }}>
            {lang === "en"
              ? "Please select an account to view its general ledger"
              : "Defter-i kebir için lütfen yukarıdan bir hesap seçin"}
          </div>
        </div>
      ) : (
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", minWidth: 1000, fontSize: 11, borderCollapse: "collapse" }}>
              <thead>
                <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
                  <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>
                    {lang === "en" ? "Date" : "Tarih"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 130 }}>
                    {lang === "en" ? "Voucher" : "Fiş No"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                    {lang === "en" ? "Description" : "Açıklama"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 150 }}>
                    {lang === "en" ? "Offset Accounts" : "Karşı Hesap(lar)"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "#0f766e", textTransform: "uppercase", width: 110 }}>
                    {lang === "en" ? "Debit" : "Borç"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "#b91c1c", textTransform: "uppercase", width: 110 }}>
                    {lang === "en" ? "Credit" : "Alacak"}
                  </th>
                  <th style={{ padding: "8px 6px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 120 }}>
                    {lang === "en" ? "Balance" : "Bakiye"}
                  </th>
                </tr>
              </thead>
              <tbody>
                {/* Açılış satırı */}
                <tr style={{ background: "#fef3c7", borderBottom: "1px solid var(--line)" }}>
                  <td className="mono" style={{ padding: "6px", fontSize: 11, fontWeight: 600 }}>{dateFrom}</td>
                  <td colSpan="3" style={{ padding: "6px", fontSize: 11, fontWeight: 700, color: "#92400e", textTransform: "uppercase" }}>
                    {lang === "en" ? "Opening Balance" : "Açılış Bakiyesi"}
                  </td>
                  <td className="mono text-right" style={{ padding: "6px", fontSize: 11, fontWeight: 600 }}>
                    {openingBalance.balance > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(openingBalance.balance))}` : "—"}
                  </td>
                  <td className="mono text-right" style={{ padding: "6px", fontSize: 11, fontWeight: 600 }}>
                    {openingBalance.balance < 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(-openingBalance.balance))}` : "—"}
                  </td>
                  <td className="mono text-right" style={{ padding: "6px", fontSize: 11, fontWeight: 700, color: openingBalance.balance >= 0 ? "#0f766e" : "#b91c1c" }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(Math.abs(openingBalance.balance)))} {openingBalance.balance >= 0 ? "B" : "A"}
                  </td>
                </tr>

                {/* Hareketler */}
                {filteredMovements.length === 0 ? (
                  <tr><td colSpan="7" style={{ padding: 30, textAlign: "center", color: "var(--ink-mute)", fontSize: 12 }}>
                    {lang === "en" ? "No movements in this period" : "Bu dönemde hareket yok"}
                  </td></tr>
                ) : filteredMovements.map((m, i) => {
                  const typeCfg = VOUCHER_TYPES[m.voucherType] || VOUCHER_TYPES.compound;
                  return (
                    <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                      <td className="mono" style={{ padding: "5px 6px", fontSize: 10.5 }}>{m.date}</td>
                      <td className="mono" style={{ padding: "5px 6px", fontSize: 10.5, fontWeight: 700, color: typeCfg.color }}>
                        {m.voucherNo}
                      </td>
                      <td style={{ padding: "5px 6px", fontSize: 10.5 }} className="truncate">{m.lineDescription || "—"}</td>
                      <td className="mono" style={{ padding: "5px 6px", fontSize: 10 }}>
                        {m.offsetAccounts.join(", ") || "—"}
                      </td>
                      <td className="mono text-right" style={{ padding: "5px 6px", fontSize: 11, color: m.debit > 0 ? "#0f766e" : "var(--ink-mute)", opacity: m.debit > 0 ? 1 : 0.3, fontWeight: m.debit > 0 ? 600 : 400 }}>
                        {m.debit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(m.debit))}` : "—"}
                      </td>
                      <td className="mono text-right" style={{ padding: "5px 6px", fontSize: 11, color: m.credit > 0 ? "#b91c1c" : "var(--ink-mute)", opacity: m.credit > 0 ? 1 : 0.3, fontWeight: m.credit > 0 ? 600 : 400 }}>
                        {m.credit > 0 ? `${showSym ? sym + " " : ""}${fmtTL(conv(m.credit))}` : "—"}
                      </td>
                      <td className="mono text-right" style={{ padding: "5px 6px", fontSize: 11, fontWeight: 700, color: m.runningBalance >= 0 ? "#0f766e" : "#b91c1c" }}>
                        {showSym ? sym + " " : ""}{fmtTL(conv(Math.abs(m.runningBalance)))} {m.runningBalance >= 0 ? "B" : "A"}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
              <tfoot>
                <tr style={{ background: "#0f766e", color: "#fff", borderTop: "2px solid #0f766e" }}>
                  <td colSpan="4" style={{ padding: "10px 6px", fontSize: 12, fontWeight: 700, textTransform: "uppercase" }}>
                    {lang === "en" ? "TOTAL" : "TOPLAM"}
                  </td>
                  <td className="mono text-right" style={{ padding: "10px 6px", fontSize: 12, fontWeight: 700 }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(totals.debit))}
                  </td>
                  <td className="mono text-right" style={{ padding: "10px 6px", fontSize: 12, fontWeight: 700 }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(totals.credit))}
                  </td>
                  <td className="mono text-right" style={{ padding: "10px 6px", fontSize: 12, fontWeight: 700 }}>
                    {showSym ? sym + " " : ""}{fmtTL(conv(Math.abs(totals.closingBalance)))} {totals.closingBalance >= 0 ? "B" : "A"}
                  </td>
                </tr>
              </tfoot>
            </table>
          </div>
        </div>
      )}

      {/* Footer info */}
      {account && (
        <div className="flex items-center justify-between text-xs" style={{ color: "var(--ink-mute)" }}>
          <span>
            {filteredMovements.length} {lang === "en" ? "movements" : "hareket"}
            {filteredMovements.length !== movements.length && ` (${movements.length} ${lang === "en" ? "total" : "toplam"})`}
          </span>
          <span>
            {lang === "en" ? "Account Type" : "Hesap Tipi"}: {ACCOUNT_TYPES[account.type]?.label[lang] || account.type}
          </span>
        </div>
      )}
    </div>
  );
}

/* =====================================================================
   YARDIMCI DEFTER (Subsidiary Ledger Manager)
   ---------------------------------------------------------------------
   - Müşteri/Tedarikçi alt cari kartları
   - Hareket geçmişi
   - Vade analizi (Aging)
   - Cari ekstre
===================================================================== */
function SubsidiaryLedgerManager({ data, session, canAct, lang, onChange, logAudit, notify }) {
  const accounts = data.accChartOfAccounts || [];
  const entries = data.accJournalEntries || [];

  // State
  const [activeView, setActiveView] = useState("list"); // list | detail
  const [selectedAccountCode, setSelectedAccountCode] = useState(null);
  const [filterType, setFilterType] = useState("all"); // all | customer | supplier | other
  const [searchTerm, setSearchTerm] = useState("");
  const [sortBy, setSortBy] = useState("balance"); // balance | name | code
  const [showAddModal, setShowAddModal] = useState(false);

  // === Cari Hesap Kategorileri ===
  // 120 - Alıcılar (Müşteriler)
  // 121 - Alacak Senetleri
  // 320 - Satıcılar (Tedarikçiler)
  // 321 - Borç Senetleri
  // 335 - Personele Borçlar
  // 136 - Diğer Çeşitli Alacaklar
  const PARTY_CATEGORIES = {
    customer: {
      label: lang === "en" ? "Customer" : "Müşteri",
      color: "#0f766e",
      bg: "#dcfce7",
      prefixes: ["120", "121"],
      mainPrefix: "120",
      icon: UserCheck,
    },
    supplier: {
      label: lang === "en" ? "Supplier" : "Tedarikçi",
      color: "#b91c1c",
      bg: "#fee2e2",
      prefixes: ["320", "321"],
      mainPrefix: "320",
      icon: Building2,
    },
    employee: {
      label: lang === "en" ? "Employee" : "Personel",
      color: "#7c3aed",
      bg: "#ede9fe",
      prefixes: ["335", "195", "196"],
      mainPrefix: "335",
      icon: Users,
    },
    other: {
      label: lang === "en" ? "Other" : "Diğer",
      color: "#737373",
      bg: "#f3f4f6",
      prefixes: ["136", "236", "336", "436", "236"],
      mainPrefix: "136",
      icon: Briefcase,
    },
  };

  // === Cari hesapları belirle (level 3+ alt cari hesapları) ===
  const partyAccounts = useMemo(() => {
    const allPrefixes = Object.values(PARTY_CATEGORIES).flatMap(c => c.prefixes);

    return accounts.filter(acc => {
      const code = String(acc.code);
      // En az 3 karakter (örn 120.01) veya direkt 120 main
      if (acc.level < 2) return false; // Sadece detaylı hesaplar
      if (!acc.active) return false;
      // Hesap prefix'i party prefix'i ile başlamalı
      return allPrefixes.some(prefix => code.startsWith(prefix));
    }).map(acc => {
      // Kategoriyi belirle
      let category = null;
      let categoryConfig = null;
      for (const [key, cfg] of Object.entries(PARTY_CATEGORIES)) {
        if (cfg.prefixes.some(p => acc.code.startsWith(p))) {
          category = key;
          categoryConfig = cfg;
          break;
        }
      }

      // Bakiye hesapla
      let debit = 0, credit = 0;
      let lastDate = null;
      let txCount = 0;
      entries.forEach(entry => {
        if (entry.status !== "posted") return;
        (entry.lines || []).forEach(line => {
          if (line.accountCode !== acc.code) return;
          debit += Number(line.debit) || 0;
          credit += Number(line.credit) || 0;
          txCount++;
          if (!lastDate || entry.date > lastDate) lastDate = entry.date;
        });
      });
      const balance = debit - credit;

      return {
        ...acc,
        category,
        categoryConfig,
        debit,
        credit,
        balance,
        lastDate,
        txCount,
        // Müşteri için + bakiye iyi (alacak), tedarikçi için - bakiye iyi
        isFavorableBalance: category === "customer" ? balance >= 0 : balance <= 0,
      };
    });
  }, [accounts, entries, lang]);

  // === Filtreleme ===
  const filteredParties = useMemo(() => {
    let list = partyAccounts;
    if (filterType !== "all") {
      list = list.filter(p => p.category === filterType);
    }
    if (searchTerm.trim()) {
      const term = searchTerm.toLowerCase().trim();
      list = list.filter(p =>
        p.name.toLowerCase().includes(term) ||
        p.code.toLowerCase().includes(term) ||
        (p.taxId && p.taxId.toLowerCase().includes(term))
      );
    }
    // Sıralama
    list = [...list];
    if (sortBy === "balance") {
      list.sort((a, b) => Math.abs(b.balance) - Math.abs(a.balance));
    } else if (sortBy === "name") {
      list.sort((a, b) => a.name.localeCompare(b.name, "tr"));
    } else if (sortBy === "code") {
      list.sort((a, b) => a.code.localeCompare(b.code, "tr", { numeric: true }));
    }
    return list;
  }, [partyAccounts, filterType, searchTerm, sortBy]);

  // === İstatistikler ===
  const stats = useMemo(() => {
    let totalReceivable = 0, totalPayable = 0;
    let customerCount = 0, supplierCount = 0;
    let activeCustomers = 0, activeSuppliers = 0;

    partyAccounts.forEach(p => {
      if (p.category === "customer") {
        customerCount++;
        if (p.balance > 0) {
          totalReceivable += p.balance;
          activeCustomers++;
        }
      } else if (p.category === "supplier") {
        supplierCount++;
        if (p.balance < 0) {
          totalPayable += -p.balance;
          activeSuppliers++;
        }
      }
    });

    return {
      totalReceivable, totalPayable,
      customerCount, supplierCount,
      activeCustomers, activeSuppliers,
      totalParties: partyAccounts.length,
    };
  }, [partyAccounts]);

  // === Detay görünüm için seçili cari ===
  const selectedParty = useMemo(() =>
    partyAccounts.find(p => p.code === selectedAccountCode),
    [partyAccounts, selectedAccountCode]
  );

  // === Cari hareketleri (detay) ===
  const partyTransactions = useMemo(() => {
    if (!selectedParty) return [];
    const txList = [];
    entries.forEach(entry => {
      if (entry.status !== "posted") return;
      (entry.lines || []).forEach((line, idx) => {
        if (line.accountCode !== selectedParty.code) return;
        // Karşı hesapları bul
        const otherLines = (entry.lines || []).filter((_, i) => i !== idx);
        const counterAccounts = otherLines.map(l => {
          const acc = accounts.find(a => a.code === l.accountCode);
          return acc ? `${l.accountCode} ${acc.name}` : l.accountCode;
        }).join(", ");

        txList.push({
          voucherId: entry.id,
          voucherNo: entry.voucherNo,
          voucherType: entry.voucherType,
          date: entry.date,
          description: line.description || entry.description,
          debit: Number(line.debit) || 0,
          credit: Number(line.credit) || 0,
          counterAccounts,
          source: entry.source,
        });
      });
    });
    // Tarihe göre sırala
    txList.sort((a, b) => a.date.localeCompare(b.date) || a.voucherNo.localeCompare(b.voucherNo));
    // Yürüyen bakiye ekle
    let runningBalance = 0;
    txList.forEach(tx => {
      runningBalance += tx.debit - tx.credit;
      tx.runningBalance = runningBalance;
    });
    return txList;
  }, [selectedParty, entries, accounts]);

  // === Vade Analizi (Aging) — sadece müşteri/tedarikçi için ===
  const agingAnalysis = useMemo(() => {
    if (!selectedParty || !["customer", "supplier"].includes(selectedParty.category)) return null;

    const today = new Date();
    today.setHours(0, 0, 0, 0);

    // Açık (kapatılmamış) tutarları bul: FIFO algoritması
    // Borç işlemlerini sırala, alacak işlemleriyle eşleştir
    const isCustomer = selectedParty.category === "customer";
    const txList = [...partyTransactions];

    // Müşteri için: debit (alacak doğuran) → FIFO ile credit (tahsilat) düşülür
    // Tedarikçi için: credit (borç doğuran) → FIFO ile debit (ödeme) düşülür
    const openItems = [];
    let unpaidCreditPool = 0; // Açık tahsilat/ödeme havuzu

    txList.forEach(tx => {
      const inflow = isCustomer ? tx.debit : tx.credit; // Borç doğuran hareket
      const outflow = isCustomer ? tx.credit : tx.debit; // Kapatan hareket
      if (inflow > 0) {
        openItems.push({
          date: tx.date,
          amount: inflow,
          remaining: inflow,
          voucherNo: tx.voucherNo,
        });
      }
      if (outflow > 0) {
        unpaidCreditPool += outflow;
      }
    });

    // FIFO: önce eski borçları kapat
    let remainingPool = unpaidCreditPool;
    openItems.forEach(item => {
      if (remainingPool <= 0) return;
      const apply = Math.min(remainingPool, item.remaining);
      item.remaining -= apply;
      remainingPool -= apply;
    });

    // Vade kovaları
    const buckets = {
      current: { label: "0-30", amount: 0, count: 0 },
      d31_60: { label: "31-60", amount: 0, count: 0 },
      d61_90: { label: "61-90", amount: 0, count: 0 },
      d90plus: { label: "90+", amount: 0, count: 0 },
    };

    openItems.forEach(item => {
      if (item.remaining <= 0.01) return;
      const itemDate = new Date(item.date);
      const daysOld = Math.floor((today - itemDate) / 86400000);

      if (daysOld <= 30) {
        buckets.current.amount += item.remaining;
        buckets.current.count++;
      } else if (daysOld <= 60) {
        buckets.d31_60.amount += item.remaining;
        buckets.d31_60.count++;
      } else if (daysOld <= 90) {
        buckets.d61_90.amount += item.remaining;
        buckets.d61_90.count++;
      } else {
        buckets.d90plus.amount += item.remaining;
        buckets.d90plus.count++;
      }
    });

    const total = buckets.current.amount + buckets.d31_60.amount + buckets.d61_90.amount + buckets.d90plus.amount;
    return { buckets, total, openItems: openItems.filter(i => i.remaining > 0.01) };
  }, [selectedParty, partyTransactions]);

  // === Yeni Cari Ekle (Hesap Planına 120.XX veya 320.XX ekler) ===
  const addNewParty = async (formData) => {
    const { type, name, taxId, address, phone, email, contactPerson, openingBalance } = formData;
    const cfg = PARTY_CATEGORIES[type];
    if (!cfg) return;

    // En son kullanılan kod numarasını bul
    const existing = accounts.filter(a => a.code.startsWith(cfg.mainPrefix + "."));
    let maxNum = 0;
    existing.forEach(a => {
      const numPart = a.code.substring(cfg.mainPrefix.length + 1);
      const num = parseInt(numPart, 10);
      if (!isNaN(num) && num > maxNum) maxNum = num;
    });
    const newNum = String(maxNum + 1).padStart(3, "0");
    const newCode = `${cfg.mainPrefix}.${newNum}`;

    // Yeni hesap nesnesi
    const newAccount = {
      code: newCode,
      name,
      type: type === "customer" ? "aktif" : "pasif",
      level: 3,
      parentCode: cfg.mainPrefix,
      active: true,
      allowTransaction: true,
      currency: "TRY",
      taxId: taxId || "",
      address: address || "",
      phone: phone || "",
      email: email || "",
      contactPerson: contactPerson || "",
      openingBalance: Number(openingBalance) || 0,
      createdAt: new Date().toISOString(),
      createdBy: session.username,
      partyCategory: type,
    };

    const updatedAccounts = [...accounts, newAccount];
    await onChange({ ...data, accChartOfAccounts: updatedAccounts });
    logAudit && logAudit("party_create", "subledger", { code: newCode, name, type });
    notify(lang === "en"
      ? `New ${cfg.label.toLowerCase()} created: ${newCode}`
      : `Yeni ${cfg.label.toLowerCase()} oluşturuldu: ${newCode}`);
    setShowAddModal(false);
  };

  // === Cari Ekstre Excel Export ===
  const exportPartyStatement = () => {
    if (!selectedParty) return;
    const rows = [
      [lang === "en" ? "Party Statement" : "CARİ EKSTRE"],
      [`${selectedParty.code} ${selectedParty.name}`],
      [selectedParty.taxId ? `VKN/TCKN: ${selectedParty.taxId}` : ""],
      [],
      [
        lang === "en" ? "Date" : "Tarih",
        lang === "en" ? "Voucher No" : "Fiş No",
        lang === "en" ? "Description" : "Açıklama",
        lang === "en" ? "Counter Account" : "Karşı Hesap",
        lang === "en" ? "Debit" : "Borç",
        lang === "en" ? "Credit" : "Alacak",
        lang === "en" ? "Balance" : "Bakiye",
      ],
    ];

    partyTransactions.forEach(tx => {
      rows.push([
        tx.date,
        tx.voucherNo,
        tx.description,
        tx.counterAccounts,
        tx.debit > 0 ? tx.debit.toFixed(2) : "",
        tx.credit > 0 ? tx.credit.toFixed(2) : "",
        tx.runningBalance.toFixed(2),
      ]);
    });

    rows.push([]);
    rows.push([
      "", "", "",
      lang === "en" ? "TOTAL" : "TOPLAM",
      selectedParty.debit.toFixed(2),
      selectedParty.credit.toFixed(2),
      selectedParty.balance.toFixed(2),
    ]);

    const csv = rows.map(r => r.map(c => {
      const s = String(c || "");
      return s.includes(",") || s.includes('"') ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");

    const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `cari_ekstre_${selectedParty.code}_${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    notify(lang === "en" ? "Statement exported" : "Cari ekstre dışa aktarıldı");
  };

  // ===== RENDER: LIST VIEW =====
  if (activeView === "list") {
    return (
      <div className="space-y-3">
        {/* Üst Bilgi + İstatistikler */}
        <div className="card p-3" style={{ background: "linear-gradient(135deg, #cffafe 0%, #e0e7ff 100%)", border: "1px solid #0891b2" }}>
          <div className="flex items-start gap-3">
            <FileText size={20} style={{ color: "#0891b2", flexShrink: 0, marginTop: 2 }}/>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: "#0891b2" }}>
                {lang === "en" ? "Subsidiary Ledger" : "Yardımcı Defter"}
              </div>
              <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 4, lineHeight: 1.5 }}>
                {lang === "en"
                  ? "Manage customer, supplier, and other party accounts. View statements, aging analysis, and detailed transaction history."
                  : "Müşteri, tedarikçi ve diğer cari hesapları yönet. Ekstreleri, vade analizini ve detaylı hareket geçmişini görüntüle."}
              </div>
            </div>
            <button onClick={() => setShowAddModal(true)} className="btn text-xs"
              style={{ background: "#0891b2", color: "#fff", fontWeight: 700, padding: "6px 12px" }}>
              <Plus size={11}/> {lang === "en" ? "New Party" : "Yeni Cari"}
            </button>
          </div>
        </div>

        {/* KPI Kartları */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <div className="card p-3" style={{ borderLeft: "4px solid #0f766e" }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "Receivables" : "Toplam Alacak"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#0f766e" }}>
              {fmtTL(stats.totalReceivable)} ₺
            </div>
            <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
              {stats.activeCustomers} / {stats.customerCount} {lang === "en" ? "customers" : "müşteri"}
            </div>
          </div>
          <div className="card p-3" style={{ borderLeft: "4px solid #b91c1c" }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "Payables" : "Toplam Borç"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#b91c1c" }}>
              {fmtTL(stats.totalPayable)} ₺
            </div>
            <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
              {stats.activeSuppliers} / {stats.supplierCount} {lang === "en" ? "suppliers" : "tedarikçi"}
            </div>
          </div>
          <div className="card p-3" style={{
            background: stats.totalReceivable - stats.totalPayable >= 0 ? "#dcfce7" : "#fee2e2",
            borderLeft: `4px solid ${stats.totalReceivable - stats.totalPayable >= 0 ? "#15803d" : "#b91c1c"}`,
          }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
              {lang === "en" ? "Net Position" : "Net Pozisyon"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: stats.totalReceivable - stats.totalPayable >= 0 ? "#15803d" : "#b91c1c" }}>
              {fmtTLSign(stats.totalReceivable - stats.totalPayable)} ₺
            </div>
            <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
              {lang === "en" ? "Receivable - Payable" : "Alacak - Borç"}
            </div>
          </div>
          <div className="card p-3" style={{ borderLeft: "4px solid #7c3aed" }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "Total Parties" : "Toplam Cari"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4, color: "#7c3aed" }}>
              {stats.totalParties}
            </div>
            <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
              {lang === "en" ? "active accounts" : "aktif hesap"}
            </div>
          </div>
        </div>

        {/* Filtre / Arama */}
        <div className="card p-3 flex items-center gap-2 flex-wrap">
          {/* Tip Filtresi */}
          <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden" }}>
            {[
              { id: "all", label: { tr: "Tümü", en: "All" }, color: "#737373" },
              { id: "customer", label: { tr: "Müşteri", en: "Customer" }, color: "#0f766e" },
              { id: "supplier", label: { tr: "Tedarikçi", en: "Supplier" }, color: "#b91c1c" },
              { id: "employee", label: { tr: "Personel", en: "Employee" }, color: "#7c3aed" },
              { id: "other", label: { tr: "Diğer", en: "Other" }, color: "#737373" },
            ].map((opt, i, arr) => (
              <button key={opt.id} onClick={() => setFilterType(opt.id)} className="text-xs"
                style={{
                  padding: "5px 10px",
                  background: filterType === opt.id ? opt.color : "var(--bg)",
                  color: filterType === opt.id ? "#fff" : "var(--ink)",
                  fontWeight: 600, cursor: "pointer",
                  borderRight: i < arr.length - 1 ? "1px solid var(--line)" : "none",
                }}>
                {opt.label[lang] || opt.label.tr}
              </button>
            ))}
          </div>

          {/* Arama */}
          <div className="relative flex-1" style={{ minWidth: 200, maxWidth: 320 }}>
            <Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2" style={{ color: "var(--ink-mute)" }}/>
            <input
              type="text"
              placeholder={lang === "en" ? "Search by name, code, or tax ID..." : "İsim, kod veya VKN ile ara..."}
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="input pl-7 text-xs"
              style={{ width: "100%" }}
            />
          </div>

          {/* Sıralama */}
          <select value={sortBy} onChange={e => setSortBy(e.target.value)} className="input text-xs">
            <option value="balance">{lang === "en" ? "Sort by Balance" : "Bakiyeye Göre"}</option>
            <option value="name">{lang === "en" ? "Sort by Name" : "İsme Göre"}</option>
            <option value="code">{lang === "en" ? "Sort by Code" : "Koda Göre"}</option>
          </select>

          <div className="ml-auto text-xs" style={{ color: "var(--ink-mute)" }}>
            {filteredParties.length} / {partyAccounts.length}
          </div>
        </div>

        {/* Cari Listesi */}
        {filteredParties.length === 0 ? (
          <div className="card p-10 text-center">
            <FileText size={32} style={{ margin: "0 auto", color: "#0891b2", opacity: 0.5 }}/>
            <div style={{ fontSize: 14, fontWeight: 600, marginTop: 12 }}>
              {lang === "en" ? "No party accounts found" : "Cari hesap bulunamadı"}
            </div>
            <div style={{ fontSize: 12, color: "var(--ink-mute)", marginTop: 4 }}>
              {searchTerm
                ? (lang === "en" ? "Try a different search term" : "Farklı bir arama terimi deneyin")
                : (lang === "en" ? "Create your first party account to start tracking customers/suppliers." : "Müşteri/tedarikçi takibine başlamak için ilk cari hesabınızı oluşturun.")}
            </div>
            <button onClick={() => setShowAddModal(true)} className="btn btn-primary text-xs mt-4">
              <Plus size={11}/> {lang === "en" ? "Add Party" : "Cari Ekle"}
            </button>
          </div>
        ) : (
          <div className="card" style={{ padding: 0, overflow: "hidden" }}>
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
                    <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>
                      {lang === "en" ? "Code" : "Kod"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                      {lang === "en" ? "Party Name" : "Cari Adı"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>
                      {lang === "en" ? "Type" : "Tip"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Tax ID" : "VKN/TCKN"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                      {lang === "en" ? "Debit" : "Borç"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 110 }}>
                      {lang === "en" ? "Credit" : "Alacak"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 130 }}>
                      {lang === "en" ? "Balance" : "Bakiye"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 60 }}>
                      {lang === "en" ? "Tx" : "İşlem"}
                    </th>
                    <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Last Tx" : "Son İşlem"}
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {filteredParties.map(p => {
                    const Icon = p.categoryConfig?.icon || Users;
                    return (
                      <tr key={p.code}
                        onClick={() => { setSelectedAccountCode(p.code); setActiveView("detail"); }}
                        className="cursor-pointer"
                        style={{ borderBottom: "1px solid var(--line)", transition: "background 0.15s" }}
                        onMouseEnter={e => e.currentTarget.style.background = "var(--bg-alt)"}
                        onMouseLeave={e => e.currentTarget.style.background = "transparent"}
                      >
                        <td className="mono" style={{ padding: "8px 10px", fontSize: 11, fontWeight: 700, color: p.categoryConfig?.color }}>
                          {p.code}
                        </td>
                        <td style={{ padding: "8px 10px", fontSize: 12 }}>
                          <div className="flex items-center gap-2">
                            <Icon size={12} style={{ color: p.categoryConfig?.color, flexShrink: 0 }}/>
                            <span className="font-semibold">{p.name}</span>
                          </div>
                        </td>
                        <td style={{ padding: "8px 10px" }}>
                          <span className="chip" style={{
                            background: p.categoryConfig?.bg, color: p.categoryConfig?.color,
                            padding: "2px 8px", fontSize: 9, fontWeight: 700,
                          }}>
                            {p.categoryConfig?.label || "—"}
                          </span>
                        </td>
                        <td className="mono" style={{ padding: "8px 10px", fontSize: 10.5, color: "var(--ink-mute)" }}>
                          {p.taxId || "—"}
                        </td>
                        <td className="mono text-right" style={{ padding: "8px 10px", fontSize: 11 }}>
                          {p.debit > 0 ? fmtTL(p.debit) + " ₺" : "—"}
                        </td>
                        <td className="mono text-right" style={{ padding: "8px 10px", fontSize: 11 }}>
                          {p.credit > 0 ? fmtTL(p.credit) + " ₺" : "—"}
                        </td>
                        <td className="mono text-right" style={{
                          padding: "8px 10px", fontSize: 12, fontWeight: 700,
                          color: Math.abs(p.balance) < 0.01 ? "var(--ink-mute)" :
                                 p.isFavorableBalance ? "#0f766e" : "#b91c1c",
                        }}>
                          {Math.abs(p.balance) < 0.01 ? "—" : `${fmtTL(Math.abs(p.balance))} ₺`}
                          {Math.abs(p.balance) >= 0.01 && (
                            <span style={{ fontSize: 9, fontWeight: 400, marginLeft: 4, color: "var(--ink-mute)" }}>
                              {p.balance > 0 ? (lang === "en" ? "DR" : "B") : (lang === "en" ? "CR" : "A")}
                            </span>
                          )}
                        </td>
                        <td className="text-center" style={{ padding: "8px 10px", fontSize: 11, color: "var(--ink-mute)" }}>
                          {p.txCount || "—"}
                        </td>
                        <td className="mono" style={{ padding: "8px 10px", fontSize: 10, color: "var(--ink-mute)" }}>
                          {p.lastDate || "—"}
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Yeni Cari Ekleme Modal */}
        {showAddModal && (
          <NewPartyModal
            onClose={() => setShowAddModal(false)}
            onSave={addNewParty}
            lang={lang}
            categories={PARTY_CATEGORIES}
            accounts={accounts}
          />
        )}
      </div>
    );
  }

  // ===== RENDER: DETAIL VIEW =====
  if (activeView === "detail" && selectedParty) {
    const Icon = selectedParty.categoryConfig?.icon || Users;

    return (
      <div className="space-y-3">
        {/* Geri & Başlık */}
        <div className="card p-3 flex items-center gap-3 flex-wrap">
          <button onClick={() => setActiveView("list")} className="btn btn-ghost text-xs">
            ← {lang === "en" ? "Back to List" : "Listeye Dön"}
          </button>
          <div style={{ flex: 1 }}>
            <div className="flex items-center gap-2">
              <Icon size={16} style={{ color: selectedParty.categoryConfig?.color }}/>
              <span className="mono" style={{ fontSize: 14, fontWeight: 700, color: selectedParty.categoryConfig?.color }}>
                {selectedParty.code}
              </span>
              <span style={{ fontSize: 14, fontWeight: 700 }}>{selectedParty.name}</span>
              <span className="chip" style={{
                background: selectedParty.categoryConfig?.bg, color: selectedParty.categoryConfig?.color,
                padding: "2px 8px", fontSize: 9, fontWeight: 700,
              }}>
                {selectedParty.categoryConfig?.label}
              </span>
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
              {selectedParty.taxId && <>VKN: {selectedParty.taxId} · </>}
              {partyTransactions.length} {lang === "en" ? "transactions" : "işlem"}
              {selectedParty.lastDate && <> · {lang === "en" ? "Last" : "Son"}: {selectedParty.lastDate}</>}
            </div>
          </div>
          <button onClick={exportPartyStatement} className="btn btn-primary text-xs">
            <FileSpreadsheet size={11}/> {lang === "en" ? "Export Statement" : "Cari Ekstre"}
          </button>
        </div>

        {/* Bakiye Özet */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <div className="card p-3" style={{ borderLeft: "4px solid #6b7280" }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "Total Debit" : "Toplam Borç"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4 }}>
              {fmtTL(selectedParty.debit)} ₺
            </div>
          </div>
          <div className="card p-3" style={{ borderLeft: "4px solid #6b7280" }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
              {lang === "en" ? "Total Credit" : "Toplam Alacak"}
            </div>
            <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4 }}>
              {fmtTL(selectedParty.credit)} ₺
            </div>
          </div>
          <div className="card p-3" style={{
            background: selectedParty.isFavorableBalance ? "#dcfce7" : "#fee2e2",
            borderLeft: `4px solid ${selectedParty.isFavorableBalance ? "#15803d" : "#b91c1c"}`,
          }}>
            <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase", fontWeight: 600 }}>
              {lang === "en" ? "Balance" : "Bakiye"}
            </div>
            <div className="mono" style={{ fontSize: 18, fontWeight: 700, marginTop: 4, color: selectedParty.isFavorableBalance ? "#15803d" : "#b91c1c" }}>
              {fmtTL(Math.abs(selectedParty.balance))} ₺
              <span style={{ fontSize: 11, marginLeft: 4 }}>
                {selectedParty.balance > 0 ? (lang === "en" ? "Debit" : "(B)") : selectedParty.balance < 0 ? (lang === "en" ? "Credit" : "(A)") : ""}
              </span>
            </div>
            <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
              {selectedParty.balance > 0
                ? (selectedParty.category === "customer" ? (lang === "en" ? "Customer owes us" : "Bizden alacak (bize borçlu)") : (lang === "en" ? "We owe them" : "Onlara borçluyuz"))
                : selectedParty.balance < 0
                  ? (selectedParty.category === "supplier" ? (lang === "en" ? "We owe them" : "Onlara borçluyuz") : (lang === "en" ? "They owe us" : "Bizden alacaklı"))
                  : (lang === "en" ? "Settled" : "Mutabık")}
            </div>
          </div>
          {selectedParty.partyCategory && (
            <div className="card p-3" style={{ borderLeft: "4px solid #1d4ed8" }}>
              <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                {lang === "en" ? "Opening Balance" : "Açılış Bakiyesi"}
              </div>
              <div className="mono" style={{ fontSize: 16, fontWeight: 700, marginTop: 4 }}>
                {fmtTL(selectedParty.openingBalance || 0)} ₺
              </div>
            </div>
          )}
        </div>

        {/* Vade Analizi (Aging) */}
        {agingAnalysis && agingAnalysis.total > 0.01 && (
          <div className="card p-4">
            <div className="flex items-center justify-between mb-3">
              <div className="flex items-center gap-2">
                <Clock size={14} style={{ color: "#b45309" }}/>
                <span style={{ fontSize: 13, fontWeight: 700 }}>
                  {lang === "en" ? "Aging Analysis" : "Vade Analizi (Yaşlandırma)"}
                </span>
              </div>
              <div className="mono text-xs" style={{ color: "var(--ink-mute)" }}>
                {lang === "en" ? "Total Open" : "Toplam Açık"}: <span className="font-bold" style={{ color: selectedParty.category === "customer" ? "#0f766e" : "#b91c1c" }}>{fmtTL(agingAnalysis.total)} ₺</span>
              </div>
            </div>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              {[
                { key: "current", color: "#15803d", bg: "#dcfce7" },
                { key: "d31_60", color: "#ca8a04", bg: "#fef3c7" },
                { key: "d61_90", color: "#ea580c", bg: "#ffedd5" },
                { key: "d90plus", color: "#b91c1c", bg: "#fee2e2" },
              ].map(({ key, color, bg }) => {
                const bucket = agingAnalysis.buckets[key];
                const pct = agingAnalysis.total > 0 ? (bucket.amount / agingAnalysis.total) * 100 : 0;
                return (
                  <div key={key} className="p-3 rounded" style={{ background: bg, borderLeft: `3px solid ${color}` }}>
                    <div style={{ fontSize: 9, color, textTransform: "uppercase", fontWeight: 700 }}>
                      {bucket.label} {lang === "en" ? "days" : "gün"}
                    </div>
                    <div className="mono" style={{ fontSize: 14, fontWeight: 700, color, marginTop: 4 }}>
                      {fmtTL(bucket.amount)} ₺
                    </div>
                    <div className="text-xs" style={{ color: "var(--ink-mute)", marginTop: 2 }}>
                      {bucket.count} {lang === "en" ? "items" : "kalem"} · {pct.toFixed(0)}%
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Görsel barlama */}
            <div style={{ background: "var(--bg-alt)", borderRadius: 2, height: 14, overflow: "hidden", display: "flex", marginTop: 12 }}>
              {[
                { key: "current", color: "#15803d" },
                { key: "d31_60", color: "#ca8a04" },
                { key: "d61_90", color: "#ea580c" },
                { key: "d90plus", color: "#b91c1c" },
              ].map(({ key, color }) => {
                const bucket = agingAnalysis.buckets[key];
                const pct = agingAnalysis.total > 0 ? (bucket.amount / agingAnalysis.total) * 100 : 0;
                if (pct < 1) return null;
                return (
                  <div key={key} style={{
                    background: color,
                    width: `${pct}%`,
                    height: "100%",
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontSize: 9, fontWeight: 700, color: "#fff",
                  }}>
                    {pct > 8 ? `${pct.toFixed(0)}%` : ""}
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* Hareket Listesi */}
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ padding: "10px 14px", background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
            <div style={{ fontSize: 13, fontWeight: 700 }}>
              {lang === "en" ? "Transaction History" : "Hareket Geçmişi"}
            </div>
          </div>
          {partyTransactions.length === 0 ? (
            <div className="p-10 text-center" style={{ color: "var(--ink-mute)" }}>
              {lang === "en" ? "No transactions yet" : "Henüz hareket yok"}
            </div>
          ) : (
            <div style={{ overflowX: "auto" }}>
              <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse" }}>
                <thead>
                  <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Date" : "Tarih"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Voucher" : "Fiş No"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                      {lang === "en" ? "Description" : "Açıklama"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "left", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>
                      {lang === "en" ? "Counter Account" : "Karşı Hesap"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Debit" : "Borç"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>
                      {lang === "en" ? "Credit" : "Alacak"}
                    </th>
                    <th style={{ padding: "6px 10px", textAlign: "right", fontSize: 9, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase", width: 130 }}>
                      {lang === "en" ? "Balance" : "Bakiye"}
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {partyTransactions.map((tx, i) => (
                    <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                      <td className="mono" style={{ padding: "6px 10px", fontSize: 10.5, color: "var(--ink-mute)" }}>
                        {tx.date}
                      </td>
                      <td className="mono" style={{ padding: "6px 10px", fontSize: 10.5, fontWeight: 700, color: "var(--accent)" }}>
                        {tx.voucherNo}
                      </td>
                      <td style={{ padding: "6px 10px", fontSize: 11 }}>
                        {tx.description}
                      </td>
                      <td style={{ padding: "6px 10px", fontSize: 10, color: "var(--ink-mute)" }} className="truncate">
                        {tx.counterAccounts}
                      </td>
                      <td className="mono text-right" style={{ padding: "6px 10px", fontSize: 11, fontWeight: tx.debit > 0 ? 600 : 400 }}>
                        {tx.debit > 0 ? fmtTL(tx.debit) + " ₺" : "—"}
                      </td>
                      <td className="mono text-right" style={{ padding: "6px 10px", fontSize: 11, fontWeight: tx.credit > 0 ? 600 : 400 }}>
                        {tx.credit > 0 ? fmtTL(tx.credit) + " ₺" : "—"}
                      </td>
                      <td className="mono text-right" style={{
                        padding: "6px 10px", fontSize: 11, fontWeight: 700,
                        color: tx.runningBalance > 0 ? "#0f766e" : tx.runningBalance < 0 ? "#b91c1c" : "var(--ink-mute)",
                      }}>
                        {Math.abs(tx.runningBalance) < 0.01 ? "0,00" : fmtTL(Math.abs(tx.runningBalance))} ₺
                        {Math.abs(tx.runningBalance) >= 0.01 && (
                          <span style={{ fontSize: 9, fontWeight: 400, marginLeft: 3, opacity: 0.7 }}>
                            {tx.runningBalance > 0 ? "B" : "A"}
                          </span>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
                <tfoot>
                  <tr style={{ background: "var(--bg-alt)", borderTop: "2px solid var(--line)", fontWeight: 700 }}>
                    <td colSpan="4" style={{ padding: "8px 10px", fontSize: 12, textTransform: "uppercase" }}>
                      {lang === "en" ? "TOTAL" : "TOPLAM"}
                    </td>
                    <td className="mono text-right" style={{ padding: "8px 10px", fontSize: 12 }}>
                      {fmtTL(selectedParty.debit)} ₺
                    </td>
                    <td className="mono text-right" style={{ padding: "8px 10px", fontSize: 12 }}>
                      {fmtTL(selectedParty.credit)} ₺
                    </td>
                    <td className="mono text-right" style={{
                      padding: "8px 10px", fontSize: 13, fontWeight: 700,
                      color: selectedParty.isFavorableBalance ? "#0f766e" : "#b91c1c",
                    }}>
                      {fmtTL(Math.abs(selectedParty.balance))} ₺
                      <span style={{ fontSize: 9, fontWeight: 400, marginLeft: 3 }}>
                        {selectedParty.balance > 0 ? "B" : selectedParty.balance < 0 ? "A" : ""}
                      </span>
                    </td>
                  </tr>
                </tfoot>
              </table>
            </div>
          )}
        </div>

        {/* İletişim Bilgileri */}
        {(selectedParty.taxId || selectedParty.address || selectedParty.phone || selectedParty.email) && (
          <div className="card p-4">
            <div className="flex items-center gap-2 mb-3">
              <FileText size={14} style={{ color: "var(--accent)" }}/>
              <span style={{ fontSize: 13, fontWeight: 700 }}>
                {lang === "en" ? "Contact Information" : "İletişim Bilgileri"}
              </span>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 text-xs">
              {selectedParty.taxId && (
                <div>
                  <div style={{ color: "var(--ink-mute)", fontSize: 9, textTransform: "uppercase", fontWeight: 600 }}>VKN/TCKN</div>
                  <div className="mono" style={{ fontSize: 12, fontWeight: 600 }}>{selectedParty.taxId}</div>
                </div>
              )}
              {selectedParty.contactPerson && (
                <div>
                  <div style={{ color: "var(--ink-mute)", fontSize: 9, textTransform: "uppercase", fontWeight: 600 }}>
                    {lang === "en" ? "Contact Person" : "Yetkili Kişi"}
                  </div>
                  <div style={{ fontSize: 12, fontWeight: 600 }}>{selectedParty.contactPerson}</div>
                </div>
              )}
              {selectedParty.phone && (
                <div>
                  <div style={{ color: "var(--ink-mute)", fontSize: 9, textTransform: "uppercase", fontWeight: 600 }}>
                    {lang === "en" ? "Phone" : "Telefon"}
                  </div>
                  <div className="mono" style={{ fontSize: 12 }}>{selectedParty.phone}</div>
                </div>
              )}
              {selectedParty.email && (
                <div>
                  <div style={{ color: "var(--ink-mute)", fontSize: 9, textTransform: "uppercase", fontWeight: 600 }}>Email</div>
                  <div style={{ fontSize: 12 }}>{selectedParty.email}</div>
                </div>
              )}
              {selectedParty.address && (
                <div className="md:col-span-2">
                  <div style={{ color: "var(--ink-mute)", fontSize: 9, textTransform: "uppercase", fontWeight: 600 }}>
                    {lang === "en" ? "Address" : "Adres"}
                  </div>
                  <div style={{ fontSize: 12 }}>{selectedParty.address}</div>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    );
  }

  return null;
}

/* ===================================================================== */
/* NEW PARTY MODAL */
/* ===================================================================== */
function NewPartyModal({ onClose, onSave, lang, categories, accounts }) {
  const [type, setType] = useState("customer");
  const [name, setName] = useState("");
  const [taxId, setTaxId] = useState("");
  const [contactPerson, setContactPerson] = useState("");
  const [phone, setPhone] = useState("");
  const [email, setEmail] = useState("");
  const [address, setAddress] = useState("");
  const [openingBalance, setOpeningBalance] = useState("");

  const handleSubmit = () => {
    if (!name.trim()) {
      alert(lang === "en" ? "Name is required" : "İsim zorunludur");
      return;
    }
    onSave({
      type,
      name: name.trim(),
      taxId: taxId.trim(),
      contactPerson: contactPerson.trim(),
      phone: phone.trim(),
      email: email.trim(),
      address: address.trim(),
      openingBalance: Number(openingBalance) || 0,
    });
  };

  // Sonraki kod tahmini
  const cfg = categories[type];
  const existing = accounts.filter(a => a.code.startsWith(cfg.mainPrefix + "."));
  let maxNum = 0;
  existing.forEach(a => {
    const numPart = a.code.substring(cfg.mainPrefix.length + 1);
    const num = parseInt(numPart, 10);
    if (!isNaN(num) && num > maxNum) maxNum = num;
  });
  const nextCode = `${cfg.mainPrefix}.${String(maxNum + 1).padStart(3, "0")}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="card w-full max-w-2xl" style={{ maxHeight: "90vh", overflow: "auto" }}>
        <div className="p-4 flex items-center justify-between" style={{ borderBottom: "1px solid var(--line)" }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700 }}>
              {lang === "en" ? "New Party Account" : "Yeni Cari Hesap"}
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
              {lang === "en" ? `Next code: ` : `Sıradaki kod: `}
              <span className="mono font-bold" style={{ color: cfg.color }}>{nextCode}</span>
            </div>
          </div>
          <button onClick={onClose} className="btn btn-ghost text-xs">
            <X size={14}/>
          </button>
        </div>

        <div className="p-4 space-y-3">
          {/* Tip Seçici */}
          <div>
            <div className="label mb-1.5">{lang === "en" ? "Party Type" : "Cari Tipi"} *</div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              {Object.entries(categories).map(([key, c]) => {
                const Icon = c.icon;
                return (
                  <button key={key} onClick={() => setType(key)} className="p-3 rounded"
                    style={{
                      background: type === key ? c.color : c.bg,
                      color: type === key ? "#fff" : c.color,
                      border: `1px solid ${type === key ? c.color : c.bg}`,
                      cursor: "pointer", fontWeight: 600, fontSize: 12,
                    }}>
                    <Icon size={16} style={{ margin: "0 auto 4px" }}/>
                    {c.label}
                  </button>
                );
              })}
            </div>
          </div>

          {/* İsim + VKN */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <div>
              <div className="label mb-1">{lang === "en" ? "Name" : "Cari Adı"} *</div>
              <input type="text" value={name} onChange={e => setName(e.target.value)} className="input w-full" placeholder="ABC Ltd. Şti." autoFocus/>
            </div>
            <div>
              <div className="label mb-1">VKN / TCKN</div>
              <input type="text" value={taxId} onChange={e => setTaxId(e.target.value)} className="input w-full mono" placeholder="1234567890"/>
            </div>
          </div>

          {/* Yetkili + Telefon */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <div>
              <div className="label mb-1">{lang === "en" ? "Contact Person" : "Yetkili Kişi"}</div>
              <input type="text" value={contactPerson} onChange={e => setContactPerson(e.target.value)} className="input w-full" placeholder="Ad Soyad"/>
            </div>
            <div>
              <div className="label mb-1">{lang === "en" ? "Phone" : "Telefon"}</div>
              <input type="text" value={phone} onChange={e => setPhone(e.target.value)} className="input w-full mono" placeholder="+90 555 555 5555"/>
            </div>
          </div>

          {/* Email + Açılış Bakiyesi */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <div>
              <div className="label mb-1">Email</div>
              <input type="email" value={email} onChange={e => setEmail(e.target.value)} className="input w-full" placeholder="info@example.com"/>
            </div>
            <div>
              <div className="label mb-1">{lang === "en" ? "Opening Balance" : "Açılış Bakiyesi"} (TRY)</div>
              <MoneyInput value={openingBalance} onChange={v => setOpeningBalance(v)} className="input w-full mono" placeholder="0,00"/>
            </div>
          </div>

          {/* Adres */}
          <div>
            <div className="label mb-1">{lang === "en" ? "Address" : "Adres"}</div>
            <textarea value={address} onChange={e => setAddress(e.target.value)} className="input w-full" rows={2} placeholder={lang === "en" ? "Full address..." : "Tam adres..."}/>
          </div>
        </div>

        <div className="p-4 flex items-center justify-end gap-2" style={{ borderTop: "1px solid var(--line)" }}>
          <button onClick={onClose} className="btn btn-ghost text-xs">
            {lang === "en" ? "Cancel" : "İptal"}
          </button>
          <button onClick={handleSubmit} className="btn btn-primary text-xs">
            <Save size={11}/> {lang === "en" ? "Create Party" : "Cariyi Oluştur"}
          </button>
        </div>
      </div>
    </div>
  );
}

/* =====================================================================
   CARİ YÖNETİMİ MODÜLÜ (Parties Module) — TMO Standardına Uygun
   ---------------------------------------------------------------------
   5 Ana Görünüm:
   1. Cari Kart Listesi (filtreleme, arama, listeleme)
   2. Cari Kart Tanım (11 sekmeli detaylı form)
   3. Cari Muavin Defteri (split-screen — sol cari listesi, sağ hareketler)
   4. Cari Fiş Giriş (11 tip fiş — Açılış/Virman/Kur Farkı/Vade Farkı/...)
   5. Cari Fiş Listesi (filtreleme + muhasebeleştirme + Excel)
===================================================================== */

// Cari Tipleri (7 kategori)
