/* =====================================================================
   AGING REPORT VIEW — Cari Yaşlandırma Raporu
   ---------------------------------------------------------------------
   Açık bakiyeleri vade gününden bugüne göre 5 bucket'a yerleştirir:
     - Vadesi gelmemiş (geleceğe)
     - 0-30 gün geçmiş
     - 31-60 gün geçmiş
     - 61-90 gün geçmiş
     - 90+ gün geçmiş (kronik)
   Müşteri/Tedarikçi ayrımı, sıralama, Excel ihrac.
===================================================================== */
function AgingReportView({ parties = [], invoices = [], lang = "tr", onPartyClick }) {
  const [filterType, setFilterType] = useState("all"); // all | customer | supplier
  const [sortBy, setSortBy] = useState("total"); // total | overdue | name
  const [searchQuery, setSearchQuery] = useState("");
  const [asOfDate, setAsOfDate] = useState(new Date().toISOString().slice(0, 10));

  // Yaşlandırma hesapla
  const agingData = useMemo(() => {
    const refDate = new Date(asOfDate); refDate.setHours(0, 0, 0, 0);
    const rows = [];

    parties.forEach(party => {
      // Bu cariye ait açık faturalar
      const partyInvoices = invoices.filter(i => i.partyId === party.id);
      if (partyInvoices.length === 0) return;

      // 5 bucket: future, 0-30, 31-60, 61-90, 90+
      let bucket_future = 0;
      let bucket_0_30 = 0;
      let bucket_31_60 = 0;
      let bucket_61_90 = 0;
      let bucket_90plus = 0;
      let totalOpen = 0;

      partyInvoices.forEach(inv => {
        const total = Number(inv.total) || 0;
        const paid = Number(inv.paidAmount) || 0;
        const remaining = total - paid;
        if (remaining <= 0.01) return; // kapanmış

        // Tip işareti: out (giden satış) = alacak, in (gelen alış) = borç
        const signed = inv.type === "out" ? remaining : -remaining;

        if (!inv.dueDate) {
          bucket_future += signed;
        } else {
          const due = new Date(inv.dueDate); due.setHours(0, 0, 0, 0);
          const daysOverdue = Math.floor((refDate - due) / 86400000);

          if (daysOverdue < 0) bucket_future += signed;
          else if (daysOverdue <= 30) bucket_0_30 += signed;
          else if (daysOverdue <= 60) bucket_31_60 += signed;
          else if (daysOverdue <= 90) bucket_61_90 += signed;
          else bucket_90plus += signed;
        }
        totalOpen += signed;
      });

      if (Math.abs(totalOpen) < 0.01) return; // tamamen kapalı cari

      const overdue = bucket_0_30 + bucket_31_60 + bucket_61_90 + bucket_90plus;
      rows.push({
        party,
        bucket_future, bucket_0_30, bucket_31_60, bucket_61_90, bucket_90plus,
        totalOpen, overdue,
        overduePct: totalOpen !== 0 ? (Math.abs(overdue) / Math.abs(totalOpen)) * 100 : 0,
      });
    });

    // Filtre: tip
    let filtered = rows;
    if (filterType === "customer") {
      filtered = filtered.filter(r => r.totalOpen > 0); // alacaklı
    } else if (filterType === "supplier") {
      filtered = filtered.filter(r => r.totalOpen < 0); // borçlu
    }

    // Filtre: arama
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      filtered = filtered.filter(r =>
        (r.party.code || "").toLowerCase().includes(q) ||
        (r.party.name || "").toLowerCase().includes(q)
      );
    }

    // Sıralama
    filtered.sort((a, b) => {
      if (sortBy === "name") return (a.party.name || "").localeCompare(b.party.name || "");
      if (sortBy === "overdue") return Math.abs(b.overdue) - Math.abs(a.overdue);
      return Math.abs(b.totalOpen) - Math.abs(a.totalOpen);
    });

    return filtered;
  }, [parties, invoices, filterType, sortBy, searchQuery, asOfDate]);

  // Toplamlar
  const totals = useMemo(() => {
    const t = {
      future: 0, b0_30: 0, b31_60: 0, b61_90: 0, b90plus: 0, total: 0, overdue: 0,
    };
    agingData.forEach(r => {
      t.future += r.bucket_future;
      t.b0_30 += r.bucket_0_30;
      t.b31_60 += r.bucket_31_60;
      t.b61_90 += r.bucket_61_90;
      t.b90plus += r.bucket_90plus;
      t.total += r.totalOpen;
      t.overdue += r.overdue;
    });
    return t;
  }, [agingData]);

  // Excel ihrac
  const exportToExcel = () => {
    const wb = XLSX.utils.book_new();
    const wsData = [
      [
        lang === "en" ? "Code" : "Kod",
        lang === "en" ? "Name" : "Ad",
        lang === "en" ? "Future" : "Vadesi Gelmemiş",
        "0-30",
        "31-60",
        "61-90",
        "90+",
        lang === "en" ? "Total" : "Toplam",
        lang === "en" ? "Overdue %" : "Vadesi Geçen %",
      ],
      ...agingData.map(r => [
        r.party.code || "",
        r.party.name || "",
        r.bucket_future,
        r.bucket_0_30,
        r.bucket_31_60,
        r.bucket_61_90,
        r.bucket_90plus,
        r.totalOpen,
        r.overduePct,
      ]),
      // Toplam satırı
      [
        "", lang === "en" ? "TOTAL" : "TOPLAM",
        totals.future, totals.b0_30, totals.b31_60, totals.b61_90, totals.b90plus, totals.total, "",
      ],
    ];
    const ws = XLSX.utils.aoa_to_sheet(wsData);
    ws["!cols"] = [{ wch: 12 }, { wch: 30 }, { wch: 16 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 14 }, { wch: 18 }, { wch: 12 }];
    XLSX.utils.book_append_sheet(wb, ws, lang === "en" ? "Aging" : "Yaslandirma");
    XLSX.writeFile(wb, `yaslandirma_${asOfDate}.xlsx`);
  };

  return (
    <div className="space-y-3">
      {/* Header & Filtreler */}
      <div className="card p-3">
        <div className="flex items-center gap-2 flex-wrap mb-3">
          <Clock size={16} style={{ color: "#0891b2" }}/>
          <h3 style={{ fontSize: 15, fontWeight: 700 }}>
            {lang === "en" ? "Aging Report" : "Cari Yaşlandırma Raporu"}
          </h3>
          <span className="chip" style={{ background: "#e0f2fe", color: "#0891b2", padding: "2px 8px", fontSize: 10, fontWeight: 700 }}>
            {agingData.length} {lang === "en" ? "parties" : "cari"}
          </span>
          <div style={{ marginLeft: "auto" }}>
            <button onClick={exportToExcel} className="btn text-sm"
              style={{ background: "#15803d", color: "#fff", padding: "6px 12px" }}>
              <FileSpreadsheet size={12}/> {lang === "en" ? "Export Excel" : "Excel İndir"}
            </button>
          </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
          {/* Tarih */}
          <div>
            <label className="label text-xs">{lang === "en" ? "As of Date" : "Rapor Tarihi"}</label>
            <input type="date" value={asOfDate} onChange={e => setAsOfDate(e.target.value)}
              className="input text-xs w-full" style={{ padding: "6px 8px" }}/>
          </div>
          {/* Tip filtresi */}
          <div>
            <label className="label text-xs">{lang === "en" ? "Type" : "Tip"}</label>
            <select value={filterType} onChange={e => setFilterType(e.target.value)}
              className="input text-xs w-full" style={{ padding: "6px 8px" }}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="customer">{lang === "en" ? "Receivable (AR)" : "Alacaklılar"}</option>
              <option value="supplier">{lang === "en" ? "Payable (AP)" : "Borçlular"}</option>
            </select>
          </div>
          {/* Sıralama */}
          <div>
            <label className="label text-xs">{lang === "en" ? "Sort By" : "Sırala"}</label>
            <select value={sortBy} onChange={e => setSortBy(e.target.value)}
              className="input text-xs w-full" style={{ padding: "6px 8px" }}>
              <option value="total">{lang === "en" ? "Total (desc)" : "Toplam (azalan)"}</option>
              <option value="overdue">{lang === "en" ? "Overdue (desc)" : "Vadesi Geçen (azalan)"}</option>
              <option value="name">{lang === "en" ? "Name" : "Cari Adı"}</option>
            </select>
          </div>
          {/* Arama */}
          <div>
            <label className="label text-xs">{lang === "en" ? "Search" : "Ara"}</label>
            <input type="text" value={searchQuery} onChange={e => setSearchQuery(e.target.value)}
              placeholder={lang === "en" ? "Code or name..." : "Kod veya ad..."}
              className="input text-xs w-full" style={{ padding: "6px 8px" }}/>
          </div>
        </div>
      </div>

      {/* Özet kartlar */}
      <div className="grid grid-cols-2 md:grid-cols-6 gap-2">
        <div className="p-2 rounded text-center" style={{ background: "#dbeafe", border: "1px solid #1d4ed8" }}>
          <div style={{ fontSize: 9, color: "#1d4ed8", fontWeight: 700, textTransform: "uppercase" }}>
            {lang === "en" ? "Future" : "V. Gelmemiş"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: "#1d4ed8", marginTop: 2 }}>
            {fmtTL(totals.future)} ₺
          </div>
        </div>
        <div className="p-2 rounded text-center" style={{ background: "#fef3c7", border: "1px solid #ca8a04" }}>
          <div style={{ fontSize: 9, color: "#854d0e", fontWeight: 700, textTransform: "uppercase" }}>
            0-30 {lang === "en" ? "days" : "gün"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: "#854d0e", marginTop: 2 }}>
            {fmtTL(totals.b0_30)} ₺
          </div>
        </div>
        <div className="p-2 rounded text-center" style={{ background: "#fed7aa", border: "1px solid #ea580c" }}>
          <div style={{ fontSize: 9, color: "#9a3412", fontWeight: 700, textTransform: "uppercase" }}>
            31-60 {lang === "en" ? "days" : "gün"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: "#9a3412", marginTop: 2 }}>
            {fmtTL(totals.b31_60)} ₺
          </div>
        </div>
        <div className="p-2 rounded text-center" style={{ background: "#fecaca", border: "1px solid #dc2626" }}>
          <div style={{ fontSize: 9, color: "#991b1b", fontWeight: 700, textTransform: "uppercase" }}>
            61-90 {lang === "en" ? "days" : "gün"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, color: "#991b1b", marginTop: 2 }}>
            {fmtTL(totals.b61_90)} ₺
          </div>
        </div>
        <div className="p-2 rounded text-center" style={{ background: "#7f1d1d", border: "1px solid #450a0a", color: "#fff" }}>
          <div style={{ fontSize: 9, fontWeight: 700, textTransform: "uppercase", opacity: 0.9 }}>
            90+ {lang === "en" ? "days" : "gün"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, marginTop: 2 }}>
            {fmtTL(totals.b90plus)} ₺
          </div>
        </div>
        <div className="p-2 rounded text-center" style={{ background: "var(--ink)", color: "#fff" }}>
          <div style={{ fontSize: 9, fontWeight: 700, textTransform: "uppercase", opacity: 0.9 }}>
            {lang === "en" ? "Total" : "Toplam"}
          </div>
          <div className="mono" style={{ fontSize: 13, fontWeight: 700, marginTop: 2 }}>
            {fmtTL(totals.total)} ₺
          </div>
        </div>
      </div>

      {/* Tablo */}
      <div className="card" style={{ overflow: "hidden" }}>
        <div style={{ overflowX: "auto" }}>
          <table className="grid" style={{ minWidth: 900 }}>
            <thead>
              <tr>
                <th className="label-cell" style={{ minWidth: 200 }}>
                  {lang === "en" ? "Party" : "Cari"}
                </th>
                <th style={{ background: "#dbeafe" }}>{lang === "en" ? "Future" : "V. Gelmemiş"}</th>
                <th style={{ background: "#fef3c7" }}>0-30</th>
                <th style={{ background: "#fed7aa" }}>31-60</th>
                <th style={{ background: "#fecaca" }}>61-90</th>
                <th style={{ background: "#7f1d1d", color: "#fff" }}>90+</th>
                <th style={{ background: "var(--ink)", color: "#fff" }}>{lang === "en" ? "Total" : "Toplam"}</th>
                <th>{lang === "en" ? "Overdue %" : "Vadesi Geçen %"}</th>
              </tr>
            </thead>
            <tbody>
              {agingData.length === 0 ? (
                <tr><td colSpan={8} className="text-center" style={{ padding: 30, color: "var(--ink-mute)" }}>
                  {lang === "en" ? "No open balances" : "Açık bakiye bulunamadı"}
                </td></tr>
              ) : agingData.map((r, i) => (
                <tr key={i} style={{ cursor: "pointer" }}
                  onClick={() => onPartyClick?.(r.party)}
                  onMouseEnter={e => e.currentTarget.style.background = "var(--bg-alt)"}
                  onMouseLeave={e => e.currentTarget.style.background = ""}>
                  <td className="label-cell">
                    <div className="mono text-xs" style={{ color: "var(--ink-mute)" }}>{r.party.code}</div>
                    <div className="text-xs font-bold">{r.party.name}</div>
                  </td>
                  <td className="mono" style={{ color: r.bucket_future !== 0 ? "#1d4ed8" : "var(--ink-mute)" }}>
                    {r.bucket_future !== 0 ? `${fmtTL(r.bucket_future)} ₺` : "-"}
                  </td>
                  <td className="mono" style={{ color: r.bucket_0_30 !== 0 ? "#854d0e" : "var(--ink-mute)" }}>
                    {r.bucket_0_30 !== 0 ? `${fmtTL(r.bucket_0_30)} ₺` : "-"}
                  </td>
                  <td className="mono" style={{ color: r.bucket_31_60 !== 0 ? "#9a3412" : "var(--ink-mute)" }}>
                    {r.bucket_31_60 !== 0 ? `${fmtTL(r.bucket_31_60)} ₺` : "-"}
                  </td>
                  <td className="mono" style={{ color: r.bucket_61_90 !== 0 ? "#991b1b" : "var(--ink-mute)", fontWeight: r.bucket_61_90 !== 0 ? 700 : 400 }}>
                    {r.bucket_61_90 !== 0 ? `${fmtTL(r.bucket_61_90)} ₺` : "-"}
                  </td>
                  <td className="mono" style={{
                    color: r.bucket_90plus !== 0 ? "#fff" : "var(--ink-mute)",
                    background: r.bucket_90plus !== 0 ? "#7f1d1d" : "transparent",
                    fontWeight: 700,
                  }}>
                    {r.bucket_90plus !== 0 ? `${fmtTL(r.bucket_90plus)} ₺` : "-"}
                  </td>
                  <td className="mono" style={{ fontWeight: 700, color: r.totalOpen > 0 ? "#15803d" : "#b91c1c" }}>
                    {fmtTL(r.totalOpen)} ₺
                  </td>
                  <td>
                    <span className="chip" style={{
                      background: r.overduePct >= 50 ? "#fee2e2" : r.overduePct >= 25 ? "#fef3c7" : "#dcfce7",
                      color: r.overduePct >= 50 ? "#b91c1c" : r.overduePct >= 25 ? "#854d0e" : "#15803d",
                      padding: "1px 6px", fontSize: 10, fontWeight: 700,
                    }}>
                      %{r.overduePct.toFixed(0)}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
            {agingData.length > 0 && (
              <tfoot>
                <tr className="grand-total">
                  <td className="label-cell" style={{ fontWeight: 700 }}>
                    {lang === "en" ? "TOTAL" : "TOPLAM"}
                  </td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.future)} ₺</td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.b0_30)} ₺</td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.b31_60)} ₺</td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.b61_90)} ₺</td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.b90plus)} ₺</td>
                  <td className="mono" style={{ fontWeight: 700 }}>{fmtTL(totals.total)} ₺</td>
                  <td>-</td>
                </tr>
              </tfoot>
            )}
          </table>
        </div>
      </div>

      {/* Yardım */}
      <div className="card p-2" style={{ background: "#eff6ff", border: "1px solid #1d4ed8", display: "flex", gap: 8, alignItems: "start" }}>
        <Info size={12} style={{ color: "#1d4ed8", flexShrink: 0, marginTop: 2 }}/>
        <div className="text-xs" style={{ color: "#1e3a8a", lineHeight: 1.5 }}>
          {lang === "en"
            ? "Aging buckets show days past due date. Positive = receivable (customer owes you), negative = payable (you owe). Click any row to view detailed ledger."
            : "Yaşlandırma kovaları vadeden geçen günleri gösterir. Pozitif = alacak (müşteri borçlu), negatif = borç (siz borçlusunuz). Detay için satıra tıklayın."}
        </div>
      </div>
    </div>
  );
}

function PartiesModule({ data, session, canAct, lang, onChange, logAudit, notify, setView, activeView: activeViewProp, setActiveView: setActiveViewProp }) {
  const parties = data.accParties || [];
  const cariVouchers = data.accCariVouchers || [];
  const entries = data.accJournalEntries || [];
  const accounts = data.accChartOfAccounts || [];
  const banks = data.bankAccounts || [];

  // State
  const [activeViewState, setActiveViewState] = useState("list");
  const activeView = activeViewProp ?? activeViewState;
  const setActiveView = setActiveViewProp ?? setActiveViewState;
  const [selectedPartyId, setSelectedPartyId] = useState(null);
  const [selectedVoucherId, setSelectedVoucherId] = useState(null);
  const [showNewPartyModal, setShowNewPartyModal] = useState(false);
  const [showCompareModal, setShowCompareModal] = useState(false);
  const [showImportModal, setShowImportModal] = useState(false);

  // Kontrollü activeView menüden besleniyor; modül yeniden açıldığında seçim
  // gerektiren bir drill-down state (detail/edit/voucher_edit) kalmışsa listeye dön
  useEffect(() => {
    if (!["list", "muavin", "voucher_list", "aging"].includes(activeView)) {
      setActiveView("list");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Çek/Senet'ten gelen yönlendirmeyi yakala
  useEffect(() => {
    try {
      const partyId = localStorage.getItem("prometa_goto_party_muavin");
      if (partyId) {
        localStorage.removeItem("prometa_goto_party_muavin");
        const exists = (data.accParties || []).find(p => p.id === partyId);
        if (exists) {
          setSelectedPartyId(partyId);
          setActiveView("muavin");
        }
      }
    } catch (e) {}
  }, []);  // sadece mount'ta

  const selectedParty = useMemo(() =>
    parties.find(p => p.id === selectedPartyId),
    [parties, selectedPartyId]
  );

  const moduleTabs = [
    { id: "list",         label: { tr: "Cari Kart Listesi",   en: "Party List" },         icon: Users },
    { id: "muavin",       label: { tr: "Cari Muavin Defteri", en: "Subsidiary Ledger" },  icon: FileText },
    { id: "voucher_list", label: { tr: "Cari Fiş Listesi",    en: "Voucher List" },       icon: ClipboardList },
    { id: "aging",        label: { tr: "Yaşlandırma",         en: "Aging Report" },       icon: Clock },
  ];

  return (
    <div className="space-y-3">
      {/* Sayfa Başlığı */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <div className="label mb-1">{lang === "en" ? "Accounts Receivable / Payable" : "Müşteri / Tedarikçi / Personel"}</div>
          <h1 className="display text-2xl flex items-center gap-2">
            <Building2 size={22} style={{ color: "#0891b2" }}/>
            {lang === "en" ? "Party Management" : "Cari Yönetimi"}
          </h1>
          <p className="text-sm mt-1" style={{ color: "var(--ink-mute)" }}>
            {lang === "en"
              ? "Comprehensive party card management with risk, parameters, integration"
              : "Risk, parametre, teminat ve entegrasyon ile kapsamlı cari kart yönetimi"}
          </p>
        </div>
        {activeView === "list" && (
          <div className="flex items-center gap-2">
            <button onClick={() => setShowImportModal(true)} className="btn btn-ghost text-sm"
              style={{ fontWeight: 700, padding: "8px 14px" }}
              title={lang === "en" ? "Excel Import / Export" : "Excel İçe / Dışa Aktar"}>
              <Upload size={13}/> {lang === "en" ? "Excel" : "Excel"}
            </button>
            <button onClick={() => setShowCompareModal(true)} className="btn text-sm"
              style={{ background: "#7c3aed", color: "#fff", fontWeight: 700, padding: "8px 14px" }}>
              <Sparkles size={13}/> {lang === "en" ? "AI Compare" : "AI Karşılaştır"}
            </button>
            <button onClick={() => setShowNewPartyModal(true)} className="btn text-sm"
              style={{ background: "#0891b2", color: "#fff", fontWeight: 700, padding: "8px 16px" }}>
              <Plus size={14}/> {lang === "en" ? "New Party" : "Yeni Cari"}
            </button>
          </div>
        )}
        {activeView === "edit" && selectedParty && (
          <button onClick={() => setActiveView("list")} className="btn btn-ghost text-sm">
            ← {lang === "en" ? "Back to List" : "Listeye Dön"}
          </button>
        )}
      </div>

      {/* İçerik — alt sekme navigasyonu menüye taşındı (akordeon) */}
      <div className="flex gap-3" style={{ minHeight: 600 }}>
        {/* Sağ İçerik */}
        <div style={{ flex: 1, minWidth: 0 }}>
          {/* Görünüm Render */}
          {activeView === "list" && (
            <PartyListView
              parties={parties} accounts={accounts} entries={entries}
              cariVouchers={cariVouchers}
              invoices={data.invoices || []}
              lang={lang} session={session}
              onEdit={(p) => { setSelectedPartyId(p.id); setActiveView("edit"); }}
              onViewMuavin={(p) => { setSelectedPartyId(p.id); setActiveView("muavin"); }}
              onDelete={async (p) => {
                if (!confirm(lang === "en" ? `Delete ${p.name}?` : `${p.name} silinsin mi?`)) return;
                const newParties = parties.filter(x => x.id !== p.id);
                await onChange({ ...data, accParties: newParties });
                notify(lang === "en" ? "Party deleted" : "Cari silindi");
              }}
            />
          )}

          {activeView === "edit" && selectedParty && (
            <PartyCardEditor
              party={selectedParty}
              data={data}
              session={session} lang={lang}
              onSave={async (updated) => {
                const newParties = parties.map(p => p.id === updated.id ? updated : p);
                await onChange({ ...data, accParties: newParties });
                logAudit && logAudit("party_update", "party", { id: updated.id });
                notify(lang === "en" ? "Party saved" : "Cari kaydedildi");
              }}
              onCancel={() => setActiveView("list")}
            />
          )}

          {activeView === "muavin" && (
            <PartyMuavinView
              parties={parties}
              selectedPartyId={selectedPartyId}
              setSelectedPartyId={setSelectedPartyId}
              cariVouchers={cariVouchers}
              entries={entries}
              accounts={accounts}
              invoices={data.invoices || []}
              checks={data.checks || []}
              lang={lang}
              onGoToVoucher={(vId) => { setSelectedVoucherId(vId); setActiveView("voucher_edit"); }}
              onGoToJournal={(voucherNo) => {
                try { localStorage.setItem("prometa_goto_journal_voucher", voucherNo); } catch (e) {}
                setView?.("accounting");
              }}
            />
          )}

          {activeView === "voucher_list" && (
            <CariVoucherListView
              vouchers={cariVouchers}
              parties={parties}
              lang={lang}
              onNew={() => { setSelectedVoucherId(null); setActiveView("voucher_edit"); }}
              onEdit={(v) => { setSelectedVoucherId(v.id); setActiveView("voucher_edit"); }}
              onDelete={async (v) => {
                if (!confirm(lang === "en" ? "Delete voucher?" : "Fiş silinsin mi?")) return;
                const newVouchers = cariVouchers.filter(x => x.id !== v.id);
                await onChange({ ...data, accCariVouchers: newVouchers });
                notify(lang === "en" ? "Voucher deleted" : "Fiş silindi");
              }}
            />
          )}

          {activeView === "voucher_edit" && (
            <CariVoucherEditor
              voucher={cariVouchers.find(v => v.id === selectedVoucherId)}
              parties={parties}
              accounts={accounts}
              data={data}
              session={session}
              lang={lang}
              onSave={async (voucher) => {
                const exists = cariVouchers.some(v => v.id === voucher.id);
                const newVouchers = exists
                  ? cariVouchers.map(v => v.id === voucher.id ? voucher : v)
                  : [...cariVouchers, voucher];
                await onChange({ ...data, accCariVouchers: newVouchers });
                logAudit && logAudit("cari_voucher_save", "voucher", { id: voucher.id });
                notify(lang === "en" ? "Voucher saved" : "Fiş kaydedildi");
                setActiveView("voucher_list");
              }}
              onCancel={() => setActiveView("voucher_list")}
            />
          )}

          {activeView === "aging" && (
            <AgingReportView
              parties={parties}
              invoices={data.invoices || []}
              lang={lang}
              onPartyClick={(p) => { setSelectedPartyId(p.id); setActiveView("muavin"); }}
            />
          )}
        </div>
      </div>

      {/* Yeni Cari Modalı */}
      {showNewPartyModal && (
        <PartyQuickCreateModal
          lang={lang}
          existingParties={parties}
          onSave={async (newParty) => {
            const updated = [...parties, newParty];
            await onChange({ ...data, accParties: updated });
            logAudit && logAudit("party_create", "party", { id: newParty.id, name: newParty.name });
            notify(lang === "en" ? "Party created" : "Cari oluşturuldu");
            setShowNewPartyModal(false);
            setSelectedPartyId(newParty.id);
            setActiveView("edit");
          }}
          onClose={() => setShowNewPartyModal(false)}
        />
      )}

      {/* Multi-Cari Karşılaştırma Modal */}
      {showCompareModal && (
        <MultiCariComparisonModal
          parties={parties}
          invoices={data.invoices || []}
          lang={lang}
          onClose={() => setShowCompareModal(false)}
        />
      )}

      {/* Excel İçe/Dışa Aktarım Modalı */}
      {showImportModal && (
        <PartyExcelImportModal
          data={data}
          lang={lang}
          onChange={onChange}
          notify={notify}
          logAudit={logAudit}
          onClose={() => setShowImportModal(false)}
        />
      )}
    </div>
  );
}

/* ===================================================================== */
/* PARTY QUICK CREATE MODAL                                              */
/* ===================================================================== */
function PartyQuickCreateModal({ lang, existingParties, onSave, onClose }) {
  const [type, setType] = useState("customer");
  const [personType, setPersonType] = useState("real");
  const [name, setName] = useState("");
  const [taxId, setTaxId] = useState("");

  const cfg = PARTY_TYPES[type];
  const existing = existingParties.filter(p => p.code?.startsWith(cfg.mainCode));
  let maxNum = 0;
  existing.forEach(p => {
    const m = String(p.code).match(/\.A?0*(\d+)$/i);
    if (m) {
      const n = parseInt(m[1], 10);
      if (!isNaN(n) && n > maxNum) maxNum = n;
    }
  });
  const previewCode = `${cfg.mainCode}.A${String(maxNum + 1).padStart(3, "0")}`;

  const handleSubmit = () => {
    if (!name.trim()) {
      alert(lang === "en" ? "Name is required" : "İsim zorunludur");
      return;
    }
    const newParty = {
      id: `party_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      code: previewCode,
      name: name.trim(),
      taxId: taxId.trim(),
      type, personType,
      status: "active", origin: "TR",
      contactInfo: [], authorizedPersons: [], banks: [],
      risk: {
        blacklistBuy: false, blacklistSell: false, bannedFromTender: false,
        sgkDebt: null, taxDebt: null, debtAmount: 0,
        statusDescription: "", statusDate: null, details: [],
      },
      params: {
        partialShipment: false, invoicePrintCount: 1,
        usage: { buying: true, selling: true, export: false, import: false, finance: false },
        orderApproval: { riskCheck: true, dueCheck: true, agingCheck: false, agingDays: 0 },
        dueTracking: [],
        debtCloseControl: { days: 0, action: "continue" },
      },
      accounting: {
        costCenter: "", cariClass: "alici",
        accountCode_alici: "", accountCode_satici: "",
        accountCode_personel: "", accountCode_diger: "",
      },
      guarantees: [],
      integration: {
        eFatura: { type: "", labelInfo: "", scenario: "", pBoxLabel: "", senderLabel: "", intermediary: "", isUser: false, isPublic: false, isCustoms: false, replaceDeliveryNote: false, defaultInvoiceType: "", bankAccountNo: "" },
        eArsiv: { retailAccount: false, deliveryMethod: "", email: "", email2: "", email3: "" },
        eIrsaliye: { isUser: false, labelInfo: "", scenario: "" },
      },
      kvkkFiles: [], formSendPrefs: [],
      identityInfo: {
        nCuzdanNo: "", baba: "", anne: "", cinsiyet: "", dogumYeri: "",
        dogumTarihi: null, olumTarihi: null, medeniHal: "",
        il: "", ilce: "", mahalle: "", ciltNo: "", siraNo: "", aileSiraNo: "", kayitDurumu: "",
      },
      seizureRecords: [],
      address: "", vatOffice: "", vatOfficeCode: "", mersisNo: "",
      projectCode: "", specialCode: "", paymentTermDays: 0,
      createdAt: new Date().toISOString(),
    };
    onSave(newParty);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="card w-full max-w-2xl" style={{ maxHeight: "90vh", overflow: "auto" }}>
        <div className="p-4 flex items-center justify-between" style={{ borderBottom: "1px solid var(--line)" }}>
          <div>
            <div style={{ fontSize: 16, fontWeight: 700 }}>
              {lang === "en" ? "New Party — Quick Create" : "Yeni Cari — Hızlı Oluştur"}
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
              {lang === "en" ? "Next code:" : "Sıradaki kod:"} <span className="mono font-bold" style={{ color: cfg.color }}>{previewCode}</span>
            </div>
          </div>
          <button onClick={onClose} className="btn btn-ghost text-xs"><X size={14}/></button>
        </div>
        <div className="p-4 space-y-3">
          <div>
            <div className="label mb-1.5">{lang === "en" ? "Party Type" : "Cari Sınıfı"} *</div>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
              {Object.entries(PARTY_TYPES).map(([key, c]) => (
                <button key={key} onClick={() => setType(key)} className="p-2 rounded text-xs"
                  style={{
                    background: type === key ? c.color : c.bg,
                    color: type === key ? "#fff" : c.color,
                    border: `1px solid ${type === key ? c.color : c.bg}`,
                    cursor: "pointer", fontWeight: 600,
                  }}>
                  {c[lang] || c.tr}
                </button>
              ))}
            </div>
          </div>
          <div>
            <div className="label mb-1.5">{lang === "en" ? "Person Type" : "Kişi Türü"} *</div>
            <div className="flex items-center" style={{ border: "1px solid var(--line)", borderRadius: 4, overflow: "hidden", width: "fit-content" }}>
              <button onClick={() => setPersonType("real")} className="text-xs"
                style={{ padding: "6px 14px", background: personType === "real" ? "var(--accent)" : "var(--bg)", color: personType === "real" ? "#fff" : "var(--ink)", fontWeight: 600, cursor: "pointer", borderRight: "1px solid var(--line)" }}>
                {lang === "en" ? "Real Person" : "Gerçek Kişi"}
              </button>
              <button onClick={() => setPersonType("legal")} className="text-xs"
                style={{ padding: "6px 14px", background: personType === "legal" ? "var(--accent)" : "var(--bg)", color: personType === "legal" ? "#fff" : "var(--ink)", fontWeight: 600, cursor: "pointer" }}>
                {lang === "en" ? "Legal Entity" : "Tüzel Kişi"}
              </button>
            </div>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Name / Title" : "Adı / Ünvanı"} *</div>
            <input className="input w-full" value={name} onChange={e => setName(e.target.value)} autoFocus
              placeholder={lang === "en" ? "ABC Ltd. Co." : "ABC Ltd. Şti."}/>
          </div>
          <div>
            <div className="label mb-1">{personType === "real" ? "T.C. Kimlik No" : "Vergi Kimlik No"}</div>
            <input className="input w-full mono" value={taxId}
              onChange={e => setTaxId(e.target.value.replace(/\D/g, "").slice(0, 11))}
              placeholder={personType === "real" ? "12345678901" : "1234567890"}/>
          </div>
        </div>
        <div className="p-4 flex items-center justify-end gap-2" style={{ borderTop: "1px solid var(--line)" }}>
          <button onClick={onClose} className="btn btn-ghost text-xs">{lang === "en" ? "Cancel" : "İptal"}</button>
          <button onClick={handleSubmit} className="btn text-xs"
            style={{ background: "#0891b2", color: "#fff", fontWeight: 700, padding: "8px 16px" }}>
            <Save size={11}/> {lang === "en" ? "Create & Open" : "Oluştur ve Aç"}
          </button>
        </div>
      </div>
    </div>
  );
}

/* ===================================================================== */
/* PARTY EXCEL IMPORT/EXPORT MODAL — Cari Kartı CSV İçe/Dışa Aktarım     */
/* ===================================================================== */
function PartyExcelImportModal({ data, lang, onClose, onChange, notify, logAudit }) {
  const parties = data.accParties || [];
  const [activeTab, setActiveTab] = useState("export"); // export | template | import
  const [importMode, setImportMode] = useState("merge"); // merge | only_new | replace_all
  const [importFile, setImportFile] = useState(null);
  const [parsedRows, setParsedRows] = useState([]);
  const [validationResults, setValidationResults] = useState(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const fileInputRef = useRef(null);

  // === Tip / kişi türü / statü çözümleyiciler (TR etiket + key kabul eder) ===
  const TYPE_LABELS = {
    customer:    ["customer", "müşteri", "musteri"],
    supplier:    ["supplier", "tedarikçi", "tedarikci"],
    both:        ["both", "alıcı + satıcı", "alici + satici", "alıcı+satıcı", "alici+satici"],
    employee:    ["employee", "personel"],
    shareholder: ["shareholder", "ortak"],
    affiliate:   ["affiliate", "bağlı ortaklık", "bagli ortaklik"],
    other:       ["other", "diğer", "diger"],
  };
  const resolveType = (v) => {
    const s = String(v || "").toLowerCase().trim();
    if (!s) return null;
    for (const [k, arr] of Object.entries(TYPE_LABELS)) {
      if (k === s || arr.includes(s)) return k;
    }
    return null;
  };
  const resolvePersonType = (v) => {
    const s = String(v || "").toLowerCase().trim();
    if (["legal", "tüzel", "tuzel"].some(x => s.includes(x))) return "legal";
    return "real";
  };
  const resolveStatus = (v) => {
    const s = String(v || "").toLowerCase().trim();
    if (["passive", "pasif"].some(x => s.includes(x))) return "passive";
    return "active";
  };
  const yesNoValues = ["evet", "yes", "true", "1", "doğru", "dogru"];
  const parseYesNo = (val) => {
    if (val === null || val === undefined || val === "") return null;
    return yesNoValues.includes(String(val).toLowerCase().trim());
  };

  const phoneOf = (p) => (p.contactInfo || []).find(c => c.number)?.number || "";
  const emailOf = (p) => (p.contactInfo || []).find(c => c.email)?.email || "";

  // === Sütun şablonu ===
  const COLUMNS = [
    { key: "code",                 header_tr: "Cari Kodu",          header_en: "Code",            required: false, format: (p) => p.code || "" },
    { key: "type",                 header_tr: "Cari Sınıfı",        header_en: "Type",            required: true,  format: (p) => (PARTY_TYPES[p.type]?.tr || p.type || "") },
    { key: "personType",           header_tr: "Kişi Türü",          header_en: "Person Type",     required: false, format: (p) => (p.personType === "legal" ? "Tüzel" : "Gerçek") },
    { key: "name",                 header_tr: "Adı / Ünvanı",       header_en: "Name",            required: true,  format: (p) => p.name || "" },
    { key: "taxId",                header_tr: "VKN / TCKN",         header_en: "Tax ID",          required: false, format: (p) => p.taxId || "" },
    { key: "status",               header_tr: "Statü",              header_en: "Status",          required: false, format: (p) => ((p.status || "active") === "passive" ? "Pasif" : "Aktif") },
    { key: "vatOffice",            header_tr: "Vergi Dairesi",      header_en: "Tax Office",      required: false, format: (p) => p.vatOffice || "" },
    { key: "vatOfficeCode",        header_tr: "Vergi Dairesi Kodu", header_en: "Tax Office Code", required: false, format: (p) => p.vatOfficeCode || "" },
    { key: "mersisNo",             header_tr: "Mersis No",          header_en: "Mersis No",       required: false, format: (p) => p.mersisNo || "" },
    { key: "origin",               header_tr: "Menşei",             header_en: "Origin",          required: false, format: (p) => p.origin || "TR" },
    { key: "phone",                header_tr: "Telefon",            header_en: "Phone",           required: false, format: (p) => phoneOf(p) },
    { key: "email",                header_tr: "E-posta",            header_en: "Email",           required: false, format: (p) => emailOf(p) },
    { key: "address",              header_tr: "Adres",              header_en: "Address",         required: false, format: (p) => p.address || "" },
    { key: "projectCode",          header_tr: "Proje Kodu",         header_en: "Project Code",    required: false, format: (p) => p.projectCode || "" },
    { key: "specialCode",          header_tr: "Özel Kod",           header_en: "Special Code",    required: false, format: (p) => p.specialCode || "" },
    { key: "paymentTermDays",      header_tr: "Vade (Gün)",         header_en: "Payment Term",    required: false, format: (p) => p.paymentTermDays ?? "" },
    { key: "accountCode_alici",    header_tr: "Müşteri Hes. Kodu",  header_en: "AR Account",      required: false, format: (p) => p.accounting?.accountCode_alici || "" },
    { key: "accountCode_satici",   header_tr: "Tedarikçi Hes. Kodu",header_en: "AP Account",      required: false, format: (p) => p.accounting?.accountCode_satici || "" },
    { key: "accountCode_personel", header_tr: "Personel Hes. Kodu", header_en: "Employee Account",required: false, format: (p) => p.accounting?.accountCode_personel || "" },
    { key: "accountCode_diger",    header_tr: "Diğer Hes. Kodu",    header_en: "Other Account",   required: false, format: (p) => p.accounting?.accountCode_diger || "" },
    { key: "creditLimit",          header_tr: "Kredi Limiti",       header_en: "Credit Limit",    required: false, format: (p) => p.risk?.creditLimit ?? "" },
    { key: "riskLevel",            header_tr: "Risk Seviyesi",      header_en: "Risk Level",      required: false, format: (p) => p.risk?.riskLevel || "" },
    { key: "blacklistBuy",         header_tr: "Alış Kara Liste",    header_en: "Buy Blacklist",   required: false, format: (p) => (p.risk?.blacklistBuy ? "Evet" : "Hayır") },
    { key: "blacklistSell",        header_tr: "Satış Kara Liste",   header_en: "Sell Blacklist",  required: false, format: (p) => (p.risk?.blacklistSell ? "Evet" : "Hayır") },
    { key: "bannedFromTender",     header_tr: "İhaleden Men",       header_en: "Banned",          required: false, format: (p) => (p.risk?.bannedFromTender ? "Evet" : "Hayır") },
  ];

  // === CSV oluştur ===
  const buildCsv = (rows) => {
    return rows.map(r => r.map(c => {
      const s = String(c == null ? "" : c);
      return s.includes(",") || s.includes("\"") || s.includes("\n")
        ? `"${s.replace(/"/g, '""')}"` : s;
    }).join(",")).join("\n");
  };

  const downloadCsv = (csv, filename) => {
    const blob = new Blob(["﻿" + csv], { type: "text/csv;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = filename;
    link.click();
    URL.revokeObjectURL(url);
  };

  // === Dışa Aktar ===
  const handleExport = () => {
    const headers = COLUMNS.map(c => lang === "en" ? c.header_en : c.header_tr);
    const rows = [headers];
    const sorted = [...parties].sort((a, b) =>
      String(a.code || "").localeCompare(String(b.code || ""), "tr", { numeric: true })
    );
    sorted.forEach(p => rows.push(COLUMNS.map(c => c.format(p))));
    downloadCsv(buildCsv(rows), `cari_listesi_${new Date().toISOString().split("T")[0]}.csv`);
    notify(lang === "en" ? `Exported ${parties.length} parties` : `${parties.length} cari dışa aktarıldı`);
    logAudit && logAudit("export", "party", { count: parties.length });
  };

  // === Şablon İndir ===
  const handleDownloadTemplate = () => {
    const headers = COLUMNS.map(c => lang === "en" ? c.header_en : c.header_tr);
    const examples = [
      ["320.A001", "Tedarikçi", "Tüzel",  "ABC İNŞAAT LTD. ŞTİ.", "1234567890",  "Aktif", "Beşiktaş", "034", "0123456789012345", "TR", "0212 000 00 00", "info@abc.com",   "Levent Mah. No:1", "PRJ01", "OZL1", "60", "120.01", "320.01", "", "", "100000", "low",    "Hayır", "Hayır", "Hayır"],
      ["120.A001", "Müşteri",   "Gerçek", "MEHMET YILMAZ",        "12345678901", "Aktif", "Kadıköy",  "035", "",                 "TR", "0532 000 00 00", "mehmet@mail.com","Moda Cad. No:5",   "",      "",     "30", "120.02", "",       "", "", "50000",  "medium", "Hayır", "Hayır", "Hayır"],
    ];
    const rows = [headers, ...examples];
    rows.push([]);
    rows.push(["# " + (lang === "en" ? "INSTRUCTIONS" : "TALİMATLAR")]);
    rows.push(["# " + (lang === "en" ? "Required fields: Type, Name" : "Zorunlu alanlar: Cari Sınıfı, Adı / Ünvanı")]);
    rows.push(["# " + (lang === "en" ? "Code is optional — auto-generated by type if left blank" : "Cari Kodu boş bırakılırsa sınıfa göre otomatik üretilir")]);
    rows.push(["# " + (lang === "en" ? "Type: Müşteri, Tedarikçi, Alıcı + Satıcı, Personel, Ortak, Bağlı Ortaklık, Diğer" : "Cari Sınıfı: Müşteri, Tedarikçi, Alıcı + Satıcı, Personel, Ortak, Bağlı Ortaklık, Diğer")]);
    rows.push(["# " + (lang === "en" ? "Person Type: Gerçek or Tüzel" : "Kişi Türü: Gerçek veya Tüzel")]);
    rows.push(["# " + (lang === "en" ? "Status: Aktif or Pasif" : "Statü: Aktif veya Pasif")]);
    rows.push(["# " + (lang === "en" ? "Risk Level: low, medium, high, critical" : "Risk Seviyesi: low, medium, high, critical")]);
    rows.push(["# " + (lang === "en" ? "Yes/No fields (blacklist, banned): Evet or Hayır" : "Evet/Hayır alanları (kara liste, men): Evet veya Hayır")]);
    rows.push(["# " + (lang === "en" ? "Matching: by Code, otherwise by Tax ID" : "Eşleştirme: Cari Kodu ile, yoksa VKN/TCKN ile")]);
    downloadCsv(buildCsv(rows), "cari_listesi_sablon.csv");
    notify(lang === "en" ? "Template downloaded" : "Şablon indirildi");
  };

  // === CSV Parse ===
  const parseCsv = (text) => {
    text = text.replace(/^﻿/, "");
    const lines = [];
    let current = "", inQuotes = false, row = [];
    for (let i = 0; i < text.length; i++) {
      const c = text[i], next = text[i + 1];
      if (inQuotes) {
        if (c === '"' && next === '"') { current += '"'; i++; }
        else if (c === '"') inQuotes = false;
        else current += c;
      } else {
        if (c === '"') inQuotes = true;
        else if (c === ',') { row.push(current); current = ""; }
        else if (c === '\n' || c === '\r') {
          if (current !== "" || row.length > 0) { row.push(current); lines.push(row); row = []; current = ""; }
          if (c === '\r' && next === '\n') i++;
        } else current += c;
      }
    }
    if (current !== "" || row.length > 0) { row.push(current); lines.push(row); }
    return lines;
  };

  // === Dosya yükleme ===
  const handleFileChange = async (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setImportFile(file);
    setIsProcessing(true);
    try {
      const text = await file.text();
      const rows = parseCsv(text);
      if (rows.length < 2) {
        notify(lang === "en" ? "File is empty or has no data" : "Dosya boş veya veri yok", "err");
        setIsProcessing(false);
        return;
      }
      const header = rows[0].map(h => String(h || "").trim().toLowerCase());
      const dataRows = rows.slice(1).filter(r =>
        r.length > 0 && !String(r[0] || "").trim().startsWith("#") && r.some(c => String(c || "").trim() !== "")
      );
      const headerMap = {};
      COLUMNS.forEach(col => {
        const trIdx = header.indexOf(col.header_tr.toLowerCase());
        const enIdx = header.indexOf(col.header_en.toLowerCase());
        const keyIdx = header.indexOf(col.key.toLowerCase());
        if (trIdx >= 0) headerMap[col.key] = trIdx;
        else if (enIdx >= 0) headerMap[col.key] = enIdx;
        else if (keyIdx >= 0) headerMap[col.key] = keyIdx;
      });
      const missingCols = COLUMNS.filter(c => c.required && headerMap[c.key] === undefined);
      if (missingCols.length > 0) {
        notify(
          lang === "en"
            ? `Missing required columns: ${missingCols.map(c => c.header_en).join(", ")}`
            : `Eksik zorunlu sütunlar: ${missingCols.map(c => c.header_tr).join(", ")}`,
          "err"
        );
        setIsProcessing(false);
        return;
      }
      const parsed = dataRows.map((row, idx) => {
        const obj = { _rowNumber: idx + 2 };
        Object.entries(headerMap).forEach(([key, colIdx]) => {
          obj[key] = String(row[colIdx] || "").trim();
        });
        return obj;
      });
      setParsedRows(parsed);
      validateRows(parsed);
    } catch (err) {
      notify(lang === "en" ? "Failed to read file: " + err.message : "Dosya okunamadı: " + err.message, "err");
    } finally {
      setIsProcessing(false);
    }
  };

  // === Validation ===
  const validateRows = (rows) => {
    const errors = [];
    const warnings = [];
    const seenKeys = new Set();
    const validRiskLevels = ["", "low", "medium", "high", "critical"];
    let newCount = 0, updateCount = 0, errorCount = 0;

    rows.forEach(row => {
      const rowErrors = [];
      if (!row.name || !row.name.trim()) {
        rowErrors.push(lang === "en" ? "Name is empty" : "Ad/Ünvan boş");
      }
      if (!resolveType(row.type)) {
        rowErrors.push(lang === "en" ? `Invalid type "${row.type}"` : `Geçersiz cari sınıfı "${row.type}"`);
      }
      if (row.riskLevel && !validRiskLevels.includes(String(row.riskLevel).toLowerCase().trim())) {
        rowErrors.push(lang === "en" ? `Invalid risk level "${row.riskLevel}"` : `Geçersiz risk seviyesi "${row.riskLevel}"`);
      }

      // Dosya içi tekrar (kod veya VKN)
      const dupKey = (row.code && row.code.trim()) || (row.taxId && row.taxId.trim());
      if (dupKey) {
        if (seenKeys.has(dupKey)) {
          warnings.push({
            row: row._rowNumber,
            message: lang === "en" ? `Duplicate "${dupKey}" in file` : `Dosyada tekrar eden "${dupKey}"`,
          });
        }
        seenKeys.add(dupKey);
      }

      // Mevcut mu?
      let existing = null;
      if (row.code && row.code.trim()) existing = parties.find(p => p.code === row.code.trim());
      if (!existing && row.taxId && row.taxId.trim()) existing = parties.find(p => p.taxId && p.taxId === row.taxId.trim());

      if (existing) {
        if (importMode === "only_new") {
          warnings.push({
            row: row._rowNumber,
            message: lang === "en" ? `"${existing.code}" already exists, will be skipped` : `"${existing.code}" zaten var, atlanacak`,
          });
        } else updateCount++;
      } else newCount++;

      if (rowErrors.length > 0) {
        errorCount++;
        errors.push({ row: row._rowNumber, code: row.code, name: row.name, messages: rowErrors });
      }
    });

    setValidationResults({
      total: rows.length, newCount, updateCount, errorCount,
      errors, warnings, canProceed: errors.length === 0,
    });
  };

  // === Boş cari iskeleti (PartyQuickCreateModal ile aynı şema) ===
  const makeBaseParty = (type, personType) => ({
    type, personType,
    status: "active", origin: "TR",
    contactInfo: [], authorizedPersons: [], banks: [],
    risk: {
      blacklistBuy: false, blacklistSell: false, bannedFromTender: false,
      sgkDebt: null, taxDebt: null, debtAmount: 0,
      statusDescription: "", statusDate: null, details: [],
    },
    params: {
      partialShipment: false, invoicePrintCount: 1,
      usage: { buying: true, selling: true, export: false, import: false, finance: false },
      orderApproval: { riskCheck: true, dueCheck: true, agingCheck: false, agingDays: 0 },
      dueTracking: [],
      debtCloseControl: { days: 0, action: "continue" },
    },
    accounting: {
      costCenter: "", cariClass: "alici",
      accountCode_alici: "", accountCode_satici: "",
      accountCode_personel: "", accountCode_diger: "",
    },
    guarantees: [],
    integration: {
      eFatura: { type: "", labelInfo: "", scenario: "", pBoxLabel: "", senderLabel: "", intermediary: "", isUser: false, isPublic: false, isCustoms: false, replaceDeliveryNote: false, defaultInvoiceType: "", bankAccountNo: "" },
      eArsiv: { retailAccount: false, deliveryMethod: "", email: "", email2: "", email3: "" },
      eIrsaliye: { isUser: false, labelInfo: "", scenario: "" },
    },
    kvkkFiles: [], formSendPrefs: [],
    identityInfo: {
      nCuzdanNo: "", baba: "", anne: "", cinsiyet: "", dogumYeri: "",
      dogumTarihi: null, olumTarihi: null, medeniHal: "",
      il: "", ilce: "", mahalle: "", ciltNo: "", siraNo: "", aileSiraNo: "", kayitDurumu: "",
    },
    seizureRecords: [],
    address: "", vatOffice: "", vatOfficeCode: "", mersisNo: "",
    projectCode: "", specialCode: "", paymentTermDays: 0,
  });

  const buildContactInfo = (row, existing) => {
    const phone = (row.phone || "").trim();
    const email = (row.email || "").trim();
    if (!phone && !email) return existing?.contactInfo || [];
    const list = [];
    if (phone) list.push({ id: 1, type: "GSM", number: phone, email: "", preferred: true, smsAllowed: true });
    if (email) list.push({ id: 2, type: "Email", number: "", email, preferred: !phone, smsAllowed: false });
    return list;
  };

  // === İçe Aktarma uygulama ===
  const handleImport = async () => {
    if (!validationResults?.canProceed) return;
    if (!confirm(
      lang === "en"
        ? `Import ${validationResults.newCount} new and update ${validationResults.updateCount} parties?`
        : `${validationResults.newCount} yeni cari eklenecek ve ${validationResults.updateCount} cari güncellenecek. Onaylıyor musunuz?`
    )) return;

    setIsProcessing(true);
    try {
      let working = importMode === "replace_all" ? [] : [...parties];

      // Sınıf (mainCode) bazlı sıradaki kod sayacı
      const codeCounter = {};
      const nextCode = (type) => {
        const mainCode = PARTY_TYPES[type]?.mainCode || "320";
        if (codeCounter[mainCode] == null) {
          let mx = 0;
          working.forEach(p => {
            if (!String(p.code || "").startsWith(mainCode)) return;
            const m = String(p.code).match(/\.A?0*(\d+)$/i);
            if (m) { const n = parseInt(m[1], 10); if (!isNaN(n) && n > mx) mx = n; }
          });
          codeCounter[mainCode] = mx;
        }
        codeCounter[mainCode] += 1;
        return `${mainCode}.A${String(codeCounter[mainCode]).padStart(3, "0")}`;
      };

      parsedRows.forEach(row => {
        const type = resolveType(row.type);
        if (!type || !row.name?.trim()) return;

        let existing = null;
        if (importMode !== "replace_all") {
          if (row.code && row.code.trim()) existing = working.find(p => p.code === row.code.trim());
          if (!existing && row.taxId && row.taxId.trim()) existing = working.find(p => p.taxId && p.taxId === row.taxId.trim());
        }
        if (existing && importMode === "only_new") return;

        const fields = {
          type,
          personType: resolvePersonType(row.personType),
          name: row.name.trim(),
          taxId: (row.taxId || "").trim(),
          status: resolveStatus(row.status),
          vatOffice: (row.vatOffice || "").trim(),
          vatOfficeCode: (row.vatOfficeCode || "").trim(),
          mersisNo: (row.mersisNo || "").trim(),
          origin: (row.origin || "TR").trim() || "TR",
          address: (row.address || "").trim(),
          projectCode: (row.projectCode || "").trim(),
          specialCode: (row.specialCode || "").trim(),
          paymentTermDays: row.paymentTermDays ? Number(row.paymentTermDays) || 0 : 0,
        };
        const accounting = {
          accountCode_alici: (row.accountCode_alici || "").trim(),
          accountCode_satici: (row.accountCode_satici || "").trim(),
          accountCode_personel: (row.accountCode_personel || "").trim(),
          accountCode_diger: (row.accountCode_diger || "").trim(),
        };
        const riskFields = {
          creditLimit: row.creditLimit ? Number(row.creditLimit) || 0 : 0,
          riskLevel: (row.riskLevel || "").toLowerCase().trim(),
          blacklistBuy: parseYesNo(row.blacklistBuy) === true,
          blacklistSell: parseYesNo(row.blacklistSell) === true,
          bannedFromTender: parseYesNo(row.bannedFromTender) === true,
        };

        if (existing) {
          Object.assign(existing, fields, {
            accounting: { ...existing.accounting, ...accounting },
            risk: { ...existing.risk, ...riskFields },
            contactInfo: buildContactInfo(row, existing),
            updatedAt: new Date().toISOString(),
            updatedBy: "import",
          });
        } else {
          const base = makeBaseParty(type, fields.personType);
          const code = (row.code && row.code.trim() && !working.some(p => p.code === row.code.trim()))
            ? row.code.trim()
            : nextCode(type);
          const newParty = {
            ...base,
            ...fields,
            code,
            id: `party_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
            accounting: { ...base.accounting, ...accounting },
            risk: { ...base.risk, ...riskFields },
            contactInfo: buildContactInfo(row, null),
            createdAt: new Date().toISOString(),
            createdBy: "import",
          };
          working.push(newParty);
        }
      });

      await onChange({ ...data, accParties: working });
      logAudit && logAudit("import", "party", {
        mode: importMode, new: validationResults.newCount, updated: validationResults.updateCount,
      });
      notify(
        lang === "en"
          ? `Imported: ${validationResults.newCount} new, ${validationResults.updateCount} updated`
          : `${validationResults.newCount} yeni, ${validationResults.updateCount} güncelleme tamamlandı`
      );
      onClose();
    } catch (err) {
      notify(lang === "en" ? "Import failed: " + err.message : "İçe aktarım başarısız: " + err.message, "err");
    } finally {
      setIsProcessing(false);
    }
  };

  const tabs = [
    { id: "export",   label: { tr: "Dışa Aktar",   en: "Export" } },
    { id: "template", label: { tr: "Şablon İndir",  en: "Template" } },
    { id: "import",   label: { tr: "İçe Aktar",     en: "Import" } },
  ];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{ background: "rgba(0,0,0,0.5)" }}>
      <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl max-h-[90vh] flex flex-col overflow-hidden">
        {/* Header */}
        <div className="px-5 py-4 border-b flex items-center justify-between" style={{ background: "var(--accent-soft)" }}>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700 }}>
              {lang === "en" ? "Parties — Excel Import/Export" : "Cari Kartları — Excel İçe/Dışa Aktarım"}
            </div>
            <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>
              {lang === "en" ? `${parties.length} parties in the system` : `Sistemde ${parties.length} cari var`}
            </div>
          </div>
          <button onClick={onClose} className="p-1 rounded hover:bg-bg"><X size={16}/></button>
        </div>

        {/* Sekmeler */}
        <div className="flex border-b" style={{ background: "var(--bg-alt)" }}>
          {tabs.map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id)}
              style={{
                flex: 1, padding: "10px 16px", fontSize: 12,
                fontWeight: activeTab === tab.id ? 700 : 500,
                color: activeTab === tab.id ? "var(--accent)" : "var(--ink-mute)",
                background: activeTab === tab.id ? "var(--bg)" : "transparent",
                borderBottom: activeTab === tab.id ? "2px solid var(--accent)" : "2px solid transparent",
                cursor: "pointer", textAlign: "center",
              }}>
              {tab.label[lang] || tab.label.tr}
            </button>
          ))}
        </div>

        {/* İçerik */}
        <div className="p-5 overflow-y-auto flex-1">
          {/* DIŞA AKTAR */}
          {activeTab === "export" && (
            <div className="space-y-3">
              <div className="card p-4" style={{ background: "#dcfce7", border: "1px solid #15803d" }}>
                <div style={{ fontSize: 13, color: "#15803d", lineHeight: 1.5 }}>
                  <b>{lang === "en" ? "Export to CSV/Excel" : "CSV/Excel Olarak Dışa Aktar"}</b><br/>
                  {lang === "en"
                    ? `All ${parties.length} parties will be exported with ${COLUMNS.length} fields.`
                    : `Sistemdeki ${parties.length} cari, ${COLUMNS.length} alanla dışa aktarılacak.`}
                </div>
              </div>
              <div>
                <div className="label mb-2">{lang === "en" ? "Included Fields" : "Dahil Edilen Alanlar"}</div>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-1 text-xs">
                  {COLUMNS.map(c => (
                    <div key={c.key} className="flex items-center gap-1.5" style={{ padding: "3px 6px", background: "var(--bg-alt)", borderRadius: 3 }}>
                      <span style={{ fontSize: 9, color: c.required ? "#b91c1c" : "var(--ink-mute)" }}>{c.required ? "●" : "○"}</span>
                      <span>{lang === "en" ? c.header_en : c.header_tr}</span>
                    </div>
                  ))}
                </div>
                <div className="mt-2 text-xs" style={{ color: "var(--ink-mute)" }}>
                  ● {lang === "en" ? "Required" : "Zorunlu"} &nbsp;&nbsp; ○ {lang === "en" ? "Optional" : "İsteğe bağlı"}
                </div>
              </div>
              <button onClick={handleExport} className="btn btn-primary w-full">
                <FileDown size={14}/> {lang === "en" ? `Export ${parties.length} Parties to CSV` : `${parties.length} Cariyi CSV Olarak Dışa Aktar`}
              </button>
            </div>
          )}

          {/* ŞABLON İNDİR */}
          {activeTab === "template" && (
            <div className="space-y-3">
              <div className="card p-4" style={{ background: "#dbeafe", border: "1px solid #1d4ed8" }}>
                <div style={{ fontSize: 13, color: "#1d4ed8", lineHeight: 1.5 }}>
                  <b>{lang === "en" ? "Download Import Template" : "İçe Aktarım Şablonu İndir"}</b><br/>
                  {lang === "en"
                    ? "Header row + 2 example parties + instructions. Edit in Excel, then upload via Import tab."
                    : "Başlık satırı + 2 örnek cari + talimatlar. Excel'de düzenleyin, İçe Aktar sekmesinden yükleyin."}
                </div>
              </div>
              <div className="card p-3" style={{ background: "#fef3c7", border: "1px solid #ca8a04" }}>
                <div style={{ fontSize: 12, color: "#92400e", lineHeight: 1.5 }}>
                  <b>{lang === "en" ? "Important Tips" : "Önemli İpuçları"}:</b>
                  <ul style={{ marginTop: 4, paddingLeft: 18, lineHeight: 1.6 }}>
                    <li>{lang === "en" ? "Required: Type and Name" : "Zorunlu: Cari Sınıfı ve Adı / Ünvanı"}</li>
                    <li>{lang === "en" ? "Leave Code blank to auto-generate by type" : "Kodu boş bırakırsanız sınıfa göre otomatik üretilir"}</li>
                    <li>{lang === "en" ? "Matching is by Code, otherwise Tax ID" : "Eşleştirme Cari Kodu ile, yoksa VKN/TCKN ile yapılır"}</li>
                    <li>{lang === "en" ? "Save as CSV (UTF-8)" : "CSV (UTF-8) olarak kaydedin"}</li>
                  </ul>
                </div>
              </div>
              <button onClick={handleDownloadTemplate} className="btn btn-primary w-full">
                <Download size={14}/> {lang === "en" ? "Download Empty Template" : "Boş Şablon İndir"}
              </button>
            </div>
          )}

          {/* İÇE AKTAR */}
          {activeTab === "import" && (
            <div className="space-y-3">
              <div className="card p-4" style={{ background: "#fee2e2", border: "1px solid #b91c1c" }}>
                <div style={{ fontSize: 12, color: "#b91c1c", lineHeight: 1.5 }}>
                  <b>⚠ {lang === "en" ? "Warning" : "Uyarı"}</b><br/>
                  {lang === "en"
                    ? "Import will modify your party list. Export current data first as backup!"
                    : "İçe aktarım cari listenizi değiştirecek. Önce mevcut veriyi yedek olarak dışa aktarın!"}
                </div>
              </div>
              <div>
                <div className="label mb-2">{lang === "en" ? "Import Mode" : "İçe Aktarım Modu"}</div>
                <div className="space-y-2">
                  {[
                    { id: "only_new",    label: { tr: "Sadece Yeni Carileri Ekle", en: "Only Add New" }, desc: { tr: "Mevcut cariler atlanır, yalnızca yeni cariler eklenir.", en: "Existing parties are skipped, only new ones are added." }, color: "#15803d" },
                    { id: "merge",       label: { tr: "Mevcutları Güncelle + Yenileri Ekle", en: "Merge (Update + Add)" }, desc: { tr: "Var olan cariler güncellenir, yeniler eklenir. (Önerilen)", en: "Existing parties are updated, new ones added. (Recommended)" }, color: "#1d4ed8", recommended: true },
                    { id: "replace_all", label: { tr: "Hepsini Temizle ve Yükle", en: "Replace All" }, desc: { tr: "TEHLİKELİ: Tüm mevcut cariler silinir, sadece dosyadakiler kalır.", en: "DANGEROUS: All existing parties are deleted, only file contents remain." }, color: "#b91c1c" },
                  ].map(opt => (
                    <label key={opt.id} className="flex items-start gap-2 cursor-pointer p-2 rounded" style={{
                      background: importMode === opt.id ? opt.color + "15" : "var(--bg)",
                      border: `1px solid ${importMode === opt.id ? opt.color : "var(--line)"}`,
                    }}>
                      <input type="radio" name="partyImportMode" value={opt.id}
                        checked={importMode === opt.id}
                        onChange={e => { setImportMode(e.target.value); if (parsedRows.length) validateRows(parsedRows); }}
                        style={{ marginTop: 2 }}/>
                      <div>
                        <div style={{ fontSize: 12, fontWeight: 600, color: importMode === opt.id ? opt.color : "var(--ink)" }}>
                          {opt.label[lang] || opt.label.tr}
                          {opt.recommended && (
                            <span className="ml-2" style={{ fontSize: 9, background: opt.color, color: "#fff", padding: "1px 6px", borderRadius: 3 }}>
                              {lang === "en" ? "RECOMMENDED" : "ÖNERİLEN"}
                            </span>
                          )}
                        </div>
                        <div style={{ fontSize: 11, color: "var(--ink-mute)", marginTop: 2 }}>{opt.desc[lang] || opt.desc.tr}</div>
                      </div>
                    </label>
                  ))}
                </div>
              </div>
              <div>
                <div className="label mb-2">{lang === "en" ? "CSV File" : "CSV Dosyası"}</div>
                <input ref={fileInputRef} type="file" accept=".csv,.txt" onChange={handleFileChange} className="input w-full text-xs"/>
                {importFile && (
                  <div className="mt-2 text-xs" style={{ color: "var(--ink-mute)" }}>
                    <b>{lang === "en" ? "File" : "Dosya"}:</b> {importFile.name} ({(importFile.size / 1024).toFixed(1)} KB)
                  </div>
                )}
              </div>
              {isProcessing && (
                <div className="card p-3 text-center" style={{ background: "var(--bg-alt)" }}>
                  <RefreshCw size={20} className="animate-spin" style={{ margin: "0 auto" }}/>
                  <div className="text-xs mt-2">{lang === "en" ? "Processing..." : "İşleniyor..."}</div>
                </div>
              )}
              {validationResults && !isProcessing && (
                <div className="space-y-2">
                  <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                    <div className="card p-2" style={{ borderLeft: "4px solid #737373" }}>
                      <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Total" : "Toplam"}</div>
                      <div className="mono" style={{ fontSize: 18, fontWeight: 700 }}>{validationResults.total}</div>
                    </div>
                    <div className="card p-2" style={{ borderLeft: "4px solid #15803d" }}>
                      <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "New" : "Yeni"}</div>
                      <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#15803d" }}>{validationResults.newCount}</div>
                    </div>
                    <div className="card p-2" style={{ borderLeft: "4px solid #1d4ed8" }}>
                      <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Update" : "Güncelleme"}</div>
                      <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#1d4ed8" }}>{validationResults.updateCount}</div>
                    </div>
                    <div className="card p-2" style={{ borderLeft: "4px solid #b91c1c" }}>
                      <div style={{ fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Errors" : "Hata"}</div>
                      <div className="mono" style={{ fontSize: 18, fontWeight: 700, color: "#b91c1c" }}>{validationResults.errorCount}</div>
                    </div>
                  </div>
                  {validationResults.errors.length > 0 && (
                    <div className="card p-3" style={{ background: "#fee2e2", border: "1px solid #b91c1c", maxHeight: 200, overflowY: "auto" }}>
                      <div style={{ fontSize: 12, fontWeight: 700, color: "#b91c1c", marginBottom: 6 }}>
                        ⚠ {lang === "en" ? `${validationResults.errors.length} Errors` : `${validationResults.errors.length} Hata`}
                      </div>
                      {validationResults.errors.slice(0, 20).map((err, i) => (
                        <div key={i} style={{ fontSize: 11, marginBottom: 4, color: "#b91c1c", lineHeight: 1.4 }}>
                          <b>{lang === "en" ? `Row ${err.row}` : `Satır ${err.row}`}</b>
                          {err.code && <span className="mono"> ({err.code})</span>}:
                          {err.messages.map((m, j) => <span key={j}> {m};</span>)}
                        </div>
                      ))}
                      {validationResults.errors.length > 20 && (
                        <div style={{ fontSize: 11, color: "#b91c1c", marginTop: 4, fontStyle: "italic" }}>
                          ... {lang === "en" ? `and ${validationResults.errors.length - 20} more` : `ve ${validationResults.errors.length - 20} daha`}
                        </div>
                      )}
                    </div>
                  )}
                  {validationResults.warnings.length > 0 && (
                    <div className="card p-3" style={{ background: "#fef3c7", border: "1px solid #ca8a04", maxHeight: 150, overflowY: "auto" }}>
                      <div style={{ fontSize: 12, fontWeight: 700, color: "#92400e", marginBottom: 6 }}>
                        {lang === "en" ? `${validationResults.warnings.length} Warnings` : `${validationResults.warnings.length} Uyarı`}
                      </div>
                      {validationResults.warnings.slice(0, 10).map((w, i) => (
                        <div key={i} style={{ fontSize: 11, marginBottom: 3, color: "#92400e" }}>
                          <b>{lang === "en" ? `Row ${w.row}` : `Satır ${w.row}`}</b>: {w.message}
                        </div>
                      ))}
                    </div>
                  )}
                  {parsedRows.length > 0 && (
                    <div>
                      <div className="label mb-1">{lang === "en" ? "Preview (first 5 rows)" : "Önizleme (ilk 5 satır)"}</div>
                      <div className="card" style={{ padding: 0, maxHeight: 200, overflow: "auto" }}>
                        <table style={{ width: "100%", fontSize: 10, borderCollapse: "collapse" }}>
                          <thead>
                            <tr style={{ background: "var(--bg-alt)", position: "sticky", top: 0 }}>
                              <th style={{ padding: 4, textAlign: "left" }}>#</th>
                              <th style={{ padding: 4, textAlign: "left" }}>{lang === "en" ? "Code" : "Kod"}</th>
                              <th style={{ padding: 4, textAlign: "left" }}>{lang === "en" ? "Name" : "Ad/Ünvan"}</th>
                              <th style={{ padding: 4, textAlign: "left" }}>{lang === "en" ? "Type" : "Sınıf"}</th>
                              <th style={{ padding: 4, textAlign: "left" }}>VKN/TCKN</th>
                            </tr>
                          </thead>
                          <tbody>
                            {parsedRows.slice(0, 5).map((row, i) => (
                              <tr key={i} style={{ borderBottom: "1px solid var(--line)" }}>
                                <td style={{ padding: 4 }}>{row._rowNumber}</td>
                                <td style={{ padding: 4 }} className="mono">{row.code || "—"}</td>
                                <td style={{ padding: 4 }}>{row.name}</td>
                                <td style={{ padding: 4 }}>{row.type}</td>
                                <td style={{ padding: 4 }} className="mono">{row.taxId || "—"}</td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-5 py-3 border-t flex items-center justify-between" style={{ background: "var(--bg-alt)" }}>
          <button onClick={onClose} className="btn btn-ghost text-xs">{lang === "en" ? "Close" : "Kapat"}</button>
          {activeTab === "import" && validationResults && (
            <button onClick={handleImport}
              disabled={!validationResults.canProceed || isProcessing}
              className="btn btn-primary text-xs"
              style={!validationResults.canProceed ? { opacity: 0.5, cursor: "not-allowed" } : {}}>
              <Upload size={13}/> {lang === "en" ? "Import" : "İçe Aktar"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

/* ===================================================================== */
/* PARTY LIST VIEW (TMO mockup 6_1)                                      */
/* ===================================================================== */
function PartyListView({ parties, accounts, entries, cariVouchers, invoices = [], lang, session, onEdit, onViewMuavin, onDelete }) {
  const [filters, setFilters] = useState({
    code: "", name: "", taxId: "",
    cariClass: "all", status: "all", personType: "all",
    blacklistBuy: "all", blacklistSell: "all", banned: "all",
  });
  const [sortBy, setSortBy] = useState("balance");

  // Bakiye hesapla
  const partiesWithBalance = useMemo(() => {
    return parties.map(p => {
      let voucherDebit = 0, voucherCredit = 0;
      cariVouchers.forEach(v => {
        if (v.partyId !== p.id || v.status !== "posted") return;
        (v.lines || []).forEach(line => {
          voucherDebit += Number(line.debit) || 0;
          voucherCredit += Number(line.credit) || 0;
        });
      });
      let entryDebit = 0, entryCredit = 0;
      const partyAccountCodes = [
        p.accounting?.accountCode_alici, p.accounting?.accountCode_satici,
        p.accounting?.accountCode_personel, p.accounting?.accountCode_diger,
      ].filter(Boolean);
      entries.forEach(e => {
        if (e.status !== "posted") return;
        (e.lines || []).forEach(line => {
          if (!partyAccountCodes.includes(line.accountCode)) return;
          entryDebit += Number(line.debit) || 0;
          entryCredit += Number(line.credit) || 0;
        });
      });
      // Faturalar (cari ile bağlı)
      let invoiceDebit = 0, invoiceCredit = 0;
      let invoiceCount = 0;
      invoices.forEach(inv => {
        if (inv.partyId !== p.id) return;
        invoiceCount++;
        const total = Number(inv.total) || 0;
        const paid = Number(inv.paidAmount) || 0;
        if (inv.type === "in") {
          // Gelen fatura → tedarikçiye borç doğurur (320 alacak)
          invoiceCredit += total;
          invoiceDebit += paid; // ödenen kısım
        } else {
          // Giden fatura → müşteriden alacak doğurur (120 borç)
          invoiceDebit += total;
          invoiceCredit += paid; // tahsil edilen kısım
        }
      });
      const debit = voucherDebit + entryDebit + invoiceDebit;
      const credit = voucherCredit + entryCredit + invoiceCredit;
      return { ...p, debit, credit, balance: debit - credit, invoiceCount };
    });
  }, [parties, cariVouchers, entries, invoices]);

  // Filtreleme
  const filtered = useMemo(() => {
    let list = partiesWithBalance;
    if (filters.code.trim()) list = list.filter(p => p.code?.toLowerCase().includes(filters.code.toLowerCase().trim()));
    if (filters.name.trim()) list = list.filter(p => p.name?.toLowerCase().includes(filters.name.toLowerCase().trim()));
    if (filters.taxId.trim()) list = list.filter(p => p.taxId?.includes(filters.taxId.trim()));
    if (filters.cariClass !== "all") list = list.filter(p => p.type === filters.cariClass);
    if (filters.status !== "all") list = list.filter(p => (p.status || "active") === filters.status);
    if (filters.personType !== "all") list = list.filter(p => (p.personType || "real") === filters.personType);
    if (filters.blacklistBuy !== "all") list = list.filter(p => String(p.risk?.blacklistBuy || false) === filters.blacklistBuy);
    if (filters.blacklistSell !== "all") list = list.filter(p => String(p.risk?.blacklistSell || false) === filters.blacklistSell);
    if (filters.banned !== "all") list = list.filter(p => String(p.risk?.bannedFromTender || false) === filters.banned);

    list = [...list];
    if (sortBy === "balance") list.sort((a, b) => Math.abs(b.balance) - Math.abs(a.balance));
    else if (sortBy === "name") list.sort((a, b) => (a.name || "").localeCompare(b.name || "", "tr"));
    else if (sortBy === "code") list.sort((a, b) => (a.code || "").localeCompare(b.code || "", "tr", { numeric: true }));
    return list;
  }, [partiesWithBalance, filters, sortBy]);

  // İstatistikler
  const stats = useMemo(() => {
    let totalRec = 0, totalPay = 0, activeCount = 0, blacklistCount = 0;
    partiesWithBalance.forEach(p => {
      if (p.status === "active" || !p.status) activeCount++;
      if (p.risk?.blacklistBuy || p.risk?.blacklistSell) blacklistCount++;
      if (p.balance > 0) totalRec += p.balance;
      if (p.balance < 0) totalPay += -p.balance;
    });
    return { totalRec, totalPay, activeCount, blacklistCount, total: partiesWithBalance.length };
  }, [partiesWithBalance]);

  return (
    <div className="space-y-3">
      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <div className="card p-3" style={{ borderLeft: "4px solid #0f766e" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Total Receivables" : "Toplam Alacak"}</div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, color: "#0f766e", marginTop: 4 }}>{fmtTL(stats.totalRec)} ₺</div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #b91c1c" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Total Payables" : "Toplam Borç"}</div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, color: "#b91c1c", marginTop: 4 }}>{fmtTL(stats.totalPay)} ₺</div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #1d4ed8" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Active Parties" : "Aktif Cariler"}</div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, color: "#1d4ed8", marginTop: 4 }}>{stats.activeCount} / {stats.total}</div>
        </div>
        <div className="card p-3" style={{ borderLeft: "4px solid #ea580c" }}>
          <div style={{ fontSize: 10, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Blacklisted" : "Kara Listede"}</div>
          <div className="mono" style={{ fontSize: 16, fontWeight: 700, color: "#ea580c", marginTop: 4 }}>{stats.blacklistCount}</div>
        </div>
      </div>

      {/* Arama Kriterleri */}
      <div className="card p-3">
        <div className="label mb-2 flex items-center gap-2">
          <Filter size={11}/> {lang === "en" ? "Search Criteria" : "Arama Kriterleri"}
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
          <div>
            <div className="label mb-1">{lang === "en" ? "Code" : "Cari Ünvan Kodu"}</div>
            <input className="input text-xs w-full mono" value={filters.code}
              onChange={e => setFilters({ ...filters, code: e.target.value })} placeholder="320.A001"/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Name" : "Cari Ünvan Adı"}</div>
            <input className="input text-xs w-full" value={filters.name}
              onChange={e => setFilters({ ...filters, name: e.target.value })}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Tax ID" : "T.C./Vergi No"}</div>
            <input className="input text-xs w-full mono" value={filters.taxId}
              onChange={e => setFilters({ ...filters, taxId: e.target.value })}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Person Type" : "Kişi Türü"}</div>
            <select className="input text-xs w-full" value={filters.personType}
              onChange={e => setFilters({ ...filters, personType: e.target.value })}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="real">{lang === "en" ? "Real Person" : "Gerçek"}</option>
              <option value="legal">{lang === "en" ? "Legal Entity" : "Tüzel"}</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Class" : "Cari Sınıf"}</div>
            <select className="input text-xs w-full" value={filters.cariClass}
              onChange={e => setFilters({ ...filters, cariClass: e.target.value })}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              {Object.entries(PARTY_TYPES).map(([k, v]) => (
                <option key={k} value={k}>{v[lang] || v.tr}</option>
              ))}
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Status" : "Statü"}</div>
            <select className="input text-xs w-full" value={filters.status}
              onChange={e => setFilters({ ...filters, status: e.target.value })}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="active">{lang === "en" ? "Active" : "Aktif"}</option>
              <option value="passive">{lang === "en" ? "Passive" : "Pasif"}</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Buy Blacklist" : "Alış Kara Liste"}</div>
            <select className="input text-xs w-full" value={filters.blacklistBuy}
              onChange={e => setFilters({ ...filters, blacklistBuy: e.target.value })}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="true">EVET</option>
              <option value="false">HAYIR</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Banned from Tender" : "İhaleden Men"}</div>
            <select className="input text-xs w-full" value={filters.banned}
              onChange={e => setFilters({ ...filters, banned: e.target.value })}>
              <option value="all">{lang === "en" ? "All" : "Tümü"}</option>
              <option value="true">EVET</option>
              <option value="false">HAYIR</option>
            </select>
          </div>
        </div>
        <div className="flex items-center gap-2 mt-3">
          <button onClick={() => setFilters({ code: "", name: "", taxId: "", cariClass: "all", status: "all", personType: "all", blacklistBuy: "all", blacklistSell: "all", banned: "all" })} className="btn btn-ghost text-xs">
            <RefreshCw size={11}/> {lang === "en" ? "Clear" : "Temizle"}
          </button>
          <select className="input text-xs ml-auto" value={sortBy} onChange={e => setSortBy(e.target.value)}>
            <option value="balance">{lang === "en" ? "Sort: Balance" : "Sırala: Bakiye"}</option>
            <option value="name">{lang === "en" ? "Sort: Name" : "Sırala: İsim"}</option>
            <option value="code">{lang === "en" ? "Sort: Code" : "Sırala: Kod"}</option>
          </select>
          <span className="text-xs" style={{ color: "var(--ink-mute)" }}>
            {filtered.length} / {partiesWithBalance.length}
          </span>
        </div>
      </div>

      {/* Tablo */}
      {filtered.length === 0 ? (
        <div className="card p-10 text-center">
          <Building2 size={32} style={{ margin: "0 auto", color: "#0891b2", opacity: 0.5 }}/>
          <div style={{ fontSize: 14, fontWeight: 600, marginTop: 12 }}>
            {lang === "en" ? "No parties found" : "Cari bulunamadı"}
          </div>
          <div style={{ fontSize: 12, color: "var(--ink-mute)", marginTop: 4 }}>
            {lang === "en" ? "Click 'New Party' button to create one" : "'Yeni Cari' butonuna tıklayarak oluşturun"}
          </div>
        </div>
      ) : (
        <div className="card" style={{ padding: 0, overflow: "hidden" }}>
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", fontSize: 11, borderCollapse: "collapse", minWidth: 1100 }}>
              <thead>
                <tr style={{ background: "var(--bg-alt)", borderBottom: "2px solid var(--line)" }}>
                  <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Code" : "Kod"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Name" : "Adı/Ünvanı"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Class" : "Sınıf"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Person" : "Kişi"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "left", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>VKN/TCKN</th>
                  <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Status" : "Statü"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "right", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Balance" : "Bakiye (TL)"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>BL</th>
                  <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Banned" : "Men"}</th>
                  <th style={{ padding: "8px 10px", textAlign: "center", fontSize: 10, fontWeight: 700, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Actions" : "İşlem"}</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(p => {
                  const cfg = PARTY_TYPES[p.type] || PARTY_TYPES.other;
                  const isFavorable = p.type === "supplier" ? p.balance <= 0 : p.balance >= 0;
                  return (
                    <tr key={p.id} style={{ borderBottom: "1px solid var(--line)" }}>
                      <td className="mono" style={{ padding: "6px 10px", fontWeight: 700, color: cfg.color }}>{p.code}</td>
                      <td style={{ padding: "6px 10px", fontSize: 11.5, fontWeight: 600 }}>{p.name}</td>
                      <td style={{ padding: "6px 10px" }}>
                        <span className="chip" style={{ background: cfg.bg, color: cfg.color, padding: "2px 8px", fontSize: 9, fontWeight: 700 }}>
                          {cfg[lang] || cfg.tr}
                        </span>
                      </td>
                      <td style={{ padding: "6px 10px", fontSize: 10.5 }}>
                        {p.personType === "legal" ? (lang === "en" ? "Legal" : "Tüzel") : (lang === "en" ? "Real" : "Gerçek")}
                      </td>
                      <td className="mono" style={{ padding: "6px 10px", fontSize: 10.5 }}>{p.taxId || "—"}</td>
                      <td style={{ padding: "6px 10px", textAlign: "center" }}>
                        <span className="chip" style={{
                          background: (p.status || "active") === "active" ? "#dcfce7" : "#fee2e2",
                          color: (p.status || "active") === "active" ? "#15803d" : "#b91c1c",
                          padding: "1px 6px", fontSize: 9, fontWeight: 700,
                        }}>
                          {(p.status || "active") === "active" ? "AKTİF" : "PASİF"}
                        </span>
                      </td>
                      <td className="mono text-right" style={{
                        padding: "6px 10px", fontWeight: 700,
                        color: Math.abs(p.balance) < 0.01 ? "var(--ink-mute)" : (isFavorable ? "#0f766e" : "#b91c1c"),
                      }}>
                        {Math.abs(p.balance) < 0.01 ? "—" : `${fmtTL(Math.abs(p.balance))} ${p.balance > 0 ? "(B)" : "(A)"}`}
                      </td>
                      <td style={{ padding: "6px 10px", textAlign: "center" }}>
                        {(p.risk?.blacklistBuy || p.risk?.blacklistSell) && (
                          <span title={lang === "en" ? "Blacklist" : "Kara liste"} style={{ color: "#b91c1c", fontWeight: 700, fontSize: 14 }}>●</span>
                        )}
                      </td>
                      <td style={{ padding: "6px 10px", textAlign: "center" }}>
                        {p.risk?.bannedFromTender && <span title={lang === "en" ? "Banned" : "İhaleden men"} style={{ color: "#ea580c", fontWeight: 700, fontSize: 14 }}>⨯</span>}
                      </td>
                      <td style={{ padding: "6px 10px", textAlign: "center" }}>
                        <div className="flex items-center justify-center gap-1">
                          <button onClick={() => onViewMuavin(p)} className="btn btn-ghost"
                            style={{ padding: "2px 6px", fontSize: 10 }}
                            title={lang === "en" ? "Subsidiary Ledger" : "Muavin Defteri"}>
                            <FileText size={11}/>
                          </button>
                          <button onClick={() => onEdit(p)} className="btn btn-ghost"
                            style={{ padding: "2px 6px", fontSize: 10 }} title={lang === "en" ? "Edit" : "Düzenle"}>
                            <Edit3 size={11}/>
                          </button>
                          <button onClick={() => onDelete(p)} className="btn btn-ghost"
                            style={{ padding: "2px 6px", fontSize: 10, color: "#b91c1c" }} title={lang === "en" ? "Delete" : "Sil"}>
                            <Trash2 size={11}/>
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

/* ===================================================================== */
/* PARTY CARD EDITOR — 11 SEKMELİ FORM (TMO mockup 6_1_2 ile 6_1_12)     */
/* ===================================================================== */
function PartyCardEditor({ party, data, session, lang, onSave, onCancel }) {
  const [edited, setEdited] = useState(party);
  const [activeTab, setActiveTab] = useState("cari");

  const tabs = [
    { id: "cari",        label: { tr: "Cari Bilgileri", en: "Party Info" },          icon: Users },
    { id: "banka",       label: { tr: "Banka Bilgileri", en: "Bank Info" },          icon: Landmark },
    { id: "risk",        label: { tr: "Risk Bilgileri", en: "Risk" },                icon: AlertTriangle },
    { id: "params",      label: { tr: "Parametreler", en: "Parameters" },            icon: Settings },
    { id: "muhasebe",    label: { tr: "Muhasebe Hesap", en: "Accounting" },          icon: ClipboardList },
    { id: "teminat",     label: { tr: "Teminat", en: "Guarantee" },                  icon: Shield },
    { id: "entegrasyon", label: { tr: "Entegrasyon", en: "Integration" },            icon: Layers },
    { id: "kvkk",        label: { tr: "KVKK", en: "KVKK" },                          icon: FileText },
    { id: "form",        label: { tr: "Form Gönderim", en: "Form Sending" },         icon: Send },
    { id: "kimlik",      label: { tr: "Kimlik Bilgileri", en: "Identity" },          icon: UserCheck },
    { id: "haciz",       label: { tr: "Haciz Bilgileri", en: "Seizure" },            icon: Lock, accent: "#b91c1c" },
    { id: "ai_insights", label: { tr: "AI İçgörüler", en: "AI Insights" },           icon: Sparkles, accent: "#7c3aed" },
  ];

  const updateField = (path, value) => {
    setEdited(prev => {
      const newObj = { ...prev };
      const keys = path.split(".");
      let cur = newObj;
      for (let i = 0; i < keys.length - 1; i++) {
        cur[keys[i]] = { ...(cur[keys[i]] || {}) };
        cur = cur[keys[i]];
      }
      cur[keys[keys.length - 1]] = value;
      return newObj;
    });
  };

  return (
    <div className="space-y-3">
      {/* Cari başlık */}
      <div className="card p-3 flex items-center justify-between flex-wrap gap-2">
        <div className="flex items-center gap-3">
          <span className="mono" style={{ fontSize: 16, fontWeight: 700, color: PARTY_TYPES[edited.type]?.color || "#737373" }}>{edited.code}</span>
          <span style={{ fontSize: 14, fontWeight: 700 }}>{edited.name}</span>
          <span className="chip" style={{
            background: PARTY_TYPES[edited.type]?.bg, color: PARTY_TYPES[edited.type]?.color,
            padding: "2px 8px", fontSize: 10, fontWeight: 700,
          }}>
            {PARTY_TYPES[edited.type]?.[lang] || PARTY_TYPES[edited.type]?.tr}
          </span>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={onCancel} className="btn btn-ghost text-xs">
            {lang === "en" ? "Cancel" : "İptal"}
          </button>
          <button onClick={() => onSave(edited)} className="btn text-xs"
            style={{ background: "#15803d", color: "#fff", fontWeight: 700, padding: "6px 14px" }}>
            <Save size={11}/> {lang === "en" ? "Save" : "Kaydet"}
          </button>
        </div>
      </div>

      {/* Sekmeler */}
      <div className="card p-0" style={{ overflow: "hidden" }}>
        <div className="flex items-center gap-0 overflow-x-auto" style={{ borderBottom: "1px solid var(--line)" }}>
          {tabs.map(tab => {
            const Icon = tab.icon;
            const isActive = activeTab === tab.id;
            const color = tab.accent || "var(--accent)";
            return (
              <button key={tab.id} onClick={() => setActiveTab(tab.id)} className="text-xs flex-shrink-0"
                style={{
                  padding: "10px 14px",
                  background: isActive ? color : "transparent",
                  color: isActive ? "#fff" : "var(--ink-soft)",
                  fontWeight: isActive ? 700 : 500,
                  cursor: "pointer",
                  borderRight: "1px solid var(--line)",
                }}>
                <Icon size={11} style={{ display: "inline", marginRight: 4 }}/>
                {tab.label[lang] || tab.label.tr}
              </button>
            );
          })}
        </div>

        {/* Tab içerikleri */}
        <div className="p-4">
          {activeTab === "cari"        && <TabCariBilgileri        party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "banka"       && <TabBankaBilgileri       party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "risk"        && <TabRiskBilgileri        party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "params"      && <TabParametreler         party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "muhasebe"    && <TabMuhasebeHesap        party={edited} updateField={updateField} lang={lang} accounts={data.accChartOfAccounts || []}/>}
          {activeTab === "teminat"     && <TabTeminat              party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "entegrasyon" && <TabEntegrasyon          party={edited} updateField={updateField} lang={lang} banks={data.bankAccounts || []}/>}
          {activeTab === "kvkk"        && <TabKVKK                 party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "form"        && <TabFormGonderim         party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "kimlik"      && <TabKimlik               party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "haciz"       && <TabHaciz                party={edited} updateField={updateField} lang={lang}/>}
          {activeTab === "ai_insights" && (
            <AICariInsightsPanel
              party={edited}
              invoices={data.invoices || []}
              cariVouchers={data.accCariVouchers || []}
              lang={lang}
            />
          )}
        </div>
      </div>
    </div>
  );
}

/* ===================================================================== */
/* TAB 1: CARİ BİLGİLERİ (TMO mockup 6_1_2)                             */
/* ===================================================================== */
function TabCariBilgileri({ party, updateField, lang }) {
  return (
    <div className="space-y-4">
      <div>
        <div className="label mb-2">{lang === "en" ? "Real/Legal Person Info" : "Gerçek / Tüzel Kişi Bilgileri"}</div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Code" : "Cari Ünvan Kodu"} *</div>
            <input className="input w-full mono" value={party.code || ""} onChange={e => updateField("code", e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Origin" : "Menşei"}</div>
            <select className="input w-full" value={party.origin || "TR"} onChange={e => updateField("origin", e.target.value)}>
              <option value="TR">TÜRKİYE CUMHURİYETİ</option>
              <option value="DE">ALMANYA</option>
              <option value="US">ABD</option>
              <option value="GB">İNGİLTERE</option>
              <option value="SA">SUUDİ ARABİSTAN</option>
              <option value="SY">SURİYE</option>
              <option value="IR">İRAN</option>
              <option value="RU">RUSYA</option>
              <option value="CN">ÇİN</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Project Code" : "Proje Kodu"}</div>
            <input className="input w-full" value={party.projectCode || ""} onChange={e => updateField("projectCode", e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Person Type" : "Kişi Türü"} *</div>
            <select className="input w-full" value={party.personType || "real"} onChange={e => updateField("personType", e.target.value)}>
              <option value="real">{lang === "en" ? "Real Person" : "Gerçek Kişi"}</option>
              <option value="legal">{lang === "en" ? "Legal Entity" : "Tüzel Kişi"}</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Class" : "Cari Sınıf"} *</div>
            <select className="input w-full" value={party.type || "customer"} onChange={e => updateField("type", e.target.value)}>
              {Object.entries(PARTY_TYPES).map(([k, v]) => (
                <option key={k} value={k}>{v[lang] || v.tr}</option>
              ))}
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Special Code" : "Özel Kod"}</div>
            <input className="input w-full" value={party.specialCode || ""} onChange={e => updateField("specialCode", e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{party.personType === "legal" ? "Vergi Kimlik No" : "T.C. Kimlik No"} *</div>
            <div className="flex items-center gap-1">
              <input className="input flex-1 mono" value={party.taxId || ""} onChange={e => updateField("taxId", e.target.value.replace(/\D/g, "").slice(0, 11))}/>
              <button className="btn btn-ghost text-xs" title={lang === "en" ? "Coming soon" : "Yakında"} disabled style={{ opacity: 0.6 }}>NVI</button>
              <button className="btn btn-ghost text-xs" title={lang === "en" ? "Coming soon" : "Yakında"} disabled style={{ opacity: 0.6 }}>VEDOP</button>
            </div>
          </div>
          <div>
            <div className="label mb-1">Mersis No</div>
            <input className="input w-full mono" value={party.mersisNo || ""} onChange={e => updateField("mersisNo", e.target.value)} placeholder="0234567890123456"/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Status" : "Statü"} *</div>
            <select className="input w-full" value={party.status || "active"} onChange={e => updateField("status", e.target.value)}>
              <option value="active">AKTİF</option>
              <option value="passive">PASİF</option>
            </select>
          </div>
          <div className="md:col-span-2">
            <div className="label mb-1">{lang === "en" ? "Name / Title" : "Adı / Soyadı / Ünvanı"} *</div>
            <input className="input w-full" value={party.name || ""} onChange={e => updateField("name", e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Payment Term (Days)" : "Vade Süresi (Gün)"}</div>
            <input type="number" className="input w-full mono" value={party.paymentTermDays || 0}
              onChange={e => updateField("paymentTermDays", Number(e.target.value) || 0)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Tax Office Code" : "Vergi Dairesi Kodu"}</div>
            <input className="input w-full mono" value={party.vatOfficeCode || ""} onChange={e => updateField("vatOfficeCode", e.target.value)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Tax Office Name" : "Vergi Dairesi Adı"}</div>
            <input className="input w-full" value={party.vatOffice || ""} onChange={e => updateField("vatOffice", e.target.value)}/>
          </div>
          <div className="md:col-span-3">
            <div className="label mb-1">{lang === "en" ? "Address" : "Adres"} *</div>
            <textarea className="input w-full" rows={2} value={party.address || ""} onChange={e => updateField("address", e.target.value)}/>
          </div>
        </div>
      </div>

      {/* İletişim Bilgileri */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <div className="label">{lang === "en" ? "Contact Information" : "İletişim Bilgileri"}</div>
          <button onClick={() => updateField("contactInfo", [...(party.contactInfo || []), { id: Date.now(), type: "GSM", number: "", email: "", preferred: false, smsAllowed: false }])} className="btn btn-ghost text-xs">
            <Plus size={11}/> {lang === "en" ? "Add" : "Ekle"}
          </button>
        </div>
        {(party.contactInfo || []).length === 0 ? (
          <div className="text-xs p-3" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
            {lang === "en" ? "No contact info" : "İletişim bilgisi yok"}
          </div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", fontSize: 11 }}>
              <thead>
                <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 100 }}>{lang === "en" ? "Type" : "Tür"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Number" : "Numara"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>E-mail</th>
                  <th style={{ padding: "6px", textAlign: "center", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>{lang === "en" ? "Preferred" : "Tercih"}</th>
                  <th style={{ padding: "6px", textAlign: "center", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 90 }}>SMS</th>
                  <th style={{ padding: "6px", width: 40 }}></th>
                </tr>
              </thead>
              <tbody>
                {(party.contactInfo || []).map((ci, idx) => (
                  <tr key={ci.id} style={{ borderBottom: "1px solid var(--line)" }}>
                    <td style={{ padding: "4px" }}>
                      <select className="input text-xs w-full" value={ci.type} onChange={e => {
                        const newList = [...party.contactInfo]; newList[idx] = { ...ci, type: e.target.value }; updateField("contactInfo", newList);
                      }}>
                        <option value="GSM">GSM</option>
                        <option value="Telefon">{lang === "en" ? "Phone" : "Telefon"}</option>
                        <option value="Fax">Fax</option>
                        <option value="Email">E-mail</option>
                      </select>
                    </td>
                    <td style={{ padding: "4px" }}>
                      <input className="input text-xs w-full mono" value={ci.number} onChange={e => {
                        const newList = [...party.contactInfo]; newList[idx] = { ...ci, number: e.target.value }; updateField("contactInfo", newList);
                      }} placeholder="(532) 111 11 11"/>
                    </td>
                    <td style={{ padding: "4px" }}>
                      <input className="input text-xs w-full" value={ci.email || ""} onChange={e => {
                        const newList = [...party.contactInfo]; newList[idx] = { ...ci, email: e.target.value }; updateField("contactInfo", newList);
                      }}/>
                    </td>
                    <td style={{ padding: "4px", textAlign: "center" }}>
                      <input type="checkbox" checked={ci.preferred || false} onChange={e => {
                        const newList = [...party.contactInfo]; newList[idx] = { ...ci, preferred: e.target.checked }; updateField("contactInfo", newList);
                      }}/>
                    </td>
                    <td style={{ padding: "4px", textAlign: "center" }}>
                      <input type="checkbox" checked={ci.smsAllowed || false} onChange={e => {
                        const newList = [...party.contactInfo]; newList[idx] = { ...ci, smsAllowed: e.target.checked }; updateField("contactInfo", newList);
                      }}/>
                    </td>
                    <td style={{ padding: "4px", textAlign: "center" }}>
                      <button onClick={() => updateField("contactInfo", party.contactInfo.filter(x => x.id !== ci.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                        <Trash2 size={10}/>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Yetkili Bilgileri */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <div className="label">{lang === "en" ? "Authorized Persons" : "Yetkili Bilgileri"}</div>
          <button onClick={() => updateField("authorizedPersons", [...(party.authorizedPersons || []), { id: Date.now(), name: "", title: "", department: "", phone: "", ext: "", email: "" }])} className="btn btn-ghost text-xs">
            <Plus size={11}/> {lang === "en" ? "Add" : "Ekle"}
          </button>
        </div>
        {(party.authorizedPersons || []).length === 0 ? (
          <div className="text-xs p-3" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
            {lang === "en" ? "No authorized persons" : "Yetkili bilgisi yok"}
          </div>
        ) : (
          <div style={{ overflowX: "auto" }}>
            <table style={{ width: "100%", fontSize: 11 }}>
              <thead>
                <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Name" : "Adı Soyadı"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Title" : "Ünvan"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Department" : "Birimi"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Phone" : "Tel"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 80 }}>{lang === "en" ? "Ext" : "Dahili"}</th>
                  <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>E-mail</th>
                  <th style={{ padding: "6px", width: 40 }}></th>
                </tr>
              </thead>
              <tbody>
                {(party.authorizedPersons || []).map((ap, idx) => (
                  <tr key={ap.id} style={{ borderBottom: "1px solid var(--line)" }}>
                    {["name", "title", "department", "phone", "ext", "email"].map(field => (
                      <td key={field} style={{ padding: "4px" }}>
                        <input className="input text-xs w-full" value={ap[field] || ""} onChange={e => {
                          const newList = [...party.authorizedPersons]; newList[idx] = { ...ap, [field]: e.target.value }; updateField("authorizedPersons", newList);
                        }}/>
                      </td>
                    ))}
                    <td style={{ padding: "4px", textAlign: "center" }}>
                      <button onClick={() => updateField("authorizedPersons", party.authorizedPersons.filter(x => x.id !== ap.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                        <Trash2 size={10}/>
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}

/* ===================================================================== */
/* TAB 2: BANKA BİLGİLERİ (TMO mockup 6_1_3)                            */
/* ===================================================================== */
function TabBankaBilgileri({ party, updateField, lang }) {
  const banks = party.banks || [];
  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <div className="label">{lang === "en" ? "Bank Accounts" : "Banka Bilgileri"}</div>
        <button onClick={() => updateField("banks", [...banks, { id: Date.now(), bankName: "", bankCode: "", branchName: "", branchCode: "", currency: "TRY", accountNo: "", iban: "", swift: "", status: "active", projectCode: "", specialCode: "", isSalaryAccount: false }])} className="btn btn-ghost text-xs">
          <Plus size={11}/> {lang === "en" ? "Add Bank" : "Banka Ekle"}
        </button>
      </div>
      {banks.length === 0 ? (
        <div className="text-xs p-6" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
          {lang === "en" ? "No bank accounts. Click 'Add Bank' to start." : "Banka hesabı yok."}
        </div>
      ) : (
        <div className="space-y-2">
          {banks.map((b, idx) => (
            <div key={b.id} className="card p-3" style={{ background: b.isSalaryAccount ? "#f0fdf4" : "var(--paper)" }}>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-2">
                <div>
                  <div className="label mb-1">{lang === "en" ? "Bank" : "Banka Adı"} *</div>
                  <input className="input text-xs w-full" value={b.bankName || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, bankName: e.target.value }; updateField("banks", newList);
                  }} placeholder="Akbank T.A.Ş."/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Bank Code" : "Banka Kodu"}</div>
                  <input className="input text-xs w-full mono" value={b.bankCode || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, bankCode: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Branch" : "Şube Adı"} *</div>
                  <input className="input text-xs w-full" value={b.branchName || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, branchName: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Branch Code" : "Şube Kodu"}</div>
                  <input className="input text-xs w-full mono" value={b.branchCode || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, branchCode: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Currency" : "Döviz Cinsi"} *</div>
                  <select className="input text-xs w-full" value={b.currency || "TRY"} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, currency: e.target.value }; updateField("banks", newList);
                  }}>
                    <option value="TRY">TRY</option>
                    <option value="USD">USD</option>
                    <option value="EUR">EUR</option>
                    <option value="GBP">GBP</option>
                  </select>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Account No" : "Hesap No"} *</div>
                  <input className="input text-xs w-full mono" value={b.accountNo || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, accountNo: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
                <div className="md:col-span-2">
                  <div className="label mb-1">IBAN *</div>
                  <input className="input text-xs w-full mono" value={b.iban || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, iban: e.target.value.toUpperCase() }; updateField("banks", newList);
                  }} placeholder="TR34 5678 9012 3456 7890 1234 56" maxLength={32}/>
                </div>
                <div>
                  <div className="label mb-1">SWIFT *</div>
                  <input className="input text-xs w-full mono" value={b.swift || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, swift: e.target.value.toUpperCase() }; updateField("banks", newList);
                  }}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Status" : "Durum"}</div>
                  <select className="input text-xs w-full" value={b.status || "active"} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, status: e.target.value }; updateField("banks", newList);
                  }}>
                    <option value="active">AKTİF</option>
                    <option value="passive">PASİF</option>
                  </select>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Project Code" : "Proje Kodu"}</div>
                  <input className="input text-xs w-full" value={b.projectCode || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, projectCode: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
                <div>
                  <div className="label mb-1">{lang === "en" ? "Special Code" : "Özel Kod"}</div>
                  <input className="input text-xs w-full" value={b.specialCode || ""} onChange={e => {
                    const newList = [...banks]; newList[idx] = { ...b, specialCode: e.target.value }; updateField("banks", newList);
                  }}/>
                </div>
              </div>
              <div className="flex items-center justify-between mt-3" style={{ borderTop: "1px solid var(--line)", paddingTop: 8 }}>
                <label className="flex items-center gap-2 cursor-pointer">
                  <input type="radio" name="salaryAccount" checked={b.isSalaryAccount || false} onChange={() => {
                    const newList = banks.map((x, i) => ({ ...x, isSalaryAccount: i === idx }));
                    updateField("banks", newList);
                  }}/>
                  <span className="text-xs font-semibold">{lang === "en" ? "Salary Account" : "Maaş Hesabı"}</span>
                </label>
                <button onClick={() => updateField("banks", banks.filter(x => x.id !== b.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                  <Trash2 size={11}/> {lang === "en" ? "Remove" : "Sil"}
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ===================================================================== */
/* TAB 3: RİSK BİLGİLERİ (TMO mockup 6_1_4)                              */
/* ===================================================================== */
function TabRiskBilgileri({ party, updateField, lang }) {
  const risk = party.risk || {};
  const details = risk.details || [];
  return (
    <div className="space-y-4">
      <div>
        <div className="label mb-2">{lang === "en" ? "Risk Information" : "Risk Bilgileri"}</div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Buy Blacklist" : "Alış Kara Liste"}</div>
            <select className="input text-xs w-full" value={String(risk.blacklistBuy || false)} onChange={e => updateField("risk.blacklistBuy", e.target.value === "true")}>
              <option value="false">HAYIR</option>
              <option value="true">EVET</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Sell Blacklist" : "Satış Kara Liste"}</div>
            <select className="input text-xs w-full" value={String(risk.blacklistSell || false)} onChange={e => updateField("risk.blacklistSell", e.target.value === "true")}>
              <option value="false">HAYIR</option>
              <option value="true">EVET</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Banned from Tender" : "İhaleden Men"}</div>
            <select className="input text-xs w-full" value={String(risk.bannedFromTender || false)} onChange={e => updateField("risk.bannedFromTender", e.target.value === "true")}>
              <option value="false">HAYIR</option>
              <option value="true">EVET</option>
            </select>
          </div>
          <div></div>
          <div>
            <div className="label mb-1">SGK {lang === "en" ? "Debt" : "Borcu"}</div>
            <div className="flex items-center gap-1">
              <select className="input text-xs flex-1" value={risk.sgkDebt || ""} onChange={e => updateField("risk.sgkDebt", e.target.value)}>
                <option value="">--</option>
                <option value="yes">VAR</option>
                <option value="no">YOK</option>
              </select>
              <button className="btn btn-ghost text-xs" disabled style={{ background: "#dbeafe", color: "#1d4ed8", opacity: 0.7 }} title={lang === "en" ? "Coming soon" : "Yakında"}>
                {lang === "en" ? "Query" : "Sorgula"}
              </button>
            </div>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Tax Debt" : "Vergi Borcu"}</div>
            <div className="flex items-center gap-1">
              <select className="input text-xs flex-1" value={risk.taxDebt || ""} onChange={e => updateField("risk.taxDebt", e.target.value)}>
                <option value="">--</option>
                <option value="yes">VAR</option>
                <option value="no">YOK</option>
              </select>
              <button className="btn btn-ghost text-xs" disabled style={{ background: "#dbeafe", color: "#1d4ed8", opacity: 0.7 }} title={lang === "en" ? "Coming soon" : "Yakında"}>
                GİB
              </button>
            </div>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Debt Amount" : "Borç Tutar"}</div>
            <MoneyInput className="input w-full mono" value={risk.debtAmount || ""} onChange={v => updateField("risk.debtAmount", v === '' ? 0 : v)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Status Date" : "Durum Açıklama Tarihi"}</div>
            <input type="date" className="input w-full mono" value={risk.statusDate || ""} onChange={e => updateField("risk.statusDate", e.target.value)}/>
          </div>
          <div className="md:col-span-4">
            <div className="label mb-1">{lang === "en" ? "Status Description" : "Durum Açıklaması"}</div>
            <textarea className="input w-full" rows={2} value={risk.statusDescription || ""} onChange={e => updateField("risk.statusDescription", e.target.value)}/>
          </div>
        </div>
      </div>

      {/* Risk Detay Bilgileri */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <div className="label">{lang === "en" ? "Risk Detail Information" : "Risk Detay Bilgileri"}</div>
          <button onClick={() => updateField("risk.details", [...details, { id: Date.now(), criteria: "open_account", limit: 0, exceededAction: "continue" }])} className="btn btn-ghost text-xs">
            <Plus size={11}/> {lang === "en" ? "Add" : "Ekle"}
          </button>
        </div>
        {details.length === 0 ? (
          <div className="text-xs p-3" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
            {lang === "en" ? "No risk details" : "Risk detayı yok"}
          </div>
        ) : (
          <table style={{ width: "100%", fontSize: 11 }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>{lang === "en" ? "Criteria" : "Risk Kriterleri"}</th>
                <th style={{ padding: "6px", textAlign: "right", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 150 }}>{lang === "en" ? "Limit" : "Limitler"}</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 220 }}>{lang === "en" ? "When Exceeded" : "Limit Aşıldığında"}</th>
                <th style={{ padding: "6px", width: 40 }}></th>
              </tr>
            </thead>
            <tbody>
              {details.map((d, idx) => (
                <tr key={d.id} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={d.criteria} onChange={e => {
                      const newList = [...details]; newList[idx] = { ...d, criteria: e.target.value }; updateField("risk.details", newList);
                    }}>
                      <option value="open_account">Açık Hesap</option>
                      <option value="company_check">Kurum Çek ve Senetleri</option>
                      <option value="customer_check">Müşteri Çek ve Senetleri</option>
                      <option value="endorsed_check">Ciro Çek ve Senetleri</option>
                      <option value="delivery_note">İrsaliye</option>
                      <option value="order">Sipariş</option>
                      <option value="invoice">Fatura</option>
                      <option value="budget">Bütçe</option>
                      <option value="advance">Avans</option>
                      <option value="travel">Harcırah</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <MoneyInput className="input text-xs w-full mono text-right" value={d.limit || ""} onChange={v => {
                      const newList = [...details]; newList[idx] = { ...d, limit: v === '' ? 0 : v }; updateField("risk.details", newList);
                    }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={d.exceededAction} onChange={e => {
                      const newList = [...details]; newList[idx] = { ...d, exceededAction: e.target.value }; updateField("risk.details", newList);
                    }}>
                      <option value="continue">İşleme Devam Edilecek</option>
                      <option value="warn">Kullanıcı Uyarılacak</option>
                      <option value="stop">İşlem Durdurulacak</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px", textAlign: "center" }}>
                    <button onClick={() => updateField("risk.details", details.filter(x => x.id !== d.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                      <Trash2 size={10}/>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

/* ===================================================================== */
/* TAB 4: PARAMETRELER (TMO mockup 6_1_5)                                */
/* ===================================================================== */
function TabParametreler({ party, updateField, lang }) {
  const params = party.params || {};
  const usage = params.usage || {};
  const approval = params.orderApproval || {};
  const dueTracking = params.dueTracking || [];
  const closeControl = params.debtCloseControl || {};

  return (
    <div className="space-y-4">
      <div>
        <div className="label mb-2">{lang === "en" ? "General" : "Genel"}</div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Partial Shipment" : "Parçalı Sipariş Sevkiyatı"}</div>
            <select className="input text-xs w-full" value={String(params.partialShipment || false)} onChange={e => updateField("params.partialShipment", e.target.value === "true")}>
              <option value="false">Hayır</option>
              <option value="true">Evet</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Invoice Print Count" : "Fatura Yazım Sayısı"}</div>
            <input type="number" className="input w-full mono" value={params.invoicePrintCount || 1}
              onChange={e => updateField("params.invoicePrintCount", Number(e.target.value) || 1)}/>
          </div>
        </div>
      </div>

      <div>
        <div className="label mb-2">{lang === "en" ? "Usage Area" : "Kullanım Yeri"}</div>
        <div className="grid grid-cols-2 md:grid-cols-5 gap-2">
          {[
            { k: "buying", l: { tr: "Satın Alma", en: "Buying" } },
            { k: "selling", l: { tr: "Satış", en: "Selling" } },
            { k: "export", l: { tr: "İhracat", en: "Export" } },
            { k: "import", l: { tr: "İthalat", en: "Import" } },
            { k: "finance", l: { tr: "Finans", en: "Finance" } },
          ].map(x => (
            <div key={x.k}>
              <div className="label mb-1">{x.l[lang]}</div>
              <select className="input text-xs w-full" value={String(usage[x.k] || false)} onChange={e => updateField(`params.usage.${x.k}`, e.target.value === "true")}>
                <option value="false">Hayır</option>
                <option value="true">Evet</option>
              </select>
            </div>
          ))}
        </div>
      </div>

      <div>
        <div className="label mb-2">{lang === "en" ? "Order Approval Criteria" : "Sipariş Onay Kriterleri"}</div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Risk Check" : "Risk Kriteri"}</div>
            <select className="input text-xs w-full" value={String(approval.riskCheck || false)} onChange={e => updateField("params.orderApproval.riskCheck", e.target.value === "true")}>
              <option value="false">Hayır</option>
              <option value="true">Evet</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Due Check" : "Vade Kriteri"}</div>
            <select className="input text-xs w-full" value={String(approval.dueCheck || false)} onChange={e => updateField("params.orderApproval.dueCheck", e.target.value === "true")}>
              <option value="false">Hayır</option>
              <option value="true">Evet</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Aging Check" : "Yaşlandırma Kriteri"}</div>
            <select className="input text-xs w-full" value={String(approval.agingCheck || false)} onChange={e => updateField("params.orderApproval.agingCheck", e.target.value === "true")}>
              <option value="false">Hayır</option>
              <option value="true">Evet</option>
            </select>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "Aging Days" : "Yaşlandırma Günü"}</div>
            <input type="number" className="input w-full mono" value={approval.agingDays || 0}
              onChange={e => updateField("params.orderApproval.agingDays", Number(e.target.value) || 0)}/>
          </div>
        </div>
      </div>

      <div>
        <div className="flex items-center justify-between mb-2">
          <div className="label">{lang === "en" ? "Due Tracking Criteria" : "Vade Takibi Kriterleri"}</div>
          <button onClick={() => updateField("params.dueTracking", [...dueTracking, { id: Date.now(), transactionType: "sales_invoice", trackingDays: 30, trackingAmount: 1000, action: "warn" }])} className="btn btn-ghost text-xs">
            <Plus size={11}/> Ekle
          </button>
        </div>
        {dueTracking.length === 0 ? (
          <div className="text-xs p-3" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
            {lang === "en" ? "No tracking criteria" : "Vade takibi yok"}
          </div>
        ) : (
          <table style={{ width: "100%", fontSize: 11 }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>İşlem</th>
                <th style={{ padding: "6px", textAlign: "right", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 120 }}>Gün</th>
                <th style={{ padding: "6px", textAlign: "right", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 150 }}>Tutar</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase", width: 200 }}>Yapılacak</th>
                <th style={{ padding: "6px", width: 40 }}></th>
              </tr>
            </thead>
            <tbody>
              {dueTracking.map((d, idx) => (
                <tr key={d.id} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={d.transactionType} onChange={e => {
                      const newList = [...dueTracking]; newList[idx] = { ...d, transactionType: e.target.value }; updateField("params.dueTracking", newList);
                    }}>
                      <option value="sales_invoice">Satış Faturaları</option>
                      <option value="sales_order">Satış Siparişleri</option>
                      <option value="cash">Kasa İşlemleri</option>
                      <option value="cari">Cari Hesap İşlemleri</option>
                      <option value="bank">Banka İşlemleri</option>
                      <option value="export">İhracat İşlemleri</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <input type="number" className="input text-xs w-full mono text-right" value={d.trackingDays}
                      onChange={e => { const newList = [...dueTracking]; newList[idx] = { ...d, trackingDays: Number(e.target.value) || 0 }; updateField("params.dueTracking", newList); }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <MoneyInput className="input text-xs w-full mono text-right" value={d.trackingAmount || ""}
                      onChange={v => { const newList = [...dueTracking]; newList[idx] = { ...d, trackingAmount: v === '' ? 0 : v }; updateField("params.dueTracking", newList); }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={d.action} onChange={e => {
                      const newList = [...dueTracking]; newList[idx] = { ...d, action: e.target.value }; updateField("params.dueTracking", newList);
                    }}>
                      <option value="continue">İşleme Devam Edilecek</option>
                      <option value="warn">Kullanıcı Uyarılacak</option>
                      <option value="stop">İşlem Durdurulacak</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px", textAlign: "center" }}>
                    <button onClick={() => updateField("params.dueTracking", dueTracking.filter(x => x.id !== d.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                      <Trash2 size={10}/>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      <div>
        <div className="label mb-2">{lang === "en" ? "Debt Close Date Control" : "Borç Kapama Vade Tarihi Kontrolü"}</div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
          <div>
            <div className="label mb-1">{lang === "en" ? "Days to Check" : "Kontrol Yapılacak Gün Sayısı"}</div>
            <input type="number" className="input w-full mono" value={closeControl.days || 0}
              onChange={e => updateField("params.debtCloseControl.days", Number(e.target.value) || 0)}/>
          </div>
          <div>
            <div className="label mb-1">{lang === "en" ? "When Detected" : "Kontrol Yapıldığında"}</div>
            <select className="input text-xs w-full" value={closeControl.action || "continue"} onChange={e => updateField("params.debtCloseControl.action", e.target.value)}>
              <option value="continue">İşleme Devam Edilecek</option>
              <option value="warn">Kullanıcı Uyarılacak</option>
              <option value="stop">İşlem Durdurulacak</option>
            </select>
          </div>
        </div>
      </div>
    </div>
  );
}

