/* ===================================================================== */
/* TAB 6: TEMİNAT (TMO mockup 6_1_7)                                     */
/* ===================================================================== */
function TabTeminat({ party, updateField, lang }) {
  const guarantees = party.guarantees || [];
  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between">
        <div className="label">{lang === "en" ? "Guarantee Information" : "Teminat Bilgileri"}</div>
        <button onClick={() => updateField("guarantees", [...guarantees, {
          id: Date.now(), bankCode: "", bankName: "", branch: "",
          type: "received", letterType: "bank_letter", letterKind: "advance", periodType: "termed",
          documentDate: "", dueDate: "", amount: 0, currency: "TRY", status: "open",
        }])} className="btn btn-ghost text-xs">
          <Plus size={11}/> Teminat Ekle
        </button>
      </div>
      {guarantees.length === 0 ? (
        <div className="text-xs p-6" style={{ color: "var(--ink-mute)", textAlign: "center", border: "1px dashed var(--line)", borderRadius: 4 }}>
          {lang === "en" ? "No guarantees" : "Tanımlı teminat yok"}
        </div>
      ) : (
        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", fontSize: 10.5, minWidth: 1100 }}>
            <thead>
              <tr style={{ background: "var(--bg-alt)", borderBottom: "1px solid var(--line)" }}>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Banka/Şube</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Cinsi</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Tür</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Mektup Türü</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Süre</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Belge Tarih</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Vade</th>
                <th style={{ padding: "6px", textAlign: "right", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Tutar</th>
                <th style={{ padding: "6px", textAlign: "left", fontSize: 9, color: "var(--ink-mute)", textTransform: "uppercase" }}>Durum</th>
                <th style={{ padding: "6px", width: 40 }}></th>
              </tr>
            </thead>
            <tbody>
              {guarantees.map((g, idx) => (
                <tr key={g.id} style={{ borderBottom: "1px solid var(--line)" }}>
                  <td style={{ padding: "4px" }}>
                    <input className="input text-xs w-full" value={g.bankName || ""} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, bankName: e.target.value }; updateField("guarantees", newList);
                    }} placeholder="Akbank T.A.Ş."/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={g.type} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, type: e.target.value }; updateField("guarantees", newList);
                    }}>
                      <option value="received">Alınan Teminat</option>
                      <option value="given">Verilen Teminat</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={g.letterType} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, letterType: e.target.value }; updateField("guarantees", newList);
                    }}>
                      <option value="bank_letter">Banka Teminat Mektubu</option>
                      <option value="cash">Nakit</option>
                      <option value="gov_bond">Devlet Tahvili</option>
                      <option value="check">Çek</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={g.letterKind} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, letterKind: e.target.value }; updateField("guarantees", newList);
                    }}>
                      <option value="advance">Avans Teminat</option>
                      <option value="final">Kesin Teminat</option>
                      <option value="temporary">Geçici Teminat</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={g.periodType} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, periodType: e.target.value }; updateField("guarantees", newList);
                    }}>
                      <option value="termed">Vadeli</option>
                      <option value="no_term">Vadesiz</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <input type="date" className="input text-xs w-full mono" value={g.documentDate || ""} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, documentDate: e.target.value }; updateField("guarantees", newList);
                    }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <input type="date" className="input text-xs w-full mono" value={g.dueDate || ""} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, dueDate: e.target.value }; updateField("guarantees", newList);
                    }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <MoneyInput className="input text-xs w-full mono text-right" value={g.amount || ""} onChange={v => {
                      const newList = [...guarantees]; newList[idx] = { ...g, amount: v === '' ? 0 : v }; updateField("guarantees", newList);
                    }}/>
                  </td>
                  <td style={{ padding: "4px" }}>
                    <select className="input text-xs w-full" value={g.status} onChange={e => {
                      const newList = [...guarantees]; newList[idx] = { ...g, status: e.target.value }; updateField("guarantees", newList);
                    }}>
                      <option value="open">Açık</option>
                      <option value="closed">Kapalı</option>
                    </select>
                  </td>
                  <td style={{ padding: "4px", textAlign: "center" }}>
                    <button onClick={() => updateField("guarantees", guarantees.filter(x => x.id !== g.id))} className="btn btn-ghost text-xs" style={{ color: "#b91c1c" }}>
                      <Trash2 size={10}/>
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

