/* =====================================================================
   AI: AKILLI FATURA→PROJE EŞLEŞTİRME (Gelişmiş v2)
   ---------------------------------------------------------------------
   Skorlama:
   - Proje kodu açıklamada → +80 (kesin)
   - Proje ismindeki ortak kelimeler → +15/kelime
   - Aynı cariden geçmiş fatura → +30 base + 5/freq
   - Tutar aralığı eşleşmesi → +20
   - Tarih yakınlığı (proje aktif tarih aralığında) → +15
   - Deal'e bağlı proje → +60
   - Müşterinin aktif projesi → +25
   - Aktif proje bonusu → +5
   - TF-IDF benzeri açıklama kelime eşleşmesi → +variable

   Geri bildirim ile öğrenir:
   - Kullanıcı önerilen projeyi seçtiyse → o eşleşme +10 boost (gelecekte)
   - Kullanıcı farklı seçtiyse → öneri düşürülür
===================================================================== */

/* =====================================================================
   AI FEEDBACK SİSTEMİ
   ---------------------------------------------------------------------
   Kullanıcı AI önerilerini 👍/👎 işaretler veya seçimini kaydeder.
   Bu veri:
   - data.aiFeedback[]'a saklanır
   - Backend ML servisine gönderilir (opsiyonel)
   - Gelecek önerilerin skorlamasında kullanılır
===================================================================== */
function recordAIFeedback({ type, suggestionData, userAction, accepted, rejectedFor, data, session, onChange }) {
  const feedback = {
    id: "fb_" + Date.now() + "_" + Math.random().toString(36).slice(2, 4),
    type,                                   // "project_match" | "category_match" | "party_match"
    suggestionData,                         // önerinin orijinal data'sı
    userAction,                             // "accepted" | "rejected" | "modified"
    accepted: !!accepted,
    rejectedFor: rejectedFor || null,       // kullanıcının yerine seçtiği (opsiyonel)
    userId: session?.username,
    createdAt: new Date().toISOString(),
  };

  const currentFeedback = data.aiFeedback || [];
  // Son 500 feedback tut (eski olanlar düşsün)
  const updated = [...currentFeedback, feedback].slice(-500);
  if (onChange) onChange({ ...data, aiFeedback: updated });

  // Backend ML servisine gönder (best-effort, hata olursa sessiz)
  try {
    const apiBase = window.location.protocol + "//" + window.location.hostname + ":8001";
    fetch(`${apiBase}/v1/feedback`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(feedback),
    }).catch(() => {/* Backend offline ise OK */});
  } catch {}

  return feedback;
}

/**
 * AI feedback istatistiklerini hesaplar.
 * Accuracy = kabul edilen / toplam (modifiye dahil rejected sayılır).
 */
function getAIFeedbackStats(aiFeedback = []) {
  const byType = {};
  aiFeedback.forEach(fb => {
    if (!byType[fb.type]) byType[fb.type] = { total: 0, accepted: 0, rejected: 0, modified: 0 };
    byType[fb.type].total++;
    if (fb.accepted) byType[fb.type].accepted++;
    else byType[fb.type].rejected++;
    if (fb.userAction === "modified") byType[fb.type].modified++;
  });

  const result = {};
  Object.entries(byType).forEach(([type, stats]) => {
    result[type] = {
      ...stats,
      accuracy: stats.total > 0 ? (stats.accepted / stats.total) * 100 : 0,
    };
  });
  return result;
}

/* =====================================================================
   REPORTS v3 — Excel Export Helper
   ---------------------------------------------------------------------
   XLSX library kullanarak çok-sayfalı Excel dosyası üretir.
   Her sheet için: { sheetName, headers: [str], rows: [[...]] }
===================================================================== */
async function exportReportToExcel({ filename, sheets, summary = {}, lang = "tr" }) {
  try {
    // Dinamik import — başlangıçta yüklenmez
    const XLSX = await import("xlsx");
    const wb = XLSX.utils.book_new();

    // Özet sayfası (opsiyonel)
    if (summary && Object.keys(summary).length > 0) {
      const summaryData = [
        [lang === "en" ? "REPORT SUMMARY" : "RAPOR ÖZETİ"],
        [],
        [lang === "en" ? "Generated:" : "Oluşturulma:", new Date().toLocaleString(lang === "tr" ? "tr-TR" : "en-US")],
        [lang === "en" ? "Generated by:" : "Oluşturan:", summary.generatedBy || "—"],
        [],
        ...Object.entries(summary).filter(([k]) => k !== "generatedBy").map(([k, v]) => [k, String(v)]),
      ];
      const summarySheet = XLSX.utils.aoa_to_sheet(summaryData);
      // Style: başlık kalın
      summarySheet["!cols"] = [{ width: 35 }, { width: 25 }];
      XLSX.utils.book_append_sheet(wb, summarySheet, lang === "en" ? "Summary" : "Ozet");
    }

    // Her sheet'i ekle
    sheets.forEach(sheet => {
      const rows = [sheet.headers, ...sheet.rows];
      const ws = XLSX.utils.aoa_to_sheet(rows);

      // Otomatik sütun genişlikleri
      const colWidths = sheet.headers.map((h, i) => {
        const maxLen = Math.max(
          String(h).length,
          ...sheet.rows.map(r => String(r[i] || "").length)
        );
        return { width: Math.min(50, Math.max(8, maxLen + 2)) };
      });
      ws["!cols"] = colWidths;

      // Sayfa adı 31 karakterden uzun olamaz
      const sheetName = (sheet.sheetName || "Sheet").slice(0, 31);
      XLSX.utils.book_append_sheet(wb, ws, sheetName);
    });

    // Dosyayı indir
    XLSX.writeFile(wb, filename || "rapor.xlsx");
    return true;
  } catch (err) {
    console.error("Excel export error:", err);
    alert((lang === "en" ? "Excel export failed: " : "Excel dışa aktarma başarısız: ") + err.message);
    return false;
  }
}

/**
 * Hızlı CSV export (basit veriler için, XLSX'a alternatif)
 */
function exportReportToCSV({ filename, headers, rows }) {
  const escape = (val) => {
    const s = String(val ?? "");
    if (/[",\n;]/.test(s)) return '"' + s.replace(/"/g, '""') + '"';
    return s;
  };
  const csv = [
    headers.map(escape).join(";"),
    ...rows.map(r => r.map(escape).join(";")),
  ].join("\n");
  // BOM (Excel'in TR karakter düzgün gösterimi için)
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename || "rapor.csv";
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

function suggestProjectForInvoice({ draft, invoices = [], projects = [], deals = [] }) {
  const description = String(draft.description || "").toLowerCase();
  const partyId = draft.partyId;
  const dealId = draft.dealId;
  const amount = Number(draft.total) || Number(draft.netAmount) || 0;
  const invDate = draft.date;

  const scores = new Map();

  const add = (projectId, score, reason) => {
    if (!projectId) return;
    const existing = scores.get(projectId) || { score: 0, reasons: [] };
    existing.score += score;
    existing.reasons.push(reason);
    scores.set(projectId, existing);
  };

  // Stopwords (TR + EN)
  const stopwords = new Set(["ve", "veya", "ile", "için", "bir", "bu", "fatura", "ödeme",
    "the", "a", "an", "and", "or", "with", "for", "of", "to", "in", "on"]);

  // 1. Proje kodu/ismi açıklamada geçiyor mu?
  projects.forEach(p => {
    if (!p.id) return;
    const code = String(p.code || "").toLowerCase();
    const name = String(p.name || "").toLowerCase();

    if (code && description.includes(code)) {
      add(p.id, 80, "açıklamada proje kodu");
    }

    if (name && name.length > 3) {
      const nameWords = name.split(/[\s\-_]+/)
        .filter(w => w.length > 2 && !stopwords.has(w));
      const matchingWords = nameWords.filter(w => description.includes(w));
      if (matchingWords.length > 0) {
        add(p.id, 15 * matchingWords.length, `${matchingWords.length} kelime`);
      }
    }

    if (p.status === "active") {
      add(p.id, 5, "aktif");
    }

    // Aktif tarih aralığı içinde mi?
    if (invDate && p.startDate) {
      const projectActive = invDate >= p.startDate &&
        (!p.deadline || invDate <= p.deadline);
      if (projectActive) {
        add(p.id, 15, "proje süresi içinde");
      }
    }
  });

  // 2. Aynı cariden geçmiş + projeye bağlı faturalar
  if (partyId) {
    const partyInvs = invoices.filter(i => i.partyId === partyId && i.projectId);
    const projectFreq = {};
    partyInvs.forEach(i => {
      projectFreq[i.projectId] = (projectFreq[i.projectId] || 0) + 1;
    });
    Object.entries(projectFreq).forEach(([pid, freq]) => {
      add(pid, 30 + freq * 5, `cari geçmişi (${freq}x)`);
    });

    // Tutar aralığı eşleşmesi
    if (amount > 0) {
      Object.keys(projectFreq).forEach(pid => {
        const similar = partyInvs.filter(i =>
          i.projectId === pid &&
          Math.abs(((Number(i.total) || 0) - amount)) / amount < 0.3 // ±%30
        );
        if (similar.length > 0) {
          add(pid, 20, "benzer tutar");
        }
      });
    }
  }

  // 3. Deal bağlı proje
  if (dealId) {
    const deal = deals.find(d => d.id === dealId);
    if (deal?.linkedProjectId) {
      add(deal.linkedProjectId, 60, "satış fırsatından");
    }
    if (deal?.partyId) {
      const partyProjects = projects.filter(p => p.customerId === deal.partyId && p.status === "active");
      partyProjects.forEach(p => {
        add(p.id, 25, "müşterinin aktif projesi");
      });
    }
  }

  // 4. Müşterinin aktif tek projesi varsa, otomatik öner
  if (partyId) {
    const customerActiveProjects = projects.filter(p =>
      p.customerId === partyId && p.status === "active"
    );
    if (customerActiveProjects.length === 1) {
      add(customerActiveProjects[0].id, 40, "müşterinin tek aktif projesi");
    } else if (customerActiveProjects.length > 1) {
      customerActiveProjects.forEach(p => {
        add(p.id, 10, "müşteriye ait aktif proje");
      });
    }
  }

  const sorted = Array.from(scores.entries())
    .map(([id, val]) => ({
      projectId: id,
      project: projects.find(p => p.id === id),
      score: val.score,
      reasons: val.reasons,
    }))
    .filter(s => s.project)
    .sort((a, b) => b.score - a.score)
    .slice(0, 3);

  return sorted;
}

/* =====================================================================
   AI: MILESTONE TARİHİ TAHMİNİ
   ---------------------------------------------------------------------
   Yeni proje için olası milestone tarihlerini tahmin eder.
   Mantık:
   - Aynı tipte tamamlanmış projeleri bul
   - Proje süresine (deadline - start) göre milestone'ların yüzdesel
     dağılımını öğren (örn. ilk %25, %50, %75)
   - Yeni projenin süresine bu yüzdeyi uygula
===================================================================== */
function forecastMilestones({ project, completedProjects = [], lang = "tr" }) {
  if (!project.startDate || !project.deadline) return [];

  const start = new Date(project.startDate);
  const end = new Date(project.deadline);
  const totalDays = Math.max(1, Math.floor((end - start) / 86400000));

  // Tip bazında geçmiş projelerden örüntü
  const sameType = completedProjects.filter(p =>
    p.type === project.type && p.status === "completed" &&
    p.startDate && p.deadline && (p.milestones || []).length >= 2
  );

  // Eğer hiç örnek yoksa, default 4 milestone öner
  if (sameType.length === 0) {
    return [
      { name: lang === "en" ? "Kickoff" : "Başlangıç",          pct: 5,  amountPct: 10 },
      { name: lang === "en" ? "Phase 1 Delivery" : "Faz 1 Teslimi", pct: 30, amountPct: 25 },
      { name: lang === "en" ? "Phase 2 Delivery" : "Faz 2 Teslimi", pct: 60, amountPct: 25 },
      { name: lang === "en" ? "Testing & UAT" : "Test ve Onay",  pct: 85, amountPct: 25 },
      { name: lang === "en" ? "Go-Live" : "Devreye Alma",        pct: 100, amountPct: 15 },
    ].map(m => {
      const d = new Date(start.getTime() + totalDays * (m.pct / 100) * 86400000);
      return {
        name: m.name,
        date: d.toISOString().slice(0, 10),
        amount: project.budget ? Math.round(Number(project.budget) * (m.amountPct / 100)) : 0,
        status: "pending",
      };
    });
  }

  // Geçmiş projelerin milestone örüntüsünü öğren
  const positions = []; // her milestone'un proje süresinin %kaçında olduğu
  sameType.forEach(p => {
    const pStart = new Date(p.startDate);
    const pEnd = new Date(p.deadline);
    const pTotalMs = pEnd - pStart;
    if (pTotalMs <= 0) return;
    (p.milestones || []).forEach((m, idx) => {
      if (!m.date) return;
      const mDate = new Date(m.date);
      const pct = ((mDate - pStart) / pTotalMs) * 100;
      if (pct < 0 || pct > 110) return; // outlier
      positions.push({
        index: idx,
        total: (p.milestones || []).length,
        pct,
        name: m.name,
        amountPct: p.budget > 0 ? ((Number(m.amount) || 0) / Number(p.budget)) * 100 : 0,
      });
    });
  });

  // En sık görülen milestone sayısını bul
  const countFreq = {};
  sameType.forEach(p => {
    const n = (p.milestones || []).length;
    countFreq[n] = (countFreq[n] || 0) + 1;
  });
  const mostCommonCount = Number(Object.entries(countFreq).sort((a, b) => b[1] - a[1])[0]?.[0] || 4);

  // O sayıdaki milestone'lar için ortalama position
  const buckets = [];
  for (let i = 0; i < mostCommonCount; i++) {
    const relevant = positions.filter(p => p.total === mostCommonCount && p.index === i);
    if (relevant.length === 0) {
      buckets.push({
        pct: ((i + 1) / mostCommonCount) * 100,
        amountPct: 100 / mostCommonCount,
        name: `${lang === "en" ? "Phase" : "Faz"} ${i + 1}`,
      });
    } else {
      const avgPct = relevant.reduce((s, r) => s + r.pct, 0) / relevant.length;
      const avgAmtPct = relevant.reduce((s, r) => s + r.amountPct, 0) / relevant.length;
      // En sık geçen isim
      const nameFreq = {};
      relevant.forEach(r => { nameFreq[r.name] = (nameFreq[r.name] || 0) + 1; });
      const topName = Object.entries(nameFreq).sort((a, b) => b[1] - a[1])[0]?.[0] || `${lang === "en" ? "Phase" : "Faz"} ${i + 1}`;
      buckets.push({ pct: avgPct, amountPct: avgAmtPct, name: topName });
    }
  }

  return buckets.map(b => {
    const d = new Date(start.getTime() + totalDays * (b.pct / 100) * 86400000);
    return {
      name: b.name,
      date: d.toISOString().slice(0, 10),
      amount: project.budget ? Math.round(Number(project.budget) * (b.amountPct / 100)) : 0,
      status: "pending",
      _confidence: sameType.length, // kaç örnekten öğrenildi
    };
  });
}

