function buildOpenInvoicesReport(data, lang) {
  const invoices = (data.invoices || []).filter(i =>
    (Number(i.paidAmount) || 0) < (Number(i.total) || 0)
  );
  const parties = data.accParties || [];
  const today = new Date().toISOString().slice(0, 10);

  const sales = [];
  const purchases = [];
  invoices.forEach(i => {
    const remaining = (Number(i.total) || 0) - (Number(i.paidAmount) || 0);
    const isOverdue = i.dueDate && i.dueDate < today;
    const daysOverdue = isOverdue ? Math.floor((new Date(today) - new Date(i.dueDate)) / 86400000) : 0;
    const row = [
      i.invoiceNo || "—",
      i.date,
      i.dueDate || "—",
      parties.find(p => p.id === i.partyId)?.name || i.counterparty || "—",
      Number(i.total) || 0,
      Number(i.paidAmount) || 0,
      remaining,
      i.currency || "TRY",
      isOverdue ? `${daysOverdue} ${lang === "en" ? "days" : "gün"}` : "—",
    ];
    if (i.type === "in") purchases.push(row);
    else sales.push(row);
  });

  const headers = [
    lang === "en" ? "Invoice No" : "Fatura No",
    lang === "en" ? "Date" : "Tarih",
    lang === "en" ? "Due Date" : "Vade",
    lang === "en" ? "Counterparty" : "Karşı Taraf",
    lang === "en" ? "Total" : "Toplam",
    lang === "en" ? "Paid" : "Ödenen",
    lang === "en" ? "Remaining" : "Kalan",
    lang === "en" ? "Currency" : "Para Birimi",
    lang === "en" ? "Overdue" : "Gecikme",
  ];

  return {
    sheets: [
      { sheetName: lang === "en" ? "Sales (AR)" : "Satis (AR)", headers, rows: sales },
      { sheetName: lang === "en" ? "Purchase (AP)" : "Alis (AP)", headers, rows: purchases },
    ],
    summary: {
      totalOpenAR: sales.reduce((s, r) => s + r[6], 0),
      totalOpenAP: purchases.reduce((s, r) => s + r[6], 0),
    },
  };
}

function buildCashflowReport(data, lang) {
  const today = new Date();
  const horizon90 = new Date(today.getTime() + 90 * 86400000);
  const invoices = data.invoices || [];

  // Daily flow build
  const daily = {};
  const todayStr = today.toISOString().slice(0, 10);
  const horizonStr = horizon90.toISOString().slice(0, 10);

  invoices.forEach(i => {
    if (!i.dueDate || i.dueDate < todayStr || i.dueDate > horizonStr) return;
    const remaining = (Number(i.total) || 0) - (Number(i.paidAmount) || 0);
    if (remaining <= 0) return;
    if (!daily[i.dueDate]) daily[i.dueDate] = { inflow: 0, outflow: 0 };
    if (i.type === "in") daily[i.dueDate].outflow += remaining;
    else daily[i.dueDate].inflow += remaining;
  });

  const sorted = Object.entries(daily).sort(([a], [b]) => a.localeCompare(b));
  let cumulative = 0;
  const rows = sorted.map(([date, vals]) => {
    cumulative += vals.inflow - vals.outflow;
    return [date, vals.inflow, vals.outflow, vals.inflow - vals.outflow, cumulative];
  });

  return {
    sheets: [{
      sheetName: lang === "en" ? "Cashflow 90d" : "Nakit Akis 90g",
      headers: [
        lang === "en" ? "Date" : "Tarih",
        lang === "en" ? "Inflow" : "Tahsilat",
        lang === "en" ? "Outflow" : "Ödeme",
        lang === "en" ? "Net" : "Net",
        lang === "en" ? "Cumulative" : "Kümülatif",
      ],
      rows,
    }],
    summary: {
      forecastDays: 90,
      totalInflow: rows.reduce((s, r) => s + r[1], 0),
      totalOutflow: rows.reduce((s, r) => s + r[2], 0),
    },
  };
}

